window.RECIPES = [{"pair":1,"title":"Tomato Zucchini Fritters","subtitle":"with Butter Bean Succotash & Aioli","servings":"2 (4)","cook_time":"35 (45) min","nutrition":{"calories":"680","fat":"24 g","carbohydrates":"89 g","protein":"27 g"},"description":null,"from_your_kitchen":null,"ingredients":["1 ear of corn","13.4 oz butter beans","1 red bell pepper","1 shallot","1 garlic clove","1 lemon*","1 red radish","1 zucchini","1 Roma tomato","¾ cup garbanzo bean flour","1 tsp Alamo blend chili seasoning","¼ cup Follow Your Heart® Soy-Free Vegenaise®"],"tools":null,"steps":[{"n":1,"title":null,"text":"Shuck the corn and cut kernels off the cob. Drain and rinse the butter beans. Dice the red bell pepper(s). Peel and mince the shallot(s). Peel and mince the garlic. Halve and juice the lemon(s). Slice the radish(es) into thin rounds. Grate the zucchini(s) on the medium side of a box grater. Dice the tomato(es).","img":"001_1.jpg"},{"n":2,"title":null,"text":"Heat 1 tsp (2 tsp) olive oil in a large nonstick skillet over medium-high heat. Add corn kernels and a pinch of salt and cook until tender. Add cooked corn, beans, diced pepper, minced shallot, just half the lemon juice, 1 tbsp (2 tbsp) olive oil, ¼ tsp (½ tsp) salt, and a sprinkle of pepper to a medium bowl. Mix the butter bean succotash.","img":"001_2.jpg"},{"n":3,"title":null,"text":"Add grated zucchini, diced tomato, and a pinch of salt and pepper to a colander. Let sit 5 to 6 minutes, and squeeze as much water out of the mixture as possible. Place mixture in a medium bowl, and add garbanzo bean flour and Alamo blend chili seasoning. Stir to combine.","img":"001_3.jpg"},{"n":4,"title":null,"text":"Wipe the large nonstick skillet clean, add 1 tbsp vegetable oil, and heat over medium-high heat. Scoop 6 portions of tomato zucchini fritter batter into the skillet, each about ¼ cup. Use the bottom of a measuring cup bottom to flatten the fritters. Cook fritters until browned and crisp, 3 to 5 minutes per side. Transfer tomato zucchini fritters to a paper towel-lined plate and sprinkle with salt.","img":"001_4.jpg"},{"n":5,"title":null,"text":"Add minced garlic, remaining lemon juice, Vegenaise, and a pinch of salt and pepper to a small bowl, and stir the aioli. Divide the butter bean succotash between bowls. Top with tomato zucchini fritters. Garnish with aioli and sliced radish. Tuck in!","img":"001_5.jpg"}],"tips":["* This ingredient will be split between steps.","TIP: We will reuse this skillet in a later step.","TIP: To remove moisture from the zucchini and tomato, use your hands or a spatula to press the mixture against the colander.","TIP: Work in batches for the 4 serving meal, adding 1 tbsp vegetable oil for the second batch."],"cuisine_tags":["American","Southern"],"ingredient_tags":["butter beans","corn","tomato","zucchini"],"item_tags":["chili seasoning","garbanzo bean flour","lemon","radish","vegenaise"],"issues":null,"front":"001a_IMG_9134.jpg","back":"001b_IMG_9135.jpg","era":"binder","hero":"001.jpg"},{"pair":2,"title":"Black Pepper Tofu","subtitle":"with Chinese Broccoli & Brown Rice","servings":"2 (4)","cook_time":"40 (50) min","nutrition":{"calories":"700","fat":"18 g","carbohydrates":"118 g","protein":"30 g"},"description":null,"from_your_kitchen":null,"ingredients":["¾ cup short-grain brown rice","3 garlic cloves","1 oz fresh ginger","1 shallot","1 bird's eye chile 🌶","14 oz organic extra firm tofu","3 scallions","1 celery stalk","6 oz Chinese broccoli","¼ cup cornstarch","1 tbsp vegan butter","3 tbsp tamari","2 tbsp brown sugar"],"tools":null,"steps":[{"n":1,"title":null,"text":"Add brown rice, 1½ cups (3 cups) water, and a pinch of salt to a small saucepan. Bring to a boil, cover, reduce heat to low, and cook until the water is absorbed and grains are tender, 30 to 35 minutes. Fluff brown rice with a fork.","img":"002_1.jpg"},{"n":2,"title":null,"text":"Peel and mince the garlic, ginger, and shallot(s). Mince the bird's eye chile(s). Drain tofu, pat dry, and cut into 1 inch cubes. Chop scallions into 2 inch pieces. Thinly slice the celery. Roughly chop the Chinese broccoli.","img":"002_2.jpg"},{"n":3,"title":null,"text":"Add cubed tofu and cornstarch to a large bowl, and toss. Heat 2 tbsp (4 tbsp) vegetable oil in a large nonstick skillet over medium-high heat. Add cubed tofu and cook, tossing occasionally, until browned in places, 5 to 8 minutes. Transfer crispy tofu to a paper towel-lined plate and sprinkle with salt.","img":"002_3.jpg"},{"n":4,"title":null,"text":"Return the large nonstick skillet to medium heat and add the butter. After butter is melted, add minced garlic, minced ginger, minced shallot, and 1 tsp (2 tsp) minced bird's eye chile. Cook until shallot softens, 1 to 2 minutes. In a small bowl, whisk the tamari and brown sugar until sugar dissolves.","img":"002_4.jpg"},{"n":5,"title":null,"text":"Add crispy tofu, chopped scallion, sliced celery, tamari mixture, and ¼ tsp (½ tsp) pepper to the skillet with the aromatics. Cook until tofu is heated through, 3 to 4 minutes.","img":"002_5.jpg"},{"n":6,"title":null,"text":"Divide the brown rice between bowls and top with the black pepper tofu. Return the large nonstick skillet to high heat and add chopped broccoli and ¼ cup (½ cup) water. Sprinkle with salt, and cook until broccoli is crisp-tender, 2 to 3 minutes. Serve Chinese broccoli on the side. Enjoy!","img":"002_6.jpg"}],"tips":["This item is spicy.","Substitute: gluten-free soy sauce for tamari","TIP: Make sure to wash your hands after prepping the chile(s).","TIP: If necessary, work in batches for the 4 serving meal.","TIP: Add more minced bird's eye chile if you prefer.","TIPS: Do not wash the skillet; we'll use it again in the next step. Add more pepper if you prefer more spice."],"cuisine_tags":["Chinese"],"ingredient_tags":["chinese broccoli","rice","tofu"],"item_tags":["bird's eye chile","brown sugar","cornstarch","ginger","tamari","vegan butter"],"issues":null,"front":"002a_IMG_9136.jpg","back":"002b_IMG_9137.jpg","era":"binder","hero":"002.jpg"},{"pair":3,"title":"Korean Tofu Tacos","subtitle":"with Kimchi Slaw & Cilantro","servings":"2 (4)","cook_time":"20 (30) min","nutrition":{"calories":"690","fat":"40 g","carbohydrates":"57 g","protein":"29 g"},"description":null,"from_your_kitchen":null,"ingredients":["1 garlic clove","1 oz fresh ginger","1 tbsp gochujang 🌶","2 tbsp peanut butter","1 tbsp tamari","1 tsp turbinado sugar","1 tbsp sesame oil","14 oz organic extra firm tofu","4 oz coleslaw blend","2.8 oz vegan cabbage kimchi","3 tbsp Follow Your Heart® Soy-Free Vegenaise®","6 corn tortillas","½ oz fresh cilantro"],"tools":null,"steps":[{"n":1,"title":null,"text":"Preheat the oven to 350°F. Peel and mince the garlic. Peel and mince 2 tsp (4 tsp) ginger. Add minced garlic, minced ginger, gochujang, peanut butter, tamari, turbinado sugar, sesame oil, and 2 tbsp (4 tbsp) warm water to a medium bowl. Whisk the gochujang sauce.","img":"003_1.jpg"},{"n":2,"title":null,"text":"Cut tofu into ½ inch cubes. Heat 1 tbsp (2 tbsp) vegetable oil in a large nonstick skillet over medium-high heat. Add cubed tofu and cook until crispy in places, 3 to 5 minutes. Add gochujang sauce and cook another 2 to 3 minutes.","img":"003_2.jpg"},{"n":3,"title":null,"text":"Add coleslaw blend, kimchi, Vegenaise, and a pinch of salt and pepper to a large bowl. Toss the kimchi slaw to combine.","img":"003_3.jpg"},{"n":4,"title":null,"text":"Wrap tortillas in foil and place them in the oven to warm, 4 to 5 minutes. Roughly chop the cilantro leaves and stems. Divide warm tortillas between plates and top with Korean tofu and kimchi slaw. Top the Korean tofu tacos with chopped cilantro. Tuck in!","img":"003_4.jpg"}],"tips":["This item is spicy.","Substitute: gluten-free soy sauce for tamari","TIPS: The oven will be used to warm the tortillas. You can use a toaster oven or microwave instead if you prefer. Save any remaining ginger for your own use.","Healthy Kimchi: Aside from being a convenient way to preserve vegetables, kimchi is known for its incredible health benefits. It's packed with probiotics, plus it's rich in vitamin C, beta-carotene, and fiber. These elements are essential for healthy digestion, immunity, and heart health, and scientists are continually discovering even more benefits of adding kimchi to your diet."],"cuisine_tags":["Fusion","Korean","Mexican"],"ingredient_tags":["cabbage","kimchi","tofu","tortilla"],"item_tags":["cilantro","gochujang","peanut butter","sesame oil","tamari","turbinado sugar","vegenaise"],"issues":null,"front":"003a_IMG_9138.jpg","back":"003b_IMG_9139.jpg","era":"binder","hero":"003.jpg"},{"pair":4,"title":"Lemon Zucchini Noodles","subtitle":"with Cashew Cream & Crispy Artichoke Hearts","servings":"2","cook_time":"30 min","nutrition":{"calories":"500","fat":"27 g","carbohydrates":"47 g","protein":"24 g"},"description":null,"from_your_kitchen":null,"ingredients":["½ cup cashews","13.75 oz artichoke hearts","2 zucchini","1 lemon*","1 garlic clove","2 tsp white miso paste","1 tbsp nutritional yeast","1 tbsp hemp seeds","¼ cup pumpkin seeds","½ tsp red chile flakes 🌶"],"tools":null,"steps":[{"n":1,"title":null,"text":"Add cashews and ½ cup hot water to a small bowl, and let nuts soak for at least 10 minutes. Drain artichoke hearts and pat dry.","img":"004_1.jpg"},{"n":2,"title":null,"text":"Heat 1 tbsp olive oil in a large nonstick skillet over medium heat. Add artichoke hearts and cook until crispy in places, 5 to 8 minutes. Transfer crispy artichoke hearts to a plate and sprinkle with salt.","img":"004_2.jpg"},{"n":3,"title":null,"text":"Trim zucchini and slice lengthwise into ¼ inch thick planks. Stack the zucchini planks and cut into thin strips to make noodles.","img":"004_3.jpg"},{"n":4,"title":null,"text":"Zest and halve the lemon, juice one half, and cut the other half into wedges. Peel the garlic. Add soaked cashews and the soaking water, lemon juice, peeled garlic, white miso paste, nutritional yeast, and a pinch of salt and pepper to a blender. Blend on high until cashew cream is smooth.","img":"004_4.jpg"},{"n":5,"title":null,"text":"Return skillet to medium-high heat and add zucchini noodles. Sprinkle with salt and pepper and cook, tossing occasionally, until tender, 1 to 2 minutes.","img":"004_5.jpg"},{"n":6,"title":null,"text":"Divide zucchini noodles between serving bowls. Pour cashew cream over noodles and top with crispy artichoke hearts. Sprinkle with lemon zest, hemp seeds, pumpkin seeds, and as much of the red chile flakes as you'd like. Serve with lemon wedges. Tuck in!","img":"004_6.jpg"}],"tips":["* This ingredient will be split between steps.","This item is spicy.","TIP: We will use this skillet again in a later step.","TIP: You can also use a spiralizer or mandoline to make the zucchini noodles."],"cuisine_tags":["Italian","Mediterranean"],"ingredient_tags":["artichoke hearts","cashews","zucchini"],"item_tags":["hemp seeds","lemon","miso","nutritional yeast","pumpkin seeds","red chile flakes"],"issues":null,"front":"004a_IMG_9140.jpg","back":"004b_IMG_9141.jpg","era":"binder","hero":"004.jpg"},{"pair":5,"title":"Sweet Corn Stuffed Poblanos","subtitle":"with Creamed Spinach & Cilantro","servings":"2 (4)","cook_time":"35 (50) min","nutrition":{"calories":"590","fat":"30 g","carbohydrates":"74 g","protein":"19 g"},"description":null,"from_your_kitchen":null,"ingredients":["1 Not-Chick'n™ Bouillon Cube","2 poblano peppers","1 onion","1 garlic clove","1 ear of corn","½ cup polenta","2 tsp turbinado sugar","5.5 oz coconut milk*","2 oz Treeline® Cashew Cream Cheese","4 oz baby spinach","2 tbsp nutritional yeast","¼ oz fresh cilantro"],"tools":null,"steps":[{"n":1,"title":null,"text":"Preheat the oven to 425°F. Add 2 cups (4 cups) water and bouillon cube(s) to a medium saucepan and bring to a boil. Slice one side of each poblano pepper, from stem to bottom, without fully cutting peppers in half. Remove seeds and as much of the pith as possible. Peel and thinly slice the onion(s). Peel and mince the garlic. Shuck the corn and cut kernels off the cob(s).","img":"005_1.jpg"},{"n":2,"title":null,"text":"Once the broth in the saucepan is boiling, add corn kernels, polenta, sugar, just ¼ cup (½ cup) coconut milk, and a pinch of salt and pepper. Whisk until mixture comes to a boil, and cook until thickened, 3 to 4 minutes.","img":"005_2.jpg"},{"n":3,"title":null,"text":"Place sliced onion in a baking dish and drizzle with 1 tbsp (2 tbsp) olive oil. Top with the sliced poblano peppers, and spoon sweet corn filling into each pepper. Dollop peppers with cashew cheese and bake, uncovered, until peppers are tender, 20 to 25 minutes.","img":"005_3.jpg"},{"n":4,"title":null,"text":"Heat 1 tsp (2 tsp) olive oil in a large skillet over medium-high heat. Add minced garlic and cook until fragrant, about 1 minute. Add just ½ cup (1 cup) coconut milk, baby spinach, nutritional yeast, ¼ tsp (½ tsp) salt, and a pinch of pepper. Cook until creamed spinach thickens slightly, 4 to 5 minutes.","img":"005_4.jpg"},{"n":5,"title":null,"text":"Divide the creamed spinach between plates and top with sweet corn stuffed poblanos and roasted onions. Sprinkle with cilantro leaves and stems. Bon appétit!","img":"005_5.jpg"}],"tips":["* This ingredient will be split between steps.","TIP: You may have extra filling left over depending on the size of your peppers.","TIP: Keep any remaining coconut milk for your own use.","Fresh Corn is Our Fave: We make corn the star of this recipe, allowing its natural sweetness to really shine. It also pairs well with the poblanos, and the creamed spinach and cilantro perfectly balance things out."],"cuisine_tags":["Mexican"],"ingredient_tags":["corn","poblano peppers","polenta","spinach"],"item_tags":["bouillon","cashew cream cheese","cilantro","coconut milk","nutritional yeast","turbinado sugar"],"issues":null,"front":"005a_IMG_9142.jpg","back":"005b_IMG_9143.jpg","era":"binder","hero":"005.jpg"},{"pair":6,"title":"Plantain Arepas","subtitle":"with Tofu Scramble & Guacamole","servings":"2","cook_time":"45 min","nutrition":{"calories":"590","fat":"27 g","carbohydrates":"72 g","protein":"26 g"},"description":null,"from_your_kitchen":null,"ingredients":["1 plantain","2 mini sweet peppers","1 shallot*","14 oz organic extra firm tofu","1½ tsp ground turmeric","1 tbsp nutritional yeast","½ cup masa harina","1 Roma tomato","¼ oz fresh cilantro","1 lime*","1 avocado","1 tbsp vegan butter"],"tools":null,"steps":[{"n":1,"title":null,"text":"Peel the plantain and slice into ½ inch thick rounds. Add sliced plantain to a small saucepan, cover with 1 inch water, and bring to a boil. Cook until fork-tender, 4 to 6 minutes. Drain and return plantain to the saucepan, off heat. Mash boiled plantain with a fork.","img":"006_1.jpg"},{"n":2,"title":null,"text":"Trim, deseed, and thinly slice the mini sweet peppers. Peel the shallot, slice in half, thinly slice one half, and dice the other half. Drain the tofu, pat dry, and crumble.","img":"006_2.jpg"},{"n":3,"title":null,"text":"Add 2 tbsp vegetable oil and ground turmeric to a large skillet over medium heat. Cook until fragrant, 2 to 3 minutes. Add sliced mini sweet peppers and sliced shallot. Cook until softened, 3 to 5 minutes. Add crumbled tofu, nutritional yeast, and ½ tsp salt. Cook until lightly browned, 5 to 7 minutes. Transfer the tofu scramble to a plate.","img":"006_3.jpg"},{"n":4,"title":null,"text":"Add mashed plantain, masa harina, and ¼ tsp salt to a large bowl. Add ¼ cup water and mix dough with your hands. Divide arepa dough into 4 equal parts and shape into small, flat rounds about ½ inch thick. Wipe the large skillet clean and return it to medium heat with 1 tbsp vegetable oil. Once hot, add plantain arepas and cook until golden brown, 3 to 5 minutes per side.","img":"006_4.jpg"},{"n":5,"title":null,"text":"Dice the tomato. Roughly chop cilantro leaves and stems. Halve the lime, juice one half, and cut the other half into wedges. Halve the avocado, scoop flesh into a medium bowl, and mash with a fork. Add diced shallot, diced tomato, chopped cilantro, lime juice, and a pinch of salt to the bowl, and stir the guacamole.","img":"006_5.jpg"},{"n":6,"title":null,"text":"Halve the plantain arepas crosswise and spread butter on each half. Add guacamole and tofu scramble to one half of each arepa, and top with the remaining arepa half. Serve with lime wedges and any remaining tofu scramble and guacamole. Enjoy!","img":"006_6.jpg"}],"tips":["* These ingredients will be split between steps.","TIP: We will this skillet again in the next step.","TIP: If dough is dry, add water—up to 2 tbsp—until you achieve the desired consistency."],"cuisine_tags":["Latin American"],"ingredient_tags":["avocado","masa harina","plantain","tofu"],"item_tags":["cilantro","lime","nutritional yeast","turmeric","vegan butter"],"issues":null,"front":"006a_IMG_9144.jpg","back":"006b_IMG_9145.jpg","era":"binder","hero":"006.jpg"},{"pair":7,"title":"Mushroom Cheddar Black Bean Burgers","subtitle":"with Garlic Aioli & Carrot Fries","servings":"2","cook_time":"35 min","nutrition":{"calories":"780","fat":"33 g","carbohydrates":"92 g","protein":"26 g"},"description":null,"from_your_kitchen":null,"ingredients":["2 carrots","4 oz mushrooms","1 onion*","2 tsp fajita seasoning*","13.4 oz black beans","2 garlic cloves*","2 tbsp all-purpose flour","2 oz vegan shredded cheddar","¼ cup Follow Your Heart® Soy-Free Vegenaise®","2 potato buns"],"tools":null,"steps":[{"n":1,"title":null,"text":"Preheat the oven to 425°F. Peel the carrots and slice into sticks. Add sliced carrots, 2 tsp vegetable oil, and a pinch of salt and pepper to a baking sheet, and toss to coat. Bake carrot fries until tender and browned in spots, 18 to 22 minutes.","img":"007_1.jpg"},{"n":2,"title":null,"text":"Thinly slice the mushrooms. Halve the onion, thinly slice one half, and mince the other half. Heat 2 tsp vegetable oil in a large nonstick skillet over medium-high heat. Add sliced mushrooms, sliced onion, and just ½ tsp fajita seasoning. Cook until mushrooms are browned in places, 5 to 7 minutes. Transfer the sautéed vegetables to a bowl.","img":"007_2.jpg"},{"n":3,"title":null,"text":"Drain and rinse the black beans. Peel and mince the garlic. Add just ½ cup minced onion, remaining fajita seasoning, black beans, just half the minced garlic, and flour to a large bowl. Mix with your hands, crushing the beans, until burger mix is sticky and uniform. Form into 2 patties, each about 1 inch thick.","img":"007_3.jpg"},{"n":4,"title":null,"text":"Return the large nonstick skillet to medium-high heat with 2 tbsp vegetable oil. Add black bean patties and cook until crisp and heated through, 3 to 5 minutes per side. Remove skillet from heat, top cooked black bean patties with cheddar, and cover until melted, 3 to 5 minutes.","img":"007_4.jpg"},{"n":5,"title":null,"text":"Add remaining minced garlic, Vegenaise, and a pinch of salt to a small bowl. Mix the garlic aioli.","img":"007_5.jpg"},{"n":6,"title":null,"text":"Toast the potato buns. Spread garlic aioli on the top half of each bun, and place black bean patties on the bottom halves. Top with mushroom sautéed vegetables. Serve the mushroom cheddar black bean burgers with carrot fries and garlic aioli for dipping. Tuck in!","img":"007_6.jpg"}],"tips":["* These ingredients will be split between steps.","TIPS: Don't forget to wash all produce under running water, and wipe mushrooms clean with a damp kitchen towel. We will use this skillet again.","TIP: Keep any remaining minced onion for your own use.","TIP: Add more oil as necessary to crisp the burgers."],"cuisine_tags":["American","Comfort Food"],"ingredient_tags":["black beans","carrot","mushrooms"],"item_tags":["fajita seasoning","potato buns","vegan cheddar","vegenaise"],"issues":null,"front":"007a_IMG_9146.jpg","back":"007b_IMG_9147.jpg","era":"binder","hero":"007.jpg"},{"pair":8,"title":"Punjabi Kadhi","subtitle":"with Spinach Dumplings & Mango Chutney","servings":"2","cook_time":"35 min","nutrition":{"calories":"670","fat":"24 g","carbohydrates":"96 g","protein":"20 g"},"description":null,"from_your_kitchen":null,"ingredients":["1 onion*","4 garlic cloves","1 oz fresh ginger","1 jalapeño 🌶","8 oz baby spinach*","⅔ cup garbanzo bean flour","¼ cup Forager Project® Organic Dairy-free Cashewmilk Yogurt","¼ tsp baking powder","2 tsp curry powder","5.5 oz coconut milk","1 Not-Chick'n™ Bouillon Cube","8.8 oz precooked brown rice","2 tbsp mango chutney"],"tools":null,"steps":[{"n":1,"title":null,"text":"Peel and finely dice the onion. Peel and mince the garlic and ginger. Halve, deseed, and thinly slice the jalapeño. Roughly chop just half the baby spinach.","img":"008_1.jpg"},{"n":2,"title":null,"text":"Place a medium saucepan over medium heat. Add chopped spinach and 2 tbsp water and cook, stirring occasionally, until spinach is bright green, 1 to 2 minutes. Drain, and transfer spinach to a medium bowl. To that same bowl, add just 2 tbsp diced onion, garbanzo bean flour, yogurt, baking powder, 2 tbsp vegetable oil, and ¼ tsp salt. Stir the dumpling mixture until just combined.","img":"008_2.jpg"},{"n":3,"title":null,"text":"Return the empty saucepan to medium heat with 2 tsp vegetable oil. Once hot, add remaining diced onion, minced garlic, and minced ginger. Cook until softened, 2 to 3 minutes. Add curry powder and stir. Add coconut milk, bouillon cube, and ⅔ cup water, and bring sauce to a simmer. Cook until slightly thickened, 3 to 5 minutes. Once curry sauce has thickened, reduce heat to low.","img":"008_3.jpg"},{"n":4,"title":null,"text":"Drop heaping spoonfuls of dumpling mixture into the sauce; you should get 8 dumplings. Cover dumplings and gently simmer until they expand and are firm to the touch, 5 to 8 minutes.","img":"008_4.jpg"},{"n":5,"title":null,"text":"Heat 1 tsp vegetable oil in a large skillet over medium-high heat. Add sliced jalapeño, remaining baby spinach, and a pinch of salt. Cook until spinach is bright green and wilted, 2 to 3 minutes.","img":"008_5.jpg"},{"n":6,"title":null,"text":"Make a small tear at the top of the brown rice bag and microwave bag for 1 minute. Divide warm brown rice between large bowls. Top with sautéed spinach and punjabi kadhi. Dollop with mango chutney. Tuck in!","img":"008_6.jpg"}],"tips":["* These ingredients will be split between steps.","This item is spicy.","TIP: Remember to wash your hands after handling the jalapeño.","TIP: To reheat the rice without a microwave, add precooked brown rice and 1 tbsp water to a small saucepan over medium-high heat. Cover and steam until warmed through, 3 to 4 minutes."],"cuisine_tags":["Indian"],"ingredient_tags":["chickpea flour","rice","spinach"],"item_tags":["bouillon","cashewmilk yogurt","coconut milk","curry powder","ginger","jalapeño","mango chutney"],"issues":null,"front":"008a_IMG_9148.jpg","back":"008b_IMG_9149.jpg","era":"binder","hero":"008.jpg"},{"pair":9,"title":"Spinach Artichoke Grilled Cheese","subtitle":"with Hot Pepper Mayo & Oregano Fries","servings":"2","cook_time":"25 min","nutrition":{"calories":"660","fat":"26 g","carbohydrates":"92 g","protein":"15 g"},"description":null,"from_your_kitchen":null,"ingredients":["1 russet potato","½ tsp dried oregano","2 oz pickled jalapeños 🌶","¼ cup Follow Your Heart® Soy-Free Vegenaise®*","½ cup artichoke hearts","2 garlic cloves","2 oz baby spinach","4 slices sourdough bread","2 oz vegan mozzarella"],"tools":null,"steps":[{"n":1,"title":null,"text":"Preheat the oven to 425°F. Cut potato into ½ inch thick sticks and transfer to a baking sheet. Add 2 tsp olive oil, oregano, and a pinch of salt and pepper, and toss. Roast until browned and crisp in places, 18 to 20 minutes.","img":"009_1.jpg"},{"n":2,"title":null,"text":"Finely chop the pickled jalapeños. Add chopped jalapeños, just half the Vegenaise, and a pinch of pepper to a small bowl. Stir the hot pepper mayo.","img":"009_2.jpg"},{"n":3,"title":null,"text":"Drain and roughly chop ½ cup artichoke hearts. Mince the garlic. Add 1 tsp olive oil to a large nonstick skillet over medium-high heat. Add chopped artichoke hearts and cook until crispy in places, 5 to 6 minutes. Add minced garlic and cook until aromatic, about 1 minute. Add baby spinach, stir to combine, and transfer spinach artichoke mixture to a bowl. Wipe the skillet clean and set aside, off heat.","img":"009_3.jpg"},{"n":4,"title":null,"text":"To assemble the sandwiches, place 2 slices of sourdough bread on a flat surface and spread just ½ tbsp Vegenaise on each slice. Flip slices over and spread hot pepper mayo on the other side. Add spinach artichoke mixture and mozzarella, and top with remaining bread slices to close the sandwiches. Spread remaining Vegenaise on top of each sandwich.","img":"009_4.jpg"},{"n":5,"title":null,"text":"Place the large nonstick skillet over medium heat. Add sandwiches and cook until golden brown, 2 to 3 minutes per side.","img":"009_5.jpg"},{"n":6,"title":null,"text":"Cut the spinach artichoke grilled cheese sandwiches in half and serve with oregano fries. Enjoy!","img":"009_6.jpg"}],"tips":["This item is spicy.","* This ingredient will be split between steps.","TIP: Rotate the baking sheet halfway through baking to ensure even browning.","TIP: If you're sensitive to spice, omit or use less pickled jalapeño.","TIPS: Keep the remaining artichoke hearts for your own use. We will use this skillet again.","TIP: If the bread browns before the cheese has melted, lower the heat."],"cuisine_tags":["American","Comfort Food"],"ingredient_tags":["artichoke hearts","potato","sourdough bread","spinach"],"item_tags":["oregano","pickled jalapeños","vegan mozzarella","vegenaise"],"issues":null,"front":"009a_IMG_9150.jpg","back":"009b_IMG_9151.jpg","era":"binder","hero":"009.jpg"},{"pair":10,"title":"Gnocchi Al Pesto","subtitle":"with Charred Green Beans & Lemon Zucchini","servings":"2 (4)","cook_time":"30 (40) min","nutrition":{"calories":"510","fat":"17 g","carbohydrates":"83 g","protein":"12 g"},"description":null,"from_your_kitchen":null,"ingredients":["6 oz green beans","1 zucchini","1 lemon*","1 tsp Aleppo pepper flakes 🌶","10 oz fresh gnocchi","¼ cup vegan basil pesto"],"tools":null,"steps":[{"n":1,"title":null,"text":"Bring a large pot of salted water to a boil for the gnocchi. Cut green beans in half. Trim the zucchini(s) and peel lengthwise to make ribbons. Halve the lemon(s), juice one half (1 lemon), and cut the other half (1 lemon) into wedges.","img":"010_1.jpg"},{"n":2,"title":null,"text":"Add zucchini ribbons, lemon juice, Aleppo pepper flakes, and a pinch of salt to a medium bowl. Toss to combine.","img":"010_2.jpg"},{"n":3,"title":null,"text":"Heat 2 tsp (4 tsp) olive oil in a large nonstick skillet over medium-high heat. Add halved green beans and cook until browned in places, 3 to 4 minutes. Add ¼ cup (½ cup) water, reduce heat to low, and cook green beans until crisp-tender, another 2 to 3 minutes. Sprinkle charred green beans with salt and pepper, and transfer to a bowl.","img":"010_3.jpg"},{"n":4,"title":null,"text":"Add gnocchi to the large pot of boiling water and cook until they float to the surface, 3 to 5 minutes. Drain, and shake off any excess water.","img":"010_4.jpg"},{"n":5,"title":null,"text":"Return the skillet to medium heat with 1 tbsp (2 tbsp) olive oil. Add cooked gnocchi and sauté, undisturbed, until browned in places, 2 to 4 minutes. Return charred green beans to the skillet along with the basil pesto and toss to combine. Sprinkle with salt and pepper.","img":"010_5.jpg"},{"n":6,"title":null,"text":"Divide the gnocchi al pesto with charred green beans between bowls. Serve with lemon zucchini and lemon wedges. Mangia!","img":"010_6.jpg"}],"tips":["* This ingredient will be split between steps.","This item is spicy.","TIP: We will reuse this skillet in a later step.","TIP: If the pesto is too thick, add 1 tbsp warm water (or more, if necessary), to create a thinner consistency."],"cuisine_tags":["Italian"],"ingredient_tags":["gnocchi","green beans","zucchini"],"item_tags":["aleppo pepper","basil pesto","lemon"],"issues":null,"front":"010a_IMG_9152.jpg","back":"010b_IMG_9153.jpg","era":"binder","hero":"010.jpg"},{"pair":11,"title":"Green Goddess Vegetable Pilaf","subtitle":"with Asparagus & Herbed Ranch Dressing","servings":"2 (4)","cook_time":"25 (35) min","nutrition":{"calories":"570","fat":"32 g","carbohydrates":"63 g","protein":"12 g"},"description":null,"from_your_kitchen":null,"ingredients":["½ cup basmati rice","4 oz sugar snap peas","3 scallions","1 cucumber","6 oz asparagus","¼ oz fresh mint","1 avocado","1 lemon*","¼ cup pistachios","2 tsp dried parsley","¼ cup Follow Your Heart® High Omega Vegan Ranch Salad Dressing"],"tools":null,"steps":[{"n":1,"title":null,"text":"Add basmati rice, 1 cup (2 cups) water, and a pinch of salt to a small saucepan. Bring to a boil, cover, reduce heat to low, and cook until the water is absorbed and grains are tender, 13 to 15 minutes.","img":"011_1.jpg"},{"n":2,"title":null,"text":"Thinly slice the sugar snap peas. Thinly slice scallions. Dice cucumber(s). Trim 1 inch off the ends of the asparagus. Pick and roughly chop the mint leaves. Halve the avocado(s), remove the pit(s), and thinly slice the flesh. Halve and juice the lemon(s).","img":"011_2.jpg"},{"n":3,"title":null,"text":"Heat 2 tsp (4 tsp) olive oil in a large skillet over medium-high heat. Add asparagus and cook, undisturbed, until charred in places, 2 to 4 minutes. Sprinkle with salt and pepper, toss, and cook until crisp-tender, another 1 to 2 minutes.","img":"011_3.jpg"},{"n":4,"title":null,"text":"Fluff the cooked basmati rice and transfer to a large bowl. Add sliced snap peas, sliced scallion, diced cucumber, chopped mint, just 1 tbsp (2 tbsp) lemon juice, pistachios, and 2 tsp (4 tsp) olive oil. Gently toss the vegetable pilaf. Taste, and add salt and pepper as necessary.","img":"011_4.jpg"},{"n":5,"title":null,"text":"Add remaining lemon juice, parsley, ranch dressing, and a pinch of pepper to a small bowl and stir the herbed ranch dressing. Divide the vegetable pilaf between plates and top with cooked asparagus and sliced avocado. Drizzle the green goddess vegetable pilaf with herbed ranch dressing. Bon appétit!","img":"011_5.jpg"}],"tips":["* This ingredient will be split between steps.","Full of Freshness: We packed this meal with tons of green veggies, including sugar snap peas, scallions, and asparagus, plus cucumber and avocado (which, yes, we realize are technically fruits, not veggies). We added fresh mint and dried parsley, too, sending the fresh factor off the charts. Plus, this is perfect for camping! Prep is a cinch and it's easy to toss in a container and go. Just don't forget the forks!"],"cuisine_tags":["American"],"ingredient_tags":["asparagus","avocado","cucumber","rice","sugar snap peas"],"item_tags":["lemon","mint","parsley","pistachios","ranch dressing"],"issues":null,"front":"011a_IMG_9154.jpg","back":"011b_IMG_9155.jpg","era":"binder","hero":"011.jpg"},{"pair":12,"title":"Rajas Tacos","subtitle":"with Avocado & Roasted Corn Salsa","servings":"2 (4)","cook_time":"30 (40) min","nutrition":{"calories":"570","fat":"14 g","carbohydrates":"104 g","protein":"12 g"},"description":null,"from_your_kitchen":null,"ingredients":["½ cup Spanish rice","2 poblano peppers","1 yellow onion","1 ear of corn","1 avocado","1 scallion","1 lime","¼ oz fresh cilantro","6 corn tortillas","2 tsp hot sauce (spicy)"],"tools":null,"steps":[{"n":1,"title":null,"text":"Add Spanish rice and 1 cup (2 cups) water to a small saucepan. Bring to a boil, cover, reduce heat to low, and cook until water is absorbed and rice is tender, 13 to 15 minutes.","img":"012_1.jpg"},{"n":2,"title":null,"text":"Slice peppers in half and remove the stems and seeds. Cut halved peppers into ½ inch strips. Peel and slice the onion(s). Shuck the corn and slice kernels off the cob(s). Halve the avocado(s), remove the pit(s), and dice the flesh. Slice the scallion(s). Halve the lime(s), juice one half (1 lime), and divide the other half (1 lime) into wedges. Roughly chop the cilantro leaves and stems.","img":"012_2.jpg"},{"n":3,"title":null,"text":"Set the broiler to high. Add sliced pepper, sliced onion, corn kernels, 1 tbsp (2 tbsp) vegetable oil, and a pinch of salt to a baking sheet, and toss. Broil the corn salsa on the middle rack until onions are translucent and peppers and corn are softened and lightly browned, 5 to 6 minutes.","img":"012_3.jpg"},{"n":4,"title":null,"text":"Set the oven to 400°F. Add diced avocado, sliced scallion, lime juice, chopped cilantro, and salt to a medium bowl, and stir. Wrap tortillas in foil and warm in the oven, 3 to 4 minutes.","img":"012_4.jpg"},{"n":5,"title":null,"text":"Add Spanish rice and roasted corn salsa to the tortillas. Dollop with avocado mixture and drizzle with hot sauce. Serve the rajas tacos with lime wedges. Buen provecho!","img":"012_5.jpg"}],"tips":["TIP: To cut kernels off the cob, break cob in half and slice down the sides with a knife. If you are grilling this recipe, remove kernels from cob after grilling.","TIP: All broilers are different; watch closely to ensure veggies don't burn.","TIP: If you prefer, you can use a toaster oven or microwave to heat the tortillas instead.","What Does Rajas Mean? Place corn in the husk, on the grill rack, and cook, turning occasionally, until it is steamed through to the center, about 15 minutes. The outside should be completely black, but the interior should be steamed and moist."],"cuisine_tags":["Mexican"],"ingredient_tags":["avocado","corn","poblano peppers","rice","tortilla"],"item_tags":["cilantro","hot sauce","lime","spanish rice"],"issues":null,"front":"012a_IMG_9156.jpg","back":"012b_IMG_9157.jpg","era":"binder","hero":"012.jpg"},{"pair":13,"title":"Pan Seared Broccolini","subtitle":"with Mashed Sweet Potatoes & Coconut Turmeric Relish","servings":"2 (4)","cook_time":"35 (45) min","nutrition":{"calories":"520","fat":"14 g","carbohydrates":"80 g","protein":"20 g"},"description":null,"from_your_kitchen":null,"ingredients":["1 sweet potato","½ cup beluga lentils","2 garlic cloves","1 Fresno chile (spicy)","1 oz fresh ginger","1 lemon","8 oz broccolini","2 tbsp golden raisins","2 tbsp toasted coconut","2 tsp brown mustard seeds","¼ tsp ground turmeric","2 tbsp vegan butter"],"tools":null,"steps":[{"n":1,"title":null,"text":"Peel and dice the sweet potato(es). Add diced sweet potato to a small saucepan and cover with 1 inch water. Bring to a boil and cook until fork-tender, 10 to 12 minutes. Drain and return cooked sweet potato to the saucepan, off heat. Rinse and sort the beluga lentils, and add to a separate saucepan with 1 cup (2 cups) water. Bring to a boil, cover, reduce heat to low, and simmer until lentils are tender, 20 to 24 minutes.","img":"013_1.jpg"},{"n":2,"title":null,"text":"Peel and thinly slice the garlic. Trim, halve, and deseed the Fresno chile(s), and mince one half (1 Fresno chile). Peel and mince 2 tsp (4 tsp) ginger. Halve and juice the lemon(s). Trim 1 inch off the broccolini stems.","img":"013_2.jpg"},{"n":3,"title":null,"text":"Heat 2 tbsp (4 tbsp) olive oil in a large nonstick skillet over medium heat. Add sliced garlic and cook until lightly browned, 3 to 5 minutes. Add minced Fresno chile, minced ginger, golden raisins, toasted coconut, brown mustard seeds, and turmeric. Stir and cook until aromatic, 1 to 3 minutes. Add lemon juice and transfer the coconut turmeric relish to a medium bowl.","img":"013_3.jpg"},{"n":4,"title":null,"text":"Wipe the skillet clean and return to medium-high heat. Add 2 tsp (4 tsp) olive oil, ¼ cup (½ cup) water, and a pinch of salt. Add broccolini, cover, and cook until water evaporates and broccolini is tender and crispy in places, 3 to 5 minutes. Flip and cook for an additional 2 minutes.","img":"013_4.jpg"},{"n":5,"title":null,"text":"Add butter to the cooked sweet potatoes and mash with a fork. Taste, and add salt as necessary. Divide the mashed sweet potatoes and beluga lentils between large plates. Top with pan seared broccolini and coconut turmeric relish. Enjoy!","img":"013_5.jpg"}],"tips":["TIP: To \"sort\" means to look for and discard any naturally occurring debris or stones.","TIP: Save the remaining ginger for your own use.","TIPS: Add more Fresno chile if you prefer more heat, and save any remaining chile for your own use. We will use this skillet again in the next step."],"cuisine_tags":["Fusion","Indian"],"ingredient_tags":["broccolini","lentils","sweet potato"],"item_tags":["brown mustard seeds","fresno chile","ginger","golden raisins","toasted coconut","turmeric","vegan butter"],"issues":null,"front":"013a_IMG_9158.jpg","back":"013b_IMG_9159.jpg","era":"binder","hero":"013.jpg"},{"pair":14,"title":"Crispy Cauliflower Pakoras","subtitle":"with Red Lentil Dal & Cilantro Chutney","servings":"2","cook_time":"35 min","nutrition":{"calories":"590","fat":"18 g","carbohydrates":"86 g","protein":"24 g"},"description":null,"from_your_kitchen":null,"ingredients":["1 onion","3 garlic cloves*","1 oz fresh ginger","6 oz broccoli florets","4 oz cauliflower florets","2 mini sweet peppers","¼ cup white vinegar","1 tsp turbinado sugar","½ cup red lentils","1 tsp curry powder","5.5 oz coconut milk","¾ cup garbanzo bean flour","1 tsp garam masala","¼ cup cilantro chutney (spicy)"],"tools":null,"steps":[{"n":1,"title":null,"text":"Peel and dice the onion. Peel and mince the garlic and ginger. Chop broccoli florets and cauliflower florets into bite-size pieces. Thinly slice the mini sweet peppers. Add vinegar, sugar, and a pinch of salt to a medium bowl and whisk until sugar dissolves. Add sliced mini sweet peppers and toss to combine.","img":"014_1.jpg"},{"n":2,"title":null,"text":"Rinse and sort the lentils. Heat 1 tbsp vegetable oil in a small saucepan over medium heat. Add diced onion, just half the minced garlic, minced ginger, and a pinch of salt. Cook, stirring frequently, until onion softens, 3 to 4 minutes.","img":"014_2.jpg"},{"n":3,"title":null,"text":"Add curry powder to the small saucepan, stir, and cook until fragrant, about 1 minute. Add lentils, coconut milk, and ¾ cup water. Bring to a boil, cover, reduce heat to low, and cook until lentils are tender and water is absorbed, 12 to 15 minutes.","img":"014_3.jpg"},{"n":4,"title":null,"text":"Add remaining minced garlic, garbanzo bean flour, garam masala, ½ cup cold water, and ¼ tsp salt to a large bowl and whisk the pakora batter.","img":"014_4.jpg"},{"n":5,"title":null,"text":"Add chopped broccoli florets and chopped cauliflower florets to the pakora batter and toss to coat. Heat ½ cup vegetable oil in a medium skillet over medium-high heat. Once hot, gently place coated vegetables in the skillet. Cook until lightly browned, 2 to 3 minutes per side. Transfer to a paper towel-lined plate and sprinkle with salt.","img":"014_5.jpg"},{"n":6,"title":null,"text":"Divide the red lentil dal between bowls and top with crispy cauliflower pakoras and pickled mini sweet peppers. Drizzle with cilantro chutney. Tuck in!","img":"014_6.jpg"}],"tips":["* This ingredient will be split between steps.","TIP: To \"sort\" means to look for and discard any naturally occurring debris or stones.","TIP: Work in batches to avoid overcrowding."],"cuisine_tags":["Indian"],"ingredient_tags":["broccoli","cauliflower","chickpea flour","red lentils"],"item_tags":["cilantro chutney","coconut milk","curry powder","garam masala","ginger","turbinado sugar","white vinegar"],"issues":null,"front":"014a_IMG_9160.jpg","back":"014b_IMG_9161.jpg","era":"binder","hero":"014.jpg"},{"pair":15,"title":"Green Goddess Bowls","subtitle":"with Broccoli & Ranch Dressing","servings":"2","cook_time":"15 min","nutrition":{"calories":"650","fat":"44 g","carbohydrates":"52 g","protein":"14 g"},"description":null,"from_your_kitchen":null,"ingredients":["8.8 oz precooked brown rice","6 oz broccoli florets","1 avocado","¼ oz fresh dill","¼ cup pumpkin seeds","⅓ cup Follow Your Heart® High Omega Vegan Ranch Salad Dressing"],"tools":null,"steps":[{"n":1,"title":null,"text":"Bring 2 cups salted water to a boil in a small saucepan. Make a small tear at the top of the brown rice bag and microwave bag for 1 minute. Chop broccoli florets into bite-size pieces and add to the boiling water. Cover and cook until crisp-tender, 2 to 3 minutes. Drain the broccoli."},{"n":2,"title":null,"text":"Halve the avocado, remove the pit, and dice the flesh. Pick and roughly chop the dill fronds. Divide the brown rice between bowls. Add broccoli florets, diced avocado, and chopped dill. Top with pumpkin seeds and drizzle with ranch dressing."}],"tips":[],"cuisine_tags":["American"],"ingredient_tags":["avocado","broccoli","rice"],"item_tags":["dill","pumpkin seeds","ranch dressing"],"single_page":true,"issues":null,"front":"015a_IMG_9162.jpg","back":null,"era":"binder","hero":"015.jpg"},{"pair":16,"title":"Lemon Zucchini Noodles","subtitle":"with Cashew Cream & Crispy Artichoke Hearts","servings":"2","cook_time":"30 min","nutrition":{"calories":"450","fat":"25 g","carbohydrates":"37 g","protein":"23 g"},"description":null,"from_your_kitchen":null,"ingredients":["½ cup cashews","13.75 oz artichoke hearts","2 zucchini","1 lemon*","1 garlic clove","2 tsp white miso paste","1 tbsp nutritional yeast","1 tbsp hemp seeds","¼ cup pumpkin seeds","½ tsp red chile flakes (spicy)"],"tools":null,"steps":[{"n":1,"title":null,"text":"Add cashews and ½ cup hot water to a small bowl, and let nuts soak for at least 10 minutes. Drain artichoke hearts and pat dry with a clean towel.","img":"016_1.jpg"},{"n":2,"title":null,"text":"Heat 1 tbsp olive oil in a large nonstick skillet over medium heat. Add artichoke hearts and cook until crispy in places, 5 to 8 minutes. Transfer crispy artichoke hearts to a plate and sprinkle with salt.","img":"016_2.jpg"},{"n":3,"title":null,"text":"Trim zucchini and slice lengthwise into ¼ inch thick planks. Stack the planks and cut into thin strips to make noodles.","img":"016_3.jpg"},{"n":4,"title":null,"text":"Zest and halve the lemon, juice one half, and cut the other half into wedges. Peel the garlic. Add soaked cashews and the soaking water, lemon juice, peeled garlic, white miso paste, nutritional yeast, and a pinch of salt and pepper to a blender. Blend on high until cashew cream is smooth.","img":"016_4.jpg"},{"n":5,"title":null,"text":"Return skillet to medium-high heat and add zucchini noodles. Sprinkle with salt and pepper and cook, tossing occasionally, until tender, 1 to 2 minutes.","img":"016_5.jpg"},{"n":6,"title":null,"text":"Divide zucchini noodles between serving bowls. Pour cashew cream over noodles and top with crispy artichoke hearts. Sprinkle with lemon zest, hemp seeds, pumpkin seeds, and as much of the red chile flakes as you'd like. Serve with lemon wedges. Tuck in!","img":"016_6.jpg"}],"tips":["* This ingredient will be split between steps.","TIP: We will use this skillet again.","TIP: You can also use a spiralizer or mandoline to make the zucchini noodles."],"cuisine_tags":["Fusion","Italian"],"ingredient_tags":["artichoke hearts","cashews","zucchini"],"item_tags":["hemp seeds","lemon","miso","nutritional yeast","pumpkin seeds","red chile flakes"],"issues":null,"front":"016a_IMG_9164.jpg","back":"016b_IMG_9165.jpg","era":"binder","hero":"016.jpg"},{"pair":17,"title":"Spicy Mango Tempeh","subtitle":"with Toasted Almond Couscous & Lemon Arugula","servings":"2","cook_time":"35 min","nutrition":{"calories":"580","fat":"13 g","carbohydrates":"76 g","protein":"30 g"},"description":null,"from_your_kitchen":null,"ingredients":["8 oz tempeh","1 shallot","¼ oz fresh parsley","1 lemon*","3 tbsp mango chutney","1 tbsp chile garlic sauce (spicy)","¼ cup sliced almonds","¾ cup Israeli couscous","4 oz baby arugula"],"tools":null,"steps":[{"n":1,"title":null,"text":"Cut tempeh into cubes. Peel and thinly slice the shallot. Chop the parsley leaves. Zest, halve and juice the lemon.","img":"017_1.jpg"},{"n":2,"title":null,"text":"In a medium bowl, combine just half the lemon juice, mango chutney, chile garlic sauce, 1 tbsp olive oil, and 1 tbsp water. Add a pinch of salt and stir the spicy mango sauce. Add almonds to a small saucepan over medium heat and cook until toasted, 3 to 5 minutes. Transfer toasted almonds to a small bowl.","img":"017_2.jpg"},{"n":3,"title":null,"text":"Return empty saucepan to high heat and add 1 cup water and a pinch of salt. Bring to a boil, add Israeli couscous, cover, and reduce heat to low. Cook until water is absorbed, 7 to 9 minutes. Add chopped parsley, lemon zest, toasted almonds, and 2 tsp olive oil. Taste toasted almond couscous and add salt as necessary.","img":"017_3.jpg"},{"n":4,"title":null,"text":"Heat 2 tbsp olive oil in a large nonstick skillet over medium-high heat. Add cubed tempeh and cook until crispy on all sides, 8 to 10 minutes. Sprinkle tempeh with salt and add sliced shallot. Cook until shallot is softened and browned, 2 to 4 minutes. Add spicy mango sauce, toss to coat, and cook for 1 minute.","img":"017_4.jpg"},{"n":5,"title":null,"text":"Add baby arugula, remaining lemon juice, and 1 tsp olive oil to a large bowl. Toss, and sprinkle with salt and pepper.","img":"017_5.jpg"},{"n":6,"title":null,"text":"Divide the lemon arugula between large bowls. Top with toasted almond couscous and spicy mango tempeh. Dig in!","img":"017_6.jpg"}],"tips":["* This ingredient will be split between steps.","Substitute: another green for baby arugula"],"cuisine_tags":["Fusion","Indian"],"ingredient_tags":["arugula","couscous","tempeh"],"item_tags":["chile garlic sauce","lemon","mango chutney","shallot","sliced almonds"],"issues":null,"front":"017a_IMG_9166.jpg","back":"017b_IMG_9167.jpg","era":"binder","hero":"017.jpg"},{"pair":18,"title":"Summer Vegetable Ciabatta","subtitle":"with Cashew Cheese & Roasted Tomato Vinaigrette","servings":"2","cook_time":"30 min","nutrition":{"calories":"440","fat":"19 g","carbohydrates":"64 g","protein":"16 g"},"description":null,"from_your_kitchen":null,"ingredients":["2 garlic cloves*","1 zucchini","4 mini sweet peppers","1 yellow onion","¼ oz fresh basil","2 oz roasted tomatoes","¼ cup red wine vinegar","2 ciabatta rolls","2 oz Treeline® Soft French-Style Cashew Cheese","2 oz baby arugula"],"tools":null,"steps":[{"n":1,"title":null,"text":"Peel the garlic and mince just one clove. Slice zucchini into thick rounds on a bias. Halve the mini sweet peppers and remove the seeds and stems. Peel the onion and slice into wedges. Pick and roughly chop the basil. Roughly chop the roasted tomatoes.","img":"018_1.jpg"},{"n":2,"title":null,"text":"Set broiler to high. Add sliced zucchini, halved peppers, sliced onion, 1 tsp olive oil, and a pinch of salt and pepper to a baking sheet, and toss. Broil until vegetables are tender and slightly browned, 5 to 6 minutes.","img":"018_2.jpg"},{"n":3,"title":null,"text":"Add minced garlic, chopped tomatoes, red wine vinegar, 1 tbsp olive oil, and a sprinkle of salt and pepper to a medium sized bowl. Whisk the roasted tomato vinaigrette to combine.","img":"018_3.jpg"},{"n":4,"title":null,"text":"Slice the ciabatta rolls in half. Broil in the oven, directly on the rack, until golden brown, 2 to 3 minutes. Cut the tip off the remaining garlic clove and rub the exposed clove on the toasted ciabatta.","img":"018_4.jpg"},{"n":5,"title":null,"text":"Spread cashew cheese on the bottom half of each toasted ciabatta roll. Pour just half of the roasted tomato vinaigrette on the broiled summer vegetables, directly on the baking sheet, and toss. Add vegetables to the toasted ciabatta and top with chopped basil. Add baby arugula to the remaining vinaigrette and toss. Serve arugula salad alongside the summer vegetable ciabatta. Dig in!","img":"018_5.jpg"}],"tips":["* This ingredient will be split between steps.","TIP: To cut something \"on a bias\" means to cut it diagonally instead of crosswise.","TIP: All broilers are different. Watch carefully to ensure food doesn't burn.","Get Grillin': If you opt to make this on the grill instead, you can use skewers for the veggies. (And if you're using wooden skewers make sure to soak them in water first; we recommend reading the instructions.) We also suggest cutting the zucchini into chunks instead of planks. It'll be a lot easier and every bit as delicious."],"cuisine_tags":["Italian","Mediterranean"],"ingredient_tags":["arugula","bell pepper","cashew cheese","ciabatta","zucchini"],"item_tags":["basil","cashew cheese","red wine vinegar","roasted tomatoes"],"issues":null,"front":"018a_IMG_9168.jpg","back":"018b_IMG_9169.jpg","era":"binder","hero":"018.jpg"},{"pair":19,"title":"Crispy Black Bean Patties","subtitle":"with Avocado Spinach Salad & Lime Aioli","servings":"2","cook_time":"35 min","nutrition":{"calories":"650","fat":"29 g","carbohydrates":"69 g","protein":"27 g"},"description":null,"from_your_kitchen":null,"ingredients":["13.4 oz black beans","1 garlic clove*","1 onion","1 cucumber","4 oz grape tomatoes","1 lime*","3 tbsp Follow Your Heart® Soy-Free Vegenaise®","½ cup garbanzo bean flour","2 tsp zhoug seasoning","4 oz baby spinach","1 avocado"],"tools":null,"steps":[{"n":1,"title":null,"text":"Drain and rinse the black beans. Peel and mince the garlic. Peel and finely dice just ½ cup onion. Dice the cucumber. Halve the grape tomatoes. Zest, halve, and juice the lime.","img":"019_1.jpg"},{"n":2,"title":null,"text":"Add just ¼ tsp minced garlic, just ½ tsp lime zest, just 2 tsp lime juice, Vegenaise, and a pinch of salt to a small bowl and mix the lime aioli.","img":"019_2.jpg"},{"n":3,"title":null,"text":"Add black beans, remaining minced garlic, diced onion, garbanzo bean flour, zhoug seasoning, and ½ tsp salt to a large bowl. Mix with your hands, crushing the beans, until dough is sticky and uniform. Form dough into 6 patties, each about 2 inches wide.","img":"019_3.jpg"},{"n":4,"title":null,"text":"Heat 2 tbsp vegetable oil to a large nonstick skillet over medium-high heat. Add black bean patties and cook until crisp and heated through, 3 to 5 minutes per side.","img":"019_4.jpg"},{"n":5,"title":null,"text":"Add baby spinach, remaining lime juice, 2 tsp olive oil, and a pinch of salt and pepper to a large bowl, and toss. Halve the avocado, remove the pit, and thinly slice the flesh. Divide spinach salad between bowls and top with black bean patties, diced cucumber, halved tomatoes, and sliced avocado. Drizzle with lime aioli. Bon appétit!","img":"019_5.jpg"}],"tips":["* These ingredients will be split between steps.","TIP: Save the remaining onion for your own use.","TIP: You can use a food processor for this step if you'd prefer.","TIP: Add more oil as necessary to crisp the patties.","Aioli vs Mayo—What's the Difference? Both have a creamy consistency and whitish color. But mayonnaise is an emulsion made with egg yolk and oil, and aioli is an emulsion created with just garlic and extra virgin olive oil. Sometimes egg yolk is added as well, but even then, the addition of garlic sets aioli apart from mayo. In this recipe we put our own spin on things by making lime aioli, which includes minced garlic, lime zest, lime juice, Vegenaise, and a pinch of salt. It's so good!"],"cuisine_tags":["Fusion","Middle Eastern"],"ingredient_tags":["avocado","black beans","chickpea flour","spinach"],"item_tags":["grape tomatoes","lime","vegenaise","zhoug"],"issues":null,"front":"019a_IMG_9170.jpg","back":"019b_IMG_9171.jpg","era":"binder","hero":"019.jpg"},{"pair":20,"title":"Potato Malai Kofta","subtitle":"with Sautéed Spinach & Tomato Chutney","servings":"2","cook_time":"30 min","nutrition":{"calories":"460","fat":"16 g","carbohydrates":"72 g","protein":"12 g"},"description":null,"from_your_kitchen":null,"ingredients":["1 russet potato","1 onion","2 garlic cloves","1 oz fresh ginger","4 oz green beans","1 carrot","2 tbsp tomato powder","1 tsp curry powder","5.5 oz coconut milk","¼ cup garbanzo bean flour","4 oz baby spinach","¼ cup tomato chutney"],"tools":null,"steps":[{"n":1,"title":null,"text":"Peel and dice the potato into bite-size pieces. Add diced potato to a medium saucepan and cover with 1 inch salted water. Bring to a boil and cook until fork-tender, 10 to 12 minutes.","img":"020_1.jpg"},{"n":2,"title":null,"text":"Peel and chop the onion. Peel and slice the garlic. Peel and mince just 2 tsp ginger. Slice green beans into rounds. Peel and grate carrot on the largest side of a box grater. When boiled potatoes are fork-tender, add sliced green beans and grated carrot to the saucepan and cook for 1 minute. Drain cooked vegetables and transfer to a large bowl.","img":"020_2.jpg"},{"n":3,"title":null,"text":"Return the empty saucepan to medium heat with 2 tsp olive oil. Add chopped onion, sliced garlic, and minced ginger, and cook until softened, 3 to 5 minutes. Add tomato powder, curry powder, coconut milk, and ½ tsp salt, and bring to a simmer. Cook the malai sauce until slightly thickened, 2 to 3 minutes.","img":"020_3.jpg"},{"n":4,"title":null,"text":"Add garbanzo bean flour and ¼ tsp salt to the large bowl with the cooked vegetables. Lightly mash kofta mixture and form into 6 patties, each about 1 inch thick.","img":"020_4.jpg"},{"n":5,"title":null,"text":"Heat 2 tbsp olive oil in a large nonstick skillet over medium-high heat. Add kofta patties and cook until browned and crisp, 1 to 2 minutes per side. Transfer the crispy potato kofta to a plate.","img":"020_5.jpg"},{"n":6,"title":null,"text":"Return the skillet to medium heat with 1 tsp olive oil. Add baby spinach and a pinch of salt and pepper. Cook until wilted, 2 to 3 minutes. Transfer malai sauce to a blender and blend on low until smooth. Divide malai sauce between plates and add sautéed spinach and crispy potato kofta. Top the potato malai kofta with tomato chutney. Bon appétit!","img":"020_6.jpg"}],"tips":["TIP: Don't drain the potatoes. They will continue to cook in step 2.","TIPS: We will use this saucepan again in the next step. Save the remaining ginger for your own use.","TIP: Vent blender (by removing the plastic center of the lid) and begin blending on low and finish on high to avoid splashing."],"cuisine_tags":["Indian"],"ingredient_tags":["carrot","chickpea flour","green beans","potato","spinach"],"item_tags":["coconut milk","curry powder","ginger","tomato chutney","tomato powder"],"issues":null,"front":"020a_IMG_9172.jpg","back":"020b_IMG_9173.jpg","era":"binder","hero":"020.jpg"},{"pair":21,"title":"Curried Carrot Fritters","subtitle":"with Mango Avocado Salad & Tamarind Chutney","servings":"2","cook_time":"30 min","nutrition":{"calories":"570","fat":"14 g","carbohydrates":"104 g","protein":"16 g"},"description":null,"from_your_kitchen":null,"ingredients":["¾ cup garbanzo bean flour","1½ tsp curry powder","4 carrots","1 shallot","1 garlic clove","1 mango","1 avocado","6 oz grape tomatoes","¼ oz fresh parsley","1 lime","2 tbsp tamarind chutney"],"tools":null,"steps":[{"n":1,"title":null,"text":"Add garbanzo bean flour, curry powder, and ½ cup cold water to a large bowl and whisk to combine. Grate carrots using the large side of a box grater. Add 2 cups grated carrot, ½ tsp salt and ¼ tsp pepper to the large bowl with the batter. Mix the carrot batter and set aside.","img":"021_1.jpg"},{"n":2,"title":null,"text":"Peel and mince the shallot. Peel and mince the garlic. Peel the mango, remove the pit, and thinly slice the flesh. Halve the avocado, remove the pit, and thinly slice the flesh. Halve the grape tomatoes. Pick and roughly chop the parsley leaves. Zest, halve, and juice the lime.","img":"021_2.jpg"},{"n":3,"title":null,"text":"Add minced shallot, minced garlic, sliced mango, sliced avocado, halved tomatoes, chopped parsley leaves, lime zest, lime juice, ½ tsp salt, and a pinch of pepper to a large bowl. Toss the mango avocado salad and refrigerate until ready to serve.","img":"021_3.jpg"},{"n":4,"title":null,"text":"Heat 1 tbsp vegetable oil in a large nonstick skillet over medium-high heat. Scoop 6 portions of carrot batter into the skillet, each about ¼ cup. Use a measuring cup bottom to flatten the fritters, and cook fritters until browned and crisp, 3 to 5 minutes per side. Transfer curried carrot fritters to a paper towel-lined plate and sprinkle with salt.","img":"021_4.jpg"},{"n":5,"title":null,"text":"Divide the curried carrot fritters between plates and drizzle with tamarind chutney. Serve with mango avocado salad. Dig in!","img":"021_5.jpg"}],"tips":["TIP: If necessary, work in batches to avoid overcrowding the skillet.","Madras-Style Curry Powder: Pure Delight — Madras curry originated in southeastern India and is well known for its warm, aromatic quality. Our spice blend recreates that essence with a sophisticated mix of turmeric, cumin, coriander, and fenugreek, adding tons of flavor to your meal."],"cuisine_tags":["Indian"],"ingredient_tags":["avocado","carrot","chickpea flour","mango","tomato"],"item_tags":["curry powder","lime","parsley","shallot","tamarind chutney"],"issues":null,"front":"021a_IMG_9174.jpg","back":"021b_IMG_9175.jpg","era":"binder","hero":"021.jpg"},{"pair":22,"title":"Italian Sausage Sandwiches","subtitle":"with Shallot Relish & Dilly Cucumber Salad","servings":"2","cook_time":"30 min","nutrition":{"calories":"640","fat":"21 g","carbohydrates":"86 g","protein":"37 g"},"description":null,"from_your_kitchen":null,"ingredients":["1 cucumber","5 garlic cloves*","¼ cup white vinegar","½ tsp dried dill","1 tsp turbinado sugar","2 shallots","1 Thai chile","1 oz balsamic glaze","1½ tsp agave","1 oz Follow Your Heart® Soy-Free Vegenaise®","2 Field Roast® Italian sausages","2 ciabatta rolls","2 oz baby arugula"],"tools":null,"steps":[{"n":1,"title":null,"text":"Thinly slice the cucumber into rounds. Thinly slice just 4 garlic cloves. Add sliced cucumber, sliced garlic, white vinegar, dill, sugar, and a pinch of salt to a large bowl, and toss the dilly cucumber salad to combine.","img":"022_1.jpg"},{"n":2,"title":null,"text":"Set the oven to broil. Peel and quarter the shallots. Add quartered shallots, 2 tsp olive oil, and a pinch of salt to a baking sheet, and toss. Broil until softened and well-browned in places, 7 to 10 minutes. Let broiled shallots cool for 5 minutes, transfer to a cutting board, and roughly chop into bite-size pieces. Thinly slice the Thai chile. In a medium bowl, combine chopped shallots, as much sliced chile as you'd like, balsamic glaze, and agave. Toss the shallot relish and sprinkle with salt.","img":"022_2.jpg"},{"n":3,"title":null,"text":"Peel and mince the remaining garlic clove and add to a small bowl. Add Vegenaise and a pinch of salt. Stir the garlic aioli to combine.","img":"022_3.jpg"},{"n":4,"title":null,"text":"Remove sausages from the plastic casing and slice. Heat 1 tbsp olive oil in a large nonstick skillet over medium-high heat. Add sliced sausage and cook until browned on both sides, 4 to 6 minutes. Slice ciabatta rolls in half and drizzle cut side of halved rolls with 1 tsp olive oil. Sprinkle with a pinch of salt and broil in the oven, directly on the rack, until golden brown, 2 to 3 minutes.","img":"022_4.jpg"},{"n":5,"title":null,"text":"Spread the bottom halves of the toasted ciabatta rolls with garlic aioli. Top with cooked sausage, shallot relish, and baby arugula. Serve Italian sausage sandwiches with dilly cucumber salad. Enjoy!","img":"022_5.jpg"}],"tips":["* This ingredient will be split between steps.","TIP: Continue to toss the cucumbers occasionally to ensure they are evenly coated.","TIP: All broilers are different. Watch carefully to ensure the shallots don't burn.","Want Some Fresh Air While Cooking? Then we suggest you fire up the grill! You can cook these tasty Italian sausages in your kitchen, of course, but they also cook up nicely on the grill—gas or charcoal. So if you've got a grill, now's the perfect time to put it to use."],"cuisine_tags":["American","Italian"],"ingredient_tags":["arugula","ciabatta","cucumber","shallot","vegan sausage"],"item_tags":["agave","balsamic glaze","dill","thai chile","turbinado sugar","vegenaise","white vinegar"],"issues":null,"front":"022a_IMG_9176.jpg","back":"022b_IMG_9177.jpg","era":"binder","hero":"022.jpg"},{"pair":23,"title":"Beluga Lentil Tacos","subtitle":"with Quick Guacamole & Radish Jalapeño Slaw","servings":"2","cook_time":"30 min","nutrition":{"calories":"630","fat":"27 g","carbohydrates":"84 g","protein":"21 g"},"description":null,"from_your_kitchen":null,"ingredients":["½ cup beluga lentils","1 tbsp ground cumin","4 tsp vegetable broth concentrate","2 red radishes","1 jalapeño 🌶","2 lime*","1 avocado","4 oz shredded red cabbage","3 tbsp Follow Your Heart® Soy-Free Vegenaise®","½ tsp chipotle morita powder 🌶","6 corn tortillas"],"tools":null,"steps":[{"n":1,"title":null,"text":"Preheat oven to 350°F. Rinse and sort the beluga lentils. Add beluga lentils, cumin, vegetable broth concentrate, and 1¼ cups water to a medium saucepan. Bring to a boil, cover, reduce heat to low, and simmer until lentils are tender and water is absorbed, 20 to 25 minutes.","img":"023_1.jpg"},{"n":2,"title":null,"text":"Trim and thinly slice the red radishes. Thinly slice the jalapeño.","img":"023_2.jpg"},{"n":3,"title":null,"text":"Halve and juice 1 lime and cut the remaining lime into wedges. Halve the avocado, remove the pit, and scoop the flesh into a medium bowl. Add just half the lime juice and a pinch of salt and pepper, and mash the quick guacamole with a fork.","img":"023_3.jpg"},{"n":4,"title":null,"text":"Add sliced red radish, just a few jalapeño slices, remaining lime juice, red cabbage, 1 tsp olive oil, and ⅛ tsp salt to a medium bowl. Toss the radish jalapeño slaw.","img":"023_4.jpg"},{"n":5,"title":null,"text":"Add Vegenaise, chipotle morita powder, and a pinch of salt to a small bowl. Mix the chipotle crema.","img":"023_5.jpg"},{"n":6,"title":null,"text":"Wrap corn tortillas in foil and warm in the oven for 4 to 5 minutes. Top warm corn tortillas with quick guacamole, cooked beluga lentils, and radish jalapeño slaw. Dollop the beluga lentil tacos with chipotle crema and serve with lime wedges and any remaining radish jalapeño slaw. Tuck in!","img":"023_6.jpg"}],"tips":["These items are spicy. (jalapeño, chipotle morita powder)","* This ingredient will be split between steps.","TIPS: The oven will be used to warm the tortillas. You can use a toaster oven or microwave instead if you prefer. To \"sort\" means to look for and discard any naturally occurring debris or stones.","TIP: If you're sensitive to spice, deseed the jalapeño before slicing.","TIP: If you're sensitive to spice, omit or use less chipotle morita powder."],"cuisine_tags":["Mexican"],"ingredient_tags":["avocado","lentils","radish","red cabbage","tortilla"],"item_tags":["chipotle","cumin","jalapeño","lime","vegenaise","vegetable broth concentrate"],"issues":null,"front":"023a_IMG_9178.jpg","back":"023b_IMG_9179.jpg","era":"binder","hero":"023.jpg"},{"pair":24,"title":"Mushroom Cheddar Black Bean Burgers","subtitle":"with Garlic Aioli & Carrot Fries","servings":"2 (4)","cook_time":"35 (45) min","nutrition":{"calories":"780","fat":"33 g","carbohydrates":"91 g","protein":"26 g"},"description":null,"from_your_kitchen":null,"ingredients":["2 carrots","4 oz mushrooms","1 onion*","2 tsp fajita seasoning*","13.4 oz black beans","2 garlic cloves*","2 tbsp all-purpose flour","2 oz vegan shredded cheddar","¼ cup Follow Your Heart® Soy-Free Vegenaise®","2 potato buns"],"tools":null,"steps":[{"n":1,"title":null,"text":"Preheat the oven to 425°F. Peel the carrots, slice into sticks, and place on a baking sheet. Add 2 tsp (4 tsp) vegetable oil, toss to coat, and sprinkle with salt and pepper. Bake carrot fries until tender and browned in spots, 18 to 22 minutes.","img":"024_1.jpg"},{"n":2,"title":null,"text":"Thinly slice the mushrooms. Halve the onion(s), mince one half (1 onion), and thinly slice the other half (1 onion). Heat 2 tsp (4 tsp) vegetable oil in a large nonstick skillet over medium-high heat. Add sliced mushrooms, sliced onion, and just ½ tsp (1 tsp) fajita seasoning. Cook until mushrooms are browned in places, 5 to 7 minutes. Transfer the sautéed vegetables to a bowl.","img":"024_2.jpg"},{"n":3,"title":null,"text":"Drain and rinse the black beans. Peel and mince the garlic. Add just ½ cup (1 cup) minced onion, remaining fajita seasoning, black beans, just half the minced garlic, and flour to a large bowl. Mix with your hands, crushing the beans, until burger mix is sticky and uniform, and form into 2 (4) patties about 1 inch thick.","img":"024_3.jpg"},{"n":4,"title":null,"text":"Heat 2 tbsp (4 tbsp) vegetable oil in the large nonstick skillet over medium-high heat. Add black bean patties and cook until crisp and heated through, 3 to 5 minutes per side. Remove skillet from heat, top cooked black bean patties with cheddar, and cover until melted, 3 to 5 minutes.","img":"024_4.jpg"},{"n":5,"title":null,"text":"Add remaining minced garlic, Vegenaise, and a pinch of salt to a small bowl. Mix the garlic aioli.","img":"024_5.jpg"},{"n":6,"title":null,"text":"Toast the potato buns. Spread garlic aioli on the top half of each bun, and place black bean patties on the bottom halves. Top with sautéed vegetables. Serve the mushroom cheddar black bean burgers with carrot fries and garlic aioli for dipping. Dig in!","img":"024_6.jpg"}],"tips":["* These ingredients will be split between steps.","TIPS: Don't forget to wash all produce under running water, and wipe mushrooms clean with a damp kitchen towel. We will use this skillet again.","TIP: Keep any remaining minced onion for your own use.","TIP: Add more oil as necessary to crisp the burgers.","Ingredients listed for 2 servings—if you're making 4 servings, please double your ingredients by using both bags provided. Directions for 4 servings indicated in parentheses."],"cuisine_tags":["American","Comfort Food"],"ingredient_tags":["black beans","carrot","mushrooms","potato buns","vegan cheddar"],"item_tags":["all-purpose flour","fajita seasoning","garlic","vegenaise"],"issues":null,"front":"024a_IMG_9180.jpg","back":"024b_IMG_9181.jpg","era":"binder","hero":"024.jpg"},{"pair":25,"title":"Sunflower Chickpea Sandwiches","subtitle":"with Dijon Mustard & Radishes","servings":"2","cook_time":"5 min","nutrition":{"calories":"660","fat":"25 g","carbohydrates":"77 g","protein":"26 g"},"description":null,"from_your_kitchen":null,"ingredients":["13.4 oz chickpeas","1 lemon","6 radishes","2 tbsp Follow Your Heart® Soy-Free Vegenaise®","4 tsp Dijon mustard","¼ cup sunflower seeds","4 slices sourdough bread"],"tools":null,"steps":[{"n":1,"title":null,"text":"Drain and rinse the chickpeas. Halve and juice the lemon. Trim and thinly slice the radishes. Add chickpeas to a large bowl and mash with a fork. Add lemon juice, Vegenaise, Dijon mustard, sunflower seeds, and a pinch of salt and pepper to the mashed chickpeas, and stir."},{"n":2,"title":null,"text":"Toast the sourdough bread. Add half the sunflower chickpea salad and some sliced radish to one slice of sourdough toast. Top with another slice of sourdough toast to close the sandwich. Repeat to make the second sandwich."}],"tips":[],"cuisine_tags":["American"],"ingredient_tags":["chickpeas","radish","sourdough bread","sunflower seeds"],"item_tags":["dijon mustard","lemon","vegenaise"],"single_page":true,"issues":null,"front":"025a_IMG_9182.jpg","back":null,"era":"binder","hero":"025.jpg"},{"pair":26,"title":"Green Curry Noodles","subtitle":"with Basil & Thai Tomato Salad","servings":"2","cook_time":"35 min","nutrition":{"calories":"690","fat":"29 g","carbohydrates":"73 g","protein":"31 g"},"description":null,"from_your_kitchen":null,"ingredients":["2 garlic cloves","1 oz fresh ginger","1 shallot","¼ oz fresh basil","14 oz organic extra firm tofu","4 oz green beans","1 lime*","¼ cup peanuts","2 oz grape tomatoes","1½ tsp tamari","1 tbsp green curry paste","5.5 oz coconut milk","1 tsp turbinado sugar","4 oz rice noodles"],"tools":null,"steps":[{"n":1,"title":null,"text":"Bring a large pot of salted water to a boil for the noodles. Peel and thinly slice the garlic. Peel and mince the ginger. Peel and slice the shallot. Pick the basil leaves. Drain tofu, pat dry, and slice into 1 inch pieces.","img":"026_1.jpg"},{"n":2,"title":null,"text":"Heat 1 tsp vegetable oil in a large nonstick skillet over medium-high heat. Add green beans and a pinch of salt and cook until beans are charred in places, 3-4 minutes. Transfer charred green beans to a medium bowl. Halve the lime, juice one half, and cut the other half into wedges. Add lime juice to the bowl with the green beans. Roughly chop the peanuts. Halve the grape tomatoes. Add chopped peanuts, halved tomatoes, and tamari to the green beans and toss the Thai tomato salad.","img":"026_2.jpg"},{"n":3,"title":null,"text":"Heat 1 tsp vegetable oil in a small saucepan over medium-low heat. Add sliced garlic, minced ginger, and sliced shallot, and cook until fragrant, 2-3 minutes. Add green curry paste, coconut milk, turbinado sugar, salt and ¼ cup water. Bring green curry sauce to a simmer, add basil leaves, and turn off the heat.","img":"026_3.jpg"},{"n":4,"title":null,"text":"Once the water in the large pot is boiling, add rice noodles, stir, and remove from heat. Stir occasionally until noodles are tender, 12 minutes. Drain noodles and rinse under cold water to stop the cooking process, and return noodles to the pot.","img":"026_4.jpg"},{"n":5,"title":null,"text":"Heat 1 tbsp vegetable oil in the large nonstick skillet over medium-high heat. Add sliced tofu and a pinch of salt. Cook, tossing occasionally, until tofu is crispy in places, 5 to 6 minutes.","img":"026_5.jpg"},{"n":6,"title":null,"text":"Pour green curry sauce over the rice noodles and stir until noodles are coated. Divide the green curry noodles and tofu between large bowls. Top with Thai tomato salad and garnish with lime wedges. Dig in!","img":"026_6.jpg"}],"tips":["* This ingredient will be split between steps.","TIP: We will use this skillet again in a later step."],"cuisine_tags":["Thai"],"ingredient_tags":["green beans","rice noodles","tofu","tomato"],"item_tags":["basil","coconut milk","ginger","green curry paste","lime","peanuts","tamari"],"issues":null,"front":"026a_IMG_9184.jpg","back":"026b_IMG_9185.jpg","era":"binder","hero":"026.jpg"},{"pair":27,"title":"Tahini Cauliflower Steaks","subtitle":"with Red Lentil Skordalia & Charred Green Beans","servings":"2","cook_time":"40 min","nutrition":{"calories":"700","fat":"25 g","carbohydrates":"93 g","protein":"36 g"},"description":null,"from_your_kitchen":null,"ingredients":["1 russet potato","½ oz fresh dill*","1 head of cauliflower","2 garlic cloves*","1 lemon*","½ cup red lentils","3 tbsp tahini","1 tsp smoked paprika","2 tbsp white vinegar","6 oz green beans","¼ cup pumpkin seeds"],"tools":null,"steps":[{"n":1,"title":null,"text":"Preheat the oven to 425°F. Peel potato and dice into 1 inch pieces. Pick and roughly chop dill fronds. Remove cauliflower leaves and cut 1 inch off the stem. Carefully cut cauliflower into 4 \"steaks,\" each about 1 inch thick. Peel and mince the garlic. Halve the lemon, juice one half, and cut the other half into wedges.","img":"027_1.jpg"},{"n":2,"title":null,"text":"Add diced potato, red lentils, 1¼ cups water, and a pinch of salt to a small saucepan. Bring to a boil, cover, reduce heat to low, and simmer until lentils are soft and potatoes are fork-tender, 14 to 16 minutes. Mash the red lentil skordalia with a fork.","img":"027_2.jpg"},{"n":3,"title":null,"text":"Spread 2 tsp oil on a baking sheet. In a medium bowl, combine just half the minced garlic, just 1 tbsp lemon juice, tahini, smoked paprika, 2 tbsp olive oil, and ¾ tsp salt. Whisk until combined. Coat cauliflower steaks with tahini mixture and place on the baking sheet. Roast until tender and well browned, 15 to 20 minutes.","img":"027_3.jpg"},{"n":4,"title":null,"text":"Add just half the chopped dill, remaining minced garlic, white vinegar, and 1 tbsp olive oil to the saucepan with the red lentil skordalia. Mash with a fork until mostly smooth. Taste, and add salt and pepper as necessary.","img":"027_4.jpg"},{"n":5,"title":null,"text":"Heat 1 tbsp olive oil in a large nonstick skillet over medium heat. Add green beans and cook until charred in places, 5 to 8 minutes. Taste, add a pinch of salt and pepper, and remove from heat.","img":"027_5.jpg"},{"n":6,"title":null,"text":"Divide the red lentil skordalia between two plates. Add tahini cauliflower steaks and sprinkle with pumpkin seeds and remaining chopped dill. Serve with charred green beans and lemon wedges. Tuck in!","img":"027_6.jpg"}],"tips":["* These ingredients will be split between steps.","TIP: Roast any leftover cauliflower florets along with the steaks.","TIP: If you prefer, you can use foil or parchment paper to line the baking sheet instead of adding oil."],"cuisine_tags":["Greek","Mediterranean"],"ingredient_tags":["cauliflower","green beans","potato","red lentils"],"item_tags":["dill","lemon","pumpkin seeds","smoked paprika","tahini","white vinegar"],"issues":null,"front":"027a_IMG_9186.jpg","back":"027b_IMG_9187.jpg","era":"binder","hero":"027.jpg"},{"pair":28,"title":"Fettuccine Arrabbiata","subtitle":"with Roasted Broccoli & Basil Pesto","servings":"2 (4)","cook_time":"25 (35) min","nutrition":{"calories":"570","fat":"12 g","carbohydrates":"103 g","protein":"20 g"},"description":null,"from_your_kitchen":null,"ingredients":["1 onion","4 garlic cloves","6 oz broccoli florets","6 oz fettuccine","¼ cup panko breadcrumbs","14 oz crushed tomatoes","1 tsp Italian seasoning blend","½ tsp red chile flakes 🌶","2 tbsp vegan basil pesto","2 tbsp vegan parmesan"],"tools":null,"steps":[{"n":1,"title":null,"text":"Preheat the oven to 425°F. Bring a large pot of salted water to a boil. Peel and dice the onion(s). Peel and mince the garlic. Chop broccoli florets into bite-size pieces.","img":"028_1.jpg"},{"n":2,"title":null,"text":"Add fettuccine to the boiling water and cook until al dente, 10 to 12 minutes. Drain pasta and return to the pot, off heat.","img":"028_2.jpg"},{"n":3,"title":null,"text":"Add chopped broccoli florets, 1 tsp (2 tsp) olive oil, and a pinch of salt and pepper to a baking sheet, and toss. Roast until browned and crisp in places, 10 to 12 minutes.","img":"028_3.jpg"},{"n":4,"title":null,"text":"Heat a medium saucepan over medium heat. Add panko breadcrumbs, 2 tsp (4 tsp) olive oil, and ¼ tsp (½ tsp) salt, and stir frequently until breadcrumbs are golden brown, 2 to 4 minutes. Transfer toasted panko breadcrumbs to a small bowl.","img":"028_4.jpg"},{"n":5,"title":null,"text":"Return the medium saucepan to medium-high heat with 2 tsp (4 tsp) olive oil. Once hot, add diced onion, minced garlic, and a pinch of salt and pepper. Cook until onion is softened, 3 to 5 minutes. Add tomatoes, Italian seasoning blend, ¼ tsp (½ tsp) red chile flakes, and ½ tsp (1 tsp) salt. Cook the arrabbiata sauce until it begins to simmer, 3 to 5 minutes.","img":"028_5.jpg"},{"n":6,"title":null,"text":"Add arrabbiata sauce to the pot with the fettuccine, and stir. Divide the fettuccine arrabbiata between large bowls, ladling any remaining arrabbiata sauce over the pasta. Serve with roasted broccoli and top with toasted panko breadcrumbs, basil pesto, and parmesan. Enjoy!","img":"028_6.jpg"}],"tips":["This item is spicy. (red chile flakes)","TIP: We will use this saucepan again in the next step.","TIP: If you're sensitive to spice, add less of the red chile flakes.","Ingredients listed for 2 servings—if you're making 4 servings, please double your ingredients by using both bags provided. Directions for 4 servings indicated in parentheses."],"cuisine_tags":["Italian"],"ingredient_tags":["broccoli","pasta","tomato"],"item_tags":["basil pesto","italian seasoning","panko breadcrumbs","red chile flakes","vegan parmesan"],"issues":null,"front":"028a_IMG_9188.jpg","back":"028b_IMG_9189.jpg","era":"binder","hero":"028.jpg"},{"pair":29,"title":"Greek Seitan Gyros","subtitle":"with Quick Pickles & Lemon Yogurt","servings":"2 (4)","cook_time":"25 (35) min","nutrition":{"calories":"540","fat":"9 g","carbohydrates":"71 g","protein":"48 g"},"description":null,"from_your_kitchen":null,"ingredients":["1 cucumber","1 red onion","8 oz seitan","1 lemon","1 Roma tomato","½ oz fresh mint","2 tbsp Champagne vinegar","2 tsp ras el hanout","¼ cup Forager Project® Organic Dairy-Free Cashewmilk Yogurt","2 multigrain flatbreads"],"tools":null,"steps":[{"n":1,"title":null,"text":"Preheat the oven to 350°F. Thinly slice cucumber(s) into rounds. Peel and thinly slice 1 cup (2 cups) onion. Thinly slice the seitan. Halve and juice the lemon(s). Thinly slice the tomato(es). Pick the mint leaves.","img":"029_1.jpg"},{"n":2,"title":null,"text":"Add sliced cucumber, Champagne vinegar, and a pinch of salt and pepper to a medium bowl, and toss to coat. Set quick pickles aside until step 5.","img":"029_2.jpg"},{"n":3,"title":null,"text":"Heat 2 tbsp (4 tbsp) olive oil in a large nonstick skillet over medium-high heat. Add sliced seitan and a pinch of salt and cook until seitan is browned in places, 4 to 6 minutes. Sprinkle crispy seitan with just 1 tsp (2 tsp) ras el hanout and cook until fragrant, about 1 minute.","img":"029_3.jpg"},{"n":4,"title":null,"text":"Add yogurt, just 1 tbsp (2 tbsp) lemon juice, and a pinch of salt to a small bowl, and whisk the lemon yogurt. Place flatbreads directly on the oven rack and toast until warm, 2 to 3 minutes.","img":"029_4.jpg"},{"n":5,"title":null,"text":"Top toasted flatbreads with crispy seitan, quick pickles, as much sliced onion as you'd like, and sliced tomato. Top the Greek seitan gyros with mint leaves and lemon yogurt. To eat, fold one side of the flatbread over the other, like a taco. Dig in!","img":"029_5.jpg"}],"tips":["TIP: The oven will be used to toast the flatbreads. If you have a toaster oven you can use that instead.","TIP: Add more ras el hanout if you prefer.","TIP: Don't let the flatbreads get too crispy. They should still be pliable enough to fold.","Crispy Seitan = Amazing Seitan — We love seitan because it's high in protein, mimics the texture of meat, and impressively soaks up flavor. And while there are many ways to serve it, in this recipe it's all about creating some crisp. To make delightfully crispy seitan, get the pan nice and hot, somewhere between medium-high and high heat—and make sure you're using enough oil. Finally, toss the seitan occasionally, not too often!","Ingredients listed for 2 servings—if you're making 4 servings, please double your ingredients by using both bags provided. Directions for 4 servings indicated in parentheses."],"cuisine_tags":["Greek","Mediterranean"],"ingredient_tags":["cucumber","flatbread","red onion","seitan","tomato"],"item_tags":["cashewmilk yogurt","champagne vinegar","lemon","mint","ras el hanout"],"issues":null,"front":"029a_IMG_9190.jpg","back":"029b_IMG_9191.jpg","era":"binder","hero":"029.jpg"},{"pair":30,"title":"Roasted Red Pepper Shakshuka","subtitle":"with Za'atar Tofu & Crispy Shallots","servings":"2","cook_time":"25 min","nutrition":{"calories":"590","fat":"31 g","carbohydrates":"63 g","protein":"33 g"},"description":null,"from_your_kitchen":null,"ingredients":["1 shallot","3 garlic cloves","4 oz roasted red peppers","¼ oz fresh mint","14 oz organic extra firm tofu","1 tbsp za'atar seasoning","2 tsp cumin seeds","14.5 oz crushed tomatoes","1 multigrain flatbread","2 oz Treeline® Soft French-Style Cashew Cheese","¼ cup crispy shallots"],"tools":null,"steps":[{"n":1,"title":null,"text":"Preheat the oven to 400°F. Crumble the tofu into bite-size pieces. Peel and mince the shallot(s) and garlic. Drain the red peppers. Pick the mint leaves from the stems.","img":"030_1.jpg"},{"n":2,"title":null,"text":"Place the crumbled tofu on a baking sheet and toss with 2 tsp (4 tsp) olive oil, za'atar seasoning, and a pinch of salt and pepper. Bake until browned in places, 12 to 15 minutes.","img":"030_2.jpg"},{"n":3,"title":null,"text":"Heat 3 tbsp (6 tbsp) olive oil in a large skillet over medium-high heat. Add the minced shallot, minced garlic, and cumin seeds. Cook until fragrant, 1 to 2 minutes. Add the red peppers, tomatoes, ½ tsp (1 tsp) salt, and a pinch of pepper. Bring to a simmer and cook until the sauce thickens, 5 to 8 minutes.","img":"030_3.jpg"},{"n":4,"title":null,"text":"Place the multigrain flatbread(s) directly on the oven rack. Bake until slightly crisp, 3 to 5 minutes. Add the baked za'atar tofu to the sauce and simmer 2 to 3 minutes. Remove the roasted red pepper shakshuka from heat and dollop with cashew cheese. Top with crispy shallots and mint leaves. Serve family style with crispy flatbread on the side. Enjoy!","img":"030_4.jpg"}],"tips":["What is shakshuka? Though it originated in Northern Africa, Shakshuka has been embraced by cultures around the world, particularly in Israel where it's one of the country's national dishes. Traditionally, eggs are poached in a smoky, spicy, vegetable-packed tomato sauce, but in this recipe we replace eggs with cashew cheese. The result is a tasty protein source. Ultimately, no matter which ingredients you include, this one-skillet wonder is a delicious meal that can be served for breakfast, lunch, or dinner!"],"cuisine_tags":["Mediterranean","Middle Eastern"],"ingredient_tags":["flatbread","roasted red peppers","tofu","tomato"],"item_tags":["cashew cheese","crispy shallots","cumin seeds","mint","za'atar"],"issues":null,"front":"030a_IMG_9192.jpg","back":"030b_IMG_9193.jpg","era":"binder","hero":"030.jpg"},{"pair":31,"title":"Parmesan Gnocchi","subtitle":"with Melted Summer Squash & Basil","servings":"2 (4)","cook_time":"25 (35) min","nutrition":{"calories":"500","fat":"15 g","carbohydrates":"82 g","protein":"9 g"},"description":null,"from_your_kitchen":null,"ingredients":["3 garlic cloves","2 yellow squash","1 lemon*","½ oz fresh basil","10 oz fresh gnocchi","1 tbsp vegan butter","3 tbsp vegan parmesan","1 tsp crushed Aleppo pepper"],"tools":null,"steps":[{"n":1,"title":null,"text":"Bring a large pot of salted water to a boil. Peel and thinly slice the garlic. Trim the yellow squash and slice into half moons. Halve the lemon(s), juice one half (1 lemon), and divide the other half (1 lemon) into wedges. Pick the basil leaves from the stems.","img":"031_1.jpg"},{"n":2,"title":null,"text":"Heat 2 tsp (4 tsp) olive oil in a large nonstick skillet over medium-high heat. Add the sliced garlic and a pinch of salt and pepper. Cook until garlic is lightly browned, 2 to 3 minutes. Transfer the crispy garlic to a small bowl and return skillet to medium-high heat.","img":"031_2.jpg"},{"n":3,"title":null,"text":"Add the sliced yellow squash to the skillet and cook until lightly browned in places, 3 to 4 minutes. Reduce heat to low and cook until the squash softens and breaks down, another 5 to 7 minutes. Transfer the melted summer squash to a bowl.","img":"031_3.jpg"},{"n":4,"title":null,"text":"Add the gnocchi to the large pot of boiling water and cook until the gnocchi floats, 3 to 5 minutes. Drain the cooked gnocchi and shake to remove excess water.","img":"031_4.jpg"},{"n":5,"title":null,"text":"Return skillet to medium-high heat with the butter. Once melted, add the cooked gnocchi and cook, undisturbed, until browned in places, 2 to 4 minutes. Add the parmesan and melted summer squash and stir to combine. Remove skillet from heat and add the lemon juice.","img":"031_5.jpg"},{"n":6,"title":null,"text":"Divide the parmesan gnocchi with melted summer squash between bowls. Top with basil leaves, crispy garlic, and as much of the Aleppo pepper as you'd like. Serve with lemon wedges. Dig in!","img":"031_6.jpg"}],"tips":["TIP: We will reuse this skillet in a later step.","* This ingredient will be split between steps.","This item is spicy. (Aleppo pepper)","Substitute: another fresh herb for basil"],"cuisine_tags":["Italian"],"ingredient_tags":["basil","gnocchi","summer squash"],"item_tags":["aleppo pepper","garlic","lemon","vegan butter","vegan parmesan"],"issues":null,"front":"031a_IMG_9194.jpg","back":"031b_IMG_9195.jpg","era":"binder","hero":"031.jpg"},{"pair":32,"title":"Harissa Tempeh","subtitle":"with Pistachio Pilaf & Zucchini","servings":"2 (4)","cook_time":"35 (45) min","nutrition":{"calories":"650","fat":"17 g","carbohydrates":"95 g","protein":"28 g"},"description":null,"from_your_kitchen":null,"ingredients":["¾ cup short-grain brown rice","1 zucchini","1 shallot","8 oz tempeh","1 lemon*","2 tbsp harissa paste","1 tbsp agave","¼ cup pistachios"],"tools":null,"steps":[{"n":1,"title":null,"text":"Add the brown rice, 1¾ (3½) cups water, and a pinch of salt to a small saucepan and bring to a boil. Cover, reduce heat to low, and cook until water is absorbed, 30 to 35 minutes.","img":"032_1.jpg"},{"n":2,"title":null,"text":"Halve the zucchini lengthwise and slice into half moons. Peel and thinly slice the shallot(s). Cut the tempeh into 1 inch cubes. Halve and juice the lemon(s).","img":"032_2.jpg"},{"n":3,"title":null,"text":"Add the harissa paste, agave, just half the lemon juice, 1 tbsp (2 tbsp) olive oil, and a pinch of salt in a small bowl. Stir the harissa sauce.","img":"032_3.jpg"},{"n":4,"title":null,"text":"Heat 2 tbsp (4 tbsp) olive oil in a large nonstick skillet over medium-high heat. Add the cubed tempeh and cook until crispy, 8 to 10 minutes. Sprinkle tempeh with salt and add the sliced shallot. Cook until the shallot begins to brown, 2 to 4 minutes.","img":"032_4.jpg"},{"n":5,"title":null,"text":"Add the harissa sauce to the skillet. Cook until the tempeh is caramelized and sticky, 2 to 4 minutes. Move the harissa tempeh to the side of the skillet and add the sliced zucchini. Sprinkle with salt and cook until tender, 2 to 4 minutes.","img":"032_5.jpg"},{"n":6,"title":null,"text":"Add the remaining lemon juice and pistachios to the cooked brown rice and stir. Divide the pistachio pilaf between plates. Top with harissa tempeh and zucchini. Dig in!","img":"032_6.jpg"}],"tips":["* This ingredient will be split between steps.","Substitute: yellow squash for zucchini"],"cuisine_tags":["Middle Eastern","Moroccan"],"ingredient_tags":["pistachios","rice","tempeh","zucchini"],"item_tags":["agave","harissa","lemon","shallot"],"issues":null,"front":"032a_IMG_9196.jpg","back":"032b_IMG_9197.jpg","era":"binder","hero":"032.jpg"},{"pair":33,"title":"Creamy Tahini Noodles","subtitle":"with Crispy Shiitakes & Quick Pickles","servings":"2","cook_time":"30 min","nutrition":{"calories":"590","fat":"21 g","carbohydrates":"85 g","protein":"21 g"},"description":null,"from_your_kitchen":null,"ingredients":["1 cucumber","3 tbsp rice vinegar*","1 tsp agave*","6 oz Lacinato kale","6 oz shiitake mushrooms","2 garlic cloves","3 tbsp tahini","2 tbsp tamari","1 tbsp sesame oil","6 oz soba noodles"],"tools":null,"steps":[{"n":1,"title":null,"text":"Bring a large pot of salted water to a boil for the soba noodles. Peel and thinly slice the cucumber. Add sliced cucumber, just 2 tbsp rice vinegar, just ½ tsp agave, and ⅛ tsp salt to a medium bowl. Toss to combine, and set the quick pickles aside.","img":"033_1.jpg"},{"n":2,"title":null,"text":"Destem Lacinato kale and thinly slice the leaves. Trim shiitake mushroom stems and thinly slice the caps. Peel and mince the garlic. Add remaining rice vinegar, remaining agave, minced garlic, tahini, tamari, sesame oil, 2 tbsp hot water, and a pinch of salt to a medium bowl and whisk the tahini sauce.","img":"033_2.jpg"},{"n":3,"title":null,"text":"Heat 2 tbsp vegetable oil in a large nonstick skillet over medium-high heat. Add sliced shiitake mushrooms and cook, stirring occasionally, until well browned, 5 to 6 minutes. Transfer to a paper towel-lined plate and sprinkle with salt.","img":"033_3.jpg"},{"n":4,"title":null,"text":"Once the water is boiling, add soba noodles and gently stir. Cook until al dente, 2 to 3 minutes. Drain noodles and run under cool water to stop the cooking process.","img":"033_4.jpg"},{"n":5,"title":null,"text":"Return skillet to medium-high heat and add sliced Lacinato kale and 1 tbsp water. Cook until kale is wilted, 2 to 3 minutes. Remove skillet from heat, add cooked soba noodles and tahini sauce to the kale, and stir.","img":"033_5.jpg"},{"n":6,"title":null,"text":"Divide the creamy tahini noodles between large bowls and top with crispy shiitakes and quick pickles. Enjoy!","img":"033_6.jpg"}],"tips":["TIP: Don't forget to wash all produce under running water, and wipe mushrooms clean with a damp kitchen towel.","TIP: We will reuse this skillet in a later step.","* These ingredients will be split between steps.","Substitute: soy sauce for tamari"],"cuisine_tags":["Fusion","Japanese"],"ingredient_tags":["cucumber","kale","mushrooms","soba noodles"],"item_tags":["agave","rice vinegar","sesame oil","tahini","tamari"],"issues":null,"front":"033a_IMG_9198.jpg","back":"033b_IMG_9199.jpg","era":"binder","hero":"033.jpg"},{"pair":34,"title":"Kashmiri Chickpea Bowls","subtitle":"with Yogurt Smashed Vegetables & Golden Raisins","servings":"2","cook_time":"25 min","nutrition":{"calories":"530","fat":"7 g","carbohydrates":"106 g","protein":"23 g"},"description":null,"from_your_kitchen":null,"ingredients":["½ cup jasmine rice","4 oz curly kale","1 cucumber","4 radishes","1 garlic clove","1 lemon*","13.4 oz chickpeas","2 tsp Kashmiri chile powder","¼ cup Forager Project® Organic Dairy-Free Cashewmilk Yogurt","1 tsp dried dill","2 tbsp golden raisins"],"tools":null,"steps":[{"n":1,"title":null,"text":"Preheat the oven to 400°F. Add jasmine rice, 1 cup water, and a pinch of salt to a small saucepan. Bring to a boil, cover, reduce heat to low, and cook until water is absorbed and grains are tender, 14 to 16 minutes.","img":"034_1.jpg"},{"n":2,"title":null,"text":"Destem curly kale and roughly chop the leaves. Place cucumber and radishes on a cutting board. Smash vegetables by using the flat side of a knife and applying pressure with the heel of your hand until the vegetables split. Tear the smashed vegetables into bite-size pieces. Peel and mince the garlic. Halve and juice the lemon. Drain and rinse the chickpeas, and pat dry.","img":"034_2.jpg"},{"n":3,"title":null,"text":"Place chickpeas on a baking sheet and toss with 1 tbsp olive oil, ½ tsp Kashmiri chile powder, and a pinch of salt. Roast until crispy, 12 to 15 minutes.","img":"034_3.jpg"},{"n":4,"title":null,"text":"Add minced garlic, just 1 tbsp lemon juice, yogurt, and a pinch of salt and pepper to a medium bowl, and stir the yogurt dressing. Add smashed vegetables and toss to coat.","img":"034_4.jpg"},{"n":5,"title":null,"text":"Heat 1 tsp olive oil in a large skillet over medium-high heat. Add chopped curly kale and a pinch of salt and pepper, and cook until the greens are wilted, 1 to 2 minutes.","img":"034_5.jpg"},{"n":6,"title":null,"text":"Fluff the cooked jasmine rice with a fork and add remaining lemon juice, dill, golden raisins, and 1 tsp olive oil. Gently stir the pilaf to combine. Divide pilaf and cooked curly kale between shallow bowls. Top with kashmiri chickpeas and yogurt smashed vegetables. Enjoy!","img":"034_6.jpg"}],"tips":["TIPS: Cover the chickpeas with a wire rack if they begin to pop in the oven. The Kashmiri chile powder is spicy; use more or less if you prefer.","* This ingredient will be split between steps.","This item is spicy. (Kashmiri chile powder)"],"cuisine_tags":["Indian"],"ingredient_tags":["chickpeas","cucumber","kale","radish","rice"],"item_tags":["cashewmilk yogurt","dill","golden raisins","kashmiri chile powder","lemon"],"issues":null,"front":"034a_IMG_9200.jpg","back":"034b_IMG_9201.jpg","era":"binder","hero":"034.jpg"},{"pair":35,"title":"Sicilian-Style Broccoli","subtitle":"with Tarragon Hazelnut Relish & Lemon Caper Millet","servings":"2","cook_time":"30 min","nutrition":{"calories":"460","fat":"15 g","carbohydrates":"70 g","protein":"17 g"},"description":null,"from_your_kitchen":null,"ingredients":["1 shallot","½ cup millet","1 broccoli crown","4 oz broccoli rabe","¼ oz fresh tarragon","1 garlic clove","1 lemon*","⅓ cup hazelnuts","2 tbsp capers","¼ cup golden raisins"],"tools":null,"steps":[{"n":1,"title":null,"text":"Peel and mince the shallot. Heat 1 tsp olive oil in a small saucepan over medium heat. Add minced shallot and cook until softened, 1 to 2 minutes. Add millet and toast until aromatic and beginning to pop, 3 to 5 minutes. Add 1 cup water and a pinch of salt. Bring to a boil, cover, reduce heat to low, and cook until the water is absorbed and grains are tender, 17 to 20 minutes. Remove cooked millet from heat and set aside, covered.","img":"035_1.jpg"},{"n":2,"title":null,"text":"Cut the broccoli crown into large florets and thinly slice. Trim and roughly chop the broccoli rabe. Pick and roughly chop the tarragon leaves. Peel and mince the garlic. Halve and juice the lemon.","img":"035_2.jpg"},{"n":3,"title":null,"text":"Place a large skillet over medium heat and add hazelnuts. Cook, shaking the pan occasionally, until nuts are toasted, 3 to 5 minutes. Let toasted hazelnuts cool, and transfer to a cutting board. Remove skins and roughly chop the nuts. Add chopped tarragon, minced garlic, chopped hazelnuts, 2 tbsp olive oil, and a pinch of salt to a small bowl. Stir the tarragon hazelnut relish.","img":"035_3.jpg"},{"n":4,"title":null,"text":"Return the skillet to medium-heat with 1 tbsp olive oil. Add sliced broccoli florets and cook until until crisp-tender, 2 to 3 minutes per side. Add chopped broccoli rabe and cook until bright green and just wilted, 3 to 5 minutes. Sprinkle charred broccoli with salt and add just half the lemon juice.","img":"035_4.jpg"},{"n":5,"title":null,"text":"Fluff the cooked millet with a fork. Add remaining lemon juice, capers, golden raisins, and a pinch of salt, and stir. Divide the lemon caper millet between plates. Top with Sicilian-style broccoli and tarragon hazelnut relish. Tuck in!","img":"035_5.jpg"}],"tips":["* This ingredient will be split between steps.","Culinary Inspo? Caponata! When creating this dish our culinary team was inspired by caponata—described by Martha Rose Shulman, a food columnist for The New York Times, as \"a Sicilian sweet and sour version of ratatouille.\" It's sweet, savory, and a little nutty, just like this dish. Enjoy!"],"cuisine_tags":["Italian","Mediterranean"],"ingredient_tags":["broccoli","broccoli rabe","hazelnuts","millet"],"item_tags":["capers","golden raisins","lemon","shallot","tarragon"],"issues":null,"front":"035a_IMG_9202.jpg","back":"035b_IMG_9203.jpg","era":"binder","hero":"035.jpg"},{"pair":36,"title":"Kashmiri Roasted Vegetables & Tofu Paneer","subtitle":"with Cucumber Raita & Millet","servings":"2 (4)","cook_time":"35 (45) min","nutrition":{"calories":"560","fat":"17 g","carbohydrates":"82 g","protein":"29 g"},"description":null,"from_your_kitchen":null,"ingredients":["½ cup millet","14 oz organic extra firm tofu","3 carrots","2 garlic cloves","1 oz fresh ginger","1 tbsp Kashmiri chile powder","1 tbsp tomato powder","4 oz grape tomatoes","1 cucumber","1 lemon*","¼ cup vegan sour cream","¼ cup mango chutney"],"tools":null,"steps":[{"n":1,"title":null,"text":"Preheat the oven to 425°F. Add millet to a small saucepan over medium-high heat. Toast until millet is aromatic and begins to pop, 3 to 5 minutes. Add 1 cup (2 cups) water and a pinch of salt. Bring to a boil, cover, reduce heat to low, and cook until the water is absorbed and grains are tender, 17 to 20 minutes. Remove cooked millet from heat and set aside, covered.","img":"036_1.jpg"},{"n":2,"title":null,"text":"Drain tofu and cut into cubes. Peel and roughly chop carrots. Peel and mince the garlic and ginger. Add minced garlic, minced ginger, 2 tsp Kashmiri chile powder, tomato powder, 2 tbsp (4 tbsp) vegetable oil, 2 tbsp (4 tbsp) warm water, and ½ tsp (1 tsp) salt to a medium bowl and whisk the Kashmiri marinade.","img":"036_2.jpg"},{"n":3,"title":null,"text":"Place cubed tofu, chopped carrot, and grape tomatoes on a baking sheet, add Kashmiri marinade, and toss to coat. Roast until tofu is browned in places and carrots are tender, 23 to 25 minutes.","img":"036_3.jpg"},{"n":4,"title":null,"text":"Grate cucumber(s) on the largest side of a box grater. Add grated cucumber to a medium bowl. Halve and juice the lemon(s). Add just half the lemon juice, sour cream, and a pinch of salt to the cucumber. Stir the cucumber raita to combine.","img":"036_4.jpg"},{"n":5,"title":null,"text":"Drizzle remaining lemon juice over roasted tofu and vegetables. Divide cooked millet between bowls. Top with Kashmiri roasted vegetables & tofu paneer. Serve with cucumber raita and mango chutney. Tuck in!","img":"036_5.jpg"}],"tips":["TIP: Add more Kashmiri chile powder if you prefer.","This item is spicy. (Kashmiri chile powder)","* This ingredient will be split between steps.","Kashmiri Chile: The term \"Kashmiri chile\" is actually somewhat of a misnomer. Due to the extremely small quantity of chiles grown in the Kashmir region of India, most are typically reserved for local consumption. So most Kashmiri chile powder on the market isn't made with authentic Kashmiri chiles. Ours is made using finely ground red chiles from India and it has a rich red color and moderate heat level."],"cuisine_tags":["Indian"],"ingredient_tags":["carrot","cucumber","millet","tofu","tomato"],"item_tags":["ginger","kashmiri chile powder","lemon","mango chutney","tomato powder","vegan sour cream"],"issues":null,"front":"036a_IMG_9204.jpg","back":"036b_IMG_9205.jpg","era":"binder","hero":"036.jpg"},{"pair":37,"title":"Pan Seared Broccolini","subtitle":"with Mashed Sweet Potatoes & Coconut Turmeric Relish","servings":"2 (4)","cook_time":"35 (45) min","nutrition":{"calories":"520","fat":"16 g","carbohydrates":"80 g","protein":"21 g"},"description":null,"from_your_kitchen":null,"ingredients":["1 sweet potato","½ cup beluga lentils","2 garlic cloves","1 Fresno chile","1 oz fresh ginger","1 lemon","8 oz broccolini","2 tbsp golden raisins","2 tbsp toasted coconut","2 tsp brown mustard seeds","¼ tsp ground turmeric","2 tbsp vegan butter"],"tools":null,"steps":[{"n":1,"title":null,"text":"Peel and dice the sweet potato(es). Add diced sweet potato to a small saucepan and cover with 1 inch water. Bring to a boil and cook until fork-tender, 10 to 12 minutes. Drain and return cooked sweet potato to the saucepan, off heat. Rinse and sort the beluga lentils, and add to a separate saucepan with 1 cup (2 cups) water. Bring to a boil, cover, reduce heat to low, and simmer until lentils are tender, 20 to 24 minutes.","img":"037_1.jpg"},{"n":2,"title":null,"text":"Peel and thinly slice the garlic. Trim, halve, and deseed the Fresno chile(s), and mince one half (1 Fresno chile). Peel and mince 2 tsp (4 tsp) ginger. Halve and juice the lemon(s). Trim 1 inch off the broccolini stems.","img":"037_2.jpg"},{"n":3,"title":null,"text":"Heat 2 tbsp (4 tbsp) olive oil in a large nonstick skillet over medium heat. Add sliced garlic and cook until lightly browned, 3 to 5 minutes. Add minced Fresno chile, minced ginger, golden raisins, coconut, brown mustard seeds, and turmeric. Stir and cook until aromatic, 1 to 3 minutes. Add lemon juice and transfer the coconut turmeric relish to a medium bowl.","img":"037_3.jpg"},{"n":4,"title":null,"text":"Wipe the skillet clean and return to medium-high heat. Add 2 tsp (4 tsp) olive oil, ¼ cup (½ cup) water, and a pinch of salt. Add broccolini, cover, and cook until water evaporates and broccolini is tender and crispy in places, 3 to 5 minutes. Flip and cook for an additional 2 minutes.","img":"037_4.jpg"},{"n":5,"title":null,"text":"Add butter to the cooked sweet potatoes and mash with a fork. Taste, and add salt as necessary. Divide the mashed sweet potatoes and cooked beluga lentils between large plates. Top with pan seared broccolini and coconut turmeric relish. Enjoy!","img":"037_5.jpg"}],"tips":["TIP: To \"sort\" means to look for and discard any naturally occurring debris or stones.","TIP: Save the remaining ginger for your own use.","TIP: Add more Fresno chile if you prefer more heat. Save any remaining chile for your own use.","This item is spicy. (Fresno chile)"],"cuisine_tags":["Fusion","Indian"],"ingredient_tags":["broccolini","lentils","sweet potato"],"item_tags":["brown mustard seeds","fresno chile","ginger","golden raisins","toasted coconut","turmeric","vegan butter"],"issues":null,"front":"037a_IMG_9206.jpg","back":"037b_IMG_9207.jpg","era":"binder","hero":"037.jpg"},{"pair":38,"title":"Coconut Tofu","subtitle":"with Crunchy Date Slaw & Peanut Sauce","servings":"2","cook_time":"30 min","nutrition":{"calories":"800","fat":"32 g","carbohydrates":"109 g","protein":"31 g"},"description":null,"from_your_kitchen":null,"ingredients":["½ cup sushi rice","14 oz organic extra firm tofu","2 oz dates","1 lime","6 oz shredded red cabbage","2 tbsp sesame seeds*","⅓ cup toasted coconut","¼ cup panko breadcrumbs","¼ cup cornstarch","¼ cup spicy peanut sauce"],"tools":null,"steps":[{"n":1,"title":null,"text":"Add sushi rice, 1 cup water, and a pinch of salt to a small saucepan. Bring to a boil, cover, reduce heat to low, and cook until the grains are tender and water is absorbed, 13 to 15 minutes.","img":"038_1.jpg"},{"n":2,"title":null,"text":"Pat tofu dry and cut into 8 slices. Finely chop the dates, removing the pits. Halve and juice the lime. Add chopped dates, lime juice, red cabbage, just 1 tsp sesame seeds, 1 tsp vegetable oil, and a pinch of salt to a medium bowl. Toss the crunchy date slaw.","img":"038_2.jpg"},{"n":3,"title":null,"text":"Chop the toasted coconut. Add remaining sesame seeds, chopped coconut, and breadcrumbs to a plate, and mix. In a separate bowl, combine cornstarch and ¼ cup cold water and whisk.","img":"038_3.jpg"},{"n":4,"title":null,"text":"Toss sliced tofu in the cornstarch mixture, remove, and press into the coconut breadcrumbs. Heat ¼ cup vegetable oil in a large nonstick skillet over medium heat. Add breaded tofu and cook until browned, 3 to 4 minutes per side. Transfer to a plate, sprinkle with salt, and cover loosely to keep warm.","img":"038_4.jpg"},{"n":5,"title":null,"text":"Wipe the skillet clean and return to medium-low heat. Add spicy peanut sauce and 2 tbsp water. Cook until hot, 1 to 2 minutes.","img":"038_5.jpg"},{"n":6,"title":null,"text":"Divide the rice and crunchy date slaw between plates. Top with coconut tofu and serve with peanut sauce for dipping. Bon appétit!","img":"038_6.jpg"}],"tips":["TIP: Instead of chopping the toasted coconut, you can also seal it in a plastic bag and crush with a rolling pin or mug.","* This ingredient will be split between steps.","This item is spicy. (spicy peanut sauce)"],"cuisine_tags":["Fusion","Thai"],"ingredient_tags":["dates","red cabbage","rice","tofu"],"item_tags":["cornstarch","lime","panko breadcrumbs","peanut sauce","sesame seeds","toasted coconut"],"issues":null,"front":"038a_IMG_9208.jpg","back":"038b_IMG_9209.jpg","era":"binder","hero":"038.jpg"},{"pair":39,"title":"Roasted Sweet Potatoes & Beluga Lentils","subtitle":"with Citrus Pecan Salad & Chipotle Crema","servings":"2 (4)","cook_time":"30 (40) min","nutrition":{"calories":"660","fat":"25 g","carbohydrates":"98 g","protein":"25 g"},"description":null,"from_your_kitchen":null,"ingredients":["½ cup beluga lentils","2 sweet potatoes","2 oranges","½ oz fresh cilantro","¼ cup pecans","2 oz Treeline® Soft French-Style Cashew Cheese","1 garlic clove","2.5 oz Forager Project® Organic Dairy-Free Cashewmilk Yogurt","¼ tsp chipotle morita spice"],"tools":null,"steps":[{"n":1,"title":null,"text":"Preheat the oven to 425°F. Rinse and sort the beluga lentils. Add lentils and 1¼ cups (2½ cups) water to a medium saucepan. Bring to a boil, cover, reduce heat to low, and simmer until lentils are tender and water is absorbed, 20 to 23 minutes. Drain any remaining water, transfer lentils to a bowl, and rinse the saucepan.","img":"039_1.jpg"},{"n":2,"title":null,"text":"Halve sweet potatoes lengthwise, and cut each half into 3 to 4 long wedges. Transfer to a baking sheet cut side down, coat with 1 tbsp (2 tbsp) olive oil, and sprinkle with salt and pepper. Roast until tender, 22 to 26 minutes.","img":"039_2.jpg"},{"n":3,"title":null,"text":"Peel the oranges and chop into bite-size pieces. Pick cilantro leaves and reserve the tender stems. Add chopped orange, cilantro leaves and stems, pecans, and a pinch of salt to a medium bowl, and stir to combine. Crumble cashew cheese into the bowl, and gently toss the citrus pecan salad. Peel and mince the garlic.","img":"039_3.jpg"},{"n":4,"title":null,"text":"In a small bowl, combine the yogurt and ⅛ tsp (¼ tsp) chipotle morita spice. Stir the chipotle crema.","img":"039_4.jpg"},{"n":5,"title":null,"text":"Return the medium saucepan to medium heat with 1 tbsp (2 tbsp) olive oil. Add minced garlic and cook until golden and toasted, 2 to 3 minutes. Add cooked lentils and cook until heated through. Taste, and add salt as necessary.","img":"039_5.jpg"},{"n":6,"title":null,"text":"Slightly mash the sweet potatoes with a fork. Smear chipotle crema on large plates. Top with roasted sweet potatoes, beluga lentils and citrus pecan salad. Drizzle with olive oil. Bon appétit!","img":"039_6.jpg"}],"tips":["TIP: We will use this saucepan again","TIP: Add more chipotle morita spice if you prefer.","This item is spicy. (chipotle morita spice)"],"cuisine_tags":["Fusion","Latin American"],"ingredient_tags":["lentils","oranges","pecans","sweet potato"],"item_tags":["cashew cheese","cashewmilk yogurt","chipotle","cilantro"],"issues":null,"front":"039a_IMG_9210.jpg","back":"039b_IMG_9211.jpg","era":"binder","hero":"039.jpg"},{"pair":40,"title":"Sprouting Broccoli Salads","subtitle":"with Sunflower Seeds & Miso Power Dressing","servings":"2 (4)","cook_time":"30 (40) min","nutrition":{"calories":"640","fat":"33 g","carbohydrates":"65 g","protein":"27 g"},"description":null,"from_your_kitchen":null,"ingredients":["¾ cup farro","2 garlic cloves","6 oz broccoli florets","6 oz Brussels sprouts","2 mini sweet peppers","2 oz Castelvetrano olives","1 lemon*","⅓ cup hemp seeds","1 tbsp white miso paste","¼ cup sunflower seeds"],"tools":null,"steps":[{"n":1,"title":null,"text":"Add farro and a pinch of salt to a small saucepan and cover with 1 inch cold water. Bring to a boil, reduce heat to medium, and cook until farro is tender, 18 to 20 minutes. Drain farro and return to the saucepan, off heat.","img":"040_1.jpg"},{"n":2,"title":null,"text":"Peel and mince the garlic. Chop broccoli florets into bite-size pieces. Thinly slice Brussels sprouts. Trim and thinly slice mini sweet peppers into rounds. Check Castelvetrano olives, remove any pits, and halve the olives. Zest, halve, and juice the lemon(s).","img":"040_2.jpg"},{"n":3,"title":null,"text":"Heat 1 tbsp (2 tbsp) olive oil in a large skillet over medium-high heat. Add minced garlic, chopped broccoli florets, and a pinch of salt and pepper. Cook, tossing occasionally, until broccoli is lightly browned and crisp-tender, 4 to 6 minutes. Turn off the heat, add lemon zest, and toss.","img":"040_3.jpg"},{"n":4,"title":null,"text":"Add 2 tbsp (4 tbsp) lemon juice, hemp seeds, white miso paste, ¼ cup (½ cup) water, and 2 tbsp (4 tbsp) olive oil to a blender. Blend miso power dressing on high until smooth. Taste, and add salt as necessary.","img":"040_4.jpg"},{"n":5,"title":null,"text":"Add seared broccoli florets, sliced Brussels sprouts, 3 tbsp (6 tbsp) miso power dressing, and sunflower seeds to a large bowl. Toss the sprouting broccoli salad.","img":"040_5.jpg"},{"n":6,"title":null,"text":"Divide cooked farro between bowls and top with sprouting broccoli salad. Drizzle with remaining miso power dressing. Top with sliced mini sweet peppers and halved Castelvetrano olives. Dig in!","img":"040_6.jpg"}],"tips":["* This ingredient will be split between steps.","Substitute: radishes for mini sweet peppers"],"cuisine_tags":["Fusion","Mediterranean"],"ingredient_tags":["bell pepper","broccoli","brussels sprouts","farro"],"item_tags":["castelvetrano olives","hemp seeds","lemon","miso","sunflower seeds"],"issues":null,"front":"040a_IMG_9212.jpg","back":"040b_IMG_9213.jpg","era":"binder","hero":"040.jpg"},{"pair":41,"title":"Tahini Cauliflower Steaks","subtitle":"with Red Lentil Skordalia & Charred Green Beans","servings":"2","cook_time":"40 min","nutrition":{"calories":"700","fat":"25 g","carbohydrates":"93 g","protein":"36 g"},"description":null,"from_your_kitchen":null,"ingredients":["1 russet potato","½ oz fresh dill*","1 head of cauliflower","2 garlic cloves*","1 lemon*","½ cup red lentils","3 tbsp tahini","1 tsp smoked paprika","2 tbsp white vinegar","6 oz green beans","¼ cup pumpkin seeds"],"tools":null,"steps":[{"n":1,"title":null,"text":"Preheat the oven to 425°F. Peel russet potato and dice into 1 inch pieces. Pick and roughly chop dill fronds. Remove cauliflower leaves and cut 1 inch off the stem. Carefully cut cauliflower into 4 \"steaks,\" each about 1 inch thick. Peel and mince the garlic. Halve the lemon, juice one half, and cut the other half into wedges.","img":"041_1.jpg"},{"n":2,"title":null,"text":"Add diced russet potato, red lentils, 1¼ cups water, and a pinch of salt to a small saucepan. Bring to a boil, cover, reduce heat to low, and simmer until lentils are soft and potatoes are fork-tender, 14 to 16 minutes. Mash the red lentil skordalia with a fork.","img":"041_2.jpg"},{"n":3,"title":null,"text":"Line a baking sheet with foil or parchment paper. In a medium bowl, combine just half the minced garlic, just 1 tbsp lemon juice, tahini, smoked paprika, 2 tbsp olive oil, and ¾ tsp salt. Whisk until combined. Coat cauliflower steaks with tahini mixture and place on the lined baking sheet. Roast until tender and well browned, 15 to 20 minutes.","img":"041_3.jpg"},{"n":4,"title":null,"text":"Add just half the chopped dill, remaining minced garlic, white vinegar, and 1 tbsp olive oil to the saucepan with the red lentil skordalia. Mash with a fork until mostly smooth. Taste, and add salt and pepper as necessary.","img":"041_4.jpg"},{"n":5,"title":null,"text":"Heat 1 tbsp olive oil in a large nonstick skillet over medium heat. Add green beans and cook until they are charred in places, 5 to 8 minutes. Taste, add salt and pepper as necessary, and remove from heat.","img":"041_5.jpg"},{"n":6,"title":null,"text":"Divide red lentil skordalia between two large plates. Add tahini cauliflower steaks, and sprinkle with pumpkin seeds and remaining chopped dill. Serve with charred green beans and lemon wedges. Dig in!","img":"041_6.jpg"}],"tips":["* These ingredients will be split between steps.","TIP: Roast any remaining cauliflower florets along with the steaks.","TIP: If you don't have foil or parchment paper, add 2 tsp oil to the baking sheet instead (though the cauliflower may stick slightly)."],"cuisine_tags":["Greek","Mediterranean"],"ingredient_tags":["cauliflower","green beans","potato","red lentils"],"item_tags":["dill","lemon","pumpkin seeds","smoked paprika","tahini","white vinegar"],"issues":null,"front":"041a_IMG_9214.jpg","back":"041b_IMG_9215.jpg","era":"binder","hero":"041.jpg"},{"pair":42,"title":"Falafel Spiced Tofu","subtitle":"with Pickled Cauliflower & Creamy Cashew Dressing","servings":"2","cook_time":"35 min","nutrition":{"calories":"450","fat":"28 g","carbohydrates":"30 g","protein":"28 g"},"description":null,"from_your_kitchen":null,"ingredients":["½ cup cashews","14 oz organic extra firm tofu","2 garlic cloves*","1 tbsp zhoug seasoning","1 lemon","4 oz curly kale","2 oz Castelvetrano olives","4 oz roasted red peppers","3.5 oz curried pickled cauliflower"],"tools":null,"steps":[{"n":1,"title":null,"text":"Preheat the oven to 425°F. Add cashews and ½ cup hot water to a small bowl. Crumble tofu into bite-size pieces and add to a large bowl. Peel and mince the garlic. Add just half the minced garlic to the bowl with the tofu, along with zhoug seasoning, 2 tsp vegetable oil, ½ tsp salt, and a pinch of pepper. Toss to coat.","img":"042_1.jpg"},{"n":2,"title":null,"text":"Line a baking sheet with foil or parchment paper. Place tofu mixture on the baking sheet and bake until browned and crispy in places, 25 to 30 minutes.","img":"042_2.jpg"},{"n":3,"title":null,"text":"Halve and juice the lemon. Destem and thinly slice the curly kale. Check the Castelvetrano olives, remove any pits, and roughly chop the olives. Drain the roasted red peppers.","img":"042_3.jpg"},{"n":4,"title":null,"text":"Add the cashews, their soaking water, remaining minced garlic, lemon juice, and a pinch of salt and pepper to a blender. Blend until smooth. Taste the creamy cashew dressing and add salt as necessary.","img":"042_4.jpg"},{"n":5,"title":null,"text":"Add the sliced curly kale and 2 tsp olive oil to a large bowl, and massage kale until bright green. Add chopped Castelvetrano olives, roasted red peppers, and just half the creamy cashew dressing, and toss to combine.","img":"042_5.jpg"},{"n":6,"title":null,"text":"Divide the kale salad between bowls. Top with falafel spiced tofu and pickled cauliflower. Drizzle with remaining creamy cashew dressing. Bon appétit!","img":"042_6.jpg"}],"tips":["* This ingredient will be split between steps.","TIP: If you don't have foil or parchment paper, add 2 tsp oil to the baking sheet instead."],"cuisine_tags":["Mediterranean","Middle Eastern"],"ingredient_tags":["cashews","cauliflower","kale","tofu"],"item_tags":["castelvetrano olives","lemon","pickled cauliflower","roasted red peppers","zhoug"],"issues":null,"front":"042a_IMG_9216.jpg","back":"042b_IMG_9217.jpg","era":"binder","hero":"042.jpg"},{"pair":43,"title":"Sausage Jambalaya","subtitle":"with Kale & Long Grain Rice","servings":"2","cook_time":"40 min","nutrition":{"calories":"660","fat":"10 g","carbohydrates":"108 g","protein":"37 g"},"description":null,"from_your_kitchen":null,"ingredients":["1 onion","1 green bell pepper","1 celery stalk","3 garlic cloves","4 oz curly kale","2 links Field Roast® Sausage","¾ cup basmati rice","1 tsp chipotle morita powder 🌶","14.5 oz fire roasted diced tomatoes","2 tsp vegetable broth concentrate"],"tools":null,"steps":[{"n":1,"title":null,"text":"Peel and dice the onion. Trim, deseed, and dice the green bell pepper. Dice the celery. Peel and mince the garlic. Desteem the curly kale and roughly chop the leaves.","img":"043_1.jpg"},{"n":2,"title":null,"text":"Remove sausages from the plastic casing and slice into rounds. Heat 2 tbsp vegetable oil in a large pot over medium-high heat. Add sliced sausage and cook, stirring occasionally, until it begins to crisp, 4 to 5 minutes. Add chopped curly kale and cook until kale is bright green and wilted, 1 to 2 minutes. Transfer sautéed sausage and curly kale to a plate.","img":"043_2.jpg"},{"n":3,"title":null,"text":"Return the pot to medium-high heat. Add diced onion, diced green bell pepper, and diced celery to the pot and cook until softened, 3 to 4 minutes. Add minced garlic and a pinch of salt and cook until fragrant, about 30 seconds.","img":"043_3.jpg"},{"n":4,"title":null,"text":"Add the basmati rice, chipotle morita powder, tomatoes, vegetable broth concentrate, and 1¼ cups water to the pot. Bring to a boil, cover, reduce heat to low, and cook until the water is absorbed and rice is tender, 15 to 18 minutes.","img":"043_4.jpg"},{"n":5,"title":null,"text":"Add the sautéed sausage and curly kale to the jambalaya and cook until warm, 1 to 2 minutes. Divide the sausage jambalaya with kale and long-grain rice between large bowls. Dig in!","img":"043_5.jpg"}],"tips":["This item is spicy. (chipotle morita powder)","TIP: If you're sensitive to spice, omit or use less chipotle.","A Divine and Delicious Base: You've probably heard of mirepoix, the French term for a flavor base made from sautéed onion, carrot, and celery. It's a key component of many of the soups, stews, and sauces you love. But say you swap in green peppers for carrots, what's that called? In the southeastern United States, people call that mixture the Holy Trinity, and it's the foundation of classic Cajun dishes like gumbo and jambalaya."],"cuisine_tags":["Cajun/Creole","Southern"],"ingredient_tags":["bell pepper","kale","rice","vegan sausage"],"item_tags":["celery","chipotle morita powder","fire roasted tomatoes","vegetable broth concentrate"],"issues":null,"front":"043a_IMG_9218.jpg","back":"043b_IMG_9219.jpg","era":"binder","hero":"043.jpg"},{"pair":44,"title":"Cavatappi Bolognese","subtitle":"with Rosemary & Parmesan","servings":"2","cook_time":"30 min","nutrition":{"calories":"450","fat":"4 g","carbohydrates":"90 g","protein":"19 g"},"description":null,"from_your_kitchen":null,"ingredients":["1 shallot","3 garlic cloves","1 carrot","¼ oz fresh rosemary","6 oz broccolini","4 oz cauliflower florets","5 oz cavatappi","¼ tsp red chile flakes 🌶","14 oz crushed tomatoes","2 tbsp red miso paste","2 tbsp vegan parmesan"],"tools":null,"steps":[{"n":1,"title":null,"text":"Bring a large pot of salted water to a boil for the pasta. Peel and roughly chop the shallot and garlic. Peel and roughly chop the carrot. Pick the rosemary leaves, and mince. Trim the broccolini and chop into 2 inch pieces.","img":"044_1.jpg"},{"n":2,"title":null,"text":"Add the chopped shallot and chopped garlic to a food processor, and pulse until finely chopped. Add chopped carrot and cauliflower florets to the shallot and garlic in the food processor and pulse until pieces are the size of rice grains, 10 to 12 pulses.","img":"044_2.jpg"},{"n":3,"title":null,"text":"Add cavatappi to the boiling water, stir, and cook until al dente, 8 to 10 minutes. Reserve ¾ cup pasta water, drain the pasta, and return pasta to the large pot, off heat. Toss cooked cavatappi with 1 tsp olive oil to prevent sticking.","img":"044_3.jpg"},{"n":4,"title":null,"text":"Heat 1 tbsp olive oil in a large nonstick skillet over medium heat. Add processed vegetable mixture and cook, stirring occasionally, until shallot is softened, 3 to 5 minutes. Add red chile flakes and ½ tsp minced rosemary and cook until fragrant, about 30 seconds.","img":"044_4.jpg"},{"n":5,"title":null,"text":"Add the crushed tomatoes, red miso paste, and reserved pasta water to the skillet and stir to dissolve the miso. Cook, stirring occasionally, until cauliflower is tender and sauce has thickened, 4 to 6 minutes. Add ½ tsp salt, taste, and add more salt as necessary.","img":"044_5.jpg"},{"n":6,"title":null,"text":"Divide the cooked cavatappi between large plates and top with bolognese sauce. Return the large pot to medium-high heat with 1 tsp olive oil. Add chopped broccolini, cook until crisp-tender, and sprinkle with salt. Add cooked broccolini to the plates and top everything with parmesan. Mangia!","img":"044_6.jpg"}],"tips":["This item is spicy. (red chile flakes)"],"cuisine_tags":["Italian"],"ingredient_tags":["broccolini","carrot","cauliflower","pasta"],"item_tags":["crushed tomatoes","miso","red chile flakes","rosemary","vegan parmesan"],"issues":null,"front":"044a_IMG_9220.jpg","back":"044b_IMG_9221.jpg","era":"binder","hero":"044.jpg"},{"pair":45,"title":"Crispy Carrot Dumplings","subtitle":"with Hazelnut Sesame Butter & Apple Arugula Salad","servings":"2","cook_time":"45 min","nutrition":{"calories":"770","fat":"39 g","carbohydrates":"96 g","protein":"18 g"},"description":null,"from_your_kitchen":null,"ingredients":["4 carrots","¼ cup hazelnuts","¼ oz fresh parsley*","1 apple","1 tbsp Champagne vinegar","2 oz Treeline Cashew Cream Cheese","½ tsp pumpkin pie spice","20 dumpling wrappers","3 tbsp vegan butter","1 tbsp white sesame seeds","2 oz baby arugula"],"tools":null,"steps":[{"n":1,"title":null,"text":"Bring a medium saucepan of salted water to a boil for the carrots. Peel carrots and thinly slice into rounds. Finely chop the hazelnuts. Finely chop the parsley leaves. Thinly slice the apple. Add sliced apple, Champagne vinegar, and a pinch of salt to a medium bowl and toss.","img":"045_1.jpg"},{"n":2,"title":null,"text":"Once the water is boiling, add sliced carrots and cook until fork-tender, 6 to 7 minutes. Drain boiled carrots and transfer to a food processor. Add just half the chopped parsley, cream cheese, pumpkin pie spice, and ½ tsp salt to the food processor and blend until smooth, scraping down the sides as necessary.","img":"045_2.jpg"},{"n":3,"title":null,"text":"Place dumpling wrappers on a flat surface and fill a small bowl with cold water. Use a tablespoon to place carrot filling in the center of each wrapper. Dip your finger in the cold water and wet the rim of each wrapper. Fold dumpling wrappers over the filling and press down to seal, pinching tightly.","img":"045_3.jpg"},{"n":4,"title":null,"text":"Melt butter in a large nonstick skillet over medium heat. Add chopped hazelnuts, white sesame seeds, and a pinch of salt. Cook, tossing frequently, until fragrant, 2 to 3 minutes. Use a slotted spoon to transfer toasted nuts and sesame seeds to a bowl, reserving the butter in the skillet.","img":"045_4.jpg"},{"n":5,"title":null,"text":"Increase the heat to medium-high. Add half the carrot dumplings to the skillet and cook until browned and crispy, 2 to 3 minutes. Flip dumplings and cook for 1 minute. Add ¼ cup water, reduce heat to medium, and cover. Steam crispy carrot dumplings until tender and the water has evaporated, 3 to 4 minutes. Repeat with remaining dumplings.","img":"045_5.jpg"},{"n":6,"title":null,"text":"Add baby arugula, 1 tsp olive oil, and a pinch of pepper to the bowl with the apples. Toss the apple arugula salad to coat evenly. Divide the crispy carrot dumplings between plates and sprinkle with toasted hazelnuts and sesame seeds and remaining chopped parsley. Serve the apple arugula salad on the side. Dig in!","img":"045_6.jpg"}],"tips":["* This ingredient will be split between steps.","TIP: The nuts and seeds can burn quickly, so reduce heat if necessary."],"cuisine_tags":["Fusion"],"ingredient_tags":["apple","arugula","carrot","dumplings","hazelnuts"],"item_tags":["cashew cream cheese","champagne vinegar","pumpkin pie spice","sesame seeds","vegan butter"],"issues":null,"front":"045a_IMG_9222.jpg","back":"045b_IMG_9223.jpg","era":"binder","hero":"045.jpg"},{"pair":46,"title":"Japanese Yam Sushi Bowls","subtitle":"with Sesame Spinach & Citrus Aioli","servings":"2","cook_time":"30 min","nutrition":{"calories":"730","fat":"17 g","carbohydrates":"131 g","protein":"14 g"},"description":null,"from_your_kitchen":null,"ingredients":["2 Japanese yams","¾ cup quinoa speckled rice","1 cucumber","1 tbsp chile garlic sauce 🌶","1 tbsp rice vinegar","1 lime*","3 tbsp Follow Your Heart® Soy-Free Vegenaise®","4 oz baby spinach","1 tbsp tuxedo sesame seeds*","1 nori sheet"],"tools":null,"steps":[{"n":1,"title":null,"text":"Preheat the oven to 425°F. Cut Japanese yams into wedges and place on a baking sheet. Toss with 2 tsp vegetable oil and a pinch of salt and pepper, and bake until wedges are crisp and slightly browned, 20 to 25 minutes.","img":"046_1.jpg"},{"n":2,"title":null,"text":"Add the quinoa speckled rice, 1¼ cups water, and a pinch of salt to a small saucepan. Bring to a boil, cover, reduce heat to low, and cook until the water is absorbed and rice is tender, 15 to 20 minutes.","img":"046_2.jpg"},{"n":3,"title":null,"text":"Thinly slice the cucumber. Add sliced cucumber, chile garlic sauce, and rice vinegar to a medium bowl and toss.","img":"046_3.jpg"},{"n":4,"title":null,"text":"Zest and halve the lime, juice one half, and cut the other half into wedges. Add lime zest, lime juice, Vegenaise, and a pinch of salt to a small bowl. Mix the citrus aioli.","img":"046_4.jpg"},{"n":5,"title":null,"text":"Heat 1 tsp vegetable oil in a large nonstick skillet over medium-high heat. Add baby spinach, just 2 tsp tuxedo sesame seeds, and a pinch of salt and pepper. Cook until spinach is wilted, 1 to 2 minutes.","img":"046_5.jpg"},{"n":6,"title":null,"text":"Divide the cooked quinoa speckled rice between large bowls. Add roasted Japanese yam wedges, sesame spinach, and spicy cucumbers, and drizzle with citrus aioli. Tear the nori sheet into pieces and sprinkle over the bowls. Top the Japanese yam sushi bowls with remaining tuxedo sesame seeds. Serve with lime wedges. Itadakimasu! (In Japan, this is often said before a meal to express thanks to whomever prepared the food.)","img":"046_6.jpg"}],"tips":["This item is spicy. (chile garlic sauce)","* These ingredients will be split between steps.","Substitute: sweet potato for Japanese yam"],"cuisine_tags":["Japanese"],"ingredient_tags":["cucumber","quinoa","rice","spinach","yam"],"item_tags":["chile garlic sauce","lime","nori","rice vinegar","sesame seeds","vegenaise"],"issues":null,"front":"046a_IMG_9224.jpg","back":"046b_IMG_9225.jpg","era":"binder","hero":"046.jpg"},{"pair":47,"title":"Calabrian Bean & Veggie Bowls","subtitle":"with Toasted Farro & Basil Cashew Sauce","servings":"2","cook_time":"35 min","nutrition":{"calories":"380","fat":"12 g","carbohydrates":"56 g","protein":"19 g"},"description":null,"from_your_kitchen":null,"ingredients":["¾ cup farro","⅓ cup cashews","3 garlic cloves*","6 oz broccolini","6 oz parsnip","4 oz roasted red peppers","1 lime","½ oz fresh basil*","2 tbsp white sesame seeds*","5.3 oz Brami® Hot Chili Pepper Italian Snacking Lupini Beans 🌶"],"tools":null,"steps":[{"n":1,"title":null,"text":"Preheat the oven to 400°F. Add farro and a pinch of salt to a small saucepan and cover with 1 inch cold water. Bring to a boil, reduce heat to medium, and cook until farro is tender, 18 to 20 minutes. Drain well and return farro to the saucepan, uncovered, off heat.","img":"047_1.jpg"},{"n":2,"title":null,"text":"Add cashews to a small bowl and cover with ⅓ cup hot water. Peel garlic cloves. Trim one inch off the broccolini stems. Peel parsnip and chop into bite-size pieces. Drain and finely chop the roasted red peppers. Halve and juice the lime.","img":"047_2.jpg"},{"n":3,"title":null,"text":"Add broccolini to one side of a baking sheet and chopped parsnip to the other side, and toss vegetables with 1 tbsp olive oil and a pinch of salt and pepper. Roast until tender and browned in places, 12 to 15 minutes.","img":"047_3.jpg"},{"n":4,"title":null,"text":"Pick the basil leaves. Add cashews and their soaking water, just 1 peeled garlic clove, lime juice, just half the basil leaves, just 1 tbsp white sesame seeds, and a pinch of salt to a blender. Blend the basil cashew sauce until smooth.","img":"047_4.jpg"},{"n":5,"title":null,"text":"Thinly slice remaining peeled garlic cloves. Heat 1 tbsp olive oil in a large nonstick skillet over medium-high heat. Add cooked farro and cook, undisturbed, until grains are glistening and toasted, 3 to 5 minutes. Add sliced garlic, roasted parsnip, chopped red peppers, and lupini beans and cook until warmed through, 3 to 4 minutes. Sprinkle with salt and pepper.","img":"047_5.jpg"},{"n":6,"title":null,"text":"Tear remaining basil leaves. Divide toasted farro mixture between large bowls. Add roasted broccolini and drizzle with basil cashew sauce. Top the Calabrian bean and veggie bowls with torn basil leaves and remaining white sesame seeds. Dig in!","img":"047_6.jpg"}],"tips":["* These ingredients will be split between steps.","This item is spicy. (lupini beans)","Let's Talk about Lupini Beans: Lupini beans, a legume related to chickpeas and lentils, are popular in Mediterranean cuisines. Because they have a slightly bitter taste, these beans are often pickled and eaten as a snack. They have a thick skin that you can eat, or you can squeeze the lupini bean and the seed will shoot out!"],"cuisine_tags":["Italian","Mediterranean"],"ingredient_tags":["broccolini","cashews","farro","lupini beans","parsnip"],"item_tags":["basil","hot chili pepper","lime","roasted red peppers","sesame seeds"],"issues":null,"front":"047a_IMG_9226.jpg","back":"047b_IMG_9227.jpg","era":"binder","hero":"047.jpg"},{"pair":48,"title":"Thai Tempeh Khao Soi","subtitle":"with Bok Choy & Crispy Onions","servings":"2","cook_time":"30 min","nutrition":{"calories":"840","fat":"22 g","carbohydrates":"120 g","protein":"28 g"},"description":null,"from_your_kitchen":null,"ingredients":["1 oz fresh ginger","2 garlic cloves","6 oz baby bok choy","1 shallot","1 lime*","1 Thai chile 🌶","2 tsp turbinado sugar*","¾ cup coconut milk","2 tbsp red curry paste 🌶","2 tsp tamari","7 oz dried rice noodles","8 oz tempeh","2 tbsp crispy onions"],"tools":null,"steps":[{"n":1,"title":null,"text":"Bring a large pot of salted water to a boil for the rice noodles. Peel and mince the ginger and garlic. Trim and thinly slice the baby bok choy. Peel and thinly slice the shallot. Halve and juice the lime. Thinly slice the Thai chile.","img":"048_1.jpg"},{"n":2,"title":null,"text":"Add the sliced shallot, just half the lime juice, just 1 tsp turbinado sugar, and a pinch of salt to a small bowl and toss to combine.","img":"048_2.jpg"},{"n":3,"title":null,"text":"Measure ¾ cup coconut milk and set aside. Heat 1 tbsp vegetable oil in a medium saucepan over medium-high heat. Add minced ginger, minced garlic, and red curry paste, and cook until fragrant, 1 to 2 minutes. Add reserved coconut milk, tamari, 1½ cups water, ½ tsp salt, and ½ tsp pepper. Bring to a simmer, add sliced baby bok choy, and reduce heat to low.","img":"048_3.jpg"},{"n":4,"title":null,"text":"Add rice noodles to the large pot of boiling water, stir, and remove from heat. Cook, stirring occasionally, until noodles are tender, 8 to 10 minutes. Drain noodles and rinse under cold water to stop the cooking process.","img":"048_4.jpg"},{"n":5,"title":null,"text":"Heat 2 tbsp vegetable oil in a large nonstick skillet over medium-high heat. Crumble tempeh and add to the skillet. Add a pinch of salt and pepper and cook, tossing occasionally, until tempeh is browned and crispy, 5 to 7 minutes. Add remaining turbinado sugar and cook another 2 to 3 minutes.","img":"048_5.jpg"},{"n":6,"title":null,"text":"Add the remaining lime juice to the broth. Taste, and add salt as necessary. Divide broth between shallow bowls. Add the cooked rice noodles, crispy tempeh, pickled shallot, and sliced Thai chile. Top the Thai tempeh khao soi with crispy onions. Bon appétit!","img":"048_6.jpg"}],"tips":["* These ingredients will be split between steps.","These items are spicy. (Thai chile, red curry paste)","Substitute: broccoli for baby bok choy","TIP: Keep any remaining coconut milk for your own use."],"cuisine_tags":["Thai"],"ingredient_tags":["bok choy","rice noodles","tempeh"],"item_tags":["coconut milk","crispy onions","ginger","lime","red curry paste","tamari","thai chile","turbinado sugar"],"issues":null,"front":"048a_IMG_9228.jpg","back":"048b_IMG_9229.jpg","era":"binder","hero":"048.jpg"},{"pair":49,"title":"Chile Butter Roasted Delicata Squash","subtitle":"with Garlicky Greens & Lemon Yogurt","servings":"2","cook_time":"35 min","nutrition":{"calories":"460","fat":"11 g","carbohydrates":"69 g","protein":"22 g"},"description":null,"from_your_kitchen":null,"ingredients":["1 cup French green lentils","1 delicata squash","1 lemon*","¼ cup Forager Project® Organic Dairy-free Cashewmilk Yogurt","2 tbsp vegan butter","2 tbsp chile garlic sauce 🌶","2 garlic cloves","6 oz gai lan","¼ oz fresh dill"],"tools":null,"steps":[{"n":1,"title":null,"text":"Preheat the oven to 375°F. Rinse and sort the French green lentils, and add to a small saucepan with 2¼ cups water and a pinch of salt. Bring to a boil, cover, reduce heat to low, and simmer until lentils are tender, 18 to 20 minutes. Drain any remaining water.","img":"049_1.jpg"},{"n":2,"title":null,"text":"Trim the ends off the delicata squash, remove the seeds, and slice squash into 6 rounds, each about ½ inch thick. Add sliced squash to a baking sheet and toss with 1 tbsp vegetable oil and a pinch of salt and pepper. Roast until fork-tender, 18 to 20 minutes.","img":"049_2.jpg"},{"n":3,"title":null,"text":"Zest and halve the lemon, juice one half, and cut the other half into wedges. Add yogurt, just ½ tsp lemon zest, just 2 tsp lemon juice, and a pinch of salt to a small bowl, and stir. In another small bowl, combine butter and as much chile garlic sauce as you'd like, and mix well.","img":"049_3.jpg"},{"n":4,"title":null,"text":"Peel and thinly slice the garlic. Roughly chop the gai lan. Heat 2 tsp vegetable oil in a large nonstick skillet over medium-high heat. Add sliced garlic and cook until lightly browned in places. Add chopped gai lan and a pinch of salt and pepper and cook until tender, 2 to 3 minutes.","img":"049_4.jpg"},{"n":5,"title":null,"text":"Pick the dill fronds from the stem. Spread chile butter on the roasted squash. Divide the French green lentils and garlicky greens between plates, and top with chile butter roasted delicata squash. Drizzle with lemon yogurt and sprinkle with dill fronds and remaining lemon zest. Serve with lemon wedges and dollop any remaining chile butter on top. Enjoy!","img":"049_5.jpg"}],"tips":["* This ingredient will be split between steps.","This item is spicy. (chile garlic sauce)","Substitute: butternut squash for delicata squash","TIP: To \"sort\" means to look for and discard any naturally occurring debris or stones.","TIP: The dill fronds are the wispy green leaves on the thick stems.","Delicate and Delicious! Some people say delicata squash tastes like a mix of fresh corn and pumpkin. We say: Yum! Plus, delicata squash is high in beta-carotene and vitamin C, low in calories, and astonishingly versatile. It's great boiled, sautéed, steamed, and roasted—and the skin is delicious roasted, too."],"cuisine_tags":["American","Fusion"],"ingredient_tags":["delicata squash","gai lan","lentils"],"item_tags":["cashewmilk yogurt","chile garlic sauce","dill","lemon","vegan butter"],"issues":null,"front":"049a_IMG_9230.jpg","back":"049b_IMG_9231.jpg","era":"binder","hero":"049.jpg"},{"pair":50,"title":"Creamy Tomato Bisque","subtitle":"with Quinoa & Parmesan Roasted Cauliflower","servings":"2 (4)","cook_time":"25 (30) min","nutrition":{"calories":"460","fat":"26 g","carbohydrates":"48 g","protein":"11 g"},"description":null,"from_your_kitchen":null,"ingredients":["¼ cup quinoa","6 oz cauliflower florets","4 garlic cloves","1 shallot","¼ cup cashews","14.5 oz fire roasted diced tomatoes","5.5 oz coconut milk","¼ oz fresh basil","2 tbsp soy-free vegan parmesan"],"tools":null,"steps":[{"n":1,"title":null,"text":"Preheat oven to 400°F. Add the quinoa, ½ cup (1 cup) water, and a pinch of salt to a small saucepan over high heat. Bring to a boil, reduce heat, cover, and cook until the spirals burst and water is absorbed, 10 to 12 minutes.","img":"050_1.jpg"},{"n":2,"title":null,"text":"Transfer the cauliflower florets to a baking sheet and toss with 1 tbsp (2 tbsp) olive oil and a pinch of salt and pepper. Roast until tender and browned in places, 12 to 15 minutes.","img":"050_2.jpg"},{"n":3,"title":null,"text":"Peel and chop the garlic. Peel and roughly chop the shallot(s). Heat 1 tbsp (2 tbsp) olive oil in a large pot over medium heat. Add chopped garlic and chopped shallot and cook until softened, 3 to 5 minutes.","img":"050_3.jpg"},{"n":4,"title":null,"text":"Add the cashews, tomatoes, coconut milk, and ¼ cup (½ cup) water to the large pot. Bring to a boil, reduce heat to low, and simmer for 3 to 5 minutes. Carefully pour bisque into a blender and purée until smooth. Sprinkle tomato bisque with salt and pepper.","img":"050_4.jpg"},{"n":5,"title":null,"text":"Tear the basil leaves. Toss roasted cauliflower with just 1 tbsp (2 tbsp) parmesan. Divide the creamy tomato bisque between large bowls. Top with quinoa and parmesan roasted cauliflower. Sprinkle with torn basil leaves and remaining parmesan. Soup's on!","img":"050_5.jpg"}],"tips":["Substitute: broccoli florets for cauliflower florets","Ingredients listed for 2 servings—if you're making 4 servings, please double your ingredients by using both bags provided. Directions for 4 servings indicated in parentheses.","TIP: Blend in batches for the 4 serving meal.","Avoid a Soup Explosion: Hot liquids expand and can create a powerful vortex in your blender. Follow these tips to ensure your soup ends up in your bowls, not on your walls. Give the soup mixture a few minutes to cool down. Fill half the blender jar with soup, add the blender lid, and remove the center part of the lid or open the spout to release steam. Hold a towel over the opening to prevent soup from escaping, and turn on the blender. Start on low and slowly increase the speed. Voilà!"],"cuisine_tags":["American","Comfort Food"],"ingredient_tags":["cashews","cauliflower","quinoa","tomato"],"item_tags":["basil","coconut milk","fire roasted tomatoes","vegan parmesan"],"issues":null,"front":"050a_IMG_9232.jpg","back":"050b_IMG_9233.jpg","era":"binder","hero":"050.jpg"},{"pair":51,"title":"Herb Sausages","subtitle":"with Caraway Roasted Potatoes & Maple Mustard Dressing","servings":"2 (4)","cook_time":"30 (40) min","nutrition":{"calories":"550","fat":"8 g","carbohydrates":"91 g","protein":"34 g"},"description":null,"from_your_kitchen":null,"ingredients":["2 carrots","1 onion","4 oz Brussels sprouts","1 lb fingerling potatoes","2 vegan herbed sausages","2 tsp caraway seeds","2 tbsp Dijon mustard","2 tbsp maple syrup"],"tools":null,"steps":[{"n":1,"title":null,"text":"Preheat the oven to 450°F. Peel and roughly chop the carrots and onion(s). Trim and halve the Brussels sprouts. Halve the fingerling potatoes lengthwise. Remove sausages from the casing and halve lengthwise.","img":"051_1.jpg"},{"n":2,"title":null,"text":"Add the chopped carrot, chopped onion, halved Brussels sprouts, halved fingerling potatoes, caraway seeds, 1 tbsp (2 tbsp) olive oil, and a pinch of salt and pepper to a baking sheet. Toss to evenly coat, and roast until the vegetables begin to brown, 15 to 17 minutes.","img":"051_2.jpg"},{"n":3,"title":null,"text":"Combine the Dijon mustard and maple syrup in a small bowl. Mix the maple mustard dressing.","img":"051_3.jpg"},{"n":4,"title":null,"text":"Heat 1 tbsp (2 tbsp) olive oil in a large nonstick skillet over medium-high heat. Place halved sausages cut side down and cook until well browned and crisp, 3 to 5 minutes. Flip sausages and cook another 1 to 3 minutes.","img":"051_4.jpg"},{"n":5,"title":null,"text":"Divide the caraway roasted vegetables and herbed sausages between large, shallow plates. Drizzle 1 tbsp (2 tbsp) maple mustard dressing on top, and serve any remaning dressing on the side for dipping. Enjoy!","img":"051_5.jpg"}],"tips":["Caraway Power! If you've eaten rye or pumpernickel breads, you've tasted caraway seeds. These delicious seeds, which are part of the parsley family, add a mild anise flavor and a citrusy, peppery smell to all sorts of classic dishes and savory baked goods. In particular, caraway is very common in Austrian and German cooking, but you'll also find it in Middle Eastern dishes and in condiments like harissa. Besides being a popular culinary ingredient, caraway has been used for hundreds of years as a digestive aid. Research shows that these flavorful seeds can help rebuild your intestinal flora and yeast, acting as a natural probiotic."],"cuisine_tags":["American","German"],"ingredient_tags":["brussels sprouts","carrot","potato","vegan sausage"],"item_tags":["caraway seeds","dijon mustard","maple syrup"],"issues":null,"front":"051a_IMG_9234.jpg","back":"051b_IMG_9235.jpg","era":"binder","hero":"051.jpg"},{"pair":52,"title":"Crispy Hearts of Palm Tacos","subtitle":"with Avocado Salsa & Chipotle Ranch","servings":"2 (4)","cook_time":"40 (45) min","nutrition":{"calories":"530","fat":"28 g","carbohydrates":"68 g","protein":"8 g"},"description":null,"from_your_kitchen":null,"ingredients":["2 radishes","1 jalapeño (spicy)","14 oz hearts of palm","1 lime*","4 oz green cabbage","1 tsp Mexican oregano","1 avocado","¼ cup Follow Your Heart® High Omega Vegan Ranch Salad Dressing","½ tsp chipotle morita powder (spicy)","⅓ cup white rice flour","⅓ cup cornstarch","6 corn tortillas"],"tools":null,"steps":[{"n":1,"title":null,"text":"Preheat oven to 350°F for the tortillas. Trim, halve, and thinly slice the radishes. Trim, deseed, and thinly slice the jalapeño(s). Drain the hearts of palm and cut each piece in half crosswise. Gently flatten each piece with the palm of your hand.","img":"052_1.jpg"},{"n":2,"title":null,"text":"Halve and juice the lime(s). Add just half the lime juice, green cabbage, Mexican oregano, and a pinch of salt to a medium bowl. Toss the curtido slaw.","img":"052_2.jpg"},{"n":3,"title":null,"text":"Halve the avocado(s), remove the pit(s), and dice the flesh. Transfer diced avocado to a medium bowl. Add sliced radish, sliced jalapeño, remaining lime juice, and a pinch of salt and pepper. Toss the avocado salsa. Add ranch dressing and as much of the chipotle morita powder as you'd like to a small bowl, and whisk the chipotle aioli until smooth.","img":"052_3.jpg"},{"n":4,"title":null,"text":"Add ¾ cup (1½ cups) vegetable oil to a large skillet over medium-high heat. Add white rice flour, cornstarch, and ⅓ cup (⅔ cup) water to a medium bowl, and whisk until smooth. Dip flattened hearts of palm pieces in the batter and gently place them in the hot oil, working in batches. Cook until crispy, 3 to 4 minutes per side. Transfer crispy hearts of palm to a paper towel-lined plate and sprinkle with salt.","img":"052_4.jpg"},{"n":5,"title":null,"text":"Wrap the corn tortillas in foil and warm in the oven, 4 to 5 minutes. Place warmed corn tortillas on a flat surface and divide the curtido slaw and crispy hearts of palm between them. Add the avocado salsa and drizzle with chipotle aioli. Dig in!","img":"052_5.jpg"}],"tips":["TIP: If you have a toaster oven or microwave, you can use either one to warm the tortillas instead.","TIP: We suggest starting with ⅛ tsp (¼ tsp) chipotle morita powder.","TIP: Work in batches for the 4 serving meal.","* This ingredient will be split between steps."],"cuisine_tags":["Mexican"],"ingredient_tags":["avocado","cabbage","hearts of palm","radish","tortilla"],"item_tags":["chipotle morita powder","cornstarch","lime","mexican oregano","rice flour","vegan ranch dressing"],"issues":null,"front":"052a_IMG_9236.jpg","back":"052b_IMG_9237.jpg","era":"binder","hero":"052.jpg"},{"pair":53,"title":"Pan Seared Broccolini","subtitle":"with Mashed Sweet Potatoes & Coconut Turmeric Relish","servings":"2","cook_time":"35 min","nutrition":{"calories":null,"fat":null,"carbohydrates":null,"protein":null},"description":null,"from_your_kitchen":null,"ingredients":["1 sweet potato","½ cup beluga lentils","2 garlic cloves","1 Fresno chile (spicy)","1 oz fresh ginger","1 lemon","8 oz broccolini","2 tbsp golden raisins","2 tbsp toasted coconut","2 tsp brown mustard seeds","¼ tsp ground turmeric","2 tbsp vegan butter"],"tools":null,"steps":[{"n":1,"title":null,"text":"Peel and dice the sweet potato. Add diced sweet potato to a small saucepan and cover with 1 inch of water. Bring to a boil and cook until fork-tender, 10 to 12 minutes. Drain and return cooked sweet potato to the saucepan, off heat. Add beluga lentils and 1 cup water to another saucepan. Bring to a boil, cover, reduce heat to low, and simmer until lentils are tender, 20 to 24 minutes.","img":"053_1.jpg"},{"n":2,"title":null,"text":"Peel and thinly slice the garlic. Trim, deseed, and halve the Fresno chile, and mince one half. Peel and mince 2 tsp ginger. Halve and juice the lemon. Trim 1 inch off the bottom of the broccolini.","img":"053_2.jpg"},{"n":3,"title":null,"text":"Heat 2 tbsp olive oil in a large nonstick skillet over medium heat. Add sliced garlic and cook until lightly browned, 3 to 5 minutes. Add minced Fresno chile, minced ginger, golden raisins, coconut, brown mustard seeds, and turmeric. Stir, and cook until aromatic, 1 to 3 minutes. Add lemon juice and transfer the coconut turmeric relish to a medium bowl.","img":"053_3.jpg"},{"n":4,"title":null,"text":"Wipe the skillet clean and return to medium-high heat. Add 2 tsp olive oil, ¼ cup water, and a pinch of salt. Add broccolini, cover, and cook until water evaporates and broccolini is tender and crispy in places, 3 to 5 minutes. Flip and cook for an additional 2 minutes.","img":"053_4.jpg"},{"n":5,"title":null,"text":"Add butter to the cooked sweet potatoes and mash with a fork. Taste, and add salt as necessary. Divide the mashed sweet potatoes and cooked beluga lentils between large plates. Top with pan seared broccolini and coconut turmeric relish. Tuck in!","img":"053_5.jpg"}],"tips":["TIP: Save the remaining Fresno chile and ginger for your own use.","TIP: Add more Fresno chile if you prefer more heat.","Substitute: broccoli for broccolini"],"cuisine_tags":["Fusion","Indian"],"ingredient_tags":["broccolini","lentils","sweet potato"],"item_tags":["brown mustard seeds","fresno chile","ginger","golden raisins","toasted coconut","turmeric","vegan butter"],"issues":"Front card nutrition line is cut off at the bottom edge of the photo; nutrition values unreadable.","front":"053a_IMG_9238.jpg","back":"053b_IMG_9239.jpg","era":"binder","hero":"053.jpg"},{"pair":54,"title":"Crispy Fabcakes","subtitle":"with Fresh Herb Salad & Creamy Lemon Dijon Dressing","servings":"2","cook_time":"35 min","nutrition":{"calories":"750","fat":"34 g","carbohydrates":"86 g","protein":"24 g"},"description":null,"from_your_kitchen":null,"ingredients":["2 carrots","1 garlic clove","1 lemon*","13.4 oz chickpeas","14 oz hearts of palm","2 radishes","¼ oz fresh dill","1 jalapeño (spicy)","1 tbsp Dijon mustard*","¼ cup + 2 tbsp Follow Your Heart® Soy-Free Vegenaise®*","1 tbsp New England seasoning","¾ cup panko breadcrumbs*","2 oz baby arugula"],"tools":null,"steps":[{"n":1,"title":null,"text":"Preheat the oven to 400°F. Peel the carrots, then chop into 1 inch pieces. Peel and mince the garlic. Halve the lemon, juice one half, and cut the other half into wedges. Drain and rinse the chickpeas. Drain and roughly chop the hearts of palm. Trim and halve the radishes. Pick the dill fronds from the stems. Trim, deseed, and roughly chop the jalapeño.","img":"054_1.jpg"},{"n":2,"title":null,"text":"Add the chopped carrot, halved radishes, 1 tbsp vegetable oil, and a pinch of salt and pepper to a baking sheet. Toss to coat, and roast until tender and browned, 18 to 20 minutes.","img":"054_2.jpg"},{"n":3,"title":null,"text":"Add the minced garlic, lemon juice, just half the Dijon mustard, just 2 tbsp Vegenaise, 1 tbsp olive oil, and a pinch of salt and pepper to a large bowl. Whisk the lemon Dijon dressing.","img":"054_3.jpg"},{"n":4,"title":null,"text":"Add the chickpeas, chopped hearts of palm, chopped jalapeño, remaining Dijon mustard, remaining Vegenaise, New England seasoning, just ½ cup panko breadcrumbs, ½ tsp salt, and ¼ tsp pepper to a food processor. Pulse until well combined but not finely chopped, 5 to 8 pulses. Form the fabcake mixture into six 2 inch wide patties.","img":"054_4.jpg"},{"n":5,"title":null,"text":"Add 2 tbsp vegetable oil to a large nonstick skillet over medium heat. Add remaining panko breadcrumbs to a plate and gently press fabcake patties into breadcrumbs, coating both sides. Add breaded fabcakes to the skillet and cook until golden brown, 5 to 8 minutes per side. Transfer to a paper towel-lined plate and sprinkle with salt.","img":"054_5.jpg"},{"n":6,"title":null,"text":"Divide the dill fronds and baby arugula between bowls. Top with roasted carrots and radishes, and crispy fabcakes. Drizzle with creamy lemon Dijon dressing and serve with lemon wedges. Dig in!","img":"054_6.jpg"}],"tips":["TIP: Wash your hands and cutting board well after handling the jalapeño.","TIP: It's okay to start roasting the carrots before your oven is fully preheated.","TIP: Add more oil as necessary to crisp the fabcakes.","* These ingredients will be split between steps.","Substitute: another green for baby arugula"],"cuisine_tags":["American","New England"],"ingredient_tags":["arugula","carrot","chickpeas","hearts of palm"],"item_tags":["dijon mustard","dill","jalapeño","new england seasoning","panko breadcrumbs","vegenaise"],"issues":null,"front":"054a_IMG_9240.jpg","back":"054b_IMG_9241.jpg","era":"binder","hero":"054.jpg"},{"pair":55,"title":"Penne Mushroom Florentine","subtitle":"with Chickpea Pasta & Toasted Walnuts","servings":"2 (4)","cook_time":"30 (40) min","nutrition":{"calories":"650","fat":"25 g","carbohydrates":"94 g","protein":"35 g"},"description":null,"from_your_kitchen":null,"ingredients":["6 oz cremini mushrooms","2 garlic cloves","1 shallot","¼ cup walnuts","8 oz Banza® pasta","2 tbsp vegan butter","¼ cup sherry wine","1 Not-Chick'n™ Bouillon Cube","4 oz baby spinach"],"tools":null,"steps":[{"n":1,"title":null,"text":"Bring a large pot of salted water to a boil for the pasta. Thinly slice the cremini mushrooms. Peel and mince the garlic and shallot(s). Add walnuts to a large nonstick skillet over medium heat and toast, shaking the pan frequently, until fragrant, 3 to 5 minutes. Transfer toasted walnuts to a plate.","img":"055_1.jpg"},{"n":2,"title":null,"text":"Return the skillet to medium-high heat with 1 tbsp (2 tbsp) olive oil. Once hot, add sliced cremini mushrooms and a pinch of salt and cook, tossing occasionally, 3 to 5 minutes. Add minced garlic, minced shallot, and a pinch of salt and pepper, and cook until softened, 2 to 4 minutes.","img":"055_2.jpg"},{"n":3,"title":null,"text":"Add pasta to the boiling water. Cook, stirring occasionally, until al dente, 3 to 5 minutes. Reserve 1 cup (2 cups) pasta water. Drain the pasta and rinse under cold water to stop the cooking process.","img":"055_3.jpg"},{"n":4,"title":null,"text":"Add the butter and sherry wine to the skillet with the mushrooms and cook for 1 minute. Add bouillon cube(s) to the reserved pasta water, whisk, and add to the skillet. Bring to a boil and cook until slightly thickened, 2 to 3 minutes. Add baby spinach and cooked pasta to the skillet and cook until hot, 1 to 2 minutes.","img":"055_4.jpg"},{"n":5,"title":null,"text":"Divide the penne mushroom florentine between large bowls and top with toasted walnuts. Buon appetito!","img":"055_5.jpg"}],"tips":["TIP: Don't forget to wash all produce under running water, and wipe mushrooms clean with a damp kitchen towel.","Delicious, Healthy, and ... Foamy? Chickpea pasta is gluten-free and packed with protein and fiber, plus it has fewer carbs than traditional pasta. This is definitely the vegan pasta we've been waiting for. BTW, it's totally normal to see foam when you boil chickpea pasta. To help reduce the foaming, fill your pot with more water than you need, and lower the heat. You can also add a splash of oil, and frequently stir the pasta."],"cuisine_tags":["Italian"],"ingredient_tags":["mushrooms","pasta","spinach","walnuts"],"item_tags":["bouillon","chickpea pasta","shallot","sherry wine","vegan butter"],"issues":null,"front":"055a_IMG_9242.jpg","back":"055b_IMG_9243.jpg","era":"binder","hero":"055.jpg"},{"pair":56,"title":"Sesame Ginger Noodles","subtitle":"with Stir-Fried Greens & Toasted Peanuts","servings":"2","cook_time":"25 min","nutrition":{"calories":"610","fat":"29 g","carbohydrates":"76 g","protein":"17 g"},"description":null,"from_your_kitchen":null,"ingredients":["6 oz gai lan","1 oz fresh ginger","2 mini sweet peppers","1 tbsp tamari","1 tbsp peanut butter","2 tbsp rice vinegar","2 tbsp sesame oil*","2 tbsp chili garlic sauce* (spicy)","6 oz udon","¼ cup peanuts","4 oz Swiss chard"],"tools":null,"steps":[{"n":1,"title":null,"text":"Add 2 quarts water and 1 tbsp salt to a medium saucepan and bring to a boil. Chop gai lan into 1 inch pieces. Peel and mince 2 tsp ginger. Trim and thinly slice the mini sweet peppers.","img":"056_1.jpg"},{"n":2,"title":null,"text":"Add the minced ginger, tamari, peanut butter, rice vinegar, just half the sesame oil, just half the chili garlic sauce, and ¼ hot water to a medium bowl and whisk the sesame ginger sauce.","img":"056_2.jpg"},{"n":3,"title":null,"text":"Add the udon to the boiling water and cook until al dente, 6 to 8 minutes. Drain noodles and run under cold water to stop the cooking process. Heat the remaining sesame oil in a large nonstick skillet over medium heat. Add peanuts and a pinch of salt and pepper. Cook until nuts are toasted and fragrant, 1 to 3 minutes. Use a slotted spoon to transfer the toasted peanuts to a small bowl, leaving the oil in the skillet.","img":"056_3.jpg"},{"n":4,"title":null,"text":"Return the skillet with sesame oil to high heat. Thinly slice the Swiss chard. Add chopped gai lan, sliced Swiss chard, and a pinch of salt and pepper to the skillet. Cook until bright green and tender, 2 to 3 minutes.","img":"056_4.jpg"},{"n":5,"title":null,"text":"Add the cooked udon and sesame ginger sauce to the skillet with the greens. Cook, tossing frequently, until evenly coated and warmed through, 1 to 3 minutes.","img":"056_5.jpg"},{"n":6,"title":null,"text":"Divide the sesame ginger noodles and stir-fried greens between bowls. Top with sliced mini sweet peppers and toasted peanuts. Enjoy!","img":"056_6.jpg"}],"tips":["TIP: Save any remaining ginger for your own use.","TIPS: The sauce will not be completely smooth. Keep any remaining chili garlic sauce for your own use.","* These ingredients will be split between steps."],"cuisine_tags":["Chinese","Fusion"],"ingredient_tags":["gai lan","peanuts","swiss chard","udon"],"item_tags":["chile garlic sauce","ginger","peanut butter","rice vinegar","sesame oil","tamari"],"issues":null,"front":"056a_IMG_9244.jpg","back":"056b_IMG_9245.jpg","era":"binder","hero":"056.jpg"},{"pair":57,"title":"Coconut Lentil Soup","subtitle":"with Caraway Roasted Vegetables","servings":"2 (4)","cook_time":"30 (40) min","nutrition":{"calories":"840","fat":"30 g","carbohydrates":"112 g","protein":"35 g"},"description":null,"from_your_kitchen":null,"ingredients":["6 oz cauliflower florets","2 carrots","2 tsp caraway seeds","1 onion","1 oz fresh ginger","2 garlic cloves","1 cup red lentils","1 scallion","11 oz coconut milk*","2 tbsp tomato powder","1 tsp curry powder"],"tools":null,"steps":[{"n":1,"title":null,"text":"Preheat the oven to 400°F. Chop cauliflower florets into bite-size pieces. Peel carrots and slice into rounds. Add chopped cauliflower and sliced carrot to a baking sheet and toss with 1 tbsp (2 tbsp) olive oil. Sprinkle with caraway seeds and a pinch of salt and pepper, and roast until tender and browned in places, 18 to 23 minutes.","img":"057_1.jpg"},{"n":2,"title":null,"text":"Peel and dice the onion(s). Peel and mince the ginger and garlic. Rinse and sort the red lentils. Thinly slice the scallion(s).","img":"057_2.jpg"},{"n":3,"title":null,"text":"Heat 1 tbsp (2 tbsp) olive oil in a large pot over medium-high heat. Add diced onion and a pinch of salt and pepper. Cook until softened, 3 to 5 minutes. Add minced ginger and minced garlic and cook until fragrant, about 1 minute. Open the coconut milk and reserve just 1 tbsp (2 tbsp) coconut cream for garnish.","img":"057_3.jpg"},{"n":4,"title":null,"text":"Measure 2 tbsp (4 tbsp) tomato powder and add to the large pot along with the curry powder. Stir to coat the vegetables. Add red lentils, 2½ cups (5 cups) water, and a pinch of salt and pepper, and bring soup to a boil. Lower heat to a simmer and cook, stirring occasionally, until lentils are tender, 15 to 18 minutes.","img":"057_4.jpg"},{"n":5,"title":null,"text":"Once the lentils are tender, add remaining coconut milk and stir. Bring soup to a simmer. Taste, and add salt and pepper as necessary.","img":"057_5.jpg"},{"n":6,"title":null,"text":"Ladle the coconut lentil soup into large bowls and top with caraway roasted vegetables. Sprinkle sliced scallion on top and dollop with the reserved coconut cream. Bon appétit!","img":"057_6.jpg"}],"tips":["TIP: To \"sort\" means to look for and discard any naturally occurring debris or stones.","TIP: The coconut cream is the thick, solid cream at the top of the can.","TIP: Keep any remaining tomato powder for your own use.","* This ingredient will be split between steps."],"cuisine_tags":["Comfort Food","Indian"],"ingredient_tags":["carrot","cauliflower","coconut milk","lentils"],"item_tags":["caraway seeds","curry powder","ginger","scallions","tomato powder"],"issues":null,"front":"057a_IMG_9246.jpg","back":"057b_IMG_9247.jpg","era":"binder","hero":"057.jpg"},{"pair":58,"title":"Black Pepper Tofu","subtitle":"with Chinese Broccoli & Brown Rice","servings":"2 (4)","cook_time":"40 (50) min","nutrition":{"calories":"660","fat":"19 g","carbohydrates":"105 g","protein":"29 g"},"description":null,"from_your_kitchen":null,"ingredients":["¾ cup short-grain brown rice","3 garlic cloves","1 oz fresh ginger","1 shallot","1 bird's eye chile (spicy)","14 oz organic extra firm tofu","3 scallions","1 celery stalk","6 oz Chinese broccoli","¼ cup cornstarch","1 tbsp vegan butter","¼ cup tamari","2 tbsp brown sugar"],"tools":null,"steps":[{"n":1,"title":null,"text":"Add the short-grain brown rice, 1½ cups (3 cups) water, and a pinch of salt to a small saucepan. Bring to a boil, cover, reduce heat to low, and cook until water is absorbed, 30 to 35 minutes. Fluff the cooked short-grain brown rice with a fork.","img":"058_1.jpg"},{"n":2,"title":null,"text":"Peel and mince the garlic, ginger, and shallot(s). Mince the bird's eye chile(s). Drain tofu, pat dry with a clean kitchen towel, and cut into 1 inch cubes. Chop scallions into 2 inch pieces. Thinly slice the celery. Roughly chop the Chinese broccoli.","img":"058_2.jpg"},{"n":3,"title":null,"text":"Place cubed tofu in a large bowl and toss with the cornstarch. Heat 2 tbsp (4 tbsp) vegetable oil in a large nonstick skillet over medium-high heat. Add cubed tofu and cook, tossing occasionally, until browned in places, 5 to 8 minutes. Transfer the crispy tofu to a paper towel-lined plate and sprinkle with salt.","img":"058_3.jpg"},{"n":4,"title":null,"text":"Return the skillet to medium heat and add butter. Once melted, add minced garlic, minced ginger, minced shallot, and as much minced bird's eye chile as you'd like. Cook until shallot softens, 1 to 2 minutes. In a small bowl, whisk the tamari and brown sugar until sugar dissolves.","img":"058_4.jpg"},{"n":5,"title":null,"text":"Add the crispy tofu, chopped scallion, sliced celery, tamari mixture, and up to 1 tbsp (2 tbsp) pepper to the skillet. Cook until tofu is heated through, 3 to 4 minutes.","img":"058_5.jpg"},{"n":6,"title":null,"text":"Divide the short-grain brown rice between bowls and top with the black pepper tofu. Add chopped Chinese broccoli and ¼ cup (½ cup) water to the skillet over high heat. Sprinkle with salt and cook until crisp-tender, 2 to 3 minutes. Serve Chinese broccoli on the side. Bon appétit!","img":"058_6.jpg"}],"tips":["TIP: Make sure to wash your hands after prepping the chile(s).","TIP: If necessary, work in batches for the 4 serving meal.","TIP: We suggest starting with 1 tsp minced bird's eye chile.","TIP: We will use this skillet again in the next step.","Substitute: broccoli for Chinese broccoli"],"cuisine_tags":["Chinese"],"ingredient_tags":["chinese broccoli","rice","tofu"],"item_tags":["bird's eye chile","black pepper","brown sugar","cornstarch","ginger","tamari"],"issues":null,"front":"058a_IMG_9248.jpg","back":"058b_IMG_9249.jpg","era":"binder","hero":"058.jpg"},{"pair":59,"title":"Sunflower Chickpea Sandwiches","subtitle":"with Dijon Mustard & Radishes","servings":"2","cook_time":"5 min","nutrition":{"calories":"670","fat":"23 g","carbohydrates":"78 g","protein":"25 g"},"description":null,"from_your_kitchen":null,"ingredients":["13.4 oz chickpeas","1 lemon","6 radishes","2 tbsp Follow Your Heart® Soy-Free Vegenaise®","4 tsp Dijon mustard","¼ cup sunflower seeds","4 slices sourdough bread"],"tools":null,"steps":[{"n":1,"title":null,"text":"Drain and rinse the chickpeas. Halve and juice the lemon. Thinly slice the radishes. Add chickpeas to a large bowl and mash with a fork. Add lemon juice, Vegenaise, Dijon mustard, sunflower seeds, and a pinch of salt and pepper, and stir."},{"n":2,"title":null,"text":"Toast the sourdough bread. To assemble the sandwiches, top one slice of sourdough toast with some of the sunflower chickpea salad and sliced radishes. Add a slice of sourdough toast to close the sandwich. Repeat to make the second sandwich."}],"tips":[],"cuisine_tags":["American"],"ingredient_tags":["chickpeas","radish","sourdough bread"],"item_tags":["dijon mustard","lemon","sunflower seeds","vegenaise"],"single_page":true,"issues":null,"front":"059a_IMG_9250.jpg","back":null,"era":"binder","hero":"059.jpg"},{"pair":60,"title":"Crispy Potato Skillet","subtitle":"with Snap Pea Slaw & Scallion Sour Cream","servings":"2","cook_time":"40 min","nutrition":{"calories":"480","fat":"16 g","carbohydrates":"71 g","protein":"15 g"},"description":null,"from_your_kitchen":null,"ingredients":["¼ cup beluga lentils","14 oz red bliss potatoes","6 oz sugar snap peas","2 scallions*","1 lemon","1 red bell pepper","1 jalapeño (spicy)","3 tbsp vegan sour cream","2 garlic cloves","2 tbsp vegan butter","¼ tsp smoked paprika"],"tools":null,"steps":[{"n":1,"title":null,"text":"Rinse and sort the beluga lentils, and add to a small saucepan with ½ cup water. Bring to a boil, reduce heat to low, and simmer, covered, until lentils are tender, 20 to 24 minutes. Drain any remaining water.","img":"060_1.jpg"},{"n":2,"title":null,"text":"Add the red bliss potatoes to a large pot, cover with 1 inch cold water, and bring to a boil. Cook until potatoes are fork-tender, 10 to 12 minutes. Drain and let cool.","img":"060_2.jpg"},{"n":3,"title":null,"text":"Thinly slice the sugar snap peas and scallions. Halve and juice the lemon. Add sliced snap peas, just half the sliced scallion, lemon juice, 1 tbsp olive oil, and a pinch of salt to a medium bowl. Toss the snap pea slaw and set aside. Slice the red bell pepper into thin strips. Thinly slice the jalapeño.","img":"060_3.jpg"},{"n":4,"title":null,"text":"Add remaining sliced scallion, sour cream and a pinch of salt to a small bowl. Stir to combine the scallion sour cream. Peel and mince the garlic.","img":"060_4.jpg"},{"n":5,"title":null,"text":"Place cooled boiled potatoes on a cutting board and, using the palm of your hand, gently press each potato until the sides blister open. Heat 1 tbsp vegetable oil in a large skillet over medium heat. Add smashed potatoes and cook until golden brown and crispy, 3 to 5 minutes per side. Add sliced red bell pepper, minced garlic, butter, and paprika, and cook another 2 to 3 minutes.","img":"060_5.jpg"},{"n":6,"title":null,"text":"Taste the crispy potato skillet and add salt as necessary. Scatter cooked beluga lentils over the skillet. Serve family style, topped with snap pea slaw, scallion sour cream, and sliced jalapeño. Bon appétit!","img":"060_6.jpg"}],"tips":["TIP: To \"sort\" means to look for and discard any naturally occurring debris or stones.","* This ingredient will be split between steps."],"cuisine_tags":["American","Comfort Food"],"ingredient_tags":["bell pepper","lentils","potato","sugar snap peas"],"item_tags":["jalapeño","lemon","scallions","smoked paprika","vegan butter","vegan sour cream"],"issues":null,"front":"060a_IMG_9252.jpg","back":"060b_IMG_9253.jpg","era":"binder","hero":"060.jpg"},{"pair":61,"title":"Spicy Dan Dan Noodles","subtitle":"with Gai Lan & Smoked Nori Spice","servings":"2","cook_time":"30 min","nutrition":{"calories":"600","fat":"24 g","carbohydrates":"81 g","protein":"23 g"},"description":null,"from_your_kitchen":null,"ingredients":["8 oz cremini mushrooms","2 garlic cloves","1 shallot","6 oz gai lan","1 cucumber","2 tbsp chile garlic sauce*","¼ cup tahini","2 tbsp rice vinegar","2 tsp tamari","6 oz udon","1 lemon","1 tbsp smoked nori spice"],"tools":null,"steps":[{"n":1,"title":null,"text":"Bring a large pot of salted water to a boil for the udon. Wipe cremini mushrooms clean with a damp kitchen towel. Roughly chop the cremini mushrooms. Peel and mince the garlic and shallot. Trim 1 inch off the gai lan ends. Thinly slice the cucumber into rounds, and add sliced cucumber to a small bowl with just 1 tbsp chile garlic sauce.","img":"061_1.jpg"},{"n":2,"title":null,"text":"Add the remaining chile garlic sauce, tahini, rice vinegar, tamari, and ⅓ cup hot water to a medium bowl and mix.","img":"061_2.jpg"},{"n":3,"title":null,"text":"Add the udon to the boiling water and gently stir. Cook until al dente, 5 to 7 minutes. Drain and run under cold water to stop the cooking process.","img":"061_3.jpg"},{"n":4,"title":null,"text":"Heat 2 tsp vegetable oil in a large nonstick skillet over medium-high heat. Add the gai lan and a pinch of salt and pepper and cook until gai lan is bright green and tender, 3 to 4 minutes. Transfer the sautéed gai lan to a plate and cover to keep warm.","img":"061_4.jpg"},{"n":5,"title":null,"text":"Return the skillet to medium-high heat and add 2 tbsp vegetable oil. Add chopped cremini mushrooms, minced garlic, minced shallot, and a pinch of salt and pepper. Cook until the mushrooms are browned, 4 to 5 minutes. Remove from heat, add the cooked udon and sauce to the skillet, and toss.","img":"061_5.jpg"},{"n":6,"title":null,"text":"Halve the lemon and divide one half into wedges. Divide the dan dan noodles between plates and serve with the gai lan and spicy cucumbers. Sprinkle with smoked nori spice and squeeze the lemon half over each plate. Serve with lemon wedges. Enjoy!","img":"061_6.jpg"}],"tips":["* This ingredient will be split between steps.","Substitute: baby bok choy for gai lan"],"cuisine_tags":["Chinese"],"ingredient_tags":["cucumber","gai lan","mushrooms","udon"],"item_tags":["chile garlic sauce","rice vinegar","smoked nori spice","tahini","tamari"],"issues":null,"front":"061a_IMG_9255.jpg","back":"061b_IMG_9256.jpg","era":"binder","hero":"061.jpg"},{"pair":62,"title":"Mexican Cobb Salads","subtitle":"with Avocado & Cilantro Lime Dressing","servings":"2 (4)","cook_time":"30 (35) min","nutrition":{"calories":"710","fat":"34 g","carbohydrates":"95 g","protein":"22 g"},"description":null,"from_your_kitchen":null,"ingredients":["1 sweet potato","1 red onion","1 tsp cumin seeds","1 garlic clove","¼ oz fresh cilantro","1 lime","¼ cup Follow Your Heart® Soy-Free Vegenaise®","2 corn tortillas","13.4 oz black beans","1 head baby romaine lettuce","2 radishes","1 avocado"],"tools":null,"steps":[{"n":1,"title":null,"text":"Preheat the oven to 425°F. Dice sweet potato(es) into 1 inch pieces. Peel and chop the red onion(s) into 1 inch pieces. Transfer diced sweet potato and chopped red onion to a baking sheet and toss with 1 tbsp (2 tbsp) vegetable oil, cumin seeds, and a pinch of salt and pepper. Roast until sweet potatoes are tender, 18 to 22 minutes.","img":"062_1.jpg"},{"n":2,"title":null,"text":"Peel and mince the garlic. Finely chop the cilantro leaves and stems. Halve and juice the lime(s). Add minced garlic, chopped cilantro, lime juice, Vegenaise, and a pinch of salt to a small bowl and mix the cilantro lime dressing.","img":"062_2.jpg"},{"n":3,"title":null,"text":"Slice the corn tortillas into thin ¼ inch thick strips. Place tortilla strips on a baking sheet and toss with 2 tsp (4 tsp) vegetable oil and a pinch of salt. Bake until crispy and lightly browned, 5 to 6 minutes.","img":"062_3.jpg"},{"n":4,"title":null,"text":"Drain and rinse the black beans. Trim and chop the baby romaine lettuce. Trim and thinly slice the radishes. Halve the avocado(s), remove the pit(s), and dice the flesh.","img":"062_4.jpg"},{"n":5,"title":null,"text":"Divide the chopped baby romaine lettuce between large plates and top with the black beans, roasted vegetables, sliced radish, and diced avocado. Drizzle Mexican Cobb salads with cilantro lime dressing and sprinkle with crispy tortilla strips. Dig in!","img":"062_5.jpg"}],"tips":["TIP: Toss the tortilla strips halfway through baking.","Substitute: another fresh herb for cilantro","The Most Polarizing Herb? Cilantro has been around for centuries. In fact, evidence of cilantro seeds was found in King Tut's tomb! Today you can find cilantro in Middle Eastern, North African, European, and Asian cuisines. But despite cilantro's inclusion in so many meals, its taste is very controversial; people tend to either love it or hate it. For those of us who love it, we can't get enough of the fresh, citrusy taste. However, for about 20 percent of the population cilantro will taste like soap. Why? It's a genetic predisposition. Fun fact: Julia Child famously despised cilantro."],"cuisine_tags":["Mexican"],"ingredient_tags":["avocado","black beans","romaine lettuce","sweet potato","tortilla"],"item_tags":["cilantro","cumin","lime","radish","vegenaise"],"issues":null,"front":"062a_IMG_9257.jpg","back":"062b_IMG_9258.jpg","era":"binder","hero":"062.jpg"},{"pair":63,"title":"Spicy Thai Coconut Corn Chowder","subtitle":"with Fresh Chile & Lime","servings":"2 (4)","cook_time":"30 (40) min","nutrition":{"calories":"600","fat":"31 g","carbohydrates":"72 g","protein":"11 g"},"description":null,"from_your_kitchen":null,"ingredients":["1 ear of corn","1 onion","1 red bell pepper","8 oz Yukon Gold potatoes","1 lime*","1 Thai chile*","1 tbsp green curry paste","11 oz coconut milk","2 scallions","¼ oz fresh cilantro"],"tools":null,"steps":[{"n":1,"title":null,"text":"Cut the corn kernels off the cob(s). Peel and dice the onion(s). Deseed and dice the red bell pepper(s). Dice the Yukon Gold potatoes into ½ inch cubes. Halve the lime(s), juice one half (1 lime), and divide the other half (1 lime) into wedges. Mince the Thai chile(s).","img":"063_1.jpg"},{"n":2,"title":null,"text":"Heat 1 tbsp (2 tbsp) vegetable oil in a large pot over medium-high heat. Add diced onion, diced red bell pepper, and just half the minced Thai chile. Cook until onion is translucent and softened, 3 to 5 minutes. Add green curry paste and cook, stirring frequently, until fragrant, 1 to 2 minutes.","img":"063_2.jpg"},{"n":3,"title":null,"text":"Add the corn, diced Yukon Gold potato, coconut milk and 2 cups (4 cups) water to the pot. Bring to a boil, and reduce heat to low. Simmer chowder until potatoes are fork-tender and coconut milk has thickened slightly, 8 to 10 minutes.","img":"063_3.jpg"},{"n":4,"title":null,"text":"Thinly slice the scallions. Pick and roughly chop the cilantro leaves. Add lime juice to the chowder. Taste, and add salt as necessary. Ladle the spicy Thai coconut corn chowder into large bowls. Top with sliced scallion, chopped cilantro, and any remaining minced Thai chile. Serve with lime wedges. Enjoy!","img":"063_4.jpg"}],"tips":["* This ingredient will be split between steps.","TIP: Be sure to wash your hands after preparing the chile.","TIP: If you're sensitive to spice, use less Thai chile.","Hot, Tasty, and Nutritious: Red Thai chile peppers aren't HOT hot, but they definitely pack a punch. For reference, these peppers are about 23 times hotter than a jalapeño, and 3 times less spicy than a habanero pepper. These peppers are healthy, too. They've got vitamins A and C, which can help boost the immune system, as well as capsaicin, a chemical compound that contains anti-inflammatory properties and has been shown to help stimulate the circulatory system."],"cuisine_tags":["Thai"],"ingredient_tags":["bell pepper","corn","onion","potato"],"item_tags":["cilantro","coconut milk","green curry paste","lime","scallions","thai chile"],"issues":null,"front":"063a_IMG_9259.jpg","back":"063b_IMG_9260.jpg","era":"binder","hero":"063.jpg"},{"pair":64,"title":"Black Bean Falafel","subtitle":"with Avocado & Lime Aioli","servings":"2","cook_time":"35 min","nutrition":{"calories":"690","fat":"30 g","carbohydrates":"73 g","protein":"26 g"},"description":null,"from_your_kitchen":null,"ingredients":["13.4 oz black beans","1 garlic clove*","1 onion","1 cucumber","1 lime*","3 tbsp Follow Your Heart® Soy-Free Vegenaise®","½ cup garbanzo bean flour","2 tsp zhoug seasoning","4 oz baby spinach","1 avocado"],"tools":null,"steps":[{"n":1,"title":null,"text":"Drain and rinse the black beans. Peel and mince the garlic. Peel and finely dice the onion. Slice the cucumber into rounds. Zest, halve, and juice the lime.","img":"064_1.jpg"},{"n":2,"title":null,"text":"In a small bowl, combine just ¼ tsp minced garlic, just ½ tsp lime zest, just 2 tsp lime juice, Vegenaise, and a pinch of salt. Mix the lime aioli well.","img":"064_2.jpg"},{"n":3,"title":null,"text":"Add the black beans, remaining minced garlic, ½ cup diced onion, garbanzo bean flour, zhoug seasoning, and ½ tsp salt to a large bowl. Mix with your hands, crushing the beans, until dough is sticky and uniform. Form dough into approximately six patties, each about 2 inches wide.","img":"064_3.jpg"},{"n":4,"title":null,"text":"Heat 2 tbsp vegetable oil to a large nonstick skillet over medium-high heat. Add black bean falafel and cook until crisp and heated through, 3 to 5 minutes per side.","img":"064_4.jpg"},{"n":5,"title":null,"text":"Add the baby spinach, remaining lime juice, 2 tsp olive oil, and a pinch of salt and pepper to a large bowl and toss. Halve the avocado, remove the pit, and thinly slice the flesh. Divide the baby spinach between bowls and top with black bean falafel, sliced cucumber, and sliced avocado. Drizzle with lime aioli. Dig in!","img":"064_5.jpg"}],"tips":["* This ingredient will be split between steps.","TIP: If you have a Microplane® grater, you can also use that to grate the garlic.","TIP: You can use a food processor for this step if you'd prefer.","TIP: Add more oil as necessary to crisp the falafel.","TIP: If you'd like, top with remaining diced onion.","Garbanzo Bean Flour: Are you cooking with garbanzo bean flour yet? If not, let us convince you to try it! This flour is packed with protein, fiber, and vitamins, plus it's gluten free. And while some gluten-free flours don't hold up when baked, garbanzo bean flour has a sturdy yet tender texture that's perfect for quick breads, muffins, and fritters. Make it a staple in your kitchen!"],"cuisine_tags":["Fusion","Middle Eastern"],"ingredient_tags":["avocado","black beans","cucumber","spinach"],"item_tags":["garbanzo bean flour","lime","vegenaise","zhoug"],"issues":null,"front":"064a_IMG_9261.jpg","back":"064b_IMG_9262.jpg","era":"binder","hero":"064.jpg"},{"pair":65,"title":"Gnocchi","subtitle":"with Dilly-Fried Cabbage & Apple Arugula Salad","servings":"2","cook_time":"30 min","nutrition":{"calories":"670","fat":"25 g","carbohydrates":"103 g","protein":"12 g"},"description":null,"from_your_kitchen":null,"ingredients":["1 onion","½ oz fresh dill","1 lemon*","1 apple","2 oz baby arugula","3 tbsp vegan butter","8 oz shredded cabbage","1 tsp smoked paprika","10 oz fresh gnocchi","¼ cup vegan sour cream"],"tools":null,"steps":[{"n":1,"title":null,"text":"Bring a large pot of salted water to a boil for the gnocchi. Peel and thinly slice the onion. Pick and chop the dill fronds. Halve and juice the lemon. Thinly slice the apple and add to a medium bowl with the baby arugula.","img":"065_1.jpg"},{"n":2,"title":null,"text":"Melt the butter in a large nonstick skillet over medium-high heat. Once melted, add sliced onion and cabbage and cook, stirring occasionally, until browned and softened, 5 to 7 minutes. Add smoked paprika and 1 tsp salt, stir, and reduce heat to low.","img":"065_2.jpg"},{"n":3,"title":null,"text":"Add the gnocchi to the boiling water and cook until they float to the surface, 3 to 4 minutes. Drain, and add boiled gnocchi to the skillet with the cabbage. Cook, stirring occasionally, until browned in places, 4 to 6 minutes.","img":"065_3.jpg"},{"n":4,"title":null,"text":"Add just half the chopped dill and a pinch of pepper to the gnocchi. Taste, and add salt and pepper as necessary. Add remaining chopped dill, just half the lemon juice, sour cream, and a pinch of salt to a small bowl and combine.","img":"065_4.jpg"},{"n":5,"title":null,"text":"Add 2 tsp olive oil, remaining lemon juice, and a pinch of salt and pepper to the apple arugula salad. Divide the gnocchi with dilly-fried cabbage between large plates and top with dill sour cream. Serve with apple arugula salad. Dig in!","img":"065_5.jpg"}],"tips":["* This ingredient will be split between steps.","TIP: The dill fronds are the wispy green leaves on the thick stems.","TIP: While cooking the vegetables, reduce heat as necessary to prevent burning.","Global Sensation: Cabbage is a big part of some of our favorite sides and condiments. Can you imagine a world without coleslaw, kimchi, or sauerkraut? Neither can we! We also love it fried, sautéed, and steamed. Bring on the cabbage! Not only is it tasty, it's also a nutrient powerhouse. A single serving of cabbage contains nearly half the recommended daily dose of Vitamin C, not to mention high levels of manganese, iron, vitamin B6, and fiber."],"cuisine_tags":["Comfort Food","Eastern European"],"ingredient_tags":["apple","arugula","cabbage","gnocchi"],"item_tags":["dill","lemon","smoked paprika","vegan butter","vegan sour cream"],"issues":null,"front":"065a_IMG_9263.jpg","back":"065b_IMG_9264.jpg","era":"binder","hero":"065.jpg"},{"pair":66,"title":"New England Lobster Rolls","subtitle":"with Hearts of Palm & Lemon Pepper Potato Wedges","servings":"2 (4)","cook_time":"30 (40) min","nutrition":{"calories":"420","fat":"20 g","carbohydrates":"57 g","protein":"9 g"},"description":null,"from_your_kitchen":null,"ingredients":["10 oz Yukon Gold potatoes","14 oz hearts of palm","1 tsp New England seasoning","1 shallot","1 celery stalk","¼ oz fresh dill","1 lemon*","¼ cup Follow Your Heart® Soy-Free Vegenaise®","2 tsp capers","2 hot dog buns"],"tools":null,"steps":[{"n":1,"title":null,"text":"Preheat the oven to 425°F. Slice Yukon Gold potatoes into ½ inch thick wedges and place on a baking sheet. Toss with 2 tsp (4 tsp) vegetable oil, a pinch of salt, and ¼ tsp (½ tsp) pepper. Roast potatoes wedges until crisp in places and lightly browned, 20 to 25 minutes.","img":"066_1.jpg"},{"n":2,"title":null,"text":"Drain the hearts of palm and pat dry with a clean kitchen towel. Transfer to a baking sheet and gently toss with 1 tsp (2 tsp) vegetable oil, New England seafood seasoning, and a pinch of salt and pepper. Place pieces cut side down and roast until lightly browned, 18 to 20 minutes.","img":"066_2.jpg"},{"n":3,"title":null,"text":"Peel and mince the shallot(s). Trim and thinly slice the celery. Finely chop dill fronds. Zest and halve the lemon(s), juice one half (1 lemon), and divide the other half (1 lemon) into wedges. Add minced shallot, sliced celery, chopped dill, just 1 tbsp (2 tbsp) lemon juice, Vegenaise, and capers to a large bowl. Mix the dill dressing. Taste, and add salt and pepper as necessary.","img":"066_3.jpg"},{"n":4,"title":null,"text":"Place a large nonstick skillet over medium-high heat. Brush the top of each hot dog bun with 1 tsp olive oil and place oiled-side down in the skillet to toast, 1 to 2 minutes.","img":"066_4.jpg"},{"n":5,"title":null,"text":"Add lemon zest to the roasted potato wedges and toss to coat. Add roasted hearts of palm to the dill dressing and gently toss until evenly coated. Divide mixture between the toasted hot dog buns. Serve the New England lobster rolls with lemon pepper potato wedges and lemon wedges on the side. Bon appétit!","img":"066_5.jpg"}],"tips":["* This ingredient will be split between steps.","TIP: You can also toast hot dog buns in the oven.","Sea Seasoning: Even when you're eating plant-based meals, there's just something about the allure of foods from the sea—especially in the summer! Our famous lobster rolls transform hearts of palm into something truly spectacular, with some help from New England seasoning. Made with salt, paprika, garlic, lemon peel, onion powder, red pepper, bay leaves, and mustard, this seasoning is light, sweet, and a little bit briny. Yum!"],"cuisine_tags":["American","New England"],"ingredient_tags":["celery","hearts of palm","hot dog buns","potato"],"item_tags":["capers","dill","lemon","new england seasoning","vegenaise"],"issues":null,"front":"066a_IMG_9265.jpg","back":"066b_IMG_9266.jpg","era":"binder","hero":"066.jpg"},{"pair":67,"title":"Kimchi Tofu Stew","subtitle":"with Bok Choy & Sticky Rice","servings":"2","cook_time":"25 min","nutrition":{"calories":"480","fat":"9 g","carbohydrates":"67 g","protein":"32 g"},"description":null,"from_your_kitchen":null,"ingredients":["½ cup sushi rice","10 oz Hodo® Organic Firm Tofu","2 scallions*","2 garlic cloves","1 oz fresh ginger","6 oz baby bok choy","1 Not-Chick'n™ Bouillon Cube","2 tbsp gluten-free gochujang","2 tbsp tamari","⅓ cup vegan cabbage kimchi"],"tools":null,"steps":[{"n":1,"title":null,"text":"Add the sushi rice, 1 cup water, and a pinch of salt to a small saucepan and bring to a boil. Cover, reduce heat to low, and cook until the grains are tender and water is absorbed, 15 to 18 minutes.","img":"067_1.jpg"},{"n":2,"title":null,"text":"Cut the tofu into 1 inch cubes. Thinly slice the scallions, separating the white and green parts. Peel and thinly slice the garlic. Peel and mince the ginger. Cut the baby bok choy in half lengthwise.","img":"067_2.jpg"},{"n":3,"title":null,"text":"Heat a large pot over medium-high heat with 1 tbsp vegetable oil. Add sliced scallion whites, sliced garlic, and minced ginger and cook, stirring frequently, 1 to 2 minutes. Add cubed tofu and cook until crispy, 4 to 5 minutes. Remove the crispy tofu from heat and set aside.","img":"067_3.jpg"},{"n":4,"title":null,"text":"Return pot to stove over medium-high heat and add the bouillon cube, gochujang, tamari, and 2 cups water, and whisk to combine. Bring to a boil, and reduce heat to a simmer. Add halved baby bok choy and simmer until bright green and tender, 3 to 5 minutes.","img":"067_4.jpg"},{"n":5,"title":null,"text":"Add kimchi to the pot and stir. Taste, and add salt and pepper as necessary. Divide the stew between large, shallow bowls, and top with crispy tofu. Top the kimchi tofu stew with bok choy with sliced scallion greens and serve with sticky rice. 잘 먹겠습니다, which means \"enjoy your meal\" in Korean!","img":"067_5.jpg"}],"tips":["* This ingredient will be split between steps.","TIP: For best results, rinse your sushi rice in a fine mesh strainer before cooking.","It's Soup Season! Yep, you heard us right! When you drink or eat foods that are hotter than your internal body temperature you trigger your body's eccrine glands, which release sweat to cool you down—making this a great meal to keep you cool this summer! BTW, this same thing happens when you eat spicy foods. So, no time like the present to eat some (spicy) soup!"],"cuisine_tags":["Korean"],"ingredient_tags":["bok choy","kimchi","rice","tofu"],"item_tags":["bouillon","ginger","gochujang","scallions","tamari"],"issues":null,"front":"067a_IMG_9267.jpg","back":"067b_IMG_9268.jpg","era":"binder","hero":"067.jpg"},{"pair":68,"title":"Sprouting Broccoli Salads","subtitle":"with Sunflower Seeds & Miso Power Dressing","servings":"2","cook_time":"30 min","nutrition":{"calories":"640","fat":"33 g","carbohydrates":"65 g","protein":"27 g"},"description":null,"from_your_kitchen":null,"ingredients":["¾ cup farro","2 garlic cloves","6 oz broccoli florets","6 oz Brussels sprouts","2 mini sweet peppers","2 oz Castelvetrano olives","1 lemon*","⅓ cup hemp seeds","1 tbsp white miso paste","¼ cup sunflower seeds"],"tools":null,"steps":[{"n":1,"title":null,"text":"Add the farro and a pinch of salt to a small saucepan and cover with 1 inch cold water. Bring to a boil, reduce heat to medium, and cook until farro is tender, 18 to 20 minutes. Drain farro and return to the saucepan, off heat.","img":"068_1.jpg"},{"n":2,"title":null,"text":"Peel and mince the garlic. Chop broccoli florets into bite-size pieces. Thinly slice Brussels sprouts. Trim and thinly slice mini sweet peppers into rounds. Check Castelvetrano olives and remove any pits. Halve the olives. Zest, halve, and juice the lemon.","img":"068_2.jpg"},{"n":3,"title":null,"text":"Heat 1 tbsp olive oil in a large skillet over medium-high heat. Add minced garlic, chopped broccoli florets, and a pinch of salt and pepper. Cook, tossing occasionally, until broccoli is lightly browned and crisp-tender, 4 to 6 minutes. Turn off the heat, add lemon zest, and toss.","img":"068_3.jpg"},{"n":4,"title":null,"text":"Add 2 tbsp lemon juice, hemp seeds, white miso paste, ¼ cup water, and 2 tbsp olive oil to a blender. Blend the miso power dressing on high until smooth. Taste, and add salt as necessary.","img":"068_4.jpg"},{"n":5,"title":null,"text":"Add the seared broccoli florets, sliced Brussels sprouts, 3 tbsp miso power dressing, and sunflower seeds to a large bowl. Toss the sprouting broccoli salad to combine.","img":"068_5.jpg"},{"n":6,"title":null,"text":"Divide the cooked farro between bowls and top with sprouting broccoli salad. Drizzle with remaining miso power dressing. Top with sliced mini sweet peppers and halved Castelvetrano olives. Bon appétit!","img":"068_6.jpg"}],"tips":["* This ingredient will be split between steps.","Substitute: radishes for mini sweet peppers"],"cuisine_tags":["Fusion","Mediterranean"],"ingredient_tags":["broccoli","brussels sprouts","farro"],"item_tags":["castelvetrano olives","hemp seeds","lemon","miso","sunflower seeds"],"issues":null,"front":"068a_IMG_9269.jpg","back":"068b_IMG_9270.jpg","era":"binder","hero":"068.jpg"},{"pair":69,"title":"Creamy Tahini Noodles","subtitle":"with Black Lentils & Crispy Shiitakes","servings":"2","cook_time":"35 min","nutrition":{"calories":"780","fat":"22 g","carbohydrates":"117 g","protein":"36 g"},"description":null,"from_your_kitchen":null,"ingredients":["½ cup beluga lentils","6 oz curly kale","6 oz shiitake mushrooms","2 garlic cloves","3 tbsp tahini","2 tbsp tamari","1 tsp agave","1 tbsp sesame oil","2 tbsp rice vinegar*","6 oz soba noodles","½ oz pea shoots"],"tools":null,"steps":[{"n":1,"title":null,"text":"Bring a large pot of salted water to boil. Rinse and sort the beluga lentils. In a small saucepan, combine the lentils and 1¼ cup water. Bring to a boil, and reduce heat to low. Cook, covered, until the lentils are tender, 20 to 25 minutes. Drain any remaining water.","img":"069_1.jpg"},{"n":2,"title":null,"text":"Destem the kale and thinly slice the leaves. Wipe the mushrooms clean with a damp kitchen towel, trim the stems, and thinly slice the caps. Peel and mince the garlic. In a medium bowl, whisk together the minced garlic, tahini, tamari, agave, sesame oil, just 1 tbsp rice vinegar, 2 tbsp hot water, and a pinch of salt. Mix the tahini sauce well.","img":"069_2.jpg"},{"n":3,"title":null,"text":"Heat a large nonstick skillet over medium-high heat with 1 tbsp vegetable oil. Add the sliced mushrooms and cook, stirring occasionally, until well browned, 5 to 6 minutes. Transfer to a paper towel-lined plate and sprinkle with salt.","img":"069_3.jpg"},{"n":4,"title":null,"text":"Once the water is boiling, add the soba noodles and gently stir. Cook until al dente, 2 to 3 minutes. Drain and run under cool water to stop the cooking process.","img":"069_4.jpg"},{"n":5,"title":null,"text":"Return the skillet to medium-high heat and add 1 tsp vegetable oil and the sliced kale. Cook until wilted, 2 to 3 minutes. Remove the skillet from heat and add the cooked soba noodles, just ¼ cup of the cooked lentils, and the tahini sauce, and stir well.","img":"069_5.jpg"},{"n":6,"title":null,"text":"Toss the pea shoots with the remaining rice vinegar and a pinch of salt, directly on the cutting board. Divide the creamy tahini noodles between large bowls and add the crispy shiitakes. Sprinkle with the remaining beluga lentils and pea shoots. Enjoy!","img":"069_6.jpg"}],"tips":["* This ingredient will be split between steps.","TIP: To \"sort\" means to look for and discard any naturally occurring debris or stones.","Substitute: another mushroom for shiitakes"],"cuisine_tags":["Fusion","Japanese"],"ingredient_tags":["kale","lentils","mushrooms","soba noodles"],"item_tags":["agave","pea shoots","rice vinegar","sesame oil","tahini","tamari"],"issues":null,"front":"069a_IMG_9271.jpg","back":"069b_IMG_9272.jpg","era":"binder","hero":"069.jpg"},{"pair":70,"title":"Chickpea Massaman Curry","subtitle":"with Farro & Baby Bok Choy","servings":"2 (4)","cook_time":"30 (40) min","nutrition":{"calories":"900","fat":"35 g","carbohydrates":"110 g","protein":"31 g"},"description":null,"from_your_kitchen":null,"ingredients":["¾ cup farro","1 red bell pepper","6 oz baby bok choy","2 carrots","13.4 oz chickpeas","1 tbsp massaman curry paste","11 oz coconut milk","4 tsp tamari","2 tsp turbinado sugar","1 lime*"],"tools":null,"steps":[{"n":1,"title":null,"text":"Add the farro and a pinch of salt to a medium saucepan, cover with 1 inch of water, and bring to a boil. Reduce heat to medium and cook until grains are tender, 18 to 20 minutes. Drain and return grains to the saucepan, off heat.","img":"070_1.jpg"},{"n":2,"title":null,"text":"Trim, deseed, and chop the red bell pepper(s) into 1 inch pieces. Trim and chop the baby bok choy into 2 inch pieces. Peel and thinly slice the carrots. Drain and rinse the chickpeas.","img":"070_2.jpg"},{"n":3,"title":null,"text":"Heat 1 tbsp (2 tbsp) vegetable oil in a large pot over medium-high heat. Add chopped red bell pepper, chopped baby bok choy, sliced carrot, and a pinch of salt and pepper. Cook until vegetables begin to soften, 3 to 5 minutes.","img":"070_3.jpg"},{"n":4,"title":null,"text":"Add the massaman curry paste and cook until fragrant, about 1 minute. Add chickpeas, coconut milk, tamari, turbinado sugar, and a pinch of salt. Bring the curry to a simmer and cook until chickpeas are warmed, 4 to 6 minutes.","img":"070_4.jpg"},{"n":5,"title":null,"text":"Halve the lime(s), juice one half (1 lime), and divide the other half (1 lime) into wedges. Remove curry from heat and add lime juice. Taste, and add salt as necessary.","img":"070_5.jpg"},{"n":6,"title":null,"text":"Divide the cooked farro between bowls. Top with chickpea massaman curry and serve with lime wedges. Bon appétit!","img":"070_6.jpg"}],"tips":["* This ingredient will be split between steps.","Substitute: any color bell pepper for red bell pepper"],"cuisine_tags":["Thai"],"ingredient_tags":["bell pepper","bok choy","carrot","chickpeas","farro"],"item_tags":["coconut milk","lime","massaman curry paste","tamari","turbinado sugar"],"issues":"Handwritten annotations on both cards: front adds '+ broccoli or zuchini' to ingredients; back notes a cooking order: 'carrots 1st, red pepper 2nd, broc. or zuch 3rd, bok choy 4th'.","front":"070a_IMG_9273.jpg","back":"070b_IMG_9274.jpg","era":"binder","hero":"070.jpg"},{"pair":71,"title":"Fiesta Enchilada Skillet","subtitle":"with Mole Black Beans & Avocado","servings":"2","cook_time":"30 min","nutrition":{"calories":"660","fat":"20 g","carbohydrates":"93 g","protein":"26 g"},"description":null,"from_your_kitchen":null,"ingredients":["1 onion","2 garlic cloves","1 zucchini","13.4 oz black beans","1 ear of corn","14.5 oz diced tomatoes","2 tsp Mexican mole spice blend","1 tsp ground cumin","2 corn tortillas","2 oz vegan mozzarella","1 avocado","1 lime"],"tools":null,"steps":[{"n":1,"title":null,"text":"Peel and dice the onion. Peel and mince the garlic. Trim and dice the zucchini. Drain and rinse the black beans. Cut the corn kernels off the cob.","img":"071_1.jpg"},{"n":2,"title":null,"text":"Heat 1 tbsp vegetable oil in a large oven-safe skillet over medium-high heat. Add diced onion, minced garlic, and a pinch of salt and pepper, and cook until softened, 3 to 5 minutes. Add diced zucchini, black beans, tomatoes, Mexican mole spice blend, cumin, and ¼ tsp salt, and cook until slightly thickened, 4 to 6 minutes.","img":"071_2.jpg"},{"n":3,"title":null,"text":"Thinly slice the corn tortillas into ¼ inch thick strips. Heat 2 tbsp vegetable oil in a small skillet over medium-high heat. Once hot, add tortilla strips and cook until lightly browned and crispy, 2 to 3 minutes. Transfer to a paper towel-lined plate and sprinkle with salt.","img":"071_3.jpg"},{"n":4,"title":null,"text":"Set the oven to broil on low. Add corn kernels to the skillet with the mole black beans and stir to combine. Top with mozzarella and place skillet in oven until cheese melts, 3 to 4 minutes.","img":"071_4.jpg"},{"n":5,"title":null,"text":"Halve the avocado, remove the pit, and slice the flesh. Halve the lime, juice one half, and divide the other half into wedges. Top the fiesta enchilada skillet with crispy tortillas, sliced avocado, and lime juice. Serve with lime wedges. Enjoy!","img":"071_5.jpg"}],"tips":["TIP: The oil should sizzle when you add the tortilla strips.","TIP: All broilers are different. Watch carefully to ensure cheese doesn't burn.","Substitute: yellow squash for zucchini"],"cuisine_tags":["Mexican"],"ingredient_tags":["avocado","black beans","corn","tortilla","zucchini"],"item_tags":["cumin","diced tomatoes","lime","mole spice blend","vegan mozzarella"],"issues":null,"front":"071a_IMG_9275.jpg","back":"071b_IMG_9276.jpg","era":"binder","hero":"071.jpg"},{"pair":72,"title":"Charred Pepper Ragout","subtitle":"with Rotini & Crispy Artichokes","servings":"2 (4)","cook_time":"35 (45) min","nutrition":{"calories":"480","fat":"3.5 g","carbohydrates":"39 g","protein":"19 g"},"description":null,"from_your_kitchen":null,"ingredients":["3 garlic cloves","1 red bell pepper","1 yellow bell pepper","1 red Fresno chile","4 oz grape tomatoes","13.75 oz artichoke hearts","6 oz dried rotini","1 tbsp vegan parmesan*"],"tools":null,"steps":[{"n":1,"title":null,"text":"Bring a large pot of salted water to boil for the pasta. Peel the garlic. Trim, deseed and chop the red bell pepper(s) and yellow bell pepper(s). Trim and roughly chop the red Fresno chile(s).","img":"072_1.jpg"},{"n":2,"title":null,"text":"Position a rack in the middle of the oven and set oven to broil on high. Place peeled garlic, chopped bell peppers, as much chopped red Fresno chile as you'd like, grape tomatoes, 2 tsp (4 tsp) olive oil, ½ tsp (1 tsp) salt, and ½ tsp (1 tsp) pepper on a baking sheet and toss to combine. Broil until peppers are charred and tender, 8 to 10 minutes.","img":"072_2.jpg"},{"n":3,"title":null,"text":"Drain and rinse the artichoke hearts. Add rotini to the boiling water and stir. Cook until al dente, 7 to 9 minutes. Reserve ½ cup (1 cup) pasta water and drain the pasta.","img":"072_3.jpg"},{"n":4,"title":null,"text":"Add the charred vegetables to a food processor and pulse until well chopped. Taste the charred pepper ragout and add salt and pepper as necessary. Place artichoke hearts on the baking sheet and add 1 tsp (2 tsp) olive oil and a pinch of salt and pepper. Broil until browned and crispy, 6 to 8 minutes.","img":"072_4.jpg"},{"n":5,"title":null,"text":"Return the large pot to medium heat. Set aside a quarter of the charred pepper ragout and bring the rest to a simmer in the pot. Add cooked rotini, reserved pasta water, and just 2 tsp (4 tsp) parmesan. Continue to cook until warmed, 3 to 5 minutes. Taste, and add salt and pepper as necessary.","img":"072_5.jpg"},{"n":6,"title":null,"text":"Divide the charred pepper ragout with rotini between large bowls. Top with crispy artichoke hearts and remaining charred pepper ragout. Sprinkle with remaining parmesan. Bon appétit!","img":"072_6.jpg"}],"tips":["TIP: If you prefer more garlic, add another clove.","TIP: All broilers are different. Watch carefully to ensure the vegetables don't burn. We'll also use this baking sheet again in step 4.","TIP: We will use this pot again in step 5.","* This ingredient will be split between steps","This item is spicy. (red Fresno chile)","Substitutes: any color bell pepper for yellow bell pepper; jalapeño for red Fresno chile"],"cuisine_tags":["Italian","Mediterranean"],"ingredient_tags":["artichokes","bell pepper","pasta","tomato"],"item_tags":["fresno chile","garlic","vegan parmesan"],"issues":null,"front":"072a_IMG_9277.jpg","back":"072b_IMG_9278.jpg","era":"binder","hero":"072.jpg"},{"pair":73,"title":"Summer Burgers","subtitle":"with Pickled Jalapeños & Barbecue Fries","servings":"2","cook_time":"30 min","nutrition":{"calories":"950","fat":"45 g","carbohydrates":"92 g","protein":"32 g"},"description":null,"from_your_kitchen":null,"ingredients":["1 red onion","2 russet potatoes","2 garlic cloves","1 tbsp BBQ seasoning","2 Lightlife™ Plant-Based Burgers","2 Field Roast® Chao Slices","2 potato buns","¼ cup Follow Your Heart® Soy-Free Vegenaise®","3.5 oz pickled jalapeños"],"tools":null,"steps":[{"n":1,"title":null,"text":"Preheat the oven to 425°F. Peel and slice the red onion into ½ inch thick rounds. Cut the russet potatoes into ½ inch thick wedges. Peel and mince the garlic.","img":"073_1.jpg"},{"n":2,"title":null,"text":"Place the onion rounds on a baking sheet and toss with 2 tsp vegetable oil and a pinch of salt and pepper. Push onion rounds to one side, and add the wedged potatoes, 2 tsp vegetable oil, BBQ seasoning, and a pinch of pepper to the other side of the baking sheet. Toss to coat. Roast until the barbecue fries are crispy and browned in places, 17 to 20 minutes.","img":"073_2.jpg"},{"n":3,"title":null,"text":"Heat 2 tsp vegetable oil in a large nonstick skillet over medium heat. Once hot, add the burgers and cook until well browned, 5 to 7 minutes per side. Remove burgers from heat, top with Chao slices, and cover until cheese melts, 3 to 5 minutes. Slice the potato buns and toast directly on the oven rack, 3 to 5 minutes.","img":"073_3.jpg"},{"n":4,"title":null,"text":"Add the minced garlic, Vegenaise, and a pinch of salt and pepper to a small bowl. Mix the garlic aioli until combined.","img":"073_4.jpg"},{"n":5,"title":null,"text":"Spread some garlic aioli on the toasted potato buns. Top with the burgers, roasted onions, and jalapeños. Serve with barbecue fries and any remaining garlic aioli for dipping. Dig in!","img":"073_5.jpg"}],"tips":["TIP: Try to keep onion rounds intact to allow for even roasting.","TIP: If you prefer, you can also grill the burgers on medium heat for 5 to 7 minutes per side.","This item is spicy. (pickled jalapeños)"],"cuisine_tags":["American","Comfort Food"],"ingredient_tags":["plant-based burger","potato","red onion"],"item_tags":["bbq seasoning","garlic","pickled jalapeños","vegan cheese","vegenaise"],"issues":null,"front":"073a_IMG_9279.jpg","back":"073b_IMG_9280.jpg","era":"binder","hero":"073.jpg"},{"pair":74,"title":"Spicy Red Curry Coconut Noodles","subtitle":"with Bok Choy & Carrots","servings":"2 (4)","cook_time":"25 (35) min","nutrition":{"calories":"550","fat":"16 g","carbohydrates":"91 g","protein":"13 g"},"description":null,"from_your_kitchen":null,"ingredients":["2 carrots","1 shallot","1 oz fresh ginger","1 garlic clove","6 oz baby bok choy","2 tbsp red curry paste","5.5 oz coconut milk","1 tsp turbinado sugar","6 oz udon","¼ oz fresh mint","1 lime"],"tools":null,"steps":[{"n":1,"title":null,"text":"Bring a large pot of salted water to a boil for the udon. Peel the carrots, and continue to peel lengthwise to create \"noodles.\" Peel and thinly slice the shallot(s). Chop the unpeeled ginger into large pieces. Peel and thinly slice the garlic. Trim and thinly slice the baby bok choy.","img":"074_1.jpg"},{"n":2,"title":null,"text":"Heat 1 tsp (2 tsp) vegetable oil in a medium saucepan over medium heat. Add sliced shallot, chopped ginger, and sliced garlic. Cook until ginger and garlic are slightly toasted, 1 to 2 minutes. Add red curry paste, coconut milk, turbinado sugar, and ½ cup (1 cup) water. Bring broth to a boil, reduce heat to low, and simmer until ready to serve.","img":"074_2.jpg"},{"n":3,"title":null,"text":"Once the water is boiling, add udon and cook until al dente, 8 to 10 minutes.","img":"074_3.jpg"},{"n":4,"title":null,"text":"Pick the mint leaves. Halve and juice the lime(s). Remove ginger from the broth and add sliced baby bok choy. Add ½ tsp (1 tsp) salt and let broth continue to simmer for about 1 minute. Remove saucepan from heat and add the lime juice.","img":"074_4.jpg"},{"n":5,"title":null,"text":"Divide cooked udon and carrot \"noodles\" between bowls and top with spicy red curry coconut broth. Sprinkle with mint leaves. Enjoy!","img":"074_5.jpg"}],"tips":["TIP: Cut the ginger into large pieces so that it will be easier to remove later.","This item is spicy. (red curry paste)","Substitutes: another herb for fresh mint, baby spinach for bok choy"],"cuisine_tags":["Thai"],"ingredient_tags":["bok choy","carrot","noodles","udon"],"item_tags":["coconut milk","ginger","lime","mint","red curry paste","turbinado sugar"],"issues":null,"front":"074a_IMG_9281.jpg","back":"074b_IMG_9282.jpg","era":"binder","hero":"074.jpg"},{"pair":75,"title":"Spicy Almond Butter Noodles","subtitle":"with Gai Lan & Yellow Squash","servings":"2 (4)","cook_time":"35 (45) min","nutrition":{"calories":"650","fat":"29 g","carbohydrates":"82 g","protein":"22 g"},"description":null,"from_your_kitchen":null,"ingredients":["6 oz gai lan","1 yellow squash","2 scallions","1 garlic clove","1 lime*","¼ cup + 2 tbsp peanuts*","3 tbsp almond butter","2 tbsp tamari","1 tsp turbinado sugar","1 tbsp chile garlic sauce","6 oz udon"],"tools":null,"steps":[{"n":1,"title":null,"text":"Bring a large pot of salted water to boil for the udon. Trim the gai lan, roughly chop the leaves, and thinly slice the stems. Slice yellow squash(es) into rounds. Thinly slice the scallions. Peel the garlic. Halve the lime(s), juice one half (1 lime), and cut the other half (1 lime) into wedges.","img":"075_1.jpg"},{"n":2,"title":null,"text":"Place a large nonstick skillet over medium-low heat and add all the peanuts. Toast until fragrant, 3 to 4 minutes, and transfer to a bowl. Add garlic, lime juice, almond butter, tamari, turbinado sugar, chile garlic sauce, ½ cup (1 cup) water, and a pinch of salt to a blender. Blend almond butter sauce on high until smooth. Add just ¼ cup (½ cup) toasted peanuts and pulse to combine.","img":"075_2.jpg"},{"n":3,"title":null,"text":"Once the water is boiling, add udon and gently stir. Cook until al dente, 6 to 8 minutes. Drain udon and run under cold water to stop the cooking process.","img":"075_3.jpg"},{"n":4,"title":null,"text":"Return skillet to medium-high heat with 2 tsp (4 tsp) vegetable oil. Add chopped gai lan leaves and sliced gai lan stems, sliced yellow squash, and a pinch of salt. Cook until gai lan is bright green and tender, 3 to 5 minutes. Reduce heat to low, add spicy almond butter sauce, and bring to a simmer.","img":"075_4.jpg"},{"n":5,"title":null,"text":"Add the cooked udon and half the sliced scallions to the skillet with the vegetables, and stir. Taste, and add salt as necessary. Divide spicy almond butter noodles between bowls and top with remaining toasted peanuts and remaining sliced scallions. Serve with lime wedges. Dig in!","img":"075_5.jpg"}],"tips":["TIP: The peanuts are added last, and pulsed instead of blended, to give the sauce texture.","* These ingredients will be split between steps","This item is spicy. (chile garlic sauce)","Substitutes: bok choy for gai lan, zucchini for yellow squash"],"cuisine_tags":["Chinese","Fusion","Thai"],"ingredient_tags":["gai lan","noodles","peanuts","udon","yellow squash"],"item_tags":["almond butter","chile garlic sauce","lime","scallions","tamari","turbinado sugar"],"issues":null,"front":"075a_IMG_9283.jpg","back":"075b_IMG_9284.jpg","era":"binder","hero":"075.jpg"},{"pair":76,"title":"Gnocchi Al Pesto","subtitle":"with Charred Green Beans & Lemon Zucchini","servings":"2 (4)","cook_time":"30 (40) min","nutrition":{"calories":"510","fat":"14 g","carbohydrates":"83 g","protein":"12 g"},"description":null,"from_your_kitchen":null,"ingredients":["6 oz green beans","1 zucchini","1 lemon*","1 tsp Aleppo pepper flakes","10 oz fresh gnocchi","¼ cup vegan basil pesto"],"tools":null,"steps":[{"n":1,"title":null,"text":"Bring a large pot of salted water to a boil for the gnocchi. Cut green beans in half. Trim the zucchini(s) and peel lengthwise to make ribbons. Halve the lemon(s), juice one half (1 lemon), and cut the other half (1 lemon) into wedges.","img":"076_1.jpg"},{"n":2,"title":null,"text":"Add the zucchini ribbons, lemon juice, Aleppo pepper flakes, and a pinch of salt to a medium bowl. Toss to combine.","img":"076_2.jpg"},{"n":3,"title":null,"text":"Heat 2 tsp (4 tsp) olive oil in a large nonstick skillet over medium-high heat. Add halved green beans and cook until browned in places, 3 to 4 minutes. Add ¼ cup (½ cup) water and reduce heat to low. Cook green beans until crisp-tender, another 2 to 3 minutes. Sprinkle charred green beans with salt and pepper, and transfer to a bowl.","img":"076_3.jpg"},{"n":4,"title":null,"text":"Add the gnocchi to the large pot of boiling water and cook until they float to the surface, 3 to 5 minutes. Drain gnocchi and shake off any excess water.","img":"076_4.jpg"},{"n":5,"title":null,"text":"Return skillet to medium heat with 1 tbsp (2 tbsp) olive oil. Add cooked gnocchi and sauté, undisturbed, until browned in places, 2 to 4 minutes. Return charred green beans to the skillet along with the basil pesto and toss to combine. Sprinkle gnocchi with salt and pepper.","img":"076_5.jpg"},{"n":6,"title":null,"text":"Divide the gnocchi al pesto with charred green beans between shallow bowls. Serve with lemon zucchini and lemon wedges. Mangia!","img":"076_6.jpg"}],"tips":["TIP: We will reuse this skillet in a later step.","TIP: If the pesto is too thick, add 1 tablespoon warm water (or more, if necessary), to create a thinner consistency.","* This ingredient will be split between steps","This item is spicy. (Aleppo pepper flakes)","Substitutes: broccoli for green beans, yellow squash for zucchini"],"cuisine_tags":["Italian"],"ingredient_tags":["gnocchi","green beans","zucchini"],"item_tags":["aleppo pepper","lemon","vegan basil pesto"],"issues":null,"front":"076a_IMG_9285.jpg","back":"076b_IMG_9286.jpg","era":"binder","hero":"076.jpg"},{"pair":77,"title":"Spring Vegetable Gnocchi","subtitle":"with White Beans & Lemon Basil Butter","servings":"2","cook_time":"40 min","nutrition":{"calories":"740","fat":"18 g","carbohydrates":"104 g","protein":"22 g"},"description":null,"from_your_kitchen":null,"ingredients":["2 garlic cloves","1 shallot","2 carrots","4 oz asparagus","½ oz fresh basil*","1 lemon*","13.4 oz butter beans","10 oz fresh gnocchi","3 tbsp vegan butter","2 tbsp soy-free vegan parmesan"],"tools":null,"steps":[{"n":1,"title":null,"text":"Bring a large pot with 4 quarts water and 2 tbsp salt to a boil. Peel and mince the garlic and shallot. Peel and dice the carrots. Trim 1 inch off the asparagus and cut the remaining stalks into rounds. Thinly slice the basil. Zest, halve, and juice the lemon. Drain and rinse the butter beans.","img":"077_1.jpg"},{"n":2,"title":null,"text":"Heat 1 tbsp olive oil in a large nonstick skillet over medium-high heat. Add the minced garlic, minced shallot, diced carrot, and a pinch of salt and pepper. Cook, stirring often, until the carrots are tender, 5 to 6 minutes.","img":"077_2.jpg"},{"n":3,"title":null,"text":"Add the gnocchi to the large pot of boiling water and cook until they float to the surface, 3 to 5 minutes. Reserve ½ cup of the pasta water and drain the gnocchi. Shake off any excess water.","img":"077_3.jpg"},{"n":4,"title":null,"text":"Return the skillet with the carrots to medium-high heat and add the pasta water and butter and cook until melted, 1 to 2 minutes. Add the asparagus rounds and cook until bright green, 2 to 3 minutes. Add the lemon juice and just half of the basil, taste, and add salt and pepper as necessary. Transfer the spring vegetables and lemon basil butter to a medium bowl and cover to keep warm.","img":"077_4.jpg"},{"n":5,"title":null,"text":"Wipe the skillet and return to high heat with 1 tbsp olive oil. Once hot, add the butter beans, cooked gnocchi, ½ tsp salt, and ¼ tsp pepper. Cook, undisturbed, until well browned, 3 to 4 minutes. Sprinkle with lemon zest and parmesan, toss, and cook for another 2 minutes.","img":"077_5.jpg"},{"n":6,"title":null,"text":"Divide the spring vegetables and lemon basil butter between bowls and top with the gnocchi and butter beans. Sprinkle with the remaining sliced basil. Enjoy!","img":"077_6.jpg"}],"tips":["* These ingredients will be split between steps."],"cuisine_tags":["Italian"],"ingredient_tags":["asparagus","butter beans","carrot","gnocchi"],"item_tags":["basil","lemon","shallot","vegan butter","vegan parmesan"],"issues":null,"front":"077a_IMG_9287.jpg","back":"077b_IMG_9288.jpg","era":"binder","hero":"077.jpg"},{"pair":78,"title":"Green Goddess Vegetable Pilaf","subtitle":"with Asparagus & Herbed Ranch Dressing","servings":"2 (4)","cook_time":"25 (35) min","nutrition":{"calories":"580","fat":"33 g","carbohydrates":"63 g","protein":"13 g"},"description":null,"from_your_kitchen":null,"ingredients":["½ cup basmati rice","4 oz sugar snap peas","3 scallions","1 cucumber","6 oz asparagus","¼ oz fresh mint","1 avocado","1 lemon*","2 tsp dried parsley flakes","¼ cup Follow Your Heart® High Omega Vegan Ranch Salad Dressing","¼ cup pistachios"],"tools":null,"steps":[{"n":1,"title":null,"text":"Add the basmati rice, 1 cup (2 cups) water, and a pinch of salt to a small saucepan and bring to a boil. Cover, reduce heat to low, and cook until water is absorbed, 13 to 15 minutes.","img":"078_1.jpg"},{"n":2,"title":null,"text":"Thinly slice the sugar snap peas. Thinly slice the scallions. Dice the cucumber(s). Trim about 1 inch off the ends of the asparagus. Pick and roughly chop the mint leaves. Halve the avocado(s), remove the pit(s), and thinly slice the flesh. Halve and juice the lemon(s). Add just 1 tbsp (2 tbsp) lemon juice, the dried parsley, the ranch dressing, and a pinch of pepper to a small bowl. Stir the herbed ranch dressing.","img":"078_2.jpg"},{"n":3,"title":null,"text":"Heat a large skillet with 2 tsp (4 tsp) olive oil over medium-high heat. Add the asparagus and let cook, undisturbed, until charred in places, 2 to 4 minutes. Sprinkle with salt and pepper, toss, and cook until crisp-tender, another 1 to 2 minutes.","img":"078_3.jpg"},{"n":4,"title":null,"text":"Fluff the cooked basmati rice and transfer to a large bowl. Add the sliced snap peas, sliced scallions, diced cucumber, chopped mint leaves, pistachios, remaining lemon juice, and 2 tsp (4 tsp) olive oil and gently toss the vegetable pilaf to combine. Taste, and add salt and pepper as necessary.","img":"078_4.jpg"},{"n":5,"title":null,"text":"Divide the vegetable pilaf between large plates and top with cooked asparagus and sliced avocado. Drizzle the green goddess vegetable pilaf with herbed ranch dressing. Bon appétit!","img":"078_5.jpg"}],"tips":["* This ingredient will be split between steps.","Substitute: another herb for fresh mint"],"cuisine_tags":["American","Mediterranean"],"ingredient_tags":["asparagus","avocado","cucumber","rice","sugar snap peas"],"item_tags":["lemon","mint","parsley","pistachios","vegan ranch dressing"],"issues":null,"front":"078a_IMG_9289.jpg","back":"078b_IMG_9290.jpg","era":"binder","hero":"078.jpg"},{"pair":79,"title":"Crispy Cauliflower Pakoras","subtitle":"with Red Lentil Dal & Cilantro Chutney","servings":"2","cook_time":"35 min","nutrition":{"calories":"590","fat":"19 g","carbohydrates":"84 g","protein":"26 g"},"description":null,"from_your_kitchen":null,"ingredients":["1 onion","1 oz fresh ginger","3 garlic cloves*","6 oz broccoli florets","4 oz cauliflower florets","2 mini sweet peppers","¼ cup white vinegar","2 tsp turbinado sugar","½ cup red lentils","1 tsp curry powder","5.5 oz coconut milk","¾ cup garbanzo bean flour","1 tsp garam masala","¼ cup cilantro chutney"],"tools":null,"steps":[{"n":1,"title":null,"text":"Peel and dice the onion. Peel and mince the ginger and garlic. Chop the broccoli and cauliflower into bite-size pieces. Thinly slice the mini sweet peppers. Add the vinegar, sugar, and a pinch of salt to a medium bowl and whisk until the sugar is dissolved. Add the sliced peppers and toss to combine.","img":"079_1.jpg"},{"n":2,"title":null,"text":"Rinse and sort the red lentils. Heat a small saucepan with 1 tbsp vegetable oil over medium heat. Add the diced onion, minced ginger, just half the minced garlic, and a pinch of salt. Cook, stirring frequently, until the onion softens, 3 to 4 minutes.","img":"079_2.jpg"},{"n":3,"title":null,"text":"Add the curry powder to the saucepan, stir, and cook until fragrant, about 1 minute. Add the red lentils, coconut milk, and ¾ cup water, and bring to a boil. Cover, reduce heat to low, and cook until the lentils are tender and water is absorbed, 12 to 15 minutes.","img":"079_3.jpg"},{"n":4,"title":null,"text":"Whisk the remaining minced garlic, garbanzo bean flour, garam masala, ½ cup cold water, and ¼ tsp salt in a large bowl.","img":"079_4.jpg"},{"n":5,"title":null,"text":"Heat a medium skillet with ½ cup vegetable oil over medium-high heat. Once the oil is hot, toss the chopped broccoli florets and chopped cauliflower florets in the batter, remove, and place in the oil without overcrowding the skillet. Cook until lightly browned, 2 to 3 minutes per side. Transfer to a paper towel-lined plate and sprinkle with salt.","img":"079_5.jpg"},{"n":6,"title":null,"text":"Divide the red lentil dal between serving dishes and top with crispy cauliflower pakoras and pickled peppers. Drizzle with cilantro chutney. Enjoy!","img":"079_6.jpg"}],"tips":["TIP: To \"sort\" means to look for and discard any naturally occurring debris or stones.","TIP: Work in batches to avoid overcrowding.","* This ingredient will be split between steps.","Substitute: radishes for mini sweet peppers","Handwritten note — cilantro chutney: 1 bunch cilantro, 1 lime, ¼ tspn sugar, 2-3 thai chilis, pinch salt. Blend using mortar & pestle."],"cuisine_tags":["Indian"],"ingredient_tags":["broccoli","cauliflower","red lentils"],"item_tags":["cilantro chutney","coconut milk","curry powder","garam masala","garbanzo bean flour","ginger","white vinegar"],"issues":null,"front":"079a_IMG_9291.jpg","back":"079b_IMG_9292.jpg","era":"binder","hero":"079.jpg"},{"pair":80,"title":"Potato Malai Kofta","subtitle":"with Sautéed Spinach & Tomato Chutney","servings":"2 (4)","cook_time":"30 (45) min","nutrition":{"calories":"480","fat":"16 g","carbohydrates":"74 g","protein":"13 g"},"description":null,"from_your_kitchen":null,"ingredients":["1 russet potato","1 onion","2 garlic cloves","1 oz fresh ginger","1 carrot","¼ cup green peas","2 tbsp tomato powder","1 tsp curry powder","5.5 oz coconut milk","¼ cup garbanzo bean flour","4 oz baby spinach","¼ cup tomato chutney"],"tools":null,"steps":[{"n":1,"title":null,"text":"Peel and dice the potato into bite-size pieces. Add the diced potato to a medium saucepan and cover with 1 inch salted water. Bring to a boil and cook until fork-tender, 10 to 12 minutes.","img":"080_1.jpg"},{"n":2,"title":null,"text":"Peel and chop the onion(s). Peel and slice the garlic. Peel and mince 2 tsp (4 tsp) ginger. Peel and grate the carrot(s) on the largest side of a box grater. Once the potatoes are fork-tender, add the grated carrot and green peas to the saucepan with the potatoes and cook for 1 minute. Drain potato and carrot mixture and transfer to a large bowl.","img":"080_2.jpg"},{"n":3,"title":null,"text":"Return the empty saucepan to medium heat with 2 tsp (4 tsp) olive oil. Add the chopped onion, sliced garlic, and minced ginger. Cook until the vegetables are softened, 3 to 5 minutes. Add the tomato powder, curry powder, coconut milk, and ½ tsp (1 tsp) salt, and bring sauce to a simmer. Cook until malai sauce is slightly thickened, 2 to 3 minutes.","img":"080_3.jpg"},{"n":4,"title":null,"text":"Add the garbanzo bean flour and ¼ tsp (½ tsp) salt to the large bowl with the potato and carrot mixture, and lightly mash until there are only a few lumps. Form the potato kofta mixture into 6 (12) patties about 1 inch thick.","img":"080_4.jpg"},{"n":5,"title":null,"text":"Heat a large nonstick skillet over medium-high heat with 2 tbsp olive oil. Add the potato kofta and cook until browned and crisp, 1 to 2 minutes per side. Transfer the seared potato kofta to a plate.","img":"080_5.jpg"},{"n":6,"title":null,"text":"Return the skillet to medium heat with 1 tsp (2 tsp) olive oil. Once hot, add the spinach and a sprinkle of salt and pepper. Cook until wilted, 2 to 3 minutes. Transfer the malai sauce to a blender and blend on low until smooth. Divide the malai sauce between plates and top with sautéed spinach and potato kofta. Serve with tomato chutney for dipping. Enjoy!","img":"080_6.jpg"}],"tips":["TIP: Don't drain the potatoes yet because we'll add vegetables in step 2.","TIP: If you're making the 4 serving recipe, cook the kofta in batches.","TIP: Vent blender (by removing the plastic center of lid) to avoid splashing.","Substitute: another green for baby spinach"],"cuisine_tags":["Indian"],"ingredient_tags":["carrot","peas","potato","spinach"],"item_tags":["coconut milk","curry powder","garbanzo bean flour","ginger","tomato chutney","tomato powder"],"issues":null,"front":"080a_IMG_9293.jpg","back":"080b_IMG_9294.jpg","era":"binder","hero":"080.jpg"},{"pair":81,"title":"Eggplant Parmesan","subtitle":"with Garlicky Tomato Sauce & Lemon Basil Couscous","servings":"2","cook_time":"40 min","nutrition":{"calories":"460","fat":"4.5 g","carbohydrates":"94 g","protein":"14 g"},"description":null,"from_your_kitchen":null,"ingredients":["1 eggplant","1 shallot","4 garlic cloves*","1 lemon*","1 oz fresh basil*","1 oz vegan shredded mozzarella","¼ cup panko breadcrumbs","2 tsp Italian seasoning","14.5 oz fire roasted diced tomatoes","1 cup Israeli couscous"],"tools":null,"steps":[{"n":1,"title":null,"text":"Preheat oven to 425°F. Trim the eggplant and cut lengthwise into 4 planks. Place on a baking sheet and toss with 1 tbsp olive oil and a pinch of salt and pepper. Bake until lightly browned on each side, flipping halfway through, 15 to 20 minutes.","img":"081_1.jpg"},{"n":2,"title":null,"text":"Peel and mince the shallot and garlic. Zest and halve the lemon; juice one half and cut the other half into wedges. Pick and tear the basil leaves. Add just half the minced garlic, mozzarella, breadcrumbs, and 2 tsp olive oil to a small bowl. Toss to combine.","img":"081_2.jpg"},{"n":3,"title":null,"text":"Heat a medium saucepan over medium-high heat with 1 tbsp olive oil. Add the minced shallot, remaining minced garlic, and Italian seasoning. Cook until fragrant, 2 to 3 minutes. Add the tomatoes, ¼ tsp salt, and a pinch of pepper, and reduce heat to medium-low. Simmer until slightly thickened, 5 to 7 minutes.","img":"081_3.jpg"},{"n":4,"title":null,"text":"Add 1¼ cups water and a pinch of salt to a small saucepan and bring to a boil over high heat. Add the Israeli couscous, reduce heat to low, cover, and cook until water is absorbed, about 10 minutes. Add the lemon zest, lemon juice, just half the torn basil, 2 tsp olive oil, and a pinch of salt and pepper. Stir the lemon basil couscous to combine.","img":"081_4.jpg"},{"n":5,"title":null,"text":"Remove the baked eggplant from the oven and top with garlicky tomato sauce and breadcrumb mixture. Return to the oven and bake until breadcrumbs are golden brown, 4 to 6 minutes.","img":"081_5.jpg"},{"n":6,"title":null,"text":"Divide the lemon basil couscous between bowls and top with eggplant parmesan. Sprinkle with the remaining torn basil and serve with lemon wedges. Tuck in!","img":"081_6.jpg"}],"tips":["* These ingredients will be split between steps.","Substitute: another herb for fresh basil"],"cuisine_tags":["Italian","Mediterranean"],"ingredient_tags":["basil","couscous","eggplant","tomato"],"item_tags":["fire roasted tomatoes","italian seasoning","lemon","panko breadcrumbs","vegan mozzarella"],"issues":null,"front":"081a_IMG_9295.jpg","back":"081b_IMG_9296.jpg","era":"binder","hero":"081.jpg"},{"pair":82,"title":"Roasted Sweet Potatoes","subtitle":"with Spicy Cashew Sauce & Kraut","servings":"2 (4)","cook_time":"35 (40) min","nutrition":{"calories":"460","fat":"14 g","carbohydrates":"80 g","protein":"14 g"},"description":null,"from_your_kitchen":null,"ingredients":["2 sweet potatoes","2 garlic cloves","½ cup cashews*","2 tbsp rice vinegar","2 tsp agave","1 tsp tamari","1 tsp Aleppo pepper","8 oz Swiss chard","1 lime*","1 Thai chile","4 oz sauerkraut"],"tools":null,"steps":[{"n":1,"title":null,"text":"Preheat the oven to 425°F. Halve the sweet potatoes lengthwise and transfer to a baking sheet. Rub halved sweet potatoes with 2 tsp (4 tsp) vegetable oil, sprinkle with salt and pepper, and bake cut-side down until tender, 22 to 26 minutes.","img":"082_1.jpg"},{"n":2,"title":null,"text":"Peel the garlic and add to a blender. Measure just ⅓ cup (⅔ cup) cashews and add to the blender along with the rice vinegar, agave, tamari, Aleppo pepper, 2 tbsp (4 tbsp) olive oil, and 3 tbsp (4 tbsp) warm water. Blend spicy cashew sauce until smooth. Taste, and add salt as necessary.","img":"082_2.jpg"},{"n":3,"title":null,"text":"Thinly slice the Swiss chard stems and roughly chop the leaves. Halve the lime(s), juice one half (1 lime), and cut one half (1 lime) into wedges. Thinly slice the Thai chile(s). Place remaining cashews in a large nonstick skillet over medium heat and toast, 3 to 4 minutes. Transfer toasted cashews to a cutting board and roughly chop.","img":"082_3.jpg"},{"n":4,"title":null,"text":"When the sweet potatoes are done, heat the skillet over medium-high heat with 1 tsp (2 tsp) olive oil. Add the chopped Swiss chard leaves and sliced stems, and cook until just wilted, 2 to 3 minutes. Add the lime juice and a pinch of salt.","img":"082_4.jpg"},{"n":5,"title":null,"text":"Divide the sautéed Swiss chard between large plates. Top with roasted sweet potatoes and sauerkraut. Drizzle everything with spicy cashew sauce and sprinkle with toasted cashews and sliced Thai chile. Serve with lime wedges. Tuck in!","img":"082_5.jpg"}],"tips":["* These ingredients will be split between steps.","These items are spicy. (Aleppo pepper, Thai chile)","TIP: If you prefer more garlic, add another clove.","TIP: Be sure to wash your hands after preparing the chile(s).","Time for Kraut: Sauerkraut is experiencing a bit of a renaissance. Made from fermented cabbage and spices, it has a slightly sour taste which makes it the perfect foil for foods like sweet potatoes. But kraut is more than a tasty condiment: It has numerous health benefits, too! It's chock-full of healthy probiotics, fiber, and iron, plus it has a significant amount of Vitamin A."],"cuisine_tags":["American","Fusion"],"ingredient_tags":["cashews","sauerkraut","sweet potato","swiss chard"],"item_tags":["agave","aleppo pepper","lime","rice vinegar","sauerkraut","tamari","thai chile"],"issues":null,"front":"082a_IMG_9297.jpg","back":"082b_IMG_9298.jpg","era":"binder","hero":"082.jpg"},{"pair":83,"title":"Caribbean Sweet Potatoes","subtitle":"with Coconut Rice & Mango Salsa","servings":"2 (4)","cook_time":"35 (45) min","nutrition":{"calories":"780","fat":"16 g","carbohydrates":"6 g","protein":"25 g"},"description":null,"from_your_kitchen":null,"ingredients":["1 sweet potato","1 tbsp jerk seasoning","1 red onion*","2 garlic cloves*","1 mango","½ oz fresh parsley","1 lime*","13.4 oz kidney beans","½ cup basmati rice","5.5 oz coconut milk"],"tools":null,"steps":[{"n":1,"title":null,"text":"Preheat the oven to 425°F. Cut the sweet potato(es) into 1 inch thick wedges. Transfer to a baking sheet and toss with 2 tsp (4 tsp) vegetable oil, jerk seasoning, and a pinch of salt and pepper. Bake until tender and browned in spots, 18 to 22 minutes.","img":"083_1.jpg"},{"n":2,"title":null,"text":"Peel and mince the red onion(s). Peel and mince the garlic. Peel the mango(es), cut the flesh away from the pit, and dice. Finely chop the parsley leaves. Zest and halve the lime(s), juice one half (1 lime), and cut one half (1 lime) into wedges. Drain and rinse the kidney beans.","img":"083_2.jpg"},{"n":3,"title":null,"text":"Heat a small saucepan over medium-high with 1 tsp (2 tsp) vegetable oil. Once hot, add just half the minced red onion and just half the minced garlic. Cook until softened, 3 to 5 minutes.","img":"083_3.jpg"},{"n":4,"title":null,"text":"Add the basmati rice, coconut milk, ½ tsp (1 tsp) salt, and ⅓ cup (⅔) water to the saucepan and bring to a boil. Reduce heat to low, cover, and cook until the water is absorbed, 12 to 15 minutes.","img":"083_4.jpg"},{"n":5,"title":null,"text":"Add the remaining minced red onion, remaining minced garlic, diced mango, chopped parsley, half the lime juice, ¼ tsp (½ tsp) salt, and a pinch of pepper to a large bowl. Toss the mango salsa to combine.","img":"083_5.jpg"},{"n":6,"title":null,"text":"Stir the lime zest and kidney beans into the coconut rice, and divide between large, shallow bowls. Top with the Caribbean sweet potatoes and mango salsa. Serve with lime wedges. Tuck in!","img":"083_6.jpg"}],"tips":["* These ingredients will be split between steps.","Substitute: another herb for fresh parsley"],"cuisine_tags":["Caribbean"],"ingredient_tags":["kidney beans","mango","rice","sweet potato"],"item_tags":["coconut milk","jerk seasoning","lime","parsley"],"issues":"Front card nutrition line prints 'Carbohydrates: 6 g' which appears to be a misprint (back card panel shows 63 g); also back card sidebar nutrition (910 cal, 69 g fat) belongs to an adjacent recipe column, front card values used.","front":"083a_IMG_9299.jpg","back":"083b_IMG_9300.jpg","era":"binder","hero":"083.jpg"},{"pair":84,"title":"Greek-Style Cauliflower Steaks","subtitle":"with Tzatziki Sauce and Mashed Yams","servings":"2","cook_time":"35 minutes","nutrition":{"calories":"910","fat":"69 g","carbohydrates":"63 g","protein":"21 g"},"description":"Little touches of vinegar and garlic give mashed yams a depth of flavor similar to Greek skordalia, a delicious potato spread. While it's traditionally eaten with pita, you'll instead pair this vitamin-packed base with cauliflower steaks and zesty tzatziki sauce. Bright, fresh vegetables give the dish a pop of color and a delicious crunch.","from_your_kitchen":["1 tbsp olive oil","Salt and pepper"],"ingredients":["1 head cauliflower","8 oz Japanese yam","1 cucumber","Fresh dill","¼ cup Follow Your Heart® Vegenaise®","1 lemon","¼ cup pumpkin seeds","¼ cup kalamata olives","2 oz radish","1 clove garlic°","1 tbsp white vinegar","1 tbsp hemp seeds"],"tools":["Baking sheet","Small saucepan","Box grater","Small skillet"],"steps":[{"n":1,"title":"PREPARE THE CAULIFLOWER","text":"Set your oven to broil on high. Trim the leaves and about 1 inch of the stem off the cauliflower, leaving the whole head intact if possible. Slice the cauliflower, from the top down, into 1 inch thick steaks. On a baking sheet gently coat the steaks in 1 tbsp olive oil and season with salt and pepper. Place on the middle rack and broil until well-browned, about 18 to 24 minutes.","img":"084_1.jpg"},{"n":2,"title":"COOK THE JAPANESE YAM","text":"Peel the Japanese yam and chop into large pieces. Transfer to a small saucepan, cover with 1 inch water, and add a pinch of salt. Bring the yams to a boil and cook until fork tender, about 10 to 12 minutes. Drain, return to the saucepan, and cover to keep warm.","img":"084_2.jpg"},{"n":3,"title":"MIX THE TZATZIKI SAUCE","text":"Grate the cucumber on the largest side of a box grater. Squeeze out the excess water and add the grated cucumber to a medium bowl. Chop the dill fronds and add them to the bowl along with the Vegenaise, juice from half the lemon, and a pinch of salt. Stir well to combine and place in the refrigerator until you're ready to serve.","img":"084_3.jpg"},{"n":4,"title":"PREPARE THE TOPPINGS","text":"Place a small skillet over medium heat and add the pumpkin seeds. Cook until fragrant and toasted, about 4 to 6 minutes. Check the kalamata olives for any pits and then roughly chop. Thinly slice the radish.","img":"084_4.jpg"},{"n":5,"title":"MASH THE YAMS","text":"With the back of a fork, mash the Japanese yams until they're relatively smooth. Grate the garlic into the saucepan using a microplane or the smallest side of the box grater. Add the white vinegar and a pinch of salt and stir to combine.","img":"084_5.jpg"},{"n":6,"title":"SERVE","text":"Thinly slice the remaining lemon half. Spread the mashed yams on large plates and top with cauliflower steaks. Drizzle with tzatziki sauce and sprinkle with kalamata olives, toasted pumpkin seeds, hemp seeds, and radish. Serve with lemon slices.","img":"084_6.jpg"}],"tips":["TIP: If some florets fall off the steaks, roast them! They'll be delicious, too.","TIP: Dill fronds are the wispy dark green leaves on the thick stems.","°Find a clove of garlic in the Butter Roasted Tomato Gratin recipe bag."],"cuisine_tags":["Greek","Mediterranean"],"ingredient_tags":["cauliflower","cucumber","radish","yam"],"item_tags":["dill","hemp seeds","kalamata olives","pumpkin seeds","vegenaise","white vinegar"],"issues":null,"front":"084a_IMG_9302.jpg","back":"084b_IMG_9303.jpg","era":"card","hero":"084.jpg"},{"pair":85,"title":"Seitan Gyro","subtitle":"with Shaved Artichoke Salad and Tahini Yogurt","servings":"2","cook_time":"30 minutes","nutrition":{"calories":"570","fat":"24 g","carbohydrates":"47 g","protein":"39 g"},"description":"One of the best parts about a gyro is the combination of flavors and textures. Crispy seitan, dusted with baharat, is paired with crispy artichokes and a smooth vegan tahini yogurt. Baharat is a traditional Middle Eastern blend with allspice, cloves, and cumin. It brings an authentic, warm flavor to the dish, and you can use as little or as much as you'd like depending on your affinity for spice. Wrap everything up in warm pita and enjoy!","from_your_kitchen":["2 tbsp olive oil","Salt and pepper"],"ingredients":["Fresh parsley","1 tomato","1 cucumber","6 artichoke hearts","1 lemon","1 package Sweet Earth seitan","¼ cup potato starch","½ tsp baharat spice","¼ cup Kite Hill vegan yogurt","¼ tsp cumin","1 tbsp tahini","2 pieces whole wheat pita"],"tools":["Large nonstick skillet"],"steps":[{"n":1,"title":"GET READY","text":"Chop the parsley leaves. Slice the tomato. Thinly slice the cucumber.","img":"085_1.jpg"},{"n":2,"title":"ARTICHOKE SALAD","text":"Thinly slice the artichoke hearts, be careful, they can be slippery! Place a large nonstick skillet over medium-high heat and add 1 tbsp olive oil. Once hot, add the sliced artichokes and cook until browned in places, about 5 to 7 minutes. Let cool slightly, then add to a medium bowl along with the parsley, juice from half the lemon, and a pinch of salt and pepper. Toss well to combine.","img":"085_2.jpg"},{"n":3,"title":"CRISP THE SEITAN","text":"Thinly slice the Sweet Earth seitan. Add the potato starch to a plate and dust each piece, shaking off any excess. Return the large skillet to medium-high heat and add 1 tbsp olive oil. Once hot, add the seitan, sprinkle with salt, and cook until crisp, about 3 to 4 minutes. Cook on the other side until crisp, another 3 to 4 minutes. Sprinkle with baharat spice and remove from the heat.","img":"085_3.jpg"},{"n":4,"title":"MAKE THE TAHINI YOGURT","text":"In a small bowl mix together the Kite Hill vegan yogurt, cumin, tahini, 1 tbsp of juice from the remaining lemon half, and a pinch of salt and pepper. Stir to combine.","img":"085_4.jpg"},{"n":5,"title":"WARM THE PITA","text":"Place the whole wheat pita in the toaster or microwave to warm. You can also set the oven to broil on low and broil until warm.","img":"085_5.jpg"},{"n":6,"title":"BUILD AND SERVE","text":"Place the crispy Sweet Earth seitan onto the warmed pitas and top with the shaved artichoke salad, sliced tomatoes, and cucumbers. Drizzle with the tahini yogurt sauce. Serve any remaining salad and vegetables on the side.","img":"085_6.jpg"}],"tips":["TIP: You'll use the skillet again in the next step!","TIP: Taste the tahini yogurt and add additional lemon juice if you'd like."],"cuisine_tags":["Greek","Middle Eastern"],"ingredient_tags":["artichokes","cucumber","pita","seitan","tomato"],"item_tags":["baharat","cumin","potato starch","tahini","vegan yogurt"],"issues":null,"front":"085a_IMG_9304.jpg","back":"085b_IMG_9305.jpg","era":"card","hero":"085.jpg"},{"pair":86,"title":"Crispy Eggplant Falafel Wraps","subtitle":"with Lemon Hummus and Parsley Salad","servings":"2","cook_time":"35 minutes","nutrition":{"calories":"980","fat":"45 g","carbohydrates":"120 g","protein":"29 g"},"description":"The best part about falafel is the crispy coating, and in this dish we've replicated it on hearty eggplant, shallow fried until golden brown. Topped with creamy lemon hummus, these wraps will surely satisfy. If you need to keep the eggplant warm while you finish cooking, simply pop it in the oven on a baking sheet.","from_your_kitchen":["4 tbsp vegetable oil","Salt and pepper"],"ingredients":["Eggplant","1 can garbanzo beans","1 lemon","1 tbsp sesame oil","½ cup garbanzo bean flour","1 tbsp cumin","1 tbsp coriander","1¼ cup panko breadcrumbs","2 pieces naan","Fresh parsley","1.5 oz sun dried tomatoes"],"tools":["Food processor","Large nonstick skillet"],"steps":[{"n":1,"title":"PREPARE THE EGGPLANT","text":"Slice the eggplant into ½ inch thick rounds. Sprinkle each side with a little salt and lay them on paper towels to draw out the moisture.","img":"086_1.jpg"},{"n":2,"title":"BLEND THE HUMMUS","text":"Drain the garbanzo beans and add them to a food processor. Zest 2 tsp of lemon zest and add it to the food processor along with the juice from half the lemon and a pinch of salt and pepper. While blending on high speed, drizzle in the sesame oil and 2 tbsp water. Blend hummus on high until smooth, adding more water as necessary. Taste and adjust seasoning with salt.","img":"086_2.jpg"},{"n":3,"title":"MAKE THE BATTER","text":"In a medium bowl, combine the garbanzo bean flour, cumin, coriander, ½ cup plus 2 tbsp cold water, and a pinch of salt and pepper. Whisk the batter well. Place the panko breadcrumbs on a large plate.","img":"086_3.jpg"},{"n":4,"title":"CRISP THE EGGPLANT","text":"Place a large nonstick skillet over medium-high heat with 2 tbsp vegetable oil. Dip the eggplant into the batter, shake off the excess, then coat in the breadcrumbs. Lay the eggplant into the hot oil and cook until the bottom is browned, 2 to 3 minutes. Flip, add another 2 tbsp vegetable oil, and cook until browned on the second side. Transfer eggplant to a paper towel-lined plate and sprinkle with salt.","img":"086_4.jpg"},{"n":5,"title":"PREPARE THE SALAD","text":"Set the oven to broil on low. Pop the naan onto the oven racks to warm for 1 minute. Pick the parsley leaves and tender stems and add to a medium bowl. Slice the sun dried tomatoes and add them to the bowl along with the juice from the remaining lemon half. Season with salt and pepper and toss parsley salad to combine.","img":"086_5.jpg"},{"n":6,"title":"SERVE","text":"Stir the lemon hummus and spread it onto the warmed naan. Add a few slices of crispy eggplant, top with the parsley salad, and fold. Serve any remaining filling on the side, and enjoy any extra hummus for dipping.","img":"086_6.jpg"}],"tips":["TIP: Salt will draw the water out of the eggplant—you can brush it off afterwards.","TIP: You may need to press the eggplant into the crumbs to coat.","TIP: Cut the eggplant rounds in half if they are too big to wrap."],"cuisine_tags":["Mediterranean","Middle Eastern"],"ingredient_tags":["chickpeas","eggplant","naan","parsley"],"item_tags":["coriander","cumin","garbanzo bean flour","panko breadcrumbs","sesame oil","sun dried tomatoes"],"issues":null,"front":"086a_IMG_9306.jpg","back":"086b_IMG_9307.jpg","era":"card","hero":"086.jpg"},{"pair":87,"title":"Kimchi Quesadilla","subtitle":"with Radish Pico de Gallo and Lime Crema","servings":"2","cook_time":"25 minutes","nutrition":{"calories":"520","fat":"14 g","carbohydrates":"69 g","protein":"25 g"},"description":"What's better than a crispy quesadilla filled with smooth black beans and bright kimchi? Nothing — except for that it takes less than 30 minutes to prepare. Crunchy radishes add a great bite to classic pico de gallo — feel free to chop them however you'd like to create texture.","from_your_kitchen":["2 tsp vegetable oil","Salt"],"ingredients":["1 tomato","1 shallot","2 oz radishes","Fresh cilantro","1 lime","3 tbsp Follow Your Heart® sour cream","1 can black beans","1 tsp Mexican chile spice","4 oz kimchi","2 flour tortillas"],"tools":["Large nonstick skillet"],"steps":[{"n":1,"title":"MAKE THE PICO DE GALLO","text":"Dice the tomato. Peel and mince the shallot. Slice the radishes into thin sticks. Chop the cilantro leaves and tender stems. Combine everything in a medium bowl. Halve the lime and add the juice from half. Add a pinch of salt and stir radish pico de gallo to combine.","img":"087_1.jpg"},{"n":2,"title":"PREPARE THE \"CREMA\"","text":"Combine the Follow Your Heart® sour cream and remaining lime juice in a small bowl. Add a pinch of salt and stir the lime crema.","img":"087_2.jpg"},{"n":3,"title":"MASH THE BEANS","text":"Place a large nonstick skillet over medium heat. Pour ¼ cup of liquid from the can of beans into a measuring cup and drain the rest. Add the black beans and the reserved liquid to the skillet along with the Mexican chile spice. Cook beans until they are hot, about 5 to 7 minutes. Mash them into a spreadable paste and season with salt.","img":"087_3.jpg"},{"n":4,"title":"BUILD THE QUESADILLAS","text":"Drain any liquid from the kimchi and roughly chop. Lay the flour tortillas flat on a clean work surface and top half of each tortilla with the mashed beans, spreading them out. Top the beans with the kimchi, fold tortillas, and set aside.","img":"087_4.jpg"},{"n":5,"title":"CRISP 'EM UP","text":"Wipe the skillet clean and return to medium heat with 2 tsp vegetable oil. Once the oil is hot, add the quesadillas. Cook until the bottom is lightly browned, about 2 to 3 minutes, then carefully flip to brown the other side; another 2 to 3 minutes.","img":"087_5.jpg"},{"n":6,"title":"SERVE","text":"Cut each quesadilla into 3 pieces and divide between plates. Serve with radish pico de gallo and lime crema. Enjoy!","img":"087_6.jpg"}],"tips":["TIP: If beans are a bit dry, add water by the tablespoon to loosen them up.","TIP: You can cook the quesadillas in batches if they don't fit in the skillet together."],"cuisine_tags":["Fusion","Korean","Mexican"],"ingredient_tags":["black beans","kimchi","radish","tortilla"],"item_tags":["cilantro","lime","mexican chile spice","vegan sour cream"],"issues":null,"front":"087a_IMG_9308.jpg","back":"087b_IMG_9309.jpg","era":"card","hero":"087.jpg"},{"pair":88,"title":"Fettuccine Alfredo","subtitle":"with Mushroom Medley","servings":"2","cook_time":"30 minutes","nutrition":{"calories":"510","fat":"20 g","carbohydrates":"69 g","protein":"19 g"},"description":"Most of us are familiar with four tastes: sweet, sour, salty, and bitter. But umami, the fifth taste, is savory. Our cashew and miso cream sauce is packed with umami flavor. You'll pour it over whole wheat pasta for a hearty, flavorful meal.","from_your_kitchen":["1 tbsp olive oil","Salt and pepper"],"ingredients":["⅓ cup cashews","6 oz mushrooms","Fresh parsley","1 shallot","1 garlic clove*","2 tsp white miso paste","1 tsp oyster mushroom powder","1 lemon","6 oz whole wheat fettuccine","2 tbsp vegan parmesan"],"tools":["Large pot","Blender","Large nonstick skillet"],"steps":[{"n":1,"title":"SET THE STAGE","text":"Place a large pot of salted water on to boil. Place the cashews in a small bowl and add ½ cup hot tap water. Let nuts soak for at least 10 minutes.","img":"088_1.jpg"},{"n":2,"title":"PREP THE VEGETABLES","text":"Wipe the mushrooms clean with a damp paper towel. Thinly slice the caps and the stems. Chop the parsley leaves. Peel and thinly slice the shallot.","img":"088_2.jpg"},{"n":3,"title":"BLEND THE SAUCE","text":"Peel 1 clove garlic. Add the cashews and their soaking water to a blender. Add the garlic, white miso paste, oyster mushroom powder, and just 1 tbsp lemon juice. Blend alfredo sauce on high until smooth. Season with salt and pepper.","img":"088_3.jpg"},{"n":4,"title":"SAUTE THE MUSHROOMS","text":"Place a large nonstick skillet over medium-high heat with 1 tbsp olive oil. Add the sliced mushrooms and cook until softened and browned, about 4 to 6 minutes. Add the shallots, reduce heat to medium-low, and cook, stirring often, for an additional 2 minutes.","img":"088_4.jpg"},{"n":5,"title":"COOK THE PASTA","text":"Add the fettuccine to the boiling water, stir, and cook until al dente, about 6 to 8 minutes. Reserve ½ cup of cooking water and drain pasta. Add the fettuccine to the skillet along with the alfredo sauce, reserved cooking water, and a pinch of salt and pepper. Reduce heat to low and simmer pasta, tossing occasionally, until sauce has thickened and pasta is well coated, about 2 to 3 minutes.","img":"088_5.jpg"},{"n":6,"title":"FINISH UP","text":"Stir the chopped parsley and just half of the parmesan into the pasta. Divide fettuccine alfredo between large plates or bowls and top with remaining parmesan. Mangia!","img":"088_6.jpg"}],"tips":["*Find a head of garlic in the Collard Green Enchiladas recipe bag.","TIP: If your sauce is still too thick, add warm water by the tablespoon to loosen it up."],"cuisine_tags":["Italian"],"ingredient_tags":["cashews","mushrooms","pasta"],"item_tags":["lemon","oyster mushroom powder","parsley","vegan parmesan","white miso"],"issues":null,"front":"088a_IMG_9310.jpg","back":"088b_IMG_9311.jpg","era":"card","hero":"088.jpg"},{"pair":89,"title":"Dosa Lettuce Wraps","subtitle":"with Spiced Chickpeas and Mango Chutney","servings":"2","cook_time":"35 minutes","nutrition":{"calories":"650","fat":"33 g","carbohydrates":"83 g","protein":"18 g"},"description":"A dosa is an Indian wrap, similar to a crêpe. Here, we lighten up the dish by using tender butter lettuce leaves instead of a traditional wheat-flour wrap. Cumin, coriander, and paprika are just some of the aromatic elements you'll find in the tandoori paste included in this recipe.","from_your_kitchen":["3 tbsp plus 1 tsp vegetable oil","Salt"],"ingredients":["12 oz red bliss potatoes","1 onion","Fresh ginger","1 can chickpeas","1.5 oz tandoori paste*","1 tsp curry powder","1 head butter lettuce","1 lemon","Fresh cilantro","¼ cup mango chutney","¼ cup vegan yogurt"],"tools":["Small saucepan","Large nonstick skillet"],"steps":[{"n":1,"title":"BOIL THE POTATOES","text":"Quarter the red bliss potatoes, add to a small saucepan, and cover with 1 inch water. Bring to a boil and cook until fork tender, about 12 to 15 minutes. Drain the potatoes.","img":"089_1.jpg"},{"n":2,"title":"PREPARE THE VEGETABLES","text":"Peel and thinly slice the onion. Peel and mince the ginger. Drain and rinse the chickpeas and pat dry.","img":"089_2.jpg"},{"n":3,"title":"CRISP THE CHICKPEAS","text":"Place a large nonstick skillet over high heat with 1 tsp vegetable oil. Once hot, add the chickpeas and cook, shaking the pan occasionally, until browned in places, about 4 to 6 minutes. Remove from heat, add 1 tbsp tandoori paste, and stir until the chickpeas are evenly coated. Transfer to a bowl and cover to keep warm.","img":"089_3.jpg"},{"n":4,"title":"BUILD THE FLAVOR","text":"Return the skillet to medium-high heat with 2 tbsp vegetable oil. Add the sliced onion and cook until softened and browned in places, about 2 to 4 minutes. Add the ginger and curry powder and cook until fragrant, about 1 minute. Transfer the onions to a plate and sprinkle with salt.","img":"089_4.jpg"},{"n":5,"title":"ADD THE POTATOES","text":"Clean the skillet and return to medium-high heat with 1 tbsp vegetable oil. Once hot, and the potatoes. Cook, smashing potatoes a bit, until crisp in places, about 5 to 7 minutes. Season with salt. Separate the butter lettuce leaves. Zest half the lemon and then cut into wedges.","img":"089_5.jpg"},{"n":6,"title":"SERVE","text":"Add the lemon zest and cooked onions to the potatoes. Roughly chop the cilantro leaves and tender stems. To build your lettuce wraps, top each butter lettuce leaf with some of the crispy lemon potatoes and spiced chickpeas. Dollop with each mango chutney and yogurt. Serve with lemon wedges and the remaining tandoori paste.","img":"089_6.jpg"}],"tips":["*This item will be used in multiple steps.","TIP: No need to clean the skillet—you'll use it again."],"cuisine_tags":["Indian"],"ingredient_tags":["chickpeas","lettuce","onion","potato"],"item_tags":["cilantro","curry powder","ginger","mango chutney","tandoori paste","vegan yogurt"],"issues":null,"front":"089a_IMG_9312.jpg","back":"089b_IMG_9313.jpg","era":"card","hero":"089.jpg"},{"pair":90,"title":"Portobello Steaks","subtitle":"with Vegetable Orzo Salad & Chimichurri","servings":"2","cook_time":"30 minutes","nutrition":{"calories":"540","fat":"24 g","carbohydrates":"70 g","protein":"15 g"},"description":"The best trick to trim asparagus is to hold the ends of a spear with both hands and find the natural snapping point towards the bottom of the stalk. Line them up and cut the entire bunch at this point, discarding the woody ends. The roasted vegetables get mixed into orzo and everything gets topped with herby, citrusy chimichurri, a South American sauce known for its bright color and bold flavor– it's one of our all time favorites.","from_your_kitchen":["4 tbsp + 1 tsp olive oil","Salt and pepper"],"ingredients":["12 oz portobello mushrooms","2 tbsp balsamic vinegar","7 oz zucchini","4 oz asparagus","1 red onion*","1 garlic clove*","Fresh parsley","Fresh cilantro","1 tbsp red wine vinegar","1 lemon","¾ cup orzo","Parchment paper"],"tools":["Small saucepan","Baking sheet"],"steps":[{"n":1,"title":"MARINATE THE MUSHROOMS","text":"Bring a small saucepan of salted water to a boil. Preheat the oven to 400°F. In a large bowl, add the portobello mushrooms, balsamic vinegar, 1 tbsp olive oil, and a pinch of salt and pepper. Toss well to coat the mushrooms and let marinate while you prepare the remaining vegetables. Line a baking sheet with the parchment paper.","img":"090_1.jpg"},{"n":2,"title":"ROAST THE VEGETABLES","text":"Trim the zucchini and dice into ½ inch cubes. Trim the tough ends from the asparagus and cut remaining stalks into ½ inch pieces. Peel and chop the red onion, reserving 2 tbsp for Step 3. Add the vegetables to half of the lined baking sheet and drizzle with 1 tbsp olive oil and a pinch of salt and pepper. Add the marinated mushrooms to the other half. Roast until tender, about 15 to 20 minutes.","img":"090_2.jpg"},{"n":3,"title":"MAKE THE CHIMICHURRI","text":"Peel and mince 1 garlic clove. Mince the reserved 2 tbsp red onion. Finely chop the parsley and cilantro leaves and tender stems. In a medium bowl, add minced garlic, red onion, parsley, cilantro, red wine vinegar, 2 tbsp olive oil, and a pinch of salt and pepper. Zest 1 tsp of the lemon into the bowl and stir chimichurri to combine.","img":"090_3.jpg"},{"n":4,"title":"COOK THE ORZO","text":"Add the orzo to the boiling water and stir. Cook until tender, about 8 to 10 minutes. Drain the orzo, return to the saucepan and mix in 1 tsp olive oil.","img":"090_4.jpg"},{"n":5,"title":"FINISHING TOUCHES","text":"Once the roasted vegetables are tender, mix into the orzo. Slice the mushrooms into a few pieces. Cut the lemon into wedges.","img":"090_5.jpg"},{"n":6,"title":"TIME TO EAT","text":"Divide the vegetable orzo salad between your plates and top with the portobello steaks. Drizzle with chimichurri and serve with the lemon wedges. Enjoy!","img":"090_6.jpg"}],"tips":["* This item will be split between multiple steps.","* Find a head of garlic with the ingredients for the Seitan Massaman Curry.","TIP: Use two baking sheets if your sheets are small.","TIP: The chimichurri can be made in a food processor."],"cuisine_tags":["Latin American","Mediterranean"],"ingredient_tags":["asparagus","mushrooms","orzo","zucchini"],"item_tags":["balsamic vinegar","chimichurri","cilantro","parsley","red wine vinegar"],"issues":null,"front":"090a_IMG_9314.jpg","back":"090b_IMG_9315.jpg","era":"card","hero":"090.jpg"},{"pair":91,"title":"Vegetable Chow Mein","subtitle":"with Sweet Potato and Garlic Tamari Sauce","servings":"2","cook_time":"30 minutes","nutrition":{"calories":"650","fat":"9 g","carbohydrates":"120 g","protein":"22 g"},"description":"This dish is our twist on a takeout favorite. Classic chow mein can be loaded with preservatives, but we've made it healthier and tastier and by adding fresh vegetables and using a simple tamari and garlic sauce.","from_your_kitchen":["1 tbsp vegetable oil","Salt"],"ingredients":["8 oz sweet potato","1 clove garlic*","5 oz button mushrooms","1 red bell pepper","5 oz bok choy","11 oz fresh noodles","2 tbsp agave","3 tbsp tamari","2 oz water chestnuts","2 tbsp chile garlic sauce"],"tools":["Small saucepan","Large nonstick skillet"],"steps":[{"n":1,"title":"PREP THE VEGETABLES","text":"Fill a small saucepan with water and place over high heat to boil. Peel the sweet potato with a peeler then continue peeling beyond the skin to make noodles. Peel and mince 1 clove garlic. Thinly slice the mushrooms. Deseed and thinly slice the red bell pepper. Trim the bok choy and roughly chop.","img":"091_1.jpg"},{"n":2,"title":"BEGIN TO COOK","text":"Place a large nonstick skillet over high heat with 1 tbsp vegetable oil. Add sliced mushrooms and cook until browned in places, about 4 to 6 minutes. Add the sweet potato noodles, garlic, and red bell pepper. Cook until pepper is tender, about 2 to 3 minutes.","img":"091_2.jpg"},{"n":3,"title":"COOK THE NOODLES","text":"Add the noodles to the boiling water and immediately stir. Reduce heat to medium and cook until just al dente, about 2 to 3 minutes. Drain and rinse with cool water to halt the cooking.","img":"091_3.jpg"},{"n":4,"title":"SAUCE IT UP","text":"Add the agave, tamari, and ¼ cup water to the skillet, and reduce heat to medium. Cook until the sauce thickens slightly, about 1 minute. Add the bok choy and water chestnuts to the skillet and toss to combine. Cook until bok choy is bright green and just tender, about 2 to 3 minutes.","img":"091_4.jpg"},{"n":5,"title":"ADD THE NOODLES","text":"Add the cooked noodles to the skillet with the vegetables, sprinkle with salt, and gently toss them with tongs or a fork until well combined. Let noodles simmer, tossing occasionally to heat through, about 2 to 3 minutes.","img":"091_5.jpg"},{"n":6,"title":"CHOW DOWN","text":"Divide vegetable chow mein between large plates and top with the spicy chile garlic sauce. Grab your chopsticks and dig in!","img":"091_6.jpg"}],"tips":["*Find a head of garlic in the Pumpkin Matar recipe bag."],"cuisine_tags":["Chinese"],"ingredient_tags":["bell pepper","bok choy","mushrooms","noodles","sweet potato"],"item_tags":["agave","chile garlic sauce","tamari","water chestnuts"],"issues":null,"front":"091a_IMG_9316.jpg","back":"091b_IMG_9317.jpg","era":"card","hero":"091.jpg"},{"pair":92,"title":"Mediterranean Eggplant","subtitle":"with Cubanelle Chermoula and Apricot Couscous","servings":"2","cook_time":"45 minutes","nutrition":{"calories":"600","fat":"31 g","carbohydrates":"74 g","protein":"14 g"},"description":"Chermoula is a marinade hailing from Northern Africa. It has a smoky, citrus-y taste. Here, we use it to complement the roasted texture of the eggplant and the sweetness of apricot couscous.","from_your_kitchen":["6 tbsp olive oil","1 tsp vegetable oil","Salt and pepper"],"ingredients":["1 eggplant","1 cubanelle pepper","½ cup whole wheat couscous","Fresh ginger","1 garlic clove","Fresh dill","1 lemon","¼ tsp smoked paprika","¼ tsp cumin","2 dried apricots","2 tbsp currants","½ cup lima beans","¼ cup vegan yogurt"],"tools":["Small saucepan","Baking sheet","Medium skillet"],"steps":[{"n":1,"title":"PREP THE VEGETABLES","text":"Preheat the oven to 425°F. Cut the eggplant into rounds on the diagonal. Deseed the cubanelle pepper and roughly chop.","img":"092_1.jpg"},{"n":2,"title":"ROAST THE EGGPLANT","text":"Add ¾ cup water to a small saucepan and bring to a boil. Add the whole wheat couscous, cover, and remove from heat. Let couscous stand until Step 5. Transfer eggplant to baking sheet and coat with 4 tbsp olive oil. Season generously with salt and pepper and place in the oven. Roast until eggplant is browned on the bottom and soft, about 30 to 35 minutes.","img":"092_2.jpg"},{"n":3,"title":"CHAR THE PEPPER","text":"Place a medium skillet over medium-high heat with 1 tsp vegetable oil. Once hot, add the chopped cubanelle to the skillet. Cook, turning occasionally, until charred and softened, about 5 to 7 minutes. Remove from the heat to cool.","img":"092_3.jpg"},{"n":4,"title":"MAKE THE CHERMOULA","text":"Peel and grate the ginger. Grate 1 clove garlic into a medium bowl and add the ginger. Chop the dill fronds and add to the bowl. Zest the lemon and add just 1 tsp lemon zest to the bowl. Add the smoked paprika, cumin, ¼ tsp salt, 2 tbsp olive oil, and the juice from half the lemon. Finely chop the charred cubanelle pepper, add to the bowl and stir to combine.","img":"092_4.jpg"},{"n":5,"title":"FINISH THE COUSCOUS","text":"Finely chop the dried apricots. Fluff the cooked couscous with a fork and add the apricots, currants, lima beans, remaining lemon zest and juice, and a pinch of salt. Stir to combine.","img":"092_5.jpg"},{"n":6,"title":"SERVE","text":"Spread the vegan yogurt on the bottom of large plates. Top with apricot couscous, roasted eggplant, and cubanelle chermoula. Enjoy!","img":"092_6.jpg"}],"tips":[],"cuisine_tags":["Mediterranean","Moroccan"],"ingredient_tags":["couscous","eggplant","lima beans"],"item_tags":["chermoula","cumin","currants","dill","dried apricots","ginger","smoked paprika","vegan yogurt"],"issues":null,"front":"092a_IMG_9318.jpg","back":"092b_IMG_9319.jpg","era":"card","hero":"092.jpg"},{"pair":93,"title":"Elote Bowl","subtitle":"with Lime Chickpeas & Quinoa","servings":"2","cook_time":"25 minutes","nutrition":{"calories":"740","fat":"28 g","carbohydrates":"105 g","protein":"27 g"},"description":"Elote is the Spanish word for corn, and this sweet summer vegetable is the highlight of our \"street corn\" bowl. Mexican style corn is usually grilled, so fire it up if you have one. Instead of cutting the corn kernels from the cob, lay them whole on a hot grill and cook until charred, it should only take a few minutes. The key to crispy chickpeas is not shaking the pan too often, they should be browned in places and smell a bit toasted.","from_your_kitchen":["4 tsp olive oil","Salt"],"ingredients":["¾ cup red quinoa","1 can chickpeas","2 ears fresh corn","1 lime","2 tbsp Kite Hill vegan yogurt","1 tbsp Follow Your Heart Vegenaise®","¼ tsp cayenne pepper*","1 jalapeño","2 oz red radish","Fresh cilantro","2 tbsp pumpkin seeds","2 tsp vegan parmesan"],"tools":["Small saucepan","Large nonstick skillet with a lid"],"steps":[{"n":1,"title":"COOK THE QUINOA","text":"Add the red quinoa, 1¼ cups water, and a pinch of salt to a small saucepan and place over high heat. Bring to a boil, reduce heat to a simmer, cover, and cook quinoa until water is absorbed and spirals start to burst, about 15 minutes.","img":"093_1.jpg"},{"n":2,"title":"PREPARE THE VEGETABLES","text":"Drain and rinse the chickpeas, and dry them well with a paper towel. Peel the husks from the corn and cut the kernels off of the cob.","img":"093_2.jpg"},{"n":3,"title":"MAKE THE ELOTE SAUCE","text":"Zest the lime. In a small bowl, combine half the lime zest, Kite Hill vegan yogurt, Vegenaise®, and half of the cayenne pepper. Add the juice from half of the lime and a pinch of salt. Stir elote sauce to combine.","img":"093_3.jpg"},{"n":4,"title":"PREP THE GARNISHES","text":"Deseed and mince the jalapeño. Thinly slice the radishes. Finely chop the cilantro leaves and tender stems.","img":"093_4.jpg"},{"n":5,"title":"CRISP THE CHICKPEAS AND CORN","text":"Place a large nonstick skillet over high heat with 2 tsp olive oil. Once hot, add the chickpeas and cook undisturbed until slightly browned and crisp, about 4 to 6 minutes. Transfer to a medium bowl. Immediately return the skillet to high heat and add 2 tsp olive oil. Add the corn, cover, and cook, shaking the pan occasionally, until blackened in spots, 3 to 4 minutes. Sprinkle with salt.","img":"093_5.jpg"},{"n":6,"title":"BUILD THE BOWLS","text":"Add the juice from the remaining lime half, lime zest, jalapeño, and a pinch of salt to the crispy chickpeas, and toss well to combine. Divide the red quinoa between large bowls. Layer on the lime chickpeas, charred corn, and drizzle with elote sauce. Top with sliced radishes, cilantro, pumpkin seeds, and vegan parmesan. Sprinkle bowls with remaining cayenne pepper. Dig in!","img":"093_6.jpg"}],"tips":["*This item will be split between multiple steps","Use a lid to prevent chickpeas and corn from bouncing out of the skillet."],"cuisine_tags":["Mexican"],"ingredient_tags":["chickpeas","corn","quinoa","radish"],"item_tags":["cayenne","cilantro","jalapeño","lime","pumpkin seeds","vegan parmesan","vegan yogurt","vegenaise"],"issues":null,"front":"093a_IMG_9320.jpg","back":"093b_IMG_9321.jpg","era":"card","hero":"093.jpg"},{"pair":94,"title":"Eggplant Parmesan Flatbread","subtitle":"with Shaved Zucchini and Arugula Salad","servings":"2","cook_time":"30 minutes","nutrition":{"calories":"770","fat":"41 g","carbohydrates":"85 g","protein":"16 g"},"description":"Mozzarella and sun dried tomatoes make this dish taste like an authentic eggplant parmesan. For slicing vegetables, a mandoline may be the most useful tool in your kitchen so if you have one, use it here for the eggplant and zucchini. If you like to grill, this is a good recipe to fire it up for. The eggplant can be grilled and after the flatbreads are assembled, simply leave them on the grill for a few moments with the lid closed to melt the cheese.","from_your_kitchen":["2 tbsp + 1 tsp olive oil","Salt and pepper"],"ingredients":["14 oz eggplant","1 oz roasted garlic","2 pieces naan bread","Fresh thyme","1 oz sun dried tomatoes","½ cup Follow Your Heart vegan mozzarella","1 zucchini","1 oz hazelnuts","2 oz baby arugula","1 tbsp white balsamic vinegar"],"tools":["Large nonstick skillet","Baking sheet"],"steps":[{"n":1,"title":"COOK THE EGGPLANT","text":"Trim and thinly slice the eggplant lengthwise. Place a large nonstick skillet over medium-high heat and add 2 tbsp olive oil. Once hot, add the eggplant in one layer and cook until softened and browned, about 2 minutes each side. Once cooked, season with salt and pepper.","img":"094_1.jpg"},{"n":2,"title":"BUILD THE FLATBREAD","text":"Set the oven to broil on low. Spread the roasted garlic on the naan with a spoon. Sprinkle with salt and pepper and then layer on the eggplant, overlapping slightly, until all of the slices are used.","img":"094_2.jpg"},{"n":3,"title":"ADD THE TOPPINGS","text":"Pick the thyme leaves from the stems. Sprinkle the flatbreads with thyme leaves and sun dried tomatoes. Top with Follow Your Heart vegan mozzarella. Place the flatbreads onto a baking sheet. Broil until the vegan mozzarella is melted, about 4 to 6 minutes.","img":"094_3.jpg"},{"n":4,"title":"MAKE THE SALAD","text":"Use a peeler or mandoline to make long ribbons of zucchini and add to large bowl. Roughly chop the hazelnuts. Add the chopped hazelnuts, arugula, white balsamic vinegar, and 1 tsp olive oil to the zucchini and season with salt and pepper. Toss salad well to combine.","img":"094_4.jpg"},{"n":5,"title":"CUT THE FLATBREADS","text":"Once the flatbreads are finished, cut into quarters.","img":"094_5.jpg"},{"n":6,"title":"BON APPETIT","text":"Serve the eggplant parmesan flatbreads on large plates alongside the shaved zucchini and arugula salad.","img":"094_6.jpg"}],"tips":["Cook the eggplant in batches and add additional oil as needed.","Keep an eye on the flatbread while it's under the broiler."],"cuisine_tags":["Italian"],"ingredient_tags":["arugula","eggplant","naan","zucchini"],"item_tags":["hazelnuts","roasted garlic","sun dried tomatoes","thyme","vegan mozzarella","white balsamic vinegar"],"issues":null,"front":"094a_IMG_9322.jpg","back":"094b_IMG_9323.jpg","era":"card","hero":"094.jpg"},{"pair":95,"title":"Curried Hummus Flatbread","subtitle":"with Roasted Cauliflower & Olive Date Relish","servings":"2","cook_time":"35 minutes","nutrition":{"calories":"850","fat":"40 g","carbohydrates":"109 g","protein":"25 g"},"description":"Buttery, briny, and tangy, these trendy Castelvetrano olives are named in honor of their hometown in Southwestern Sicily. The sweet dates add a counterbalance, and everything is piled high on crisp flatbread, dolloped with vegan ricotta and drizzled with lemon juice. You'll only use half of the can of garbanzo beans here, so be sure to save the remainder for the \"Fabcakes\" that also came in your box this week.","from_your_kitchen":["2 tbsp + 2 tsp olive oil","Salt and pepper"],"ingredients":["4 oz cauliflower florets","1 lemon","1 can garbanzo beans*","1 tbsp tahini","1 tsp curry powder","2 pieces naan","Fresh parsley","0.75 oz Castelvetrano olives","3 dates","3 tbsp vegan ricotta","1 oz baby arugula"],"tools":["Baking sheet","Food processor"],"steps":[{"n":1,"title":"ROAST THE CAULIFLOWER","text":"Preheat the oven to 425°F. Cut the cauliflower into even smaller florets. Transfer to a baking sheet and toss with 1 tsp olive oil and a pinch of salt and pepper. Roast the cauliflower until tender and browned in some places, about 15 to 18 minutes.","img":"095_1.jpg"},{"n":2,"title":"MAKE THE HUMMUS","text":"Halve the lemon. Drain and rinse the garbanzo beans. Measure out ¾ cup of garbanzos (reserving the remainder for the Fabcakes recipe). Add to the food processor along with the tahini, curry powder, and juice from half the lemon. With the motor running, slowly add 2 tbsp olive oil and blend until smooth, scraping down the sides as necessary with a spatula. Season hummus with ⅛ tsp salt.","img":"095_2.jpg"},{"n":3,"title":"NAAN TIME","text":"Place the naan in the oven directly on the rack. Bake until lightly crisp, about 7 to 9 minutes.","img":"095_3.jpg"},{"n":4,"title":"PREPARE THE RELISH","text":"Finely chop the parsley leaves, Castelvetrano olives, and dates. Add to a small bowl and stir relish to combine.","img":"095_4.jpg"},{"n":5,"title":"ASSEMBLE THE FLATBREAD","text":"When the naan is toasted, spread each piece with half of the curried hummus. Layer on the olive date relish, roasted cauliflower, and dollop with bits of the vegan ricotta. Pop the flatbreads in the oven to warm, about 3 minutes.","img":"095_5.jpg"},{"n":6,"title":"FINISHING TOUCHES","text":"Remove the flatbreads from the oven and top with arugula. Sprinkle with salt and drizzle with remaining lemon juice and 1 tsp olive oil. Bon appetit!","img":"095_6.jpg"}],"tips":["*The can of garbanzo beans in this recipe bag is also for the Fabcakes.","Add more olive oil or water by the tbsp to achieve a smooth consistency."],"cuisine_tags":["Fusion","Mediterranean"],"ingredient_tags":["arugula","cauliflower","chickpeas","naan"],"item_tags":["castelvetrano olives","curry powder","dates","tahini","vegan ricotta"],"issues":null,"front":"095a_IMG_9324.jpg","back":"095b_IMG_9325.jpg","era":"card","hero":"095.jpg"},{"pair":96,"title":"Sweet-and-Sour Brussels Sprouts Stir-Fry","subtitle":"with Black Quinoa and Mint","servings":"2","cook_time":"30 minutes","nutrition":{"calories":"670","fat":"34 g","carbohydrates":"72 g","protein":"22 g"},"description":"You'll char hearty Brussels sprouts in a skillet to develop flavor before tossing them in a sweet-and-sour sauce. The sauce has a little heat from the togarashi, a blend of chile, sesame seeds, ginger, and seaweed. Edamame amps up the protein and adds texture in this quick, delicious take on fried rice.","from_your_kitchen":["2 tbsp vegetable oil","Salt"],"ingredients":["Fresh ginger","4 oz carrot","8 oz Brussels sprouts","¾ cup black quinoa","Fresh mint*","1 tbsp agave","1 tbsp rice vinegar","½ tsp togarashi spice","½ cup edamame","1 tbsp sesame oil","1 tbsp tamari","¼ cup tamari almonds"],"tools":["Large skillet with a lid","Medium skillet"],"steps":[{"n":1,"title":"PREPARE THE VEGETABLES","text":"Peel and mince the ginger. Peel and dice the carrot. Trim and halve the Brussels sprouts.","img":"096_1.jpg"},{"n":2,"title":"COOK THE QUINOA","text":"Place a large skillet over medium-high heat with 1 tbsp vegetable oil. Once hot, add the minced ginger and diced carrot. Cook until fragrant, about 1 to 2 minutes. Add the black quinoa along with 1¼ cups water, and bring to a boil. Reduce heat to low, cover, and simmer until all of the water is absorbed, about 12 to 15 minutes.","img":"096_2.jpg"},{"n":3,"title":"MAKE THE SAUCE","text":"Thinly slice half of the mint leaves. In a small bowl, combine the sliced mint, agave, rice vinegar, togarashi, and ½ tsp salt. Pick the remaining mint leaves, tear them with your hands, and set aside.","img":"096_3.jpg"},{"n":4,"title":"SEAR THE SPROUTS","text":"Place a medium skillet over medium-high heat with 1 tbsp vegetable oil. Once hot, add the halved Brussels sprouts and a pinch of salt. Arrange sprouts cut side down and cook, undisturbed, until browned and crispy, about 2 to 5 minutes. Toss, lower heat to medium-low, and add the sauce. Toss once more, and cook until sauce is syrupy and sprouts are tender, about 2 to 3 minutes.","img":"096_4.jpg"},{"n":5,"title":"FINISH THE QUINOA","text":"Once quinoa is cooked, remove the lid, and increase heat to high. Stir in edamame, sesame oil, and tamari. Cook, stirring occasionally, until edamame is warmed through and no liquid remains, about 3 to 4 minutes. Taste quinoa and season with salt as necessary.","img":"096_5.jpg"},{"n":6,"title":"PLATE AND SERVE","text":"Roughly chop the tamari almonds. Divide the quinoa between large shallow bowls and top with sweet-and-sour Brussels sprouts. Garnish with tamari almonds and torn mint. Chow down!","img":"096_6.jpg"}],"tips":["*This item will be split between multiple steps.","This item is spicy. (togarashi spice)","TIP: Searing cut-side down allows for more caramelization and flavor."],"cuisine_tags":["Fusion","Japanese"],"ingredient_tags":["brussels sprouts","carrot","edamame","quinoa"],"item_tags":["agave","ginger","mint","rice vinegar","sesame oil","tamari","tamari almonds","togarashi"],"issues":null,"front":"096a_IMG_9326.jpg","back":"096b_IMG_9327.jpg","era":"card","hero":"096.jpg"},{"pair":97,"title":"Kale Caesar","subtitle":"with Crispy Butter Beans and Everything \"Bagel\" Croutons","servings":"2","cook_time":"25 minutes","nutrition":{"calories":"460","fat":"16 g","carbohydrates":"64 g","protein":"20 g"},"description":"Fun fact: Caesar Cardini, an Italian immigrant, is credited with inventing the Caesar salad in the 1920's. Usually dressed with a combination of cheese, anchovies, egg, and oil, our kale Caesar takes a lighter approach, bumping up the flavor with briny capers, tahini, and dijon mustard. We also sub out run-of-the-mill croutons for \"everything bagel\" croutons. You'll have trouble not eating them right off the baking sheet!","from_your_kitchen":["4½ tsp olive oil","Salt and pepper"],"ingredients":["8 oz Lacinato kale","2 tsp capers","1 tbsp tahini","2 tsp Worcestershire sauce","½ tsp garlic powder","2 packets dijon mustard","1 lemon","1 shallot","3 oz asparagus","1 package butter beans","Fresh parsley","3 oz whole wheat roll","1 tbsp everything bagel spice"],"tools":["Baking sheet","Large nonstick skillet"],"steps":[{"n":1,"title":"MASSAGE THE KALE","text":"Preheat the oven to 425°F. Destem the Lacinato kale and roughly chop the leaves. Place the kale in a large bowl with ½ tsp olive oil. Massage the kale with your hands until the leaves begin to soften, about 1 to 2 minutes.","img":"097_1.jpg"},{"n":2,"title":"MAKE THE DRESSING","text":"Mince the capers and add to a small bowl. Add the tahini, Worcestershire sauce, garlic powder, dijon mustard, and a pinch of salt and pepper. Zest the lemon and set the zest aside. Add the juice from the lemon to the bowl and whisk Caesar dressing to combine.","img":"097_2.jpg"},{"n":3,"title":"PREPARE THE VEGETABLES","text":"Peel and thinly slice the shallot. Trim and thinly slice the asparagus on the diagonal. Add the shallot and asparagus to the bowl with the massaged kale. Drain the butter beans and pat dry with a paper towel. Finely chop the parsley leaves.","img":"097_3.jpg"},{"n":4,"title":"MAKE THE CROUTONS","text":"Cut the whole wheat roll into cubes. Add to a baking sheet and toss with 2 tsp olive oil and everything bagel spice. Bake until toasted and crispy in places, about 7 to 9 minutes.","img":"097_4.jpg"},{"n":5,"title":"CRISP THE BUTTER BEANS","text":"Place a large nonstick skillet over medium-high heat and add 2 tsp olive oil. Once hot, add the butter beans and cook, shaking the pan occasionally, until browned in places, about 2 to 4 minutes. Season with salt and stir in the lemon zest and chopped parsley.","img":"097_5.jpg"},{"n":6,"title":"FINISH AND SERVE","text":"Toss the massaged kale with the Caesar dressing and a pinch of salt and pepper. Place a heaping serving of the kale Caesar on your plates. Top with the crispy butter beans and everything bagel croutons. Enjoy!","img":"097_6.jpg"}],"tips":["We massage the kale to soften the leaves which aids in digestion.","Make sure your butter beans are dry, they'll get crispier that way."],"cuisine_tags":["American","Italian"],"ingredient_tags":["asparagus","butter beans","kale"],"item_tags":["capers","dijon mustard","everything bagel spice","garlic powder","tahini","worcestershire sauce"],"issues":null,"front":"097a_IMG_9328.jpg","back":"097b_IMG_9329.jpg","era":"card","hero":"097.jpg"},{"pair":98,"title":"Wicked Healthy® Beetroot Tacos","subtitle":"with Avocado Salsa","servings":"2","cook_time":"35 minutes","nutrition":{"calories":"710","fat":"18 g","carbohydrates":"68 g","protein":"12 g"},"description":"Beets are high in Vitamin C and fiber, and make the perfect centerpiece in this tasty and healthy taco dish. You'll roast the beets until they're surprisingly sweet and chewy. Blending the salsa (rather than chopping the ingredients) saves time, and this version is particularly delicious.","from_your_kitchen":["1 tbsp + 1 tsp vegetable oil","Salt and pepper"],"ingredients":["12 oz red beets","4 oz Lacinato kale","1 red onion*","1 avocado*","1 jalapeño*","2 garlic cloves*","¼ cup Follow Your Heart® Vegenaise®","Fresh cilantro","2 tbsp sherry vinegar*","4 whole wheat tortillas"],"tools":["Baking sheet","Food processor","Large skillet"],"steps":[{"n":1,"title":"ROAST THE BEETS","text":"Preheat the oven to 400°F. Peel the red beets and slice them into thin wedges, about a half-inch thick. Place the beets on a baking sheet and toss with 1 tbsp vegetable oil and a pinch of salt and pepper. Roast until tender, about 25 to 30 minutes.","img":"098_1.jpg"},{"n":2,"title":"PREP THE VEGETABLES","text":"Destem the Lacinato kale and roughly chop the leaves. Halve and peel the red onion. Roughly chop half and thinly slice the other half. Halve the avocado and remove the pit. Trim and deseed the jalapeño.","img":"098_2.jpg"},{"n":3,"title":"MAKE THE AVOCADO SALSA","text":"Add the chopped red onion and half of the avocado to a food processor. Peel and add 2 cloves garlic, Follow Your Heart® Vegenaise®, cilantro leaves and tender stems, just 1 tbsp of sherry vinegar, and as much or as little of the jalapeño as you'd like. Pulse until you have a smooth, even consistency, scraping down the sides as necessary. Season avocado salsa with salt.","img":"098_3.jpg"},{"n":4,"title":"COOK THE KALE","text":"Place a large skillet over medium-high heat with 1 tsp vegetable oil. Once hot, add the chopped kale and cook until just wilted, about 2 minutes. Season with salt and pepper.","img":"098_4.jpg"},{"n":5,"title":"WARM THE TORTILLAS","text":"Once the beets are tender, drizzle them with the remaining sherry vinegar. Wrap the whole wheat tortillas in foil and warm in the oven for a few minutes. Slice the remaining avocado.","img":"098_5.jpg"},{"n":6,"title":"BUILD YOUR TACOS","text":"Lay the warm tortillas on plates and top with a dollop of avocado salsa; spread to coat. Layer on the roasted beets, sautéed kale, sliced avocado, and some sliced red onion. Top with more avocado salsa and enjoy!","img":"098_6.jpg"}],"tips":["*These items will be split between multiple steps.","*The head of garlic in this bag is for all recipes this week.","TIP: No food processor? You can finely chop all of the ingredients in the salsa and mash.","TIP: You can also wrap the tortillas in paper towels and warm them in the microwave."],"cuisine_tags":["Mexican"],"ingredient_tags":["avocado","beets","kale","tortilla"],"item_tags":["cilantro","jalapeño","sherry vinegar","vegenaise"],"issues":null,"front":"098a_IMG_9330.jpg","back":"098b_IMG_9331.jpg","era":"card","hero":"098.jpg"},{"pair":99,"title":"Cornmeal Arepas","subtitle":"with Black Beans and Zucchini Citrus Salsa","servings":"2","cook_time":"35 minutes","nutrition":{"calories":"880","fat":"34 g","carbohydrates":"148 g","protein":"27 g"},"description":"Arepas are tender, pan seared corn cakes made of masa harina (maize flour). The masa harina is finely ground flour traditionally usually used for tamales and corn tortillas. The dough will be slightly sticky when ready. Although delicious on their own, we've taken them to another level by adding a zucchini citrus salsa.","from_your_kitchen":["2 tbsp + 2 tsp olive oil","Salt and pepper"],"ingredients":["1 cup + 2 tbsp masa harina","2 tbsp flour","2 tbsp vegan butter","1 tbsp turbinado sugar","1 orange","1 onion","1 zucchini","2 oz radish","1 lime","1 can black beans","3 oz mixed greens"],"tools":["Small saucepan","Large nonstick skillet"],"steps":[{"n":1,"title":"MAKE THE AREPA MIX","text":"In a large bowl, combine the masa harina, flour, vegan butter, turbinado sugar, ¼ tsp salt, and 1 cup hot tap water. Mix dough well with a wooden spoon to combine.","img":"099_1.jpg"},{"n":2,"title":"SUPREME THE ORANGE","text":"Trim off the top and bottom of the orange with a knife. Set the fruit on end and cut the skin away. Over a medium bowl, cut out each section of the fruit by inserting the blade of the knife between the flesh and the membrane on both sides. Squeeze any remaining juice into the bowl from the membrane.","img":"099_2.jpg"},{"n":3,"title":"PREPARE THE SALSA","text":"Peel, halve, and thinly slice the onion. Add as much or as little as you'd like to the medium bowl with the orange. Dice the zucchini. Thinly slice the radishes. Add the zucchini, radishes, 2 tsp olive oil, juice from half of the lime, and a pinch of salt and pepper to the bowl and toss salsa well to combine.","img":"099_3.jpg"},{"n":4,"title":"WARM THE BEANS","text":"Drain and rinse the black beans. Place a small saucepan over low heat and add the black beans with ½ cup water. Cook, stirring occasionally, until they are warmed through, about 4 to 5 minutes. Mash beans with a fork and season with salt. Cover to keep warm.","img":"099_4.jpg"},{"n":5,"title":"MAKE THE AREPAS","text":"Place a large nonstick skillet over medium heat and add 1 tbsp olive oil. To form the arepas, place about ¼ cup of the batter in your hands and roll it into a ball. Press gently into a flat circle and lay into the skillet. Cook the arepas until they are browned on the bottom and begin to firm up, about 5 minutes. Flip the arepas, add another 1 tbsp olive oil, and cook on the second side, about 3 to 5 minutes.","img":"099_5.jpg"},{"n":6,"title":"SERVE IT UP","text":"Cut the remaining lime half into wedges. To serve, spread the black beans on the cornmeal arepas. Top with some of the zucchini citrus salsa and mixed greens. Serve the arepas with any remaining salsa and lime wedges. Enjoy!","img":"099_6.jpg"}],"tips":["TIP: The dough will resemble the texture of pizza dough — fairly wet but easy to handle.","TIP: You can simply peel and chop the orange if you'd prefer.","TIP: Slice the onion as thinly as possible. No need to use all of it in your salsa.","TIP: You can eyeball the amount of dough or measure it out in ¼ cups."],"cuisine_tags":["Latin American"],"ingredient_tags":["black beans","masa harina","radish","zucchini"],"item_tags":["lime","orange","turbinado sugar","vegan butter"],"issues":null,"front":"099a_IMG_9332.jpg","back":"099b_IMG_9333.jpg","era":"card","hero":"099.jpg"},{"pair":100,"title":"Power Bowl","subtitle":"with Rainbow Vegetables and Zesty Dijon Dressing","servings":"2","cook_time":"30 minutes","nutrition":{"calories":"530","fat":"32 g","carbohydrates":"50 g","protein":"18 g"},"description":"Tender beluga lentils top this colorful mixture of raw and roasted vegetables, including beautiful and vitamin-rich broccoflower. The taste of crunchy vegetables is balanced out by a zesty Dijon dressing. We suggest you toss the salad with half and serve any remaining on the side.","from_your_kitchen":["1 tbsp olive oil","Salt and pepper"],"ingredients":["⅓ cup beluga lentils","3 tbsp walnuts","5 oz broccoflower florets","3 oz radish","7 oz carrots","1 cucumber","2 tbsp Dijon mustard","2 tbsp agave","1 tbsp rice vinegar","3 tbsp vegan yogurt","5 oz baby spinach","2 tbsp currants"],"tools":["Small saucepan","Baking sheet"],"steps":[{"n":1,"title":"SIMMER THE LENTILS","text":"Preheat the oven to 400°F. Combine the beluga lentils and ⅔ cup water in a small saucepan. Bring to a boil, reduce heat to low, and cook, covered, until lentils are tender and water has been absorbed, about 20 to 25 minutes. Drain any excess water and season with salt and pepper.","img":"100_1.jpg"},{"n":2,"title":"TOAST AND ROAST","text":"Add the walnuts to a baking sheet and bake until lightly toasted, about 4 to 6 minutes. Transfer the walnuts to a bowl. Cut the broccoflower into small florets and add them to the baking sheet. Toss with 1 tbsp olive oil, sprinkle with salt and pepper, and roast until tender and browned in places, about 7 to 9 minutes.","img":"100_2.jpg"},{"n":3,"title":"PREPARE THE VEGETABLES","text":"Thinly slice the radish. Peel the carrots with a peeler and then continue peeling to make ribbons. Slice the cucumber into thin rounds.","img":"100_3.jpg"},{"n":4,"title":"MAKE THE DRESSING","text":"In a medium bowl, combine the Dijon mustard, agave, rice vinegar, yogurt, and a pinch of salt and pepper. Whisk the zesty Dijon dressing until smooth.","img":"100_4.jpg"},{"n":5,"title":"TOSS THE SALAD","text":"In a large bowl, toss the baby spinach, currants, a pinch of salt and pepper, and half of the zesty Dijon dressing.","img":"100_5.jpg"},{"n":6,"title":"SERVE","text":"Divide the dressed spinach between large bowls or plates. Top with sliced radish, carrot ribbons, sliced cucumber, beluga lentils, and roasted broccoflower. Drizzle with remaining zesty Dijon dressing and dig in!","img":"100_6.jpg"}],"tips":["TIP: Beluga lentils hold their shape. When cooked properly, they'll still have a bite.","TIP: Watch the walnuts carefully—they burn easily.","TIP: Use a mandoline to slice the radish and cucumber if you have one."],"cuisine_tags":["American"],"ingredient_tags":["broccoflower","carrot","cucumber","lentils","radish","spinach"],"item_tags":["agave","currants","dijon mustard","rice vinegar","vegan yogurt","walnuts"],"issues":null,"front":"100a_IMG_9334.jpg","back":"100b_IMG_9335.jpg","era":"card","hero":"100.jpg"},{"pair":101,"title":"Wicked Healthy Fajita Tostada","subtitle":"with Chili-Lime Mango Salad","servings":"2","cook_time":"35 minutes","nutrition":{"calories":"580","fat":"15 g","carbohydrates":"91 g","protein":"25 g"},"description":"Our friends at Wicked Healthy have come up with another stellar dish here and these spicy, sweet tostadas could be our new favorite. The trick to a crispy tortilla is to get an even, light coat of oil. Try using your hands if you don't have a pastry brush. We recommend that you bake the tortillas pressed between baking sheets to keep them flat, but if you'd prefer a more rustic look, by all means, leave them uncovered! To top off your dish, enjoy a Mexican classic, chili-lime mango salad.","from_your_kitchen":["1 tbsp + 2 tsp vegetable oil","Salt and pepper"],"ingredients":["½ cup red lentils","4 corn tortillas","5 garlic cloves*","3 mini sweet peppers","1 red onion","1 lime","1 mango","1 tsp Mexican chili spice*","1 avocado","3 oz green cabbage"],"tools":["Small saucepan","2 baking sheets","Large skillet"],"steps":[{"n":1,"title":"COOK THE LENTILS","text":"Preheat the oven to 400°F. Add the red lentils, 1 cup water, and a pinch of salt to a small saucepan. Bring to a boil, cover, and reduce heat to low. Cook until the lentils are tender and all of the water has been absorbed, about 14 to 17 minutes.","img":"101_1.jpg"},{"n":2,"title":"CRISP THE TOSTADAS","text":"Lay the corn tortillas on a baking sheet. Brush both sides of each tortilla with ½ tsp vegetable oil and place another baking sheet on top to hold them down. Bake tortillas until golden brown and crisp, about 10 to 12 minutes.","img":"101_2.jpg"},{"n":3,"title":"PREPARE THE FAJITA VEGGIES","text":"Peel and thinly slice the 5 cloves of garlic. Trim, deseed, and slice the mini sweet peppers. Peel and thinly slice the red onion. Place a large skillet over medium-high heat and add 1 tbsp vegetable oil. Once hot, add the garlic, sliced peppers and onion, and a pinch of salt and pepper. Adjust heat to low, and cook until vegetables are soft and caramelized, stirring occasionally, about 12 to 15 minutes.","img":"101_3.jpg"},{"n":4,"title":"MAKE THE MANGO SALAD","text":"Zest the lime. Peel the mango, remove the flesh from the pit, and dice. In a large bowl combine the diced mango, lime zest, and the juice from half the lime. Sprinkle mango salad with a ½ tsp of the Mexican chili spice and toss to combine.","img":"101_4.jpg"},{"n":5,"title":"FINISH IT UP","text":"Once the lentils are ready, mash them with a fork (they should be spreadable). Squeeze in the juice from the remaining lime half, taste, and season with salt and pepper. Halve the avocado, remove the pit, and slice the flesh.","img":"101_5.jpg"},{"n":6,"title":"SERVE AND ENJOY","text":"Place the tostadas on large plates and top with the smashed red lentils. Layer on the fajita veggies, green cabbage, and avocado. Sprinkle with cilantro and remaining Mexican chili spice and serve with the chili-lime mango salad. Dig in!","img":"101_6.jpg"}],"tips":["* This item will be split between multiple steps.","* Find a head of garlic in this recipe bag.","Lay the tortillas on your largest baking sheet, it's ok if they overlap slightly."],"cuisine_tags":["Mexican"],"ingredient_tags":["avocado","bell pepper","cabbage","mango","red lentils","tortilla"],"item_tags":["corn tortillas","lime","mexican chili spice","vegetable oil"],"issues":null,"front":"101a_IMG_9336.jpg","back":"101b_IMG_9337.jpg","era":"card","hero":"101.jpg"},{"pair":102,"title":"Fabcake Sliders","subtitle":null,"servings":"2","cook_time":"35 minutes","nutrition":{"calories":"720","fat":"34 g","carbohydrates":"96 g","protein":"19 g"},"description":"These cakes are fabulous, so we've nicknamed them \"fabcakes\" and popped them on slider buns. You'll use half of the garbanzo beans for this recipe, save the remaining garbanzos for the Curried Flatbread. The vegan remoulade, a creamy sauce often paired with seafood, adds a tangy and salty kick and pairs perfectly with the corn too.","from_your_kitchen":null,"ingredients":[],"tools":null,"steps":[],"tips":[],"cuisine_tags":["American","Cajun/Creole"],"ingredient_tags":["chickpeas","corn","slider buns"],"item_tags":["remoulade"],"single_page":false,"issues":null,"front":"102a_IMG_9338.jpg","back":null,"era":"card","hero":"102.jpg"},{"pair":103,"title":"Za'atar Sweet Potato Noodles","subtitle":"with Crispy Chickpeas and Broccolini","servings":"2","cook_time":"30 minutes","nutrition":{"calories":"690","fat":"40 g","carbohydrates":"60 g","protein":"20 g"},"description":"In this simple and delicious meal, sweet potato noodles act as pasta. You'll toss them in a light lemon vinaigrette and season them with za'atar, a Middle Eastern spice blend of sumac, thyme, oregano, and sesame seeds. Thai basil leaves are the final touch, giving the dish another layer of flavor.","from_your_kitchen":["1 tbsp vegetable oil","3 tbsp + 2 tsp olive oil","Salt and pepper"],"ingredients":["6 oz broccolini","1 can chickpeas","1 lemon","2 cloves garlic°","2 tsp champagne vinegar","1 tbsp za'atar*","1 tsp dried mint","8 oz sweet potato noodles","Fresh Thai basil","2 tbsp hemp seeds"],"tools":["Large pot","Baking sheet","Large skillet"],"steps":[{"n":1,"title":"SET THE STAGE","text":"Preheat the oven to 400°F. Place a large pot of salted water on to boil. Trim the broccolini and roughly chop. Drain the chickpeas, rinse, and pat dry with a paper towel.","img":"103_1.jpg"},{"n":2,"title":"PREPARE THE VINAIGRETTE","text":"Zest the lemon over a medium bowl. Peel and grate the garlic into the bowl. Then add the juice from the lemon and the champagne vinegar. While whisking, slowly drizzle in 3 tbsp olive oil. Season vinaigrette with salt and pepper.","img":"103_2.jpg"},{"n":3,"title":"BAKE THE CHICKPEAS","text":"Add the chickpeas to a baking sheet and toss with 1 tbsp vegetable oil, 2 tsp of the za'atar spice, and dried mint. Season generously with salt and pepper and bake until chickpeas are crispy and lightly browned, about 14 to 16 minutes.","img":"103_3.jpg"},{"n":4,"title":"BEGIN TO COOK","text":"Place a large skillet over medium-high heat with 2 tsp olive oil. Once hot, add the broccolini and cook, tossing occasionally, until bright green and crisp-tender, about 4 to 6 minutes. Drop the sweet potato noodles into the boiling water and cook until al dente, about 3 to 4 minutes. Drain the noodles and add to the skillet with broccolini.","img":"103_4.jpg"},{"n":5,"title":"ADD THE VINAIGRETTE","text":"Add the vinaigrette to the skillet, sprinkle sweet potato noodles with salt and pepper, and toss to combine. Reduce heat to medium and cook for 2 minutes, or until heated through.","img":"103_5.jpg"},{"n":6,"title":"SERVE AND ENJOY","text":"Hand tear the Thai basil leaves. Top the lemon za'atar noodles with crispy chickpeas, hemp seeds, and Thai basil. Sprinkle with remaining za'atar and serve lemon za'atar noodles family style. Dig in!","img":"103_6.jpg"}],"tips":["°Find a head of garlic in the Forest Bowl recipe bag.","*This item will be split between multiple steps.","TIP: Crisp-tender means the vegetable should still have a good crunch."],"cuisine_tags":["Middle Eastern"],"ingredient_tags":["broccolini","chickpeas","sweet potato noodles"],"item_tags":["champagne vinegar","dried mint","hemp seeds","lemon","thai basil","za'atar"],"issues":null,"front":"103a_IMG_9340.jpg","back":"103b_IMG_9341.jpg","era":"card","hero":"103.jpg"},{"pair":104,"title":"Spiced Chickpea Grain Bowl","subtitle":"with Freekeh Tabbouleh and Roasted Beets","servings":"2","cook_time":"40 minutes","nutrition":{"calories":"710","fat":"35 g","carbohydrates":"83 g","protein":"27 g"},"description":"Freekeh is not only a fun word to say, but there is also a great story behind each grain. The wheat that will become freekeh is actually harvested very young, roasted, and then sun dried. This technique gives the grain its distinctive chewy texture and nutty flavor, and it really shines in this herb packed tabbouleh. If you don't have two baking sheets, any oven safe casserole dish will work for roasting the beets and chickpeas.","from_your_kitchen":["2 tbsp + 2 tsp olive oil","1 tbsp vegetable oil","Salt and pepper"],"ingredients":["¾ cup freekeh","7 oz red beet","1 tbsp sesame seeds","1 can chickpeas","1 tsp berbere spice","1 cucumber","1 scallion","3 oz grape tomatoes","Fresh mint","Fresh parsley","1 lemon","3 tbsp vegan yogurt"],"tools":["Small saucepan","2 Baking sheets"],"steps":[{"n":1,"title":"COOK THE FREEKEH","text":"Preheat the oven to 425°F. Place a small saucepan over medium-high and add the freekeh. Toast in the dry pan, shaking occasionally, until the freekeh becomes fragrant, about 2 minutes. Add 1¾ cups water, a pinch of salt, and bring to a boil. Reduce heat to low, cover, and let simmer until water has been absorbed, about 20 to 25 minutes. Remove from heat and let freekeh stand for an additional 5 minutes.","img":"104_1.jpg"},{"n":2,"title":"ROAST THE BEET","text":"Peel the beet and thinly slice. Transfer to a baking sheet and toss with 2 tsp olive oil and a pinch of salt and pepper. Roast until beets are tender, about 15 to 18 minutes. Sprinkle the sesame seeds on the roasted beets and return to the oven until the seeds are golden and toasted, an additional 3 to 5 minutes.","img":"104_2.jpg"},{"n":3,"title":"BAKE THE CHICKPEAS","text":"Drain and rinse the chickpeas and pat dry with a paper towel. Add to a baking sheet and toss with 1 tbsp vegetable oil and berbere spice. Season the chickpeas generously with salt and pepper and bake until crispy and lightly browned, about 14 to 16 minutes.","img":"104_3.jpg"},{"n":4,"title":"PREP THE TABBOULEH","text":"Thinly slice the cucumber and the scallion. Halve the grape tomatoes. Roughly chop the mint and parsley leaves.","img":"104_4.jpg"},{"n":5,"title":"MIX THE TABBOULEH","text":"When the freekeh has finished cooking, add the cucumber, grape tomatoes, scallion, mint, and parsley to the saucepan. Stir in juice from half the lemon and 2 tbsp olive oil. Season freekeh tabbouleh liberally with salt and pepper. Cut the remaining lemon half into wedges.","img":"104_5.jpg"},{"n":6,"title":"PLATE","text":"Divide the freekeh tabbouleh between large bowls or plates. Top with sesame roasted beets and spiced chickpeas. Dollop with vegan yogurt and serve with lemon wedges.","img":"104_6.jpg"}],"tips":["Add more or less berbere spice depending on your affinity for heat."],"cuisine_tags":["Mediterranean","Middle Eastern"],"ingredient_tags":["beets","chickpeas","cucumber","freekeh","tomato"],"item_tags":["berbere spice","lemon","mint","parsley","sesame seeds","vegan yogurt"],"issues":null,"front":"104a_IMG_9342.jpg","back":"104b_IMG_9343.jpg","era":"card","hero":"104.jpg"},{"pair":105,"title":"Wicked Healthy Chopped Salad","subtitle":"with Charred Vegetables and Ginger-Miso Dressing","servings":"2","cook_time":"30 minutes","nutrition":{"calories":"520","fat":"19 g","carbohydrates":"71 g","protein":"22 g"},"description":"This summer recipe comes from our good friends at Wicked Healthy, a Boston based Chef duo that want you to eat your vegetables and have them taste great. It can be easily adapted for a grill, so heat one up before you begin and forgo the skillet in Step 4. The garbanzo beans get pan toasted and dusted with a smoked nori spice: black and white sesame seeds with nori and smoky spices. Serve this meal family style lightly drizzled with dressing.","from_your_kitchen":["1 tbsp olive oil","Salt and pepper"],"ingredients":["½ head savoy cabbage","10 oz zucchini","1 can garbanzo beans","5 oz lacinato kale","3 scallions","1 Thai chile","Fresh cilantro","Fresh mint","1 orange","Fresh ginger","2 tbsp white miso paste","1 tbsp sesame oil","1 tbsp smoked nori spice*"],"tools":["Large nonstick skillet"],"steps":[{"n":1,"title":"PREP THE GRILLED VEGETABLES","text":"Halve the savoy cabbage and reserve half for the Okonomiyaki recipe if you have not made it yet. Cut the remaining cabbage in half. Cut the zucchini into planks, about 3 to 4 inches long. Drain the garbanzo beans and dry well with a paper towel.","img":"105_1.jpg"},{"n":2,"title":"PREP THE SALAD","text":"Destem and roughly chop the lacinato kale. Thinly slice the scallions and Thai chile. Pick the cilantro and mint leaves from the stems and roughly chop.","img":"105_2.jpg"},{"n":3,"title":"MAKE THE DRESSING","text":"Supreme the orange by trimming both ends and cutting away the peel and pith. Working over a medium bowl, remove the flesh segments, then squeeze out the remaining juice. Transfer the segments to a small bowl. Grate the ginger with a microplane (no need to peel) into the medium bowl with the orange juice and add the white miso paste and sesame oil. Whisk ginger-miso dressing to combine.","img":"105_3.jpg"},{"n":4,"title":"SEAR THE VEGETABLES","text":"Place a large nonstick skillet over medium-high heat and add 2 tsp olive oil. Once hot, add the cabbage and zucchini and season with salt and pepper. Reduce the heat to medium and cook, turning vegetables occasionally until charred in places and tender, about 4 to 6 minutes. Transfer to a cutting board.","img":"105_4.jpg"},{"n":5,"title":"CRISP THE GARBANZOS","text":"Return the skillet to medium-high heat and add 1 tsp olive oil. Add the garbanzos and cook, shaking the skillet frequently, until browned and crispy in places, about 2 to 3 minutes. Season with salt and add 1 tsp smoked nori spice.","img":"105_5.jpg"},{"n":6,"title":"BUILD THE SALAD","text":"In a medium bowl, combine 1 tbsp ginger-miso dressing with the kale and massage with your hands for about 1 minute. Chop the charred vegetables. Serve the salad on a large platter with the kale, chopped vegetables, and crispy garbanzos. Top with scallion, chiles, orange, herbs, and remaining smoked nori spice. Serve with ginger-miso dressing. Dig in!","img":"105_6.jpg"}],"tips":["* The head of cabbage included in this recipe is also for the Okonomiyaki.","* This item will be split between multiple steps.","Thai chiles are hot. If you're sensitive to spice, simply omit.","Don't have a mircoplane? Peel the ginger and mince.","This part of the dish can be grilled! Grill on high and cook until the vegetables are tender."],"cuisine_tags":["Fusion","Japanese"],"ingredient_tags":["cabbage","chickpeas","kale","zucchini"],"item_tags":["cilantro","ginger","mint","miso","orange","sesame oil","smoked nori spice","thai chile"],"issues":null,"front":"105a_IMG_9344.jpg","back":"105b_IMG_9345.jpg","era":"card","hero":"105.jpg"},{"pair":106,"title":"Butternut Barley Bowl","subtitle":"with Pickled Peppers and Pistachios","servings":"2","cook_time":"35 minutes","nutrition":{"calories":"580","fat":"24 g","carbohydrates":"84 g","protein":"13 g"},"description":"To us, nothing says autumn like fresh herbs — especially rosemary and parsley. In this fall-inspired recipe, we use these herbs to add warmth to some hearty pearled barley and butternut squash. The sweetness of the squash is the perfect complement to the pickled peppers. This combination will leave your taste buds happy and your stomach satisfied.","from_your_kitchen":["2 tsp olive oil","Salt and pepper"],"ingredients":["¾ cup barley","8 oz butternut squash","2 mini sweet peppers","1 packet turbinado sugar","2 tbsp apple cider vinegar","Pink peppercorns","1 garlic clove*","Fresh parsley","2 sprigs rosemary","1 scallion","¼ cup pistachios","2 tbsp vegan butter","2 oz baby arugula"],"tools":["2 small saucepans","Baking sheet","Large skillet"],"steps":[{"n":1,"title":"COOK THE BARLEY","text":"Preheat the oven to 400°F. Place the barley in a small saucepan and cover with 2 inches of water. Bring to a boil, season with salt, and cook until tender, about 22 to 25 minutes. Drain barley and toss with 1 tsp olive oil to prevent sticking.","img":"106_1.jpg"},{"n":2,"title":"ROAST THE BUTTERNUT","text":"Place the butternut squash onto a baking sheet and toss with 1 tsp olive oil. Sprinkle with salt and pepper and roast until tender and browned in places, about 18 to 20 minutes.","img":"106_2.jpg"},{"n":3,"title":"PICKLE THE PEPPERS","text":"Slice the mini sweet peppers into very thin strips, about ¼-inch thick. Add peppers to a small saucepan with the turbinado sugar, ¼ cup water, apple cider vinegar, pink peppercorns, and a pinch of salt. Bring to a boil and then reduce heat to low. Simmer until the peppers are soft and the liquid is syrupy, about 10 to 12 minutes.","img":"106_3.jpg"},{"n":4,"title":"CHOP THE HERBS","text":"Peel and mince 1 garlic clove. Roughly chop the parsley leaves. Destem the rosemary and mince the leaves. Thinly slice the scallion.","img":"106_4.jpg"},{"n":5,"title":"TOAST THE PISTACHIOS","text":"Add the pistachios to a large skillet over medium heat. Cook until toasted and fragrant, about 3 to 4 minutes. Add the minced garlic and vegan butter to the skillet, and cook for an additional minute. Add the cooked barley, chopped parsley, rosemary, and scallions. Season with salt and pepper and toss to combine.","img":"106_5.jpg"},{"n":6,"title":"FINISH UP","text":"Stir the baby arugula into the barley mixture and divide between two large bowls. Top herbed barley with roasted butternut squash and pickled peppers. Bon appétit!","img":"106_6.jpg"}],"tips":["* Find a head of garlic in this recipe bag.","TIP: Leave the peppers in the hot liquid off of the stove once finished."],"cuisine_tags":["American","Comfort Food"],"ingredient_tags":["arugula","barley","bell pepper","butternut squash"],"item_tags":["apple cider vinegar","pink peppercorns","pistachios","rosemary","turbinado sugar","vegan butter"],"issues":null,"front":"106a_IMG_9346.jpg","back":"106b_IMG_9347.jpg","era":"card","hero":"106.jpg"},{"pair":107,"title":"Cashew Korma","subtitle":"with Cauliflower Rice","servings":"2","cook_time":"35 minutes","nutrition":{"calories":"710","fat":"43 g","carbohydrates":"73 g","protein":"22 g"},"description":"The word \"korma\" means \"to braise,\" and that's how the cashews and vegetables — red bell pepper, Yukon potatoes, and peas — are cooked here. For this dish, we slowly cook the vegetables in coconut milk and layer in flavor with spices. This method mimics the effects of roasting, but cuts cook time in half.","from_your_kitchen":["2 tbsp vegetable oil","Salt and pepper"],"ingredients":["4 ounces Yukon gold potatoes","1 head cauliflower","1 onion","1 garlic clove*","Fresh ginger","1 red bell pepper","1 can garbanzo beans","2 tsp Indian spice blend","¼ cup cashews","¼ tsp red chile flakes","1 can coconut milk","¼ cup green peas","1 lemon"],"tools":["Medium saucepan","Food processor","Large nonstick skillet"],"steps":[{"n":1,"title":"MAKE THE CAULIFLOWER RICE","text":"Peel the potatoes, dice, and add to a medium saucepan. Cover with 1 inch water, bring to a boil, and cook until tender, about 12 to 15 minutes. Reserve ¼ cup cooking water and drain potatoes in a colander. Chop the cauliflower into florets. In batches, pulse the cauliflower in a food processor, until it reaches an even, rice-like consistency.","img":"107_1.jpg"},{"n":2,"title":"CUT THE VEGGIES","text":"Peel and dice the onion. Peel and mince 1 garlic clove. Peel and mince the ginger. Deseed and chop the red bell pepper.","img":"107_2.jpg"},{"n":3,"title":"COOK THE RICE","text":"Place a large nonstick skillet over medium-high heat with 1 tbsp vegetable oil. Add the cauliflower rice, sprinkle with salt and pepper, and cook, tossing occasionally, until it's just tender, about 5 to 7 minutes. Cover to keep warm. Drain and rinse the garbanzo beans.","img":"107_3.jpg"},{"n":4,"title":"START THE KORMA","text":"Return the large skillet to medium-high heat and add 1 tbsp vegetable oil. Add the onions and cook until slightly softened, 3 or 4 minutes. Add the Indian spice blend, garlic, ginger, bell pepper, cashews, and as much of the red chile flake as you'd like. Cook, stirring frequently until fragrant, about 1 minute.","img":"107_4.jpg"},{"n":5,"title":"SIMMER THE KORMA","text":"Add the cooked potatoes, garbanzo beans, coconut milk, peas, and reserved cooking water to the skillet. Bring sauce to a simmer, add the juice from half the lemon to the skillet, and reduce heat to low. Simmer korma, stirring occasionally, until the sauce is slightly thickened, about 4 to 6 minutes. Cut remaining lemon half into wedges.","img":"107_5.jpg"},{"n":6,"title":"SERVE AND ENJOY","text":"Taste the korma and season with salt. Divide the cauliflower rice between bowls and top with cashew korma. Serve with lemon wedges. Dig in!","img":"107_6.jpg"}],"tips":["* Find a head of garlic in the Butternut Barley Bowl recipe bag.","TIP: You can use a box grater to grate the cauliflower instead of a food processor."],"cuisine_tags":["Indian"],"ingredient_tags":["cashews","cauliflower","chickpeas","peas","potato"],"item_tags":["coconut milk","ginger","indian spice blend","lemon","red chile flakes"],"issues":null,"front":"107a_IMG_9348.jpg","back":"107b_IMG_9349.jpg","era":"card","hero":"107.jpg"},{"pair":108,"title":"Taco Salad","subtitle":"with Chipotle Seitan and Cashew Cheese Sauce","servings":"2","cook_time":"35 minutes","nutrition":{"calories":"710","fat":"35 g","carbohydrates":"64 g","protein":"43 g"},"description":"Nacho cheese sauce that's packed with protein? Yes, please! Our cashew \"cheese\" sauce takes only a couple minutes to whisk up, and we do it last minute to ensure it's hot for serving. If you want to reheat, simply whisk in a bit warm water. If you prefer not to fry the tortilla strips, brush the tortillas lightly with oil before slicing and then roast them in the oven at 400°F until they are browned and crisp.","from_your_kitchen":["½ cup vegetable oil","Salt and pepper"],"ingredients":["1 ear corn","2 oz radishes","1 heart of romaine","2 corn tortillas","1 package Sweet Earth chipotle seitan","¼ cup black olives","¼ cup pickled jalapeños","1 lime","2 tbsp cashew butter","2 tbsp nutritional yeast","¼ tsp turmeric","½ tsp paprika"],"tools":["Medium nonstick skillet","Small saucepan"],"steps":[{"n":1,"title":"PREPARE THE TOPPINGS","text":"Remove the husk from the corn and cut the kernels off the cob. Thinly slice the radishes. Roughly chop the romaine.","img":"108_1.jpg"},{"n":2,"title":"CRISP THE TORTILLAS","text":"Place a medium nonstick skillet over medium-high heat and add ½ cup vegetable oil. Slice the corn tortillas into thin strips. Once the oil is hot, add the tortilla strips and cook until golden brown and crisp, about 1 minute. Transfer to a paper towel lined plate and sprinkle immediately with salt. Transfer the hot oil to a heatproof container and return the skillet to medium-high heat.","img":"108_2.jpg"},{"n":3,"title":"COOK THE SEITAN","text":"Add the Sweet Earth chipotle seitan to the hot skillet and cook, stirring occasionally, until browned in places, about 4 to 5 minutes. Season seitan with salt and pepper.","img":"108_3.jpg"},{"n":4,"title":"BUILD THE SALAD","text":"Place the chopped romaine on large plates and top with the corn, radishes, black olives, pickled jalapeños, and chipotle seitan. Halve the lime and squeeze half over the taco salads.","img":"108_4.jpg"},{"n":5,"title":"MAKE THE CHEESE SAUCE","text":"Add the cashew butter, nutritional yeast, turmeric, paprika, ½ tsp salt, and ½ cup cold water to a small saucepan. Bring sauce to a simmer while whisking continuously, until just thickened, about 30 seconds to 1 minute. Once thickened, add juice from remaining lime, stir, and remove from heat.","img":"108_5.jpg"},{"n":6,"title":"SERVE IT UP","text":"Drizzle taco salads with some of the cashew cheese sauce and top with tortillas strips. Serve any remaining sauce on the side. Dig in!","img":"108_6.jpg"}],"tips":["No need to wipe out the empty skillet."],"cuisine_tags":["Mexican"],"ingredient_tags":["corn","radish","romaine lettuce","seitan","tortilla"],"item_tags":["black olives","cashew butter","chipotle","lime","nutritional yeast","paprika","pickled jalapeños","turmeric"],"issues":null,"front":"108a_IMG_9350.jpg","back":"108b_IMG_9351.jpg","era":"card","hero":"108.jpg"},{"pair":109,"title":"Winter Squash Flatbread","subtitle":"with Caramelized Apple and Rosemary","servings":"2","cook_time":"35 minutes","nutrition":{"calories":"560","fat":"25 g","carbohydrates":"78 g","protein":"12 g"},"description":"Despite the rich flavors, this flatbread is remarkably light. You'll create a creamy \"bechamel,\" or \"white sauce,\" using vegan butter, almond milk, and a squeeze of lemon juice. The squash and apple toppings add a sweet note that offsets the bitter punch of arugula. You may have extra minced rosemary —save it for cooking on your own.","from_your_kitchen":["2 tsp vegetable oil","1 tsp olive oil","Salt and pepper"],"ingredients":["2 sprigs rosemary*","8 oz squash","1 shallot","1 garlic clove*","½ cup almond milk","2 tbsp vegan butter","1 tsp arrowroot starch","1 lemon","1 apple","2 pieces naan","2 oz baby arugula","2 tsp white balsamic vinegar"],"tools":["Baking sheet","Small saucepan","Large nonstick skillet"],"steps":[{"n":1,"title":"ROAST THE SQUASH","text":"Preheat the oven to 425°F. Strip the rosemary leaves from the stems and mince the leaves. Add the squash to a baking sheet with 1 tsp vegetable oil, just 1 tsp minced rosemary, and a pinch of salt and pepper. Roast until the squash begins to brown in places, about 14 to 18 minutes. Peel and mince the shallot. Peel and mince 1 clove garlic.","img":"109_1.jpg"},{"n":2,"title":"MAKE THE BECHAMEL","text":"Place a small saucepan over medium heat and add the butter. Add the shallot and garlic and cook until softened, about 2 to 3 minutes. Add arrowroot starch and stir into a paste. Add the juice from half the lemon, almond milk, and a pinch of salt. Stir until thickened, about 1 minute, and remove from the heat.","img":"109_2.jpg"},{"n":3,"title":"CARAMELIZE THE APPLE","text":"Thinly slice the apple. Place a large nonstick skillet over medium-high heat with 1 tsp vegetable oil. Add the sliced apple and 1 tsp of the remaining minced rosemary to the skillet. Sprinkle with salt and cook, stirring frequently, until tender and browned in places, about 4 to 6 minutes. Squeeze in the juice from the remaining lemon onto the apples.","img":"109_3.jpg"},{"n":4,"title":"CRISP THE NAAN","text":"Pop the naan into the oven and heat until it's a little crispy, about 5 to 8 minutes.","img":"109_4.jpg"},{"n":5,"title":"BUILD THE FLATBREADS","text":"Spread the bechamel sauce onto the naan and top with the roasted squash and caramelized apples. Pop the flatbreads back into the oven for 3 minutes to warm. In a medium bowl, toss the arugula with 1 tsp olive oil and a pinch of salt and pepper.","img":"109_5.jpg"},{"n":6,"title":"CUT AND SERVE","text":"Top the winter squash flatbreads with some of the arugula salad. Drizzle with white balsamic vinegar and slice. Serve alongside any remaining arugula salad. Dig in!","img":"109_6.jpg"}],"tips":["*These items will be split between multiple steps.","*Find a head of garlic in the Beetroot Taco recipe bag.","TIP: Toss apples frequently to avoid burning.","TIP: If there are any remaining apples, toss them into the arugula."],"cuisine_tags":["American","Fusion"],"ingredient_tags":["apple","arugula","naan","squash"],"item_tags":["almond milk","arrowroot starch","lemon","rosemary","vegan butter","white balsamic vinegar"],"issues":null,"front":"109a_IMG_9352.jpg","back":"109b_IMG_9353.jpg","era":"card","hero":"109.jpg"},{"pair":110,"title":"Shakshuka","subtitle":"with Poached Tofu and Crispy Kale Chips","servings":"2","cook_time":"30 minutes","nutrition":{"calories":"610","fat":"22 g","carbohydrates":"79 g","protein":"28 g"},"description":"Middle Eastern shakshuka tends to be a breakfast dish, but it translates well to dinner. You'll poach creamy, protein-packed tofu instead of eggs. The sauce comes together fairly quickly, and will gain flavor as it simmers. When you're ready to dollop the tofu in, use a large, rounded spoon for best results.","from_your_kitchen":["2 tbsp + 1 tsp olive oil","Salt and pepper"],"ingredients":["¾ cup freekeh","1 onion","1 red bell pepper","2 cloves garlic°","4 oz red kale","½ tsp cumin","½ tsp sweet paprika","½ tsp red chile flakes","1 can fire-roasted tomatoes","1 package silken tofu","Fresh cilantro"],"tools":["Small saucepan","Large skillet","Baking sheet"],"steps":[{"n":1,"title":"MAKE THE FREEKAH","text":"Preheat the oven to 375°F. Add the freekeh, 1¼ cups water, and a pinch of salt to a small saucepan. Bring to a boil, cover, and cook until all of the water is absorbed and the grains are tender, about 20 to 25 minutes.","img":"110_1.jpg"},{"n":2,"title":"PREPARE THE VEGETABLES","text":"Peel and slice the onion. Deseed and thinly slice the red bell pepper. Peel and slice the garlic. Destem the red kale and hand tear the leaves into large pieces.","img":"110_2.jpg"},{"n":3,"title":"START THE SHAKSHUKA","text":"Place a large skillet over medium-high heat with 2 tbsp olive oil. Add the sliced onion and red bell pepper, reduce heat to medium, and cook until soft, about 6 to 8 minutes. Add the garlic, cumin, paprika, and a pinch of the red chile flakes, and cook until fragrant, about 1 minute. Add the fire-roasted tomatoes and ½ cup water. Simmer until the sauce has thickened slightly, about 8 to 10 minutes.","img":"110_3.jpg"},{"n":4,"title":"MAKE THE KALE CHIPS","text":"Add the red kale leaves to a baking sheet and toss with 1 tsp olive oil. Sprinkle with salt and pepper. Roast until crisp, about 8 to 10 minutes.","img":"110_4.jpg"},{"n":5,"title":"DOLLOP THE TOFU","text":"Taste and season the shakshuka sauce with salt and pepper. Open the silken tofu. Use a large spoon to gently scoop out dollops of tofu and drop them into the sauce. Sprinkle with salt and pepper.","img":"110_5.jpg"},{"n":6,"title":"SERVE AND ENJOY","text":"Chop the cilantro leaves and tender stems. Divide the freekeh between large plates and top with the shakshuka. Sprinkle with cilantro and serve with the crispy kale chips. Dig in!","img":"110_6.jpg"}],"tips":["°Find a head of garlic in the Miso-Walnut Meatballs recipe bag.","TIP: Add more of the red chile flakes depending on your affinity for heat."],"cuisine_tags":["Middle Eastern"],"ingredient_tags":["bell pepper","freekeh","kale","tofu","tomato"],"item_tags":["cilantro","cumin","fire-roasted tomatoes","red chile flakes","sweet paprika"],"issues":null,"front":"110a_IMG_9354.jpg","back":"110b_IMG_9355.jpg","era":"card","hero":"110.jpg"},{"pair":111,"title":"Spicy Almond Butter Udon","subtitle":"with Charred Brussels Sprouts","servings":"2","cook_time":"35 minutes","nutrition":{"calories":"800","fat":"37 g","carbohydrates":"95 g","protein":"31 g"},"description":"Smooth almond butter blends into to a deliciously creamy sauce with the help of tart lime juice and sweet maple syrup. The citrus-spiked sauce coats crisp pan seared vegetables over udon, a thick Japanese noodle that can stand up to the toppings.","from_your_kitchen":["1 tbsp + 1 tsp vegetable oil","Salt and pepper"],"ingredients":["7 oz Brussels sprouts","4 oz carrot","2 scallions*","7 oz udon noodles","¼ cup + 2 tbsp peanuts*","1 lime","1 garlic clove","3 tbsp almond butter","2 tbsp tamari","1 tbsp chili garlic sauce","2 tsp maple syrup","¼ cup edamame"],"tools":["Large pot","Large nonstick skillet","Blender"],"steps":[{"n":1,"title":"COOK THE UDON","text":"Place a large pot of salted water on to boil. Trim the Brussels sprouts and halve or quarter them. Peel the carrot and cut into 2 inch long sticks. Thinly slice the scallions. When the water comes to a boil, add the udon noodles and cook until al dente, about 6 to 8 minutes. Rinse noodles under cold water and toss with 1 tsp vegetable oil.","img":"111_1.jpg"},{"n":2,"title":"MAKE THE SAUCE","text":"Place a large nonstick skillet over medium-low heat and toast the peanuts, about 4 to 5 minutes. Cool and roughly chop. Halve the lime. In a blender, combine juice from half the lime, garlic, almond butter, tamari, as much of the chili garlic sauce as you'd like, maple syrup, and ¼ cup water. Blend on high until smooth. Add half the peanuts, season with salt, and blend once more.","img":"111_2.jpg"},{"n":3,"title":"CHAR THE BRUSSELS","text":"Place the same skillet over medium-high heat with 1 tbsp vegetable oil. Add the Brussels sprouts and cook, shaking the pan often, until charred in places, about 3 to 5 minutes. Add ¼ cup water to create some steam, reduce heat to medium, and continue cooking until sprouts are bright green and just tender, about 3 to 5 more minutes.","img":"111_3.jpg"},{"n":4,"title":"GET SAUCY","text":"Add the carrots and continue to cook until tender, about 4 to 6 minutes. Reduce heat again to low and add edamame, almond butter sauce, and ¼ cup + 2 tbsp water. Toss vegetables to combine, reduce heat, and bring sauce to a simmer.","img":"111_4.jpg"},{"n":5,"title":"ADD THE UDON","text":"Add the cooked udon to the skillet, taste and season, and toss to combine. Stir in half the chopped scallion.","img":"111_5.jpg"},{"n":6,"title":"FINISH IT UP","text":"Divide spicy almond butter udon between large plates and top with remaining scallion and chopped peanuts. Serve with lime wedges. Dig in!","img":"111_6.jpg"}],"tips":["TIP: To trim the sprouts, slice the bottom and peel away any leaves that look \"weathered.\"","TIP: Your sauce should be fairly smooth with little, textural pieces of peanuts.","TIP: If your sauce is too thick, add warm water by the tbsp to loosen.","* These items will be split between multiple steps."],"cuisine_tags":["Fusion","Japanese"],"ingredient_tags":["brussels sprouts","carrot","edamame","peanuts","udon"],"item_tags":["almond butter","chile garlic sauce","lime","maple syrup","scallions","tamari"],"issues":null,"front":"111a_IMG_9356.jpg","back":"111b_IMG_9357.jpg","era":"card","hero":"111.jpg"},{"pair":112,"title":"Vegetable Pad Thai","subtitle":"with Toasted Peanuts and Lime","servings":"2","cook_time":"30 minutes","nutrition":{"calories":"730","fat":"27 g","carbohydrates":"108 g","protein":"21 g"},"description":"We think you'll be pleasantly surprised at how quickly and easily this takeout favorite can come together in your own kitchen. Instead of a heavily sweetened sauce, we use natural lime juice and cashew butter. Pro tip for rice noodles: they cook quickly, so in Step 2, simply drop them in the boiling water and turn off the heat.","from_your_kitchen":["1 tbsp vegetable oil","Salt"],"ingredients":["6 oz baby bok choy","4 oz green beans","1 red bell pepper","3 scallions","Fresh cilantro","7 oz rice noodles","¼ cup peanuts","1 lime","2 tbsp cashew butter","3 tbsp tamari","1 tbsp sambal chile paste"],"tools":["Large pot","Large skillet"],"steps":[{"n":1,"title":"PREPARE THE VEGETABLES","text":"Place a large pot of salted water on to boil. Trim the bok choy and roughly chop. Cut the green beans in half. Deseed and thinly slice the red bell pepper. Chop the scallions into 2 inch pieces. Chop the cilantro leaves and tender stems.","img":"112_1.jpg"},{"n":2,"title":"COOK THE NOODLES","text":"Once the water is boiling, add the rice noodles and turn off the heat. Stir the noodles occasionally until they are al dente, about 8 to 10 minutes. Drain the noodles and run them under cool water to stop the cooking process.","img":"112_2.jpg"},{"n":3,"title":"TOAST THE PEANUTS","text":"Place a large skillet over medium heat and add the peanuts. Cook, tossing occasionally, until fragrant and toasted, about 4 to 6 minutes. Transfer the toasted peanuts to a small bowl.","img":"112_3.jpg"},{"n":4,"title":"SAUTÉ THE VEGETABLES","text":"Return the large skillet to medium-high heat with 1 tbsp vegetable oil. Once hot, add the bok choy, greens beans, red bell pepper, and scallions. Sprinkle with salt and cook, stirring frequently, until the bell pepper is tender and the bok choy and green beans are bright green, about 3 to 4 minutes.","img":"112_4.jpg"},{"n":5,"title":"ADD THE SAUCE","text":"In a medium bowl, whisk together the juice from the lime, cashew butter, tamari, ⅓ cup hot tap water, and as much of the sambal chile paste as you'd like. Add the sauce to the skillet with the vegetables, and then add the cooked rice noodles. Reduce heat to medium and cook, tossing frequently, until the noodles are heated through, about 2 to 4 minutes.","img":"112_5.jpg"},{"n":6,"title":"SERVE","text":"Divide the vegetable pad Thai between plates. Sprinkle with toasted peanuts and chopped cilantro. Pass any remaining sambal chile paste at the table.","img":"112_6.jpg"}],"tips":["TIP: Bok choy can hide a lot of grit. Make sure to wash well between the leaves.","TIP: Use two forks to help \"untangle\" the rice noodles.","This item is spicy. (1 tbsp sambal chile paste)"],"cuisine_tags":["Thai"],"ingredient_tags":["bell pepper","bok choy","green beans","peanuts","rice noodles"],"item_tags":["cashew butter","cilantro","lime","sambal chile paste","scallions","tamari"],"issues":null,"front":"112a_IMG_9358.jpg","back":"112b_IMG_9359.jpg","era":"card","hero":"112.jpg"},{"pair":113,"title":"Vietnamese Tofu Bowl","subtitle":"with Bamboo Rice and Pickled Vegetables","servings":"2","cook_time":"30 minutes","nutrition":{"calories":"740","fat":"34 g","carbohydrates":"128 g","protein":"17 g"},"description":"This bowl is highlighted by bright colors and bold flavors. Bamboo rice is infused with juice from fresh bamboo, which is where it gets its light green color. The combination of this fragrant rice and sweet and sour pickled vegetables is one of our favorites. We hope it becomes one of yours, too!","from_your_kitchen":["2 tbsp vegetable oil","Salt"],"ingredients":["½ cup bamboo rice","3 oz carrot","1 jalapeño","2 packets turbinado sugar","¼ cup rice vinegar","4 oz shredded daikon radish","⅓ cup potato starch","3 tbsp Follow Your Heart® Vegenaise®","Sriracha","1 package WildWood® organic extra firm sprouted tofu","Fresh cilantro°","4 oz spring mix°"],"tools":["2 small saucepans","Large nonstick skillet"],"steps":[{"n":1,"title":"COOK THE RICE","text":"Combine the bamboo rice, 1 cup water, and a pinch of salt in a small saucepan. Bring to a boil, cover, and reduce heat to low. Cook until all the water is absorbed and the rice is tender, about 14 to 16 minutes. Remove from heat, and let stand for 10 minutes before fluffing rice with a fork.","img":"113_1.jpg"},{"n":2,"title":"PREPARE TO PICKLE","text":"Peel the carrot and then continue to peel lengthwise to create \"noodles.\" Thinly slice the jalapeño.","img":"113_2.jpg"},{"n":3,"title":"PICKLE THE VEGETABLES","text":"Add the turbinado sugar, rice vinegar, and ⅔ cup water to another small saucepan and bring to boil. Add the carrot, shredded daikon radish, and as much of the jalapeño as you'd like. Turn off the heat and move the saucepan to a cool spot on the stovetop.","img":"113_3.jpg"},{"n":4,"title":"PREPARE THE AIOLI AND TOFU","text":"Add the potato starch and a pinch of salt to a plate. In a small bowl, mix together the Vegenaise and as much of the sriracha as you'd like. Drain the tofu and cut into 6 triangles (rectangular slices will also work). Wrap the slices in paper towels and press to drain the excess water.","img":"113_4.jpg"},{"n":5,"title":"COOK THE TOFU","text":"Place a large nonstick skillet over medium-high heat with 2 tbsp vegetable oil. Toss the sliced tofu in the potato starch and shake off any excess. Once the oil is hot, carefully lay the tofu into the skillet, and cook until crispy and lightly golden, about 3 minutes per side. Transfer tofu to a plate and sprinkle with salt.","img":"113_5.jpg"},{"n":6,"title":"SERVE","text":"Pick half of the cilantro leaves and tender stems (saving half for the Spicy Red Curry Ramen). Drain the liquid from the pickled vegetables. Divide the spring mix between large bowls. Top with bamboo rice, crispy tofu, pickled vegetables, and cilantro. Drizzle the Vietnamese tofu bowls with sriracha aioli and serve with any remaining sriracha for an extra, spicy kick. Dig in!","img":"113_6.jpg"}],"tips":["TIP: For best results, rinse bamboo rice in a fine mesh strainer prior to cooking.","TIP: If you prefer less spice, deseed the jalapeño.","TIP: To pick the cilantro leaves means to remove the leafy greens from the stems.","This item is spicy. (jalapeño, sriracha)","°These ingredients will be shared with other recipes this week."],"cuisine_tags":["Vietnamese"],"ingredient_tags":["carrot","daikon","rice","spring mix","tofu"],"item_tags":["cilantro","jalapeño","potato starch","rice vinegar","sriracha","turbinado sugar","vegenaise"],"issues":null,"front":"113a_IMG_9360.jpg","back":"113b_IMG_9361.jpg","era":"card","hero":"113.jpg"},{"pair":114,"title":"Walnut-Crusted Artichokes","subtitle":"with Dijon Lentils and Green Beans","servings":"2","cook_time":"35 minutes","nutrition":{"calories":"740","fat":"46 g","carbohydrates":"68 g","protein":"24 g"},"description":"Artichokes are best paired with creamy notes, and this walnut crust does the job. It will bubble on top, crisping in the the oven while you finish up the warm lentil salad. Roasted green beans are another highlight, and a simple side dish you can add to your repertoire.","from_your_kitchen":["3 tbsp olive oil","Salt and pepper"],"ingredients":["¾ cup French lentils","6 artichoke hearts","Fresh parsley","¼ cup walnuts","3 tbsp Follow Your Heart® Vegenaise®","¼ tsp red chile flakes","1 shallot","6 oz green beans","2 oz roasted red peppers","2 tsp champagne vinegar","1 packet Dijon mustard","1 lemon"],"tools":["Small saucepan","Baking sheet"],"steps":[{"n":1,"title":"COOK THE LENTILS","text":"Add the French lentils, 2 cups water, and a pinch of salt to a small saucepan over high heat. Bring lentils to a boil, reduce heat to low, and simmer until tender, about 18 to 20 minutes. Drain any remaining water and transfer lentils to a medium bowl.","img":"114_1.jpg"},{"n":2,"title":"MAKE THE WALNUT CRUST","text":"Drain the artichokes and halve lengthwise. Finely chop the parsley leaves. Finely chop the walnuts. In a small bowl, combine the parsley, walnuts, Follow Your Heart® Vegenaise®, as much of the red chile flakes as you'd like, and a pinch of salt and pepper.","img":"114_2.jpg"},{"n":3,"title":"PREPARE THE VEGETABLES","text":"Set the oven to broil on low. Place the artichokes on a baking sheet cut-side up and toss with 1 tbsp olive oil and a pinch of salt and pepper. Broil until crispy on the edges, about 10 to 12 minutes. Peel and mince the shallot. Trim the green beans. Chop the roasted red peppers.","img":"114_3.jpg"},{"n":4,"title":"FINISH THE LENTILS","text":"Once the lentils are cooked, add the minced shallot, roasted red peppers, champagne vinegar, Dijon mustard, and 2 tbsp olive oil. Season Dijon lentils with salt and pepper and stir to combine.","img":"114_4.jpg"},{"n":5,"title":"ADD THE GREEN BEANS","text":"Move the roasted artichokes to one side of the baking sheet. Spread the walnut crust over each of the artichokes. Add the green beans to the empty side of the baking sheet and toss only the green beans in any residual oil. Sprinkle with salt and pepper. Broil until green beans are just tender and walnut crust begins to brown, about 3 to 4 minutes.","img":"114_5.jpg"},{"n":6,"title":"PLATE AND EAT UP","text":"Zest the lemon onto the finished artichokes and green beans. Cut the lemon into wedges. Divide the Dijon lentils and green beans between plates and top with the walnut-crusted artichokes. Serve with the lemon wedges. Enjoy!","img":"114_6.jpg"}],"tips":["TIP: Watch artichokes carefully—all broilers are different."],"cuisine_tags":["French","Mediterranean"],"ingredient_tags":["artichokes","green beans","lentils","walnuts"],"item_tags":["champagne vinegar","dijon mustard","lemon","parsley","red chile flakes","roasted red peppers","shallot","vegenaise"],"issues":null,"front":"114a_IMG_9362.jpg","back":"114b_IMG_9363.jpg","era":"card","hero":"114.jpg"},{"pair":115,"title":"Potato Latkes","subtitle":"with Fennel Slaw and Stone Fruit Preserves","servings":"2","cook_time":"45 minutes","nutrition":{"calories":"820","fat":"56 g","carbohydrates":"74 g","protein":"9 g"},"description":"It's latke season! Although they are delicious on their own, you'll make them even better by pairing them with a creamy horseradish sauce and a crunchy fennel slaw. Stone fruit preserves are served on the side—a little bit of this sweet spread goes a long way.","from_your_kitchen":["¼ cup vegetable oil","1 tsp olive oil","Salt and pepper"],"ingredients":["12 oz yukon gold potato","1 onion","1 fennel bulb","3 oz sugar snap peas","2 tbsp white balsamic vinegar","1 tbsp horseradish","6 tbsp Follow Your Heart® Vegenaise®*","2 tbsp flour","½ tsp dried thyme","2 tbsp stone fruit preserves"],"tools":["Box grater","Large nonstick skillet"],"steps":[{"n":1,"title":"GRATE THE POTATOES","text":"Scrub the Yukon gold potato and grate with a box grater into a large bowl. Squeeze the grated potato to remove as much of the water as possible. Discard the liquid, wipe the bowl clean, and return the grated potato. Peel and finely dice the onion. Add just ½ cup of the diced onion and reserve the remaining diced onion for your own use.","img":"115_1.jpg"},{"n":2,"title":"PREPARE THE SLAW","text":"Cut the fennel bulb in half lengthwise, remove the V-shaped core, and thinly slice the bulb. Trim the sugar snap peas and thinly slice. In a medium bowl, combine the sliced fennel, sugar snap peas, white balsamic vinegar, 1 tsp olive oil, and a pinch of salt and pepper. Toss until coated evenly, and set aside.","img":"115_2.jpg"},{"n":3,"title":"MAKE THE SAUCE","text":"In a small bowl, combine the horseradish, just 2 tbsp of Follow Your Heart® Vegenaise®, and a pinch of salt. Stir until well combined.","img":"115_3.jpg"},{"n":4,"title":"FORM THE LATKES","text":"Place a large nonstick skillet over medium-high heat with ¼ cup vegetable oil. To the grated potatoes, add the remaining Vegenaise, flour, thyme, 1 tsp salt, and ½ tsp pepper and stir until well combined. Use a ¼ cup measuring cup to divide the mixture into 6 equal portions, and form them into latkes about 3 inches in diameter.","img":"115_4.jpg"},{"n":5,"title":"COOK THE LATKES","text":"Once the oil is hot, carefully place each latke into the skillet, pressing down with the bottom of the measuring cup until each patty is about a half inch thick. Lower heat to medium and fry until golden brown and crispy, about 3 to 4 minutes per side. Transfer latkes to a paper-towel lined plate and season with salt.","img":"115_5.jpg"},{"n":6,"title":"PLATE AND ENJOY","text":"Divide the fennel slaw between plates. Top with the potato latkes and serve with stone fruit preserves and horseradish sauce. Dig in!","img":"115_6.jpg"}],"tips":["TIP: The more water you squeeze out, the crispier your latkes will be!","TIP: Season with salt while the latkes are hot so it sticks.","*This item will be split between multiple steps."],"cuisine_tags":["Comfort Food","Jewish"],"ingredient_tags":["fennel","onion","potato","sugar snap peas"],"item_tags":["horseradish","stone fruit preserves","thyme","vegenaise","white balsamic vinegar"],"issues":null,"front":"115a_IMG_9364.jpg","back":"115b_IMG_9365.jpg","era":"card","hero":"115.jpg"},{"pair":116,"title":"Butter Roasted Tomato Gratin","subtitle":"with Garlic Breadcrumbs and Toasted Farro","servings":"2","cook_time":"35 minutes","nutrition":{"calories":"810","fat":"28 g","carbohydrates":"109 g","protein":"28 g"},"description":"A gratin is a dish with a crunchy, toasted topping, usually hiding a savory, creamy layer of deliciousness beneath. Here, you'll use kale, cannellini beans and garlicky breadcrumbs, with buttery roasted tomatoes as the base. The roasted garlic sea salt is a quick way to build flavor–adjust the seasoning level to your liking.","from_your_kitchen":["2 tbsp olive oil","Salt and pepper"],"ingredients":["½ cup farro","2 cloves garlic°","1 can tomatoes","2 tbsp vegan butter","Fresh thyme*","¾ cup panko breadcrumbs","2 tsp roasted garlic sea salt","4 oz kale","1 can cannellini beans"],"tools":["Medium saucepan","Baking sheet","8x8 baking dish","Large skillet"],"steps":[{"n":1,"title":"COOK THE FARRO","text":"Preheat the oven to 375°F. Add the farro to a medium saucepan and cover with 1 inch of water. Bring to a boil, reduce heat to low, and simmer until grains are tender but still have a bit of \"chew,\" about 18 to 20 minutes. Drain farro well and spread it out on baking sheet to cool.","img":"116_1.jpg"},{"n":2,"title":"ROAST THE TOMATOES","text":"Mince the garlic. Combine the minced garlic, tomatoes, butter, just half of the thyme sprigs (keep the leaves on), and a pinch of salt and pepper in an 8x8 baking dish. Bake the tomatoes until the butter has melted, about 10 minutes. Open the oven, give the buttered tomatoes a stir, and return the dish to the oven to bake for an additional 15 minutes.","img":"116_2.jpg"},{"n":3,"title":"TOAST THE BREADCRUMBS","text":"Place a large skillet over medium heat with 2 tsp olive oil. Add the panko breadcrumbs and a pinch of the roasted garlic sea salt. Toast the breadcrumbs, stirring frequently, until golden brown, about 2 to 4 minutes. Taste and add more roasted garlic sea salt if you'd like. Transfer the breadcrumbs to a small bowl. Pick the remaining thyme leaves from the stems and finely chop.","img":"116_3.jpg"},{"n":4,"title":"COOK THE KALE","text":"Destem the kale and roughly chop the leaves. Drain and rinse the cannellini beans. Return the large skillet to medium-high heat with 1 tsp olive oil. Once hot, add the chopped kale and reduce heat to medium. Cook the kale until bright green and tender, about 3 to 5 minutes. Add the cannellini beans and season with salt and pepper. Toss to combine, and cook until hot, about 1 minute.","img":"116_4.jpg"},{"n":5,"title":"TOAST THE FARRO","text":"Remove the thyme sprigs from the buttered tomatoes. Top the tomatoes with the kale and cannellini beans and sprinkle with breadcrumbs. Return the gratin to the oven until the top is well-browned, about 3 to 5 minutes. Wipe the skillet clean and return it to medium-high heat with 1 tbsp olive oil. Add the farro and chopped thyme and cook until the grains are crisp and develop a golden sheen, about 5 to 7 minutes.","img":"116_5.jpg"},{"n":6,"title":"SERVE","text":"Divide the toasted farro between large plates and top with the butter roasted tomato gratin.","img":"116_6.jpg"}],"tips":["TIP: To easily destem thyme, run your finger and thumb down the stem.","° The garlic included in this recipe bag is also for the Greek-Style Cauliflower Steaks.","*This item will be used in multiple steps."],"cuisine_tags":["Comfort Food","Italian"],"ingredient_tags":["cannellini beans","farro","kale","tomato"],"item_tags":["garlic","panko breadcrumbs","roasted garlic sea salt","thyme","vegan butter"],"issues":null,"front":"116a_IMG_9366.jpg","back":"116b_IMG_9367.jpg","era":"card","hero":"116.jpg"},{"pair":117,"title":"Tomato-Braised Artichokes","subtitle":"with Bright Dill Sauce and Farro","servings":"2","cook_time":"30 minutes","nutrition":{"calories":"650","fat":"30 g","carbohydrates":"82 g","protein":"16 g"},"description":"Artichokes are rich in vitamins and minerals—and they taste good, too. Farro, an ancient grain packed with antioxidants, serves as the perfect bed for your savory, saucy artichokes. You'll top off the dish with a drizzle of Greek-style dill sauce.","from_your_kitchen":["1 tbsp olive oil","Salt and pepper"],"ingredients":["¾ cup farro","1 shallot","3 cloves garlic","8 oz artichoke hearts","1 oz cured black olives","1 can crushed tomatoes","1 cucumber","Fresh dill","1 lemon","¼ cup Follow Your Heart® Vegenaise®"],"tools":["Small saucepan","Large skillet","Box grater"],"steps":[{"n":1,"title":"COOK THE FARRO","text":"Add the farro to a small saucepan, cover with 1 inch water, and bring to a boil. Cook until the grains are tender, about 18 to 20 minutes. Drain farro and toss with 1 tsp olive oil. Season with salt and pepper and cover to keep warm.","img":"117_1.jpg"},{"n":2,"title":"CUT THE VEGETABLES","text":"Peel and mince the shallot. Mince the garlic. Cut the artichoke hearts in half lengthwise. Check the olives for any pits, remove if necessary, and chop.","img":"117_2.jpg"},{"n":3,"title":"BEGIN TO BRAISE","text":"Place a large skillet over medium-high heat with 2 tsp olive oil. Add the shallot and garlic and cook until fragrant and slightly toasted, about 1 minute. Add the artichokes and stir to combine. Add the crushed tomatoes and 1 cup water. Bring to a boil, reduce heat to low, and simmer artichokes until the sauce has thickened slightly and you're ready to plate.","img":"117_3.jpg"},{"n":4,"title":"PREPARE THE DILL SAUCE","text":"Grate the cucumber on the on the large side of a box grater. Squeeze out the excess water from the cucumber and add cucumber to a medium bowl. Finely chop the dill fronds. Add the dill, juice from half the lemon, Follow Your Heart® Vegenaise®, and a pinch of salt to the bowl. Stir dill sauce to combine.","img":"117_4.jpg"},{"n":5,"title":"ADD THE FINISHING TOUCHES","text":"Cut the remaining lemon half into wedges. Season the artichokes with ½ tsp salt.","img":"117_5.jpg"},{"n":6,"title":"PLATING TIME","text":"Divide the farro between plates and top with the tomato-braised artichokes. Drizzle with dill sauce and sprinkle with the chopped olives. Enjoy!","img":"117_6.jpg"}],"tips":["TIP: The dill fronds are the green wispy leaves on the thick stems."],"cuisine_tags":["Greek","Mediterranean"],"ingredient_tags":["artichokes","cucumber","farro","tomato"],"item_tags":["cured black olives","dill","garlic","lemon","shallot","vegenaise"],"issues":null,"front":"117a_IMG_9368.jpg","back":"117b_IMG_9369.jpg","era":"card","hero":"117.jpg"},{"pair":118,"title":"Black Bean and Squash Enchiladas","subtitle":"with Pumpkin Seed Mole","servings":"2","cook_time":"40 minutes","nutrition":{"calories":"910","fat":"32 g","carbohydrates":"159 g","protein":"33 g"},"description":"The term mole (MOE-lay) describes a wide variety of Mexican sauces. For this dish, you'll use a classic mole paste that includes ancho chiles, almonds, raisins, cocoa, and sesame. This notoriously labor intensive sauce has been simplified here, without sacrificing on flavor.","from_your_kitchen":["1 tbsp + 2 tsp vegetable oil","Salt"],"ingredients":["¼ cup Spanish rice","1 onion","2 cloves garlic°","3 tbsp pumpkin seeds","2 tbsp mole paste","1 can black beans","1 red bell pepper","6 oz butternut squash","1 lime","6 whole wheat tortillas","1 scallion"],"tools":["Small saucepan","Medium saucepan","Large skillet","Blender","8x8 baking dish"],"steps":[{"n":1,"title":"COOK THE RICE","text":"Preheat the oven to 425°F. Combine the Spanish rice and ⅔ cup water in a small saucepan over high heat. Bring to a boil, reduce heat to low, cover, and cook until the rice is tender and the water is absorbed, about 15 to 20 minutes. Peel and dice the onion. Peel and mince the garlic.","img":"118_1.jpg"},{"n":2,"title":"START THE MOLE","text":"Place a medium saucepan over medium-high heat with 2 tsp vegetable oil. Once hot, add the onion and cook until soft and translucent, about 3 to 5 minutes. Reduce heat to medium, add pumpkin seeds and cook, stirring constantly, until the seeds are lightly toasted, about 3 to 5 minutes. Add the garlic and cook until fragrant, about 30 seconds.","img":"118_2.jpg"},{"n":3,"title":"SIMMER THE MOLE","text":"Add 1¼ cups water and mole paste to the pumpkin seed mixture and stir until the paste dissolves. Bring to a boil, reduce heat to low, and cook until sauce has thickened slightly, about 5 to 8 minutes. Drain and rinse the black beans. Deseed and thinly slice the red bell pepper.","img":"118_3.jpg"},{"n":4,"title":"PREPARE THE FILLING","text":"Place a large skillet over medium-high heat with 1 tbsp vegetable oil. Once hot, add the butternut squash and cook until browned in places and tender, about 4 to 6 minutes. Add the sliced pepper and cook until just tender, about 1 to 2 minutes. Add the black beans, cooked Spanish rice, and ½ tsp salt and stir to combine.","img":"118_4.jpg"},{"n":5,"title":"ROLL THE ENCHILADAS","text":"Transfer pumpkin seed mole sauce to a blender and blend until smooth. Add the juice from half the lime and season with 1 tsp salt. Spread ¼ cup of the mole on the bottom of a baking dish. Lay the tortillas on a clean work surface and top each with ½ cup of the vegetable rice mixture, mixing any remainder into the sauced baking dish. Drizzle each with 1 tbsp mole sauce and roll to seal, lying seam-side down into the dish.","img":"118_5.jpg"},{"n":6,"title":"PLATE AND SERVE","text":"Top enchiladas with remaining mole sauce, cover with foil, and bake until warmed through, about 8 to 10 minutes. Cut the remaining lime half into wedges. Thinly slice the scallion. Serve black bean and squash enchiladas on large plates and top with sliced scallion and lime wedges. Olé!","img":"118_6.jpg"}],"tips":["TIP: Be careful blending hot liquids—start on the lowest setting.","°Find a head of garlic in the Forest Bowl recipe bag."],"cuisine_tags":["Mexican"],"ingredient_tags":["bell pepper","black beans","butternut squash","rice","tortilla"],"item_tags":["garlic","lime","mole paste","pumpkin seeds","scallions"],"issues":null,"front":"118a_IMG_9370.jpg","back":"118b_IMG_9371.jpg","era":"card","hero":"118.jpg"},{"pair":119,"title":"Pesto Bean Burgers","subtitle":"with Roasted Peppers and Carrot Fries","servings":"2","cook_time":"30 minutes","nutrition":{"calories":"890","fat":"42 g","carbohydrates":"105 g","protein":"22 g"},"description":"These white bean burgers are deliciously tender on the inside and crispy on the outside. The roasted red peppers and basil not only give the burgers a pop of color but great flavor and texture. You'll finish off the meal with tasty carrot fries.","from_your_kitchen":["2 tsp olive oil","2 tbsp vegetable oil","Salt and pepper"],"ingredients":["1 lemon","1 can cannellini beans","2 garlic cloves*","1 tbsp flaxseed meal","¼ cup garbanzo bean flour","1 tsp herbs de Provence","¼ tsp red pepper flakes","8 oz carrots","½ tsp coriander","2 oz roasted red peppers","2 pretzel buns","Fresh basil","¼ cup Follow Your Heart® Pesto Vegenaise®","1 oz baby kale"],"tools":["Food processor","Baking sheet","Medium nonstick skillet"],"steps":[{"n":1,"title":"PREPARE THE MIX","text":"Preheat the oven to 400°F. Zest the lemon. Drain and rinse the cannellini beans. Add the lemon zest, beans, 2 cloves garlic, flaxseed meal, garbanzo bean flour, herbs de Provence, as much of the red pepper flakes as you'd like, and ¼ tsp salt to the food processor. Pulse a few times to mix, until just combined.","img":"119_1.jpg"},{"n":2,"title":"MAKE THE PATTIES","text":"Divide the bean mixture into two equal portions and form into patties about 1 inch thick. Place in the refrigerator until you're ready to cook them.","img":"119_2.jpg"},{"n":3,"title":"PREP THE CARROT FRIES","text":"Peel the carrots and cut into 4 inch long sticks. On a baking sheet, toss with 2 tsp olive oil, coriander, salt and pepper. Bake carrot fries until tender and brown in places, about 10 to 15 minutes.","img":"119_3.jpg"},{"n":4,"title":"SEAR THE BURGERS","text":"Place a medium nonstick skillet over medium-high heat with 1 tbsp vegetable oil. Cook the burger patties until golden brown and firm, about 4 to 6 minutes per side.","img":"119_4.jpg"},{"n":5,"title":"PREPARE THE TRIMMINGS","text":"Slice the roasted red peppers into thin strips. Pop the pretzel buns in the oven to warm. Pick the basil leaves from the stems.","img":"119_5.jpg"},{"n":6,"title":"BUILD THE BURGERS","text":"Halve the lemon. Spread the top pretzel buns with some of the Follow Your Heart® Pesto Vegenaise®. On the bottom buns layer the burger patties, roasted red peppers, basil, and baby kale. Top with a squeeze of lemon juice and close them up. Serve bean burgers with the carrot fries and any remaining Pesto Vegenaise for dipping. Dig in!","img":"119_6.jpg"}],"tips":["TIP: Add as much or as little of the red pepper flakes as you'd like.","*Find a head of garlic in the Beetroot Taco recipe bag."],"cuisine_tags":["American","Comfort Food"],"ingredient_tags":["cannellini beans","carrot","kale","pretzel buns"],"item_tags":["basil","coriander","flaxseed meal","garbanzo bean flour","herbs de provence","pesto vegenaise","red chile flakes","roasted red peppers"],"issues":null,"front":"119a_IMG_9372.jpg","back":"119b_IMG_9373.jpg","era":"card","hero":"119.jpg"},{"pair":120,"title":"Pumpkin Matar","subtitle":"with Coconut Yogurt and Brown Basmati Rice","servings":"2","cook_time":"35 minutes","nutrition":{"calories":"600","fat":"38 g","carbohydrates":"79 g","protein":"15 g"},"description":"Bright tomato and creamy coconut milk deliver a delicious base for this seriously satisfying dinner. You'll toss tender roasted pumpkin into the sauce for an extra layer of flavor, and add some texture with a sprinkle of pumpkin seeds.","from_your_kitchen":["1 tbsp + 1 tsp vegetable oil","Salt and pepper"],"ingredients":["¾ cup brown basmati rice","8 oz pumpkin","1 onion","1 clove garlic*","Fresh ginger","½ tsp garam masala","2 tbsp tomato paste","1 can coconut milk","½ cup green peas","2 tbsp pumpkin seeds","2 tbsp vegan yogurt"],"tools":["Small saucepan","Baking sheet","Large nonstick skillet"],"steps":[{"n":1,"title":"COOK THE RICE","text":"Preheat the oven to 400°F. Add brown basmati rice, 1¼ cups water, and a pinch of salt to a small saucepan. Bring to a boil, reduce heat to low, and cover. Cook until all water is absorbed and rice is tender, about 30 to 35 minutes.","img":"120_1.jpg"},{"n":2,"title":"ROAST THE PUMPKIN","text":"Add the cubed pumpkin to a baking sheet and toss with 1 tsp vegetable oil. Sprinkle with salt and pepper and roast until tender and browned in places, about 18 to 20 minutes.","img":"120_2.jpg"},{"n":3,"title":"PREPARE THE PRODUCE","text":"Peel and chop the onion. Peel and mince or grate 1 clove garlic. Peel and mince or grate the ginger. Place a large nonstick skillet over medium-high heat with 1 tbsp vegetable oil. Once the oil is hot, add the chopped onion and cook until softened, about 3 to 5 minutes.","img":"120_3.jpg"},{"n":4,"title":"ADD THE AROMATICS","text":"Add the garlic and ginger to the skillet and cook until fragrant, about 1 minute. Add the garam masala and toast for 30 seconds, stirring constantly.","img":"120_4.jpg"},{"n":5,"title":"ADD THE PUMPKIN","text":"Add the tomato paste, coconut milk, and ½ cup water to the skillet, and lower heat to medium. Simmer sauce until slightly thickened, about 4 to 6 minutes. Add the roasted pumpkin and green peas to the simmering sauce and season with salt and pepper. Stir to combine.","img":"120_5.jpg"},{"n":6,"title":"SERVE IT UP","text":"Divide brown basmati rice between large plates or bowls and top with the pumpkin matar. Garnish with pumpkin seeds and yogurt. Enjoy!","img":"120_6.jpg"}],"tips":["TIP: Use a microplane to grate the garlic and ginger if you have one.","TIP: Watch the garam masala carefully so it does not burn.","Once you add the coconut milk, keep a sauce at a simmer to keep it smooth.","*You'll use the head of garlic in this recipe bag in all recipes this week."],"cuisine_tags":["Indian"],"ingredient_tags":["peas","pumpkin","rice"],"item_tags":["coconut milk","garam masala","ginger","pumpkin seeds","tomato paste","vegan yogurt"],"issues":null,"front":"120a_IMG_9374.jpg","back":"120b_IMG_9375.jpg","era":"card","hero":"120.jpg"},{"pair":121,"title":"Loaded Burritos","subtitle":"with Tofu \"Chorizo\" and Spanish Rice","servings":"2","cook_time":"35 minutes","nutrition":{"calories":"990","fat":"45 g","carbohydrates":"137 g","protein":"39 g"},"description":"The Spanish rice you'll use in these loaded burritos is packed with goodness, including paprika, bell peppers, celery, onions, and kaniwa (a grain similar to quinoa). There are so many delicious ingredients in this recipe that you may have trouble keeping all of the filling inside the burritos. Stuff them with what you can and serve any remaining beans and rice on the side.","from_your_kitchen":["1 tbsp + 2 tsp vegetable oil","Salt"],"ingredients":["¼ cup Spanish rice","1 onion","2 cloves garlic*","1 can black beans","1 package WildWood® organic sprouted tofu","4 oz Lacinato kale","2 oz roasted red peppers","½ tsp Mexican oregano","1 tsp Mexican chile spice","2 whole wheat tortillas","¼ cup Follow Your Heart® Chipotle Vegenaise®","1 lime"],"tools":["Small saucepan","Large nonstick skillet"],"steps":[{"n":1,"title":"COOK THE RICE","text":"Add the Spanish rice and ⅔ cup water to a small saucepan. Bring to a boil, reduce heat to low and cover. Cook until all of the water is absorbed and the rice is tender, about 15 to 20 minutes.","img":"121_1.jpg"},{"n":2,"title":"PREP THE VEGETABLES","text":"Peel and dice the onion. Peel and mince 1 clove garlic. Drain and rinse the black beans. Drain the Wildwood® tofu and dry well with paper towels. Destem the Lacinato kale, keeping the leaves as intact as much as possible. Massage kale leaves gently with your fingers to soften them slightly. Thinly slice the roasted red peppers.","img":"121_2.jpg"},{"n":3,"title":"PREPARE THE \"CHORIZO\"","text":"Place a large nonstick skillet over medium-high heat with 1 tbsp vegetable oil. Add the diced onion and garlic and cook until softened, about 4 to 5 minutes. Crumble the tofu into the skillet and add the Mexican oregano, Mexican chile spice, and ½ tsp salt. Cook until the tofu is browned in places and has dried out a little, about 7 to 9 minutes.","img":"121_3.jpg"},{"n":4,"title":"BUILD THE BURRITOS","text":"Lay the tortillas on a clean work surface. Top with Spanish rice, tofu chorizo, roasted red peppers, ¼ cup black beans, and some of the massaged kale. Roll the burritos, tucking in the sides as you go.","img":"121_4.jpg"},{"n":5,"title":"SEAR THE BURRITOS","text":"Wipe the skillet clean and return to medium heat with 2 tsp vegetable oil. Once hot, add the burritos to the skillet, seam side down, and cook until golden brown on the bottom, about 2 to 3 minutes. Carefully flip the burritos and cook an additional 2 minutes.","img":"121_5.jpg"},{"n":6,"title":"ADD THE FINISHING TOUCHES","text":"In a small bowl, mix the Follow Your Heart® Chipotle Vegenaise® with the juice from half of the lime. Cut the other half into wedges. Slice burritos in half and serve with chipotle lime sauce, any remaining kale and black beans, and lime wedges.","img":"121_6.jpg"}],"tips":["*Find a head of garlic in the Pumpkin Matar recipe bag.","TIP: Wrap tortillas in paper towels and microwave for 10 seconds to make them more pliable.","TIP: Wrap you burritos in foil before slicing for easy eating."],"cuisine_tags":["Mexican"],"ingredient_tags":["black beans","kale","rice","tofu","tortilla"],"item_tags":["chipotle vegenaise","lime","mexican chile spice","mexican oregano","roasted red peppers"],"issues":null,"front":"121a_IMG_9376.jpg","back":"121b_IMG_9377.jpg","era":"card","hero":"121.jpg"},{"pair":122,"title":"Seitan Massaman Curry","subtitle":"with Blistered Cherry Tomatoes & Brown Basmati Rice","servings":"2","cook_time":"40 minutes","nutrition":{"calories":"870","fat":"37 g","carbohydrates":"76 g","protein":"52 g"},"description":"Massaman is a staple in many Thai restaurants, but the history can be traced back to the Middle East. The tangy tamarind base of the curry gets rounded out with warm aromatic spices like cardamom, cinnamon, and cloves. We sear the seitan before it gets tossed in the sauce so that it stays crisp, so don't be afraid to let it get nice and browned in the skillet. Adjust the heat as you go and shake the skillet frequently for best results.","from_your_kitchen":["2 tbsp vegetable oil","Salt and pepper"],"ingredients":["¾ cup brown basmati rice","1 onion","3 garlic cloves*","4 oz haricot vert","1 lime","1 package Sweet Earth seitan","1 tbsp rice flour","6 oz cherry tomatoes","2 tbsp massaman curry paste","1 can coconut milk","Fresh basil"],"tools":["Small saucepan","Large nonstick skillet"],"steps":[{"n":1,"title":"COOK THE RICE","text":"Add brown basmati rice, 1¼ cup water, and a pinch of salt to a small saucepan and bring to a boil. Reduce heat to low and cook, covered, until all water is absorbed and rice is tender, about 30 to 35 minutes. Turn off the heat, leave covered for 5 minutes, and then fluff rice with a fork.","img":"122_1.jpg"},{"n":2,"title":"PREP THE VEGETABLES","text":"Peel and chop the onion. Peel and thinly slice 3 cloves of garlic. Trim the ends off the haricot vert. Halve the lime.","img":"122_2.jpg"},{"n":3,"title":"CRISP THE SEITAN","text":"Place a large nonstick skillet over medium-high heat and add 1 tbsp vegetable oil. In a medium bowl, toss the Sweet Earth seitan with the rice flour and a pinch of salt and pepper. Once the oil is hot, add the seitan to the skillet and cook, stirring occasionally, until crisp in places, about 3 to 4 minutes.","img":"122_3.jpg"},{"n":4,"title":"COOK THE VEGETABLES","text":"Transfer the crispy seitan to a plate. Return the skillet to medium-high heat and add 1 tbsp vegetable oil. Add the cherry tomatoes, sprinkle with salt and pepper, and cook, stirring occasionally, until the tomatoes are blistered and begin to burst, about 2 minutes. Add the onion, garlic, and haricot vert to the tomatoes and cook until just softened, about 5 minutes.","img":"122_4.jpg"},{"n":5,"title":"ADD THE CURRY PASTE","text":"Add the massaman curry paste to the vegetables and stir to combine. Add the coconut milk, ¼ cup water, and reduce heat to low. Simmer curry until the sauce has thickened slightly, about 5 to 10 minutes. Squeeze half of the lime into the skillet and stir. Taste the curry and season with salt and pepper. Stir the crispy seitan into the curry.","img":"122_5.jpg"},{"n":6,"title":"SERVE THE MEAL","text":"Cut the remaining lime half into wedges. Divide the brown basmati rice between large bowls and top with seitan massaman curry. Use your hands to tear the basil leaves over the bowls. Serve with lime wedges. Enjoy!","img":"122_6.jpg"}],"tips":["*The head of garlic included in this recipe bag is for all recipes in the box this week."],"cuisine_tags":["Thai"],"ingredient_tags":["green beans","rice","seitan","tomato"],"item_tags":["basil","coconut milk","lime","massaman curry paste","rice flour"],"issues":null,"front":"122a_IMG_9378.jpg","back":"122b_IMG_9379.jpg","era":"card","hero":"122.jpg"},{"pair":123,"title":"Collard Green Enchiladas","subtitle":"with Salsa Roja and Roasted Potatoes","servings":"2","cook_time":"40 minutes","nutrition":{"calories":"910","fat":"26 g","carbohydrates":"79 g","protein":"40 g"},"description":"Plant-based tortillas? Yes, please. Collard greens make a great substitute. Smothered in salsa roja (a classic Mexican red sauce), the tender rolls of chipotle \"sausage\" and vegetables will leave you satisfied.","from_your_kitchen":["1 tbsp vegetable oil","Salt and pepper"],"ingredients":["8 oz red potatoes","1 dried ancho chile pepper","8 oz collard greens","1 onion","1 green bell pepper","Vegan chipotle sausage","3 tbsp Follow Your Heart® vegan cream cheese","3 garlic cloves*","1 can diced tomatoes","1 tsp cumin","⅓ cup Follow Your Heart® vegan mozzarella"],"tools":["Baking sheet","Large pot","Small saucepan","Blender","8x8 baking dish"],"steps":[{"n":1,"title":"ROAST THE POTATOES","text":"Preheat the oven to 400°F. Quarter the red potatoes and add to a baking sheet. Toss with 1 tsp vegetable oil and generously season with salt and pepper. Roast until crispy on the bottom and you can easily pierce with a fork, about 18 to 20 minutes.","img":"123_1.jpg"},{"n":2,"title":"COOK THE COLLARDS","text":"Place a large pot with a few inches of salted water on to boil. Add the ancho chile to a small saucepan and cover with water. Bring to a simmer over medium heat. Trim the tough stems from collard greens; the leaves should stay intact. Once the water is boiling, add the leaves to the large pot and press into the water with a spatula. Cook collards until bright green, about 1 minute. Drain and rinse with cold water.","img":"123_2.jpg"},{"n":3,"title":"COOK THE FILLING","text":"Peel and chop the onion. Deseed and chop the green bell pepper. Wipe the pot dry, return to medium-high heat, and add 1 tbsp vegetable oil. Once hot, crumble the chipotle sausage into the pot and cook, stirring occasionally, until crispy, 3 to 5 minutes. Add the chopped onion and pepper, and cook until vegetables are softened, about 4 to 5 minutes. Mix in the Follow Your Heart® cream cheese.","img":"123_3.jpg"},{"n":4,"title":"MAKE THE SALSA ROJA","text":"Peel 3 cloves of garlic. To a blender, add the garlic, diced tomatoes, cumin, and ¾ cup water. Deseed the rehydrated ancho chile and add as much or as little as you'd like to the blender. Blend salsa until smooth, taste, and season with salt. Spread ½ cup of salsa roja onto the bottom of an 8x8 baking dish.","img":"123_4.jpg"},{"n":5,"title":"ROLL THE ENCHILADAS","text":"Lay the collard leaves out on a work space and divide the sausage mixture between them. Roll, folding in the sides (like a burrito), and place enchiladas in the baking dish seam side down. Cover with salsa roja (you may have some left over) and sprinkle with the mozzarella. Bake the enchiladas, uncovered, until the top is browned and sauce is bubbling, about 10 to 15 minutes.","img":"123_5.jpg"},{"n":6,"title":"PLATE AND ENJOY","text":"Scoop the collard green enchiladas onto plates. Serve with roasted potatoes and any remaining salsa roja. Dig in!","img":"123_6.jpg"}],"tips":["*Garlic will also be used in the Fettucine Alfredo recipe.","TIP: Let the chile simmer until you're ready to make the sauce.","TIP: Start with half the chile and add from there depending on how much you like heat."],"cuisine_tags":["Mexican"],"ingredient_tags":["bell pepper","collard greens","potato","vegan sausage"],"item_tags":["ancho chile","chipotle","cumin","diced tomatoes","vegan cream cheese","vegan mozzarella"],"issues":null,"front":"123a_IMG_9380.jpg","back":"123b_IMG_9381.jpg","era":"card","hero":"123.jpg"},{"pair":124,"title":"Sweet Potato Sushi Bowl","subtitle":"with Sambal Cucumbers and Yuzu Sauce","servings":"2","cook_time":"30 minutes","nutrition":{"calories":"670","fat":"28 g","carbohydrates":"93 g","protein":"10 g"},"description":"Yuzu is an aromatic fruit, somewhere between a lemon, grapefruit, and mandarin. For this dish, you'll use yuzu juice, and the taste will take your sushi bowl to the next level. Kizami nori, a traditional Japanese garnish, is sprinkled on top. Try to get a little in each bite for maximum flavor.","from_your_kitchen":["1 tbsp vegetable oil","Salt and pepper"],"ingredients":["12 oz sweet potato","¾ cup quinoa speckled rice","1 cucumber","1 tbsp sambal","1 tsp rice vinegar","1 tsp tamari","1 tsp sesame oil","1 tsp yuzu juice","3 tbsp Follow Your Heart Vegenaise®","2 oz Lacinato kale","1 tbsp sesame seeds","Kizami nori"],"tools":["Baking sheet","Small saucepan","Large nonstick skillet"],"steps":[{"n":1,"title":"ROAST THE SWEET POTATOES","text":"Preheat the oven to 400°F. Cut the sweet potato into wedges, transfer to a baking sheet, and toss with 2 tsp vegetable oil, salt, and pepper. Bake until the wedges are crisp and slightly browned, about 20 to 25 minutes.","img":"124_1.jpg"},{"n":2,"title":"COOK THE RICE","text":"Combine the quinoa speckled rice, 1¼ cups water, and a pinch of salt in a small saucepan and bring to a boil. Reduce heat to low and cook, covered, until all of the water is absorbed and the rice is tender, about 15 to 20 minutes.","img":"124_2.jpg"},{"n":3,"title":"MARINATE THE CUCUMBER","text":"Thinly slice the cucumber on the diagonal and place in a medium bowl. To the bowl, add the sambal, rice vinegar, tamari, and sesame oil. With a fork, toss the cucumbers with the sauce, ensuring they're evenly coated. Set aside to marinate.","img":"124_3.jpg"},{"n":4,"title":"PREPARE THE YUZU SAUCE","text":"Combine the yuzu juice and Follow Your Heart® Vegenaise® in a small bowl. Sprinkle with salt and mix yuzu sauce to combine.","img":"124_4.jpg"},{"n":5,"title":"COOK THE KALE","text":"Destem and chop the Lacinato kale. Place a large nonstick skillet over medium-high heat with 1 tsp vegetable oil. Once hot, add the chopped kale, sesame seeds, and a pinch of salt and pepper, and cook until greens are just wilted, about 1 minute.","img":"124_5.jpg"},{"n":6,"title":"BUILD YOUR BOWL","text":"To serve, scoop the quinoa speckled rice into large shallow bowls. Top with sambal cucumbers, sweet potato wedges, and sesame kale. Sprinkle with kizami nori and drizzle with yuzu sauce. Grab your chopsticks and enjoy!","img":"124_6.jpg"}],"tips":["TIP: You can use a rice cooker if you have one.","TIP: Add as much or as little sambal as you'd like—it's spicy!"],"cuisine_tags":["Japanese"],"ingredient_tags":["cucumber","kale","quinoa","rice","sweet potato"],"item_tags":["kizami nori","rice vinegar","sambal","sesame oil","sesame seeds","tamari","vegenaise","yuzu juice"],"issues":null,"front":"124a_IMG_9382.jpg","back":"124b_IMG_9383.jpg","era":"card","hero":"124.jpg"},{"pair":125,"title":"Autumn Quinoa Bowl","subtitle":"with Brussels Slaw and Warm Coconut \"Bacon\"","servings":"2","cook_time":"25 minutes","nutrition":{"calories":"690","fat":"34 g","carbohydrates":"85 g","protein":"19 g"},"description":"Coconut \"bacon\" is one of our recent favorites. We use just a bit of liquid smoke, maple, and miso to amp up the crispy texture of the coconut and add a savory twist. You can reuse the tahini dressing recipe for future greens and grains — it's easy to make and delicious.","from_your_kitchen":["1 tsp olive oil","Salt and pepper"],"ingredients":["¾ cup quinoa","¼ cup walnuts","5 oz Brussels sprouts","1 scallion","1 apple","2 oz napa cabbage","1 tbsp white miso paste","1 tbsp maple syrup*","¼ tsp liquid smoke","¼ cup coconut chips","2 tbsp tahini","1 tbsp apple cider vinegar","1 oz pomegranate seeds"],"tools":["Baking sheet","Small saucepan","Small skillet","Parchment paper (included in your box)"],"steps":[{"n":1,"title":"COOK THE QUINOA","text":"Preheat oven to 300°F and line a baking sheet with parchment paper. In a small saucepan, combine the quinoa, 1¼ cups water, and a pinch of salt and place over high heat. Bring to a boil, reduce heat to a simmer, cover, and cook quinoa until water is absorbed and spirals start to burst, about 12 to 15 minutes.","img":"125_1.jpg"},{"n":2,"title":"PREPARE THE SLAW","text":"Chop the walnuts. Place a small skillet over medium-high heat and add the walnuts. Cook until toasted, shaking the pan occasionally, about 3 to 5 minutes, and remove from heat. Thinly slice the Brussels sprouts, scallion, and apple and add to a large bowl along with the toasted walnuts and napa cabbage.","img":"125_2.jpg"},{"n":3,"title":"MAKE THE COCONUT \"BACON\"","text":"Line a baking sheet with parchment paper. In a bowl, mix the miso paste, liquid smoke, a pinch of pepper, 1 tsp olive oil, and just 2 tsp maple syrup into a paste. Place the coconut chips on the baking sheet and toss them in the miso mixture, adding a little at a time until coated — you may not need all of the miso mixture. Bake until brown, stirring halfway to avoid sticking, about 5 to 8 minutes.","img":"125_3.jpg"},{"n":4,"title":"MIX THE TAHINI DRESSING","text":"In a small bowl, combine the tahini, apple cider vinegar, and remaining 1 tsp maple syrup. Add a pinch of salt and 3 tbsp water. Whisk tahini dressing until smooth.","img":"125_4.jpg"},{"n":5,"title":"TOSS THE SLAW","text":"Add the tahini dressing to the Brussels slaw. Season with salt and pepper and toss slaw well to combine.","img":"125_5.jpg"},{"n":6,"title":"BUILD YOUR BOWLS","text":"Divide the cooked quinoa between large bowls. Top with Brussels slaw and warm coconut \"bacon.\" Sprinkle with pomegranate seeds and dig in!","img":"125_6.jpg"}],"tips":["*This item will be used in multiple steps.","TIP: If you have one, use a mandoline to slice your sprouts.","TIP: The coconut bacon will crisp up as it cools."],"cuisine_tags":["American","Comfort Food"],"ingredient_tags":["apple","brussels sprouts","napa cabbage","quinoa","walnuts"],"item_tags":["apple cider vinegar","coconut chips","liquid smoke","maple syrup","miso","pomegranate seeds","tahini"],"issues":null,"front":"125a_IMG_9384.jpg","back":"125b_IMG_9385.jpg","era":"card","hero":"125.jpg"},{"pair":126,"title":"Creamy Mac N' Cheese","subtitle":"with Green Chiles and Garlic Broccoli","servings":"2","cook_time":"35 minutes","nutrition":{"calories":"880","fat":"27 g","carbohydrates":"129 g","protein":"40 g"},"description":"Creamy and decadent, no one will believe this mac n' cheese has a plant-based sauce! This family friendly meal can be made with or without the green chiles, which are generally on the milder side and packed with flavor. Buttery breadcrumbs coat the top and be sure to watch these closely in the oven, it should only take a few minutes. The garlic broccoli is a head nod to a childhood favorite; cooked last minute and served bright green.","from_your_kitchen":["2 tbsp olive oil","Salt and pepper"],"ingredients":["6 oz pipette pasta","4 garlic cloves*","2 tbsp arrowroot starch","8 oz almond milk","1 lemon","1 packet dijon mustard","5 tbsp nutritional yeast","3 tbsp vegan parmesan","1 tbsp vegan butter","½ cup panko breadcrumbs","2 tbsp green chiles","8 oz broccoli florets"],"tools":["Large pot","Large nonstick skillet with a lid","Blender","8x8 baking dish"],"steps":[{"n":1,"title":"SET THE STAGE","text":"Place a large pot of salted water over high heat. Once boiling, add the pipette pasta, stir, and cook until tender, about 8 minutes. Drain but do not rinse. Mince the garlic.","img":"126_1.jpg"},{"n":2,"title":"START THE SAUCE","text":"Place a large nonstick skillet over medium-high heat with 1 tbsp olive oil. Set aside 1 tsp of the minced garlic for Step 6. Once hot, add the remaining garlic and cook until slightly toasted, about 1 to 2 minutes. Add the arrowroot starch and whisk continuously for 1 minute.","img":"126_2.jpg"},{"n":3,"title":"MAKE THE CHEESE SAUCE","text":"Slowly whisk the almond milk into the large skillet and cook for another 2 minutes, stirring frequently. It's okay if this mixture is lumpy. Carefully transfer the sauce to a blender. Halve the lemon. Add juice from the lemon, dijon mustard, nutritional yeast, and vegan parmesan to the blender and season with salt and pepper. Blend, taste, and adjust seasoning with salt if necessary.","img":"126_3.jpg"},{"n":4,"title":"BUTTERY BREADCRUMBS","text":"Set oven to broil on high. Melt the vegan butter in a microwave or small skillet. In a small bowl, combine the melted butter, panko breadcrumbs, and a pinch of salt.","img":"126_4.jpg"},{"n":5,"title":"PUT IT ALL TOGETHER","text":"Return the cheese sauce to the large skillet and place over medium-low heat. Add as much or as little of the green chiles as you'd like to the sauce. Bring sauce to a simmer and stir in cooked pasta. Transfer mac n' cheese to a 8x8 baking dish and top with buttery breadcrumbs. Broil until golden brown, about 3 to 5 minutes.","img":"126_5.jpg"},{"n":6,"title":"SERVE IT UP","text":"Rinse the large nonstick skillet and place over medium-high heat with 1 tbsp olive oil. Once hot, add the broccoli florets and reserved garlic. Cook until garlic is fragrant, about 1 minute. Add 2 tbsp water to create steam and cover. Cook until broccoli is just tender, about 4 to 5 minutes. Serve the creamy mac n' cheese on large plates with garlic broccoli. Dig in!","img":"126_6.jpg"}],"tips":["*This ingredient is split between multiple steps.","*The head of garlic included in this recipe bag is for all recipes in the box this week.","TIP: You will reuse this skillet, no need to rinse.","TIP: Omit the green chiles if you're sensitive to heat.","TIP: If you have time, let mac n' cheese stand for 5 minutes before serving."],"cuisine_tags":["American","Comfort Food"],"ingredient_tags":["broccoli","pasta"],"item_tags":["almond milk","arrowroot starch","dijon mustard","green chiles","nutritional yeast","panko breadcrumbs","vegan butter","vegan parmesan"],"issues":null,"front":"126a_IMG_9386.jpg","back":"126b_IMG_9387.jpg","era":"card","hero":"126.jpg"},{"pair":127,"title":"Refried Butternut Tacos","subtitle":"with Roasted Grape Salsa and Plantains","servings":"2","cook_time":"40 minutes","nutrition":{"calories":"610","fat":"27 g","carbohydrates":"95 g","protein":"8 g"},"description":"Our latest taco dish provides the perfect balance of sweet and spicy. Fragrant grapes and twice-cooked butternut squash complement flavorful chipotle and jalapeño. You'll enjoy your tacos with crispy plantains on the side.","from_your_kitchen":["1 tbsp + 1 tsp olive oil","1 tbsp vegetable oil","Salt and pepper"],"ingredients":["11 oz butternut squash","5 oz red grapes","1 jalapeño","1 scallion","Fresh cilantro","1 lime","1 plantain","1 tbsp vegan butter","2 tsp agave","2 tbsp chipotle hot sauce*","4 flour tortillas","3 oz green cabbage"],"tools":["Small saucepan","Baking sheet","Large nonstick skillet","Medium skillet"],"steps":[{"n":1,"title":"COOK THE BUTTERNUT","text":"Preheat oven to 400°F. Add the butternut squash to a small saucepan and cover with at least 1 inch of cold water. Bring to a boil, reduce heat to medium, and boil squash until tender (you should be able to pierce the flesh easily with a fork), about 11 to 13 minutes. Drain squash, return to the saucepan, and mash with a fork until smooth.","img":"127_1.jpg"},{"n":2,"title":"ROAST THE GRAPES","text":"Halve the grapes. Place on a baking sheet and toss with 1 tsp olive oil and a pinch of salt and pepper. Roast until grapes are soft, fragrant, and slightly wrinkled, about 6 to 8 minutes. Let cool for at least 5 minutes.","img":"127_2.jpg"},{"n":3,"title":"PREPARE THE SALSA","text":"Deseed and mince the jalapeño. Thinly slice the scallion. Finely chop the cilantro leaves. Combine everything in a medium bowl and add the juice from half the lime. Once the grapes have cooled slightly, add to the bowl along with a pinch of salt and pepper. Mix salsa well to combine. Cut remaining lime half into wedges. Peel the plantain and slice into 1 inch thick slices on the diagonal.","img":"127_3.jpg"},{"n":4,"title":"FRY THE BUTTERNUT","text":"Place a large nonstick skillet over medium-high heat with 1 tbsp olive oil. Add the mashed butternut and press into a single layer in the skillet. Lower heat to medium and cook, undisturbed, until bottom is well browned, about 5 to 8 minutes. Stir, then smooth squash into an even layer once again, and cook for 5 minutes. Stir in just 1 tsp chipotle hot sauce, butter, and agave. Season with salt.","img":"127_4.jpg"},{"n":5,"title":"CRISP THE PLANTAINS","text":"Wrap the flour tortillas in foil or a dish towel and warm them in the oven for about 5 minutes. Place a medium nonstick skillet over medium-high heat with 1 tbsp vegetable oil. Once the oil is hot, add the sliced plantains and cook until browned on one side, about 3 to 4 minutes. Flip, sprinkle with salt, and cook until browned on the other side, another 3 to 4 minutes.","img":"127_5.jpg"},{"n":6,"title":"BUILD YOUR TACOS","text":"Cut remaining lime half into wedges. Divide the refried butternut between the warm tortillas, spreading it out a bit. Add the roasted grape salsa and green cabbage. Drizzle on any remaining chipotle hot sauce and serve with crispy plantains and lime wedges. Dig in!","img":"127_6.jpg"}],"tips":["*This ingredient will be split between multiple steps.","TIP: We will use the oven again, don't turn it off yet!","TIP: Brown spots are normal on plantains—they indicate sweetness.","TIP: Lower heat as needed to prevent squash from burning."],"cuisine_tags":["Latin American","Mexican"],"ingredient_tags":["butternut squash","cabbage","grapes","plantain","tortilla"],"item_tags":["agave","chipotle hot sauce","cilantro","jalapeño","lime","vegan butter"],"issues":null,"front":"127a_IMG_9388.jpg","back":"127b_IMG_9389.jpg","era":"card","hero":"127.jpg"},{"pair":128,"image":"015b_IMG_9163.jpg","meal_type":"BREAKFAST","title":"Smoky Tofu & Sweet Potato Hash","subtitle":"with Avocado","servings":"4","cook_time":"20 min","nutrition":{"calories":"240","fat":"12 g","carbohydrates":"26 g","protein":"14 g"},"description":null,"from_your_kitchen":null,"ingredients":["1 sweet potato","1 red onion","4 mini sweet peppers","14 oz organic extra firm tofu","1 avocado","2 tbsp nutritional yeast","2 tsp smoked paprika"],"tools":null,"steps":[{"n":1,"title":null,"text":"Dice the sweet potato. Trim, halve and thinly slice the onion. Trim and thinly slice the mini sweet peppers. Crumble the tofu. Halve the avocado, remove the pit, and thinly slice the flesh."},{"n":2,"title":null,"text":"Heat 1 tbsp vegetable oil in a large nonstick skillet over medium-high heat. Add diced sweet potato and cook until lightly browned, 3 to 4 minutes. Add ⅓ cup water, cover, and steam until potato is fork-tender, 3 to 4 minutes. Add sliced onion, sliced sweet peppers, and a pinch of salt and pepper. Cook until vegetables are browned, 5 to 8 minutes."},{"n":3,"title":null,"text":"Heat 1 tbsp vegetable oil in another large skillet over medium-high heat. Add crumbled tofu, nutritional yeast, paprika, and a pinch of salt and pepper. Cook until tofu is golden brown, 5 to 8 minutes. Divide the sweet potato hash between plates and top with smoky tofu. Serve with sliced avocado."}],"tips":[],"cuisine_tags":["American","Comfort Food"],"ingredient_tags":["avocado","bell pepper","sweet potato","tofu"],"item_tags":["nutritional yeast","smoked paprika"],"issues":null,"front":"015b_IMG_9163.jpg","back":null,"era":"binder","hero":"128.jpg"},{"pair":129,"image":"025b_IMG_9183.jpg","meal_type":"LUNCH","title":"Kimchi Grilled Cheese Sandwiches","subtitle":"with Jalapeño & Sesame Butter","servings":"2","cook_time":"10 min","nutrition":{"calories":"410","fat":"20 g","carbohydrates":"48 g","protein":"9 g"},"description":null,"from_your_kitchen":null,"ingredients":["1 jalapeño 🌶","2.8 oz vegan cabbage kimchi","2 tbsp vegan butter","4 slices sourdough bread","1 tbsp sesame seeds","2 oz vegan cheddar cheese"],"tools":null,"steps":[{"n":1,"title":null,"text":"Trim, deseed, and thinly slice the jalapeño. Roughly chop the kimchi. Spread butter on each slice of sourdough bread, and sprinkle with sesame seeds."},{"n":2,"title":null,"text":"Heat a large nonstick skillet over medium-high heat. Add 2 slices of sourdough bread, butter side down. Sprinkle ¼ of the cheddar cheese on each slice, and add sliced jalapeño and chopped kimchi. Top with remaining cheddar cheese and close sandwiches with the remaining slices of bread, with the butter side up. Continue to cook sandwiches until they're browned on both sides, 3 to 4 minutes per side. Cut sandwiches in half and serve."}],"tips":["🌶 This item is spicy."],"cuisine_tags":["Comfort Food","Fusion","Korean"],"ingredient_tags":["kimchi","sourdough bread","vegan cheese"],"item_tags":["jalapeño","sesame seeds","vegan butter"],"issues":null,"front":"025b_IMG_9183.jpg","back":null,"era":"binder","hero":"129.jpg"},{"pair":130,"image":"059b_IMG_9251.jpg","meal_type":"EXTRAS!","title":"Curried Chickpea Salads","subtitle":"with Raisins & Tomatoes","servings":"2","cook_time":"5 min","nutrition":{"calories":"550","fat":"25 g","carbohydrates":"60 g","protein":"19 g"},"description":null,"from_your_kitchen":null,"ingredients":["13.4 oz chickpeas","1 celery stalk","4 oz cherry tomatoes","1 onion","¼ cup Follow Your Heart® Soy-Free Vegenaise®","2 tsp curry powder","¼ cup raisins","2 oz teen spinach"],"tools":null,"steps":[{"n":1,"title":null,"text":"Drain and rinse the chickpeas. Thinly slice the celery. Halve the cherry tomatoes. Peel and dice the onion. Add chickpeas to a large bowl and mash with a fork. Add sliced celery, diced onion, Vegenaise, curry powder, raisins, ½ tsp salt, and a pinch of pepper, and combine."},{"n":2,"title":null,"text":"Divide the teen spinach between 2 bowls. Top with curried chickpea salad and halved cherry tomatoes."}],"tips":[],"cuisine_tags":["Fusion","Indian"],"ingredient_tags":["chickpeas","spinach","tomato"],"item_tags":["celery","curry powder","raisins","vegenaise"],"issues":null,"front":"059b_IMG_9251.jpg","back":null,"era":"binder","hero":"130.jpg"},{"pair":131,"image":"102b_IMG_9339.jpg","meal_type":null,"title":"Sweet Potato Lasagna","subtitle":"with Tofu Ricotta and Marinated Bean Salad","servings":null,"cook_time":null,"nutrition":null,"description":null,"from_your_kitchen":["4 tbsp olive oil","Salt and pepper"],"ingredients":["8 oz sweet potato","1 shallot","3 cloves garlic*","Fresh oregano*","1 can cannellini beans","1 can crushed tomatoes","1 lemon","1 package Wildwood® Sprouted Organic Tofu","¼ tsp red chile flakes 🌶","4 oz baby kale"],"tools":["Medium oven-safe skillet with lid","Food processor","Large skillet"],"steps":[{"n":1,"title":"PREPARE THE VEGETABLES","text":"Peel the sweet potato and slice into thin half-moons, about ¼ inch thick. Peel and dice the shallot. Mince 2 cloves garlic. Finely chop the oregano leaves. Drain and rinse the cannellini beans.","img":"131_1.jpg"},{"n":2,"title":"START YOUR SAUCE","text":"Place a medium oven-safe skillet over medium heat with 1 tbsp olive oil. Add the diced shallot and a pinch of salt. Cook until the shallot is translucent, 1 to 2 minutes. Stir in the minced garlic and cook until fragrant, about 1 minute. Add the crushed tomatoes, half of the chopped oregano, and a pinch of salt. Reduce heat to medium-low and bring sauce to a simmer.","img":"131_2.jpg"},{"n":3,"title":"SIMMER THE SWEET POTATOES","text":"Add the sliced sweet potatoes to the sauce, cover with lid, and cook until tender (you should be able to pierce the potatoes easily with a fork), about 10 to 12 minutes. Set your oven to broil on high.","img":"131_3.jpg"},{"n":4,"title":"MAKE THE TOFU RICOTTA","text":"Zest and halve the lemon. Drain the Wildwood® tofu and add it to a food processor along with ½ tsp chopped oregano, juice from half the lemon, 2 tbsp olive oil, ½ tsp salt, and ½ tsp pepper. Blend tofu ricotta until smooth. With a large spoon or spatula, evenly spread the tofu ricotta over the sweet potatoes and sauce. Broil lasagna until the top begins to brown, about 3 to 5 minutes.","img":"131_4.jpg"},{"n":5,"title":"PREPARE THE BEAN SALAD","text":"Place a large skillet over medium heat with 1 tbsp olive oil. Finely mince the remaining clove of garlic. Add garlic, cannellini beans, ½ tsp lemon zest, as many of the red chile flakes as you'd like, and ¼ tsp salt to the skillet. Cook until just warm, about 2 to 3 minutes. Squeeze juice from the remaining lemon half into the beans and add the baby kale. Toss well to combine.","img":"131_5.jpg"},{"n":6,"title":"SERVE AND EAT UP","text":"Cut the sweet potato lasagna into pieces. Gently remove the pieces with a large spatula and place on large plates. Sprinkle with the remaining chopped oregano and serve with the marinated bean salad. Enjoy!","img":"131_6.jpg"}],"tips":["TIP: You could use a mandoline to slice the sweet potatoes.","TIP: No oven-safe skillet? Make the sauce in a saucepan, and assemble in a baking dish.","*These items will be split between multiple steps.","🌶 This item is spicy.","Rinse and dry the produce.","Handwritten note on step 3: printed \"10 to 12\" minutes crossed out and replaced with \"20 MIN\"."],"cuisine_tags":["Comfort Food","Italian"],"ingredient_tags":["cannellini beans","kale","sweet potato","tofu","tomato"],"item_tags":["crushed tomatoes","lemon","oregano","red chile flakes"],"issues":"Directions-side landscape card only; the matching front card (hero photo, summary, nutrition) is not present, so servings/cook time/nutrition are null.","front":"102b_IMG_9339.jpg","back":null,"era":"card","hero":null}];
